def emit_replay_event(event, **data):
    """Emit optional structured replay events without affecting simulation."""
    if "turn" not in data and CURRENT_REPLAY_TURN is not None:
        data["turn"] = CURRENT_REPLAY_TURN
    if ENGINE_METRICS is not None:
        try:
            ENGINE_METRICS.record_event(event, data)
        except Exception:
            pass
    if REPLAY_EVENT_HANDLER is None:
        return
    try:
        REPLAY_EVENT_HANDLER(event, data)
    except Exception:
        pass


def explicit_focus_access_card_names():
    raw = os.environ.get("MANALOOM_FOCUS_ACCESS_CARDS", "")
    if not raw:
        return tuple()
    try:
        parsed = json.loads(raw)
    except json.JSONDecodeError:
        parsed = [part.strip() for part in raw.split("|") if part.strip()]
    if not isinstance(parsed, list):
        return tuple()
    names = []
    for item in parsed:
        name = str(item).strip()
        if name and name not in names:
            names.append(name)
    return tuple(names)


def forced_focus_access_mode():
    mode = str(os.environ.get("MANALOOM_FORCE_FOCUS_ACCESS_MODE") or "none").strip().lower()
    if mode in {"top", "library-top", "library_top"}:
        return "library_top"
    if mode in {"hand", "opening-hand", "opening_hand"}:
        return "opening_hand"
    if mode not in FORCED_FOCUS_ACCESS_MODES:
        return "none"
    return mode


def reset_decision_trace_counter():
    """Reset per-replay decision IDs without touching simulation state."""
    global DECISION_TRACE_COUNTER
    DECISION_TRACE_COUNTER = 0


def _next_decision_id(replay_id=None):
    global DECISION_TRACE_COUNTER
    DECISION_TRACE_COUNTER += 1
    prefix = replay_id or "decision"
    return f"{prefix}-{DECISION_TRACE_COUNTER:06d}"


def decision_card_option(card, effect_data=None, score=None, action=None, **extra):
    """Small, stable card/action snapshot for decision trace JSONL."""
    if card is None:
        option = {"action": action or "none"}
    elif isinstance(card, dict):
        effect_data = effect_data or get_card_effect(card)
        option = {
            "card": card.get("name", "?"),
            "action": action or "cast",
            "effect": effect_data.get("effect", card.get("effect", "unknown")),
            "cmc": card.get("cmc", 0),
            "type_line": card.get("type_line", ""),
        }
    else:
        option = {"action": action or str(card)}
    if score is not None:
        option["score"] = score
    option.update({k: v for k, v in extra.items() if v is not None})
    return option


def _option_identity(option):
    if not isinstance(option, dict):
        return str(option)
    return str(option.get("card") or option.get("action") or option)


def _option_score(option, fallback=None):
    if not isinstance(option, dict):
        return fallback
    value = option.get("score", fallback)
    try:
        return float(value)
    except (TypeError, ValueError):
        return fallback


def _comparative_option_scores(chosen, options, rejected_options, expected_benefit_score):
    chosen_score = _option_score(chosen, fallback=expected_benefit_score)
    available_scored = []
    for option in options:
        score = _option_score(option)
        if score is None:
            continue
        available_scored.append(
            {
                "option": _option_identity(option),
                "score": score,
            }
        )
    rejected_scored = []
    for option in rejected_options:
        score = _option_score(option)
        if score is None:
            continue
        rejected_scored.append(
            {
                "option": _option_identity(option),
                "score": score,
            }
        )
    best_available = max((item["score"] for item in available_scored), default=chosen_score)
    best_rejected = max((item["score"] for item in rejected_scored), default=None)
    score_gap = None
    if chosen_score is not None and best_rejected is not None:
        score_gap = chosen_score - best_rejected
    return chosen_score, available_scored, rejected_scored, best_available, best_rejected, score_gap


def _default_strategic_principle(decision_type, reason=None):
    if decision_type == "mulligan_decision":
        return "opening_hand_must_have_mana_and_early_plan"
    if decision_type == "cast_spell":
        return "spend_mana_only_for_curve_plan_or_material_advantage"
    if decision_type == "response":
        return "use_interaction_on_lethal_engines_or_high_impact_threats"
    if decision_type == "combat_attack":
        return "attack_target_selected_by_lethal_threat_and_table_position"
    if decision_type == "pass_no_action":
        return "pass_when_no_profitable_or_legal_action_is_available"
    return reason or decision_type or "battle_heuristic"


def emit_decision_trace(
    *,
    decision_type,
    player,
    turn,
    phase,
    available_options,
    chosen_option,
    rejected_options=None,
    score_components=None,
    rule_source="heuristic",
    rule_status="heuristic",
    confidence="medium",
    expected_benefit_score=0,
    actual_outcome=None,
    reason=None,
    replay_id=None,
    strategic_principle=None,
    heuristic_version=None,
    resource_delta=None,
    risk_flags=None,
    alternatives_considered=None,
    rejected_reason=None,
    expected_payoff_reason=None,
):
    """Emit optional decision trace data without changing battle behavior."""
    if DECISION_TRACE_HANDLER is None:
        return
    try:
        options = list(available_options or [])
        chosen = chosen_option or {"action": "pass"}
        chosen_key = _option_identity(chosen)
        if chosen_key and all(_option_identity(option) != chosen_key for option in options):
            options.insert(0, chosen)
        rejected = list(rejected_options or [])
        if not rejected:
            rejected = [
                option
                for option in options
                if _option_identity(option) != chosen_key
            ]
        (
            chosen_option_score,
            available_option_scores,
            rejected_option_scores,
            best_available_option_score,
            best_rejected_option_score,
            score_gap_vs_best_rejected,
        ) = _comparative_option_scores(
            chosen,
            options,
            rejected,
            expected_benefit_score,
        )
        payload = {
            "schema_version": DECISION_TRACE_SCHEMA_VERSION,
            "decision_id": _next_decision_id(replay_id),
            "replay_id": replay_id,
            "turn": turn,
            "phase": phase,
            "player": getattr(player, "name", str(player)),
            "decision_type": decision_type,
            "available_options": options,
            "chosen_option": chosen,
            "rejected_options": rejected,
            "score_components": dict(score_components or {"heuristic": 0}),
            "rule_source": rule_source or "unknown",
            "rule_status": rule_status or "unknown",
            "confidence": confidence,
            "expected_benefit_score": expected_benefit_score,
            "expected_payoff_reason": expected_payoff_reason or reason,
            "actual_outcome": actual_outcome,
            "reason": reason,
            "strategic_principle": strategic_principle
            or _default_strategic_principle(decision_type, reason),
            "heuristic_version": heuristic_version or DECISION_STRATEGY_VERSION,
            "resource_delta": dict(resource_delta or {}),
            "risk_flags": list(risk_flags or []),
            "alternatives_considered": list(
                alternatives_considered if alternatives_considered is not None else options
            ),
            "rejected_reason": rejected_reason,
            "chosen_option_score": chosen_option_score,
            "available_option_scores": available_option_scores,
            "rejected_option_scores": rejected_option_scores,
            "best_available_option_score": best_available_option_score,
            "best_rejected_option_score": best_rejected_option_score,
            "score_gap_vs_best_rejected": score_gap_vs_best_rejected,
        }
        DECISION_TRACE_HANDLER(payload)
    except Exception:
        pass


class ReplacementRegistry:
    """Local proxy that keeps replacement replay events bound to this module."""

    @staticmethod
    def process_event(event):
        return _ReplacementRegistry.process_event(
            event,
            emit_replay_event=emit_replay_event,
        )


def _record_life_lost_this_turn(player, life_before):
    if player is None:
        return
    try:
        lost = max(0, int(life_before) - int(getattr(player, "life", life_before)))
    except Exception:
        lost = 0
    if lost > 0 and hasattr(player, "record_life_lost"):
        player.record_life_lost(lost, CURRENT_REPLAY_TURN)


def _record_life_gained_this_turn(player, life_before):
    if player is None:
        return
    try:
        gained = max(0, int(getattr(player, "life", life_before)) - int(life_before))
    except Exception:
        gained = 0
    if gained > 0 and hasattr(player, "record_life_gained"):
        player.record_life_gained(gained, CURRENT_REPLAY_TURN)


def change_life(player, delta):
    life_before = getattr(player, "life", None)
    changed = _change_life(player, delta, emit_replay_event=emit_replay_event)
    if changed and life_before is not None:
        _record_life_lost_this_turn(player, life_before)
        _record_life_gained_this_turn(player, life_before)
        refresh_life_total_threshold_statics_for_player(
            player,
            turn=CURRENT_REPLAY_TURN,
            phase="life_change",
            emit_events=True,
        )
    return changed


def deal_damage(player, amount, source=None):
    life_before = getattr(player, "life", None)
    dealt = _deal_damage(player, amount, emit_replay_event=emit_replay_event, source=source)
    if dealt and life_before is not None:
        _record_life_lost_this_turn(player, life_before)
        refresh_life_total_threshold_statics_for_player(
            player,
            turn=CURRENT_REPLAY_TURN,
            phase="damage",
            emit_events=True,
        )
    return dealt


def _permanents_with_static_replacement(player, flag):
    return [
        permanent
        for permanent in getattr(player, "battlefield", []) or []
        if isinstance(permanent, dict) and permanent.get(flag)
    ]


def _first_static_replacement_permanent(player, flag):
    permanents = _permanents_with_static_replacement(player, flag)
    return permanents[0] if permanents else None


def _life_gain_replacement_amount(player, amount):
    source = _first_static_replacement_permanent(player, "life_gain_replacement_double")
    if source is None:
        return amount, None
    try:
        multiplier = max(1, int(source.get("life_gain_multiplier") or 2))
    except (TypeError, ValueError):
        multiplier = 2
    return int(amount) * multiplier, source


def gain_life(player, amount, cap=40):
    if getattr(player, "cant_gain_life", False):
        emit_replay_event(
            "life_gain_prevented",
            player=getattr(player, "name", "?"),
            amount=amount,
            source=getattr(player, "cant_gain_life_source", None),
            prevention="cant_gain_life",
            duration=getattr(player, "cant_gain_life_duration", "rest_of_game"),
            turn=CURRENT_REPLAY_TURN,
        )
        return False
    requested_amount = int(amount or 0)
    final_amount, replacement_source = _life_gain_replacement_amount(player, requested_amount)
    if replacement_source is not None and final_amount != requested_amount:
        emit_replay_event(
            "life_gain_replacement_applied",
            player=getattr(player, "name", "?"),
            card=replacement_source.get("name", "?"),
            original_amount=requested_amount,
            final_amount=final_amount,
            multiplier=int(replacement_source.get("life_gain_multiplier") or 2),
            turn=CURRENT_REPLAY_TURN,
            **replay_rule_fields(replacement_source),
        )
    life_before = getattr(player, "life", None)
    gained = _gain_life(player, final_amount, cap=cap, emit_replay_event=emit_replay_event)
    if gained:
        if life_before is not None:
            _record_life_gained_this_turn(player, life_before)
        refresh_life_total_threshold_statics_for_player(
            player,
            turn=CURRENT_REPLAY_TURN,
            phase="gain_life",
            emit_events=True,
        )
    return gained


def clear_turn_scoped_permanent_flags(all_players):
    for participant in all_players or []:
        for permanent in getattr(participant, "battlefield", []) or []:
            if not isinstance(permanent, dict):
                continue
            permanent.pop("discard_modal_modes_used_this_turn", None)
            clear_permanent_damage_this_turn_flags(permanent)
        participant.noncombat_damage_modifiers = []
        participant.cards_drawn_this_turn = 0
        participant._cards_drawn_turn_marker = CURRENT_REPLAY_TURN
        participant.lands_played_this_turn = 0
        participant.life_lost_this_turn = 0
        participant._life_lost_turn_marker = CURRENT_REPLAY_TURN
        participant.life_gained_this_turn = 0
        participant._life_gained_turn_marker = CURRENT_REPLAY_TURN
        participant.creatures_died_this_turn = 0
        participant._creatures_died_turn_marker = CURRENT_REPLAY_TURN
        participant.attacked_this_turn = 0
        participant._attacked_turn_marker = CURRENT_REPLAY_TURN


class EngineMetrics:
    """Lightweight health telemetry for battle-engine simulations."""

    def __init__(self):
        self.counters = defaultdict(int)
        self.event_counts = defaultdict(int)
        self.max_stack_depth = 0
        self.warnings = []

    def increment(self, name, amount=1):
        self.counters[name] += amount

    def record_stack_depth(self, depth):
        self.max_stack_depth = max(self.max_stack_depth, int(depth or 0))

    def record_event(self, event, data=None):
        self.event_counts[event] += 1
        if event == "replacement_applied":
            self.increment("replacement_events")
        elif event == "cast_announced":
            self.increment("cast_announcements")
        elif event == "cast_illegal":
            self.increment("illegal_casts")
        elif event == "permanent_moved_by_sba":
            self.increment("sba_permanent_moves")
        elif event == "player_eliminated":
            self.increment("player_eliminations")
        if data and data.get("warning"):
            self.warnings.append(data["warning"])

    def snapshot(self):
        return {
            "counters": dict(self.counters),
            "event_counts": dict(self.event_counts),
            "max_stack_depth": self.max_stack_depth,
            "warnings": list(self.warnings),
        }


def set_engine_metrics(metrics):
    global ENGINE_METRICS
    ENGINE_METRICS = metrics
    return metrics


def clear_engine_metrics():
    global ENGINE_METRICS
    ENGINE_METRICS = None


def record_engine_metric(name, amount=1):
    if ENGINE_METRICS is not None:
        ENGINE_METRICS.increment(name, amount)


def record_stack_depth(depth):
    if ENGINE_METRICS is not None:
        ENGINE_METRICS.record_stack_depth(depth)


def write_engine_metrics_snapshot(path, metadata=None):
    if ENGINE_METRICS is None or not path:
        return None
    payload = {
        "schema_version": "battle_engine_metrics_v1",
        "created_at": datetime.now(timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ"),
        "metadata": metadata or {},
        **ENGINE_METRICS.snapshot(),
    }
    directory = os.path.dirname(path)
    if directory:
        os.makedirs(directory, exist_ok=True)
    tmp_path = f"{path}.tmp"
    with open(tmp_path, "w", encoding="utf-8") as handle:
        json.dump(payload, handle, ensure_ascii=True, sort_keys=True, indent=2)
        handle.write("\n")
    os.replace(tmp_path, path)
    return payload


def replay_card_snapshot(card):
    """Small JSON-safe card summary for turn-by-turn replay audits."""
    if not isinstance(card, dict):
        return {"name": str(card)}
    snapshot = {
        "name": card.get("name", "?"),
        "power": card.get("power"),
        "toughness": card.get("toughness"),
        "cmc": card.get("cmc"),
        "keywords": [
            keyword
            for keyword in (
                "flying",
                "reach",
                "trample",
                "deathtouch",
                "first_strike",
                "double_strike",
                "lifelink",
                "indestructible",
                "haste",
                "vigilance",
                "hexproof",
                "shroud",
            )
            if card.get(keyword)
        ],
        "is_commander": bool(card.get("is_commander")),
        "type_line": card.get("type_line", ""),
        "tapped": bool(card.get("tapped")),
        "summoning_sick": bool(card.get("summoning_sick")),
    }
    if card.get("must_attack_defender"):
        snapshot["must_attack_defender"] = card.get("must_attack_defender")
    if card.get("must_attack_if_able") or card.get("must_attack"):
        snapshot["must_attack_if_able"] = True
    return snapshot


class CastingContext:
    """Minimal CR 601.2 casting context with locked cost and legality state."""

    def __init__(
        self,
        card,
        controller,
        phase,
        *,
        additional_generic=0,
        role="normal",
        modes=None,
        alternative_cost=None,
        x_value=0,
        targets=None,
        additional_costs=None,
        source_zone="hand",
        alternative_cost_kind=None,
    ):
        self.card = card
        self.controller = controller
        self.phase = phase
        self.additional_generic = additional_generic
        self.role = role
        self.modes = list(modes or [])
        self.alternative_cost = alternative_cost
        self.x_value = max(0, int(x_value or 0))
        self.targets = list(targets or [])
        self.additional_costs = list(additional_costs or [])
        self.source_zone = source_zone
        self.alternative_cost_kind = alternative_cost_kind
        self.locked_cost = None
        self.effect_data = {}
        self.is_legal = False
        self.paid = False

    def to_replay_fields(self):
        return {
            "cast_pipeline": "601.2_minimal",
            "locked_cost": replay_cost_snapshot(self.locked_cost),
            "additional_generic": self.additional_generic,
            "alternative_cost": self.alternative_cost,
            "x_value": self.x_value,
            "additional_costs": list(self.additional_costs),
            "modes": list(self.modes),
            "targets": list(self.targets),
            "role": self.role,
            "source_zone": self.source_zone,
            "alternative_cost_kind": self.alternative_cost_kind,
        } | replay_primary_target_fields(self.targets)


def replay_primary_target_fields(targets):
    if not targets:
        return {}
    first = targets[0]
    if isinstance(first, dict):
        target = first.get("target") or first.get("target_name")
        return {
            key: value
            for key, value in {
                "target": target,
                "target_controller": first.get("target_controller"),
                "target_type": first.get("target_type"),
                "target_legal": first.get("target_legal"),
            }.items()
            if value is not None
        }
    return {"target": str(first)}


def zero_mana_cost_snapshot(*spend_tags):
    return {
        "generic": 0,
        "colored": {},
        "hybrid": [],
        "monocolored_hybrid": [],
        "phyrexian": [],
        "phyrexian_hybrid": [],
        "spend_tags": list(spend_tags),
    }


def store_cast_context_fields(effect_data, fields):
    if isinstance(effect_data, dict):
        effect_data["_cast_context"] = copy.deepcopy(fields)
    return effect_data


def mark_cast_ledger_emitted(effect_data):
    if isinstance(effect_data, dict):
        effect_data["_cast_ledger_emitted"] = True
    return effect_data


def ensure_stack_cast_ledger_event(stack_item, turn, phase):
    if not stack_item or getattr(stack_item, "was_cast", True) is False:
        return False
    effect_data = getattr(stack_item, "effect_data", None) or {}
    if effect_data.get("effect") == "triggered_ability":
        return False
    if effect_data.get("_cast_ledger_emitted"):
        return False
    cast_context = copy.deepcopy(effect_data.get("_cast_context") or {})
    if not cast_context:
        return False
    card = getattr(stack_item, "card", None) or {}
    controller = getattr(stack_item, "controller", None)
    recovered_phase = phase or cast_context.get("phase")
    cast_context.pop("phase", None)
    emit_replay_event(
        "spell_cast",
        player=getattr(controller, "name", "?"),
        card=card.get("name", "?"),
        effect=effect_data.get("effect", "unknown"),
        type_line=card.get("type_line", ""),
        cmc=card.get("cmc", 0),
        turn=turn,
        phase=recovered_phase,
        cast_ledger_recovered=True,
        recovery_reason="stack_item_missing_cast_ledger",
        **cast_context,
        **replay_rule_fields(effect_data),
    )
    mark_cast_ledger_emitted(effect_data)
    return True


def resolved_spell_destination(card, effect_data, effect, player=None):
    if isinstance(card, dict) and card.get("is_copy"):
        return "ceased_to_exist"
    if isinstance(card, dict) and card.get("_flashback_cast"):
        return "exile"
    if isinstance(card, dict) and card.get("_adventure_cast") and card.get("_adventure_parent"):
        return "exile"
    if is_first_rebound_resolution(card, effect_data):
        return "exile"
    if effect_data.get("exiles_self"):
        return "exile"
    if effect == "ramp_ritual" and effect_data.get("sacrifice_self_for_mana"):
        return "graveyard"
    if effect == "approach":
        recorded_count = effect_data.get("_approach_cast_count_after_recorded")
        if recorded_count is not None:
            try:
                return "graveyard" if int(recorded_count) >= 2 else "library"
            except (TypeError, ValueError):
                pass
        if not effect_data.get("_approach_cast_count_recorded") and player is not None:
            return "graveyard" if getattr(player, "approach_count", 0) >= 1 else "library"
        return "library"
    if buyback_was_paid(effect_data):
        return "hand"
    if effect_data.get("shuffle_self_into_library_on_resolution"):
        return "library"
    if is_instant_or_sorcery_spell(card):
        return "graveyard"
    if effect == "land":
        return "none"
    return "battlefield"


def spell_resolution_context_fields(card, effect_data, effect, player=None):
    fields = {}
    if isinstance(effect_data, dict):
        fields.update(copy.deepcopy(effect_data.get("_cast_context") or {}))
        fields.update(copy.deepcopy(effect_data.get("_resolution_context") or {}))
    if fields.get("cast_pipeline") and not fields.get("priority_window"):
        fields.setdefault("priority_window", "direct_resolution")
        fields.setdefault("stack_depth", 0)
        fields.setdefault("resolved_from_stack", False)
    destination = resolved_spell_destination(card, effect_data, effect, player=player)
    source_zone = fields.get("source_zone") or effect_data.get("source_zone")
    if (
        not source_zone
        and isinstance(card, dict)
        and (card.get("is_copy") or (isinstance(effect_data, dict) and effect_data.get("_copied_from_spell")))
    ):
        source_zone = "stack_copy"
        fields.setdefault("cast_pipeline", "spell_copy")
        fields.setdefault("locked_cost", {"copied_spell": True})
    fields.setdefault("stack_object", card.get("name", "?"))
    fields.setdefault("result", "resolved")
    if source_zone:
        fields["source_zone"] = source_zone
        fields.setdefault("from_zone", "stack" if source_zone == "stack_copy" else source_zone)
    if destination:
        fields.setdefault("destination", destination)
        fields.setdefault("zone_after", destination)
        fields.setdefault("to_zone", destination)
    if isinstance(card, dict) and card.get("is_copy"):
        fields.setdefault("source_zone", "stack_copy")
        if not fields.get("from_zone") or fields.get("from_zone") == fields.get("source_zone") == "stack_copy":
            fields["from_zone"] = "stack"
        if not fields.get("cast_pipeline") or fields.get("cast_pipeline") == "direct_resolution":
            fields["cast_pipeline"] = "spell_copy_resolution"
        fields.setdefault("locked_cost", zero_mana_cost_snapshot("copied_spell_no_mana_payment"))
        fields.setdefault("priority_window", "copy_resolution")
        fields.setdefault("stack_depth", 0)
        fields.setdefault("resolved_from_stack", False)
    elif fields.get("cast_pipeline"):
        fields.setdefault("priority_window", "direct_spell_resolution")
        fields.setdefault("stack_depth", 0)
        fields.setdefault("resolved_from_stack", False)
    allowed = {
        "phase",
        "priority_window",
        "stack_depth",
        "stack_object",
        "stack_object_id",
        "source_zone",
        "from_zone",
        "to_zone",
        "destination",
        "zone_after",
        "cast_pipeline",
        "locked_cost",
        "resolved_from_stack",
        "result",
        "targets",
        "target",
        "target_controller",
        "target_type",
        "target_legal",
        "role",
        "additional_generic",
        "alternative_cost",
        "alternative_cost_kind",
        "x_value",
        "additional_costs",
        "modes",
    }
    return {
        key: value
        for key, value in fields.items()
        if key in allowed and value not in (None, [], {})
    }


def attach_stack_resolution_context(effect_data, stack_item, phase, stack_depth):
    fields = copy.deepcopy(effect_data.get("_cast_context") or {})
    fields.update(copy.deepcopy(effect_data.get("_resolution_context") or {}))
    if (
        isinstance(getattr(stack_item, "card", None), dict)
        and (
            stack_item.card.get("is_copy")
            or (isinstance(effect_data, dict) and effect_data.get("_copied_from_spell"))
        )
    ):
        fields.setdefault("source_zone", "stack_copy")
        fields.setdefault("from_zone", "stack")
        fields.setdefault("cast_pipeline", "spell_copy")
        fields.setdefault("locked_cost", {"copied_spell": True})
    fields.update(
        {
            "phase": phase or fields.get("phase"),
            "priority_window": "stack_resolution",
            "stack_depth": stack_depth,
            "stack_object": stack_item.card.get("name", "?"),
            "resolved_from_stack": True,
            "result": "resolved",
        }
    )
    store_cast_context_fields(effect_data, fields)
    effect_data["_resolution_context"] = copy.deepcopy(fields)
    return effect_data


def attach_direct_resolution_context(
    effect_data,
    card,
    phase,
    *,
    priority_window,
    source_zone="hand",
    locked_cost=None,
    targets=None,
    alternative_cost=None,
    alternative_cost_kind=None,
):
    fields = copy.deepcopy(effect_data.get("_cast_context") or {})
    fields.update(
        {
            "phase": phase or fields.get("phase"),
            "priority_window": priority_window,
            "stack_depth": 0,
            "stack_object": card.get("name", "?"),
            "source_zone": source_zone,
            "cast_pipeline": fields.get("cast_pipeline") or "direct_resolution",
            "locked_cost": locked_cost or fields.get("locked_cost"),
            "alternative_cost": alternative_cost or fields.get("alternative_cost"),
            "alternative_cost_kind": alternative_cost_kind or fields.get("alternative_cost_kind"),
            "targets": list(targets or fields.get("targets") or []),
            "resolved_from_stack": False,
            "result": "resolved",
        }
    )
    fields.update(replay_primary_target_fields(fields.get("targets") or []))
    store_cast_context_fields(effect_data, fields)
    effect_data["_resolution_context"] = copy.deepcopy(fields)
    return effect_data


def _type_line_lower(card):
    return str((card or {}).get("type_line") or "").lower() if isinstance(card, dict) else ""


def card_is_historic_spell(card):
    type_line = _type_line_lower(card)
    return "artifact" in type_line or "legendary" in type_line or "saga" in type_line


def flash_permission_card_matches(card, filter_name):
    if not isinstance(card, dict) or is_effective_land(card):
        return False
    normalized_filter = str(filter_name or "nonland_spells").strip().lower()
    type_line = _type_line_lower(card)
    if normalized_filter == "nonland_spells":
        return True
    if normalized_filter == "artifact_spells":
        return "artifact" in type_line
    if normalized_filter == "sorcery_spells":
        return "sorcery" in type_line
    if normalized_filter == "historic_spells":
        return card_is_historic_spell(card)
    if normalized_filter == "sliver_spells":
        return "creature" in type_line and permanent_has_subtype(card, "sliver")
    if normalized_filter == "creature_or_enchantment_spells":
        return "creature" in type_line or "enchantment" in type_line
    if normalized_filter == "green_creature_spells":
        return "creature" in type_line and _spell_has_color(card, "G")
    return False


def controller_casts_nonland_as_flash(controller, card):
    if controller is None or is_effective_land(card):
        return False
    for participant in _table_players_for(controller):
        same_controller = participant is controller
        for permanent in getattr(participant, "battlefield", []) or []:
            if not isinstance(permanent, dict):
                continue
            permission_controller = str(
                permanent.get("flash_permission_controller")
                or ("any_player" if permanent.get("flash_permission_any_player") else "self")
            )
            if not same_controller and permission_controller != "any_player":
                continue
            if permanent.get("cast_nonland_spells_as_flash"):
                return True
            if not permanent.get("cast_spells_as_flash"):
                continue
            if flash_permission_card_matches(card, permanent.get("flash_permission_filter")):
                return True
    return False


def spell_requires_main_phase(card, effect_data):
    if is_effective_land(card):
        return False
    if card_has_keyword(card, "flash") or str((effect_data or {}).get("instant") or "").lower() == "true":
        return False
    type_line = _type_line_lower(card)
    if "instant" in type_line:
        return False
    if (effect_data or {}).get("effect") == "creature":
        return True
    return any(
        card_type in type_line
        for card_type in ("sorcery", "creature", "artifact", "enchantment", "planeswalker", "battle")
    )


def can_cast_in_phase(card, effect_data, phase, controller=None):
    if is_effective_land(card):
        return False
    if str(effect_data.get("effect") or "").lower() in COUNTERLIKE_EFFECTS:
        return False
    if spell_type_cast_lock_for_card(controller, card, effect_data):
        return False
    if static_spell_limit_lock_for_card(controller, card, effect_data):
        return False
    if phase not in MAIN_PHASES:
        if controller_casts_nonland_as_flash(controller, card):
            return True
        if spell_requires_main_phase(card, effect_data):
            return False
    return True


def player_controls_commander(player):
    commander_names = set()
    commander = getattr(player, "commander", None)
    if isinstance(commander, dict):
        commander_names.add(normalize_card_name(commander.get("name", "")))
    for commander_card in getattr(player, "command_zone", []) or []:
        if isinstance(commander_card, dict):
            commander_names.add(normalize_card_name(commander_card.get("name", "")))
    commander_names.discard("")

    for permanent in getattr(player, "battlefield", []) or []:
        if not isinstance(permanent, dict):
            continue
        if permanent.get("is_commander"):
            return True
        if commander_names and normalize_card_name(permanent.get("name", "")) in commander_names:
            return True
    return False


def alternative_cost_for_effect(player, card, effect_data):
    if not isinstance(effect_data, dict):
        return None, None
    condition = str(effect_data.get("alternative_cost_condition") or "").strip().lower()
    if (
        effect_data.get("free_if_control_commander")
        or condition == "control_commander"
    ) and player_controls_commander(player):
        return str(effect_data.get("alternative_cost") or "{0}"), "control_commander"
    overload_cost = str(effect_data.get("overload_cost") or "").strip()
    if overload_cost and effect_data.get("effect") == "overload_recursion":
        graveyard_spell_count = sum(
            1
            for grave_card in getattr(player, "graveyard", []) or []
            if isinstance(grave_card, dict) and is_instant_or_sorcery_spell(grave_card)
        )
        min_targets = int(effect_data.get("overload_min_targets") or 2)
        if graveyard_spell_count >= min_targets and player.can_pay(
            card_mana_cost(card, alternative_cost=overload_cost)
        ):
            return overload_cost, "overload"
    return None, None


