BRAIN_IN_A_JAR_SCOPE = "xmage_brain_in_a_jar_charge_counter_free_cast_scry_v1"
MEDALLION_COLOR_RESTRICTIONS = {
    "pearl medallion": "W",
    "sapphire medallion": "U",
    "jet medallion": "B",
    "ruby medallion": "R",
    "emerald medallion": "G",
}
COLOR_NAME_TO_SYMBOL = {
    "white": "W",
    "blue": "U",
    "black": "B",
    "red": "R",
    "green": "G",
    "w": "W",
    "u": "U",
    "b": "B",
    "r": "R",
    "g": "G",
}
SYMBOL_TO_COLOR_NAME = {
    "W": "white",
    "U": "blue",
    "B": "black",
    "R": "red",
    "G": "green",
}


def _as_list(value):
    if value is None:
        return []
    if isinstance(value, list):
        return value
    if isinstance(value, tuple) or isinstance(value, set):
        return list(value)
    if isinstance(value, str):
        decoded = read_json_list(value)
        if decoded is not None:
            return decoded
        if "," in value:
            return [part.strip() for part in value.split(",") if part.strip()]
    return [value]


def _color_symbol(value):
    text = str(value or "").strip()
    if not text:
        return None
    return COLOR_NAME_TO_SYMBOL.get(text.lower(), text.upper())


def _symbols_from_value(value):
    symbols = set()
    for item in _as_list(value):
        symbol = _color_symbol(item)
        if symbol in SYMBOL_TO_COLOR_NAME:
            symbols.add(symbol)
    return symbols


def _spell_color_symbols(card):
    symbols = set()
    for key in ("colors", "colors_json", "card_colors"):
        symbols.update(_symbols_from_value(card.get(key)))
    if symbols:
        return symbols
    mana_cost = str(card.get("mana_cost") or "")
    for symbol in re.findall(r"\{([WUBRG])\}", mana_cost.upper()):
        symbols.add(symbol)
    return symbols


def _spell_has_color(card, requested_symbol):
    symbol = _color_symbol(requested_symbol)
    if not symbol:
        return False
    return symbol in _spell_color_symbols(card)


def _numeric_card_stat(card, stat, fallback_stat=None, default=0):
    if not isinstance(card, dict):
        return int(default or 0)
    value = card.get(stat)
    if (value is None or value == "") and fallback_stat:
        value = card.get(fallback_stat)
    if value is None or value == "":
        value = default
    try:
        return int(float(value))
    except Exception:
        return int(default or 0)


def _card_type_matches(card, allowed_types):
    allowed = {str(value).lower() for value in _as_list(allowed_types) if value}
    if not allowed:
        return True
    type_line = str(card.get("type_line") or "").lower()
    return any(card_type in type_line for card_type in allowed)


def _card_subtype_matches(card, allowed_subtypes):
    allowed = {str(value).lower() for value in _as_list(allowed_subtypes) if value}
    if not allowed:
        return True
    return any(permanent_has_subtype(card, subtype) for subtype in allowed)


def _static_cost_reduction_scope(effect_data):
    return str(effect_data.get("battle_model_scope") or STATIC_COST_REDUCTION_SCOPE).strip()


def _static_cost_reduction_amount_source(effect_data):
    for key in (
        "cost_reduction_amount_source",
        "generic_cost_reduction_source",
        "cost_reduction_dynamic",
        "amount_source",
    ):
        value = str(effect_data.get(key) or "").strip().lower()
        if value:
            return value
    if _static_cost_reduction_scope(effect_data) == POWER_BASED_INSTANT_SORCERY_COST_REDUCTION_SCOPE:
        return "source_power"
    return ""


def _static_cost_reduction_color_symbols(effect_data):
    symbols = []
    for key in (
        "cost_reduction_color_symbols",
        "cost_reduction_colors",
        "cost_reduction_colored_symbols",
        "colored_cost_reduction_symbols",
    ):
        for value in _as_list(effect_data.get(key)):
            symbol = _color_symbol(value)
            if symbol in SYMBOL_TO_COLOR_NAME and symbol not in symbols:
                symbols.append(symbol)
    return symbols


def _battlefield_creature_count_for_cost_reduction(controller):
    if controller is None:
        return 0
    count = 0
    participants = [controller, *list(getattr(controller, "_current_opponents", []) or [])]
    for participant in participants:
        for permanent in getattr(participant, "battlefield", []) or []:
            if isinstance(permanent, dict) and is_battlefield_creature(permanent):
                count += 1
    return count


def _graveyard_count_for_cost_reduction(controller, effect_data):
    if controller is None:
        return 0
    allowed_types = [str(value).lower() for value in _as_list(effect_data.get("graveyard_count_card_types")) if value]
    count = 0
    for graveyard_card in getattr(controller, "graveyard", []) or []:
        if not isinstance(graveyard_card, dict):
            continue
        if allowed_types and not _card_type_matches(graveyard_card, allowed_types):
            continue
        count += 1
    return count


def _source_power_value(source):
    for key in ("current_power", "power", "base_power"):
        if key not in source:
            continue
        try:
            return max(0, int(float(source.get(key) or 0)))
        except (TypeError, ValueError):
            continue
    return 0


def _static_cost_reduction_amount(source, effect_data, *, controller=None):
    amount_source = _static_cost_reduction_amount_source(effect_data)
    if amount_source in {"source_power", "this_power", "source_permanent_power"}:
        return _source_power_value(source)
    if amount_source == "creature_count_on_battlefield":
        return _battlefield_creature_count_for_cost_reduction(controller)
    if amount_source == "instant_sorcery_cards_in_your_graveyard_count":
        return _graveyard_count_for_cost_reduction(controller, effect_data)
    for key in (
        "cost_reduction_generic",
        "generic_cost_reduction",
        "cost_reduction_amount",
        "generic_reduction",
        "amount",
    ):
        if key not in effect_data:
            continue
        try:
            return max(0, int(effect_data.get(key) or 0))
        except (TypeError, ValueError):
            return 0
    if str(effect_data.get("effect") or "") in STATIC_COST_REDUCTION_EFFECTS:
        if _static_cost_reduction_color_symbols(effect_data):
            return 0
        return 1
    return 0


def _static_cost_reduction_card_types(effect_data):
    for key in (
        "applies_to_card_types",
        "applies_to_spell_types",
        "spell_types",
        "card_types",
    ):
        values = [str(value).lower() for value in _as_list(effect_data.get(key)) if value]
        if values:
            return values
    if _static_cost_reduction_scope(effect_data) == POWER_BASED_INSTANT_SORCERY_COST_REDUCTION_SCOPE:
        return ["instant", "sorcery"]
    return []


def _static_cost_reduction_subtypes(effect_data):
    for key in (
        "applies_to_subtypes",
        "applies_to_spell_subtypes",
        "spell_subtypes",
        "subtypes",
    ):
        values = [str(value).lower() for value in _as_list(effect_data.get(key)) if value]
        if values:
            return values
    return []


def shared_card_types(card):
    if not isinstance(card, dict):
        return []
    type_line = str(card.get("type_line") or "").lower()
    found = []
    for card_type in sorted(MTG_SHARED_CARD_TYPES):
        if re.search(rf"\b{re.escape(card_type)}\b", type_line):
            found.append(card_type)
    return found


def source_imprinted_card_types(source):
    for key in ("imprinted_card_types", "imprinted_types", "imprint_card_types"):
        values = [str(value).lower() for value in _as_list((source or {}).get(key)) if value]
        if values:
            return sorted(set(values) & MTG_SHARED_CARD_TYPES)
    imprinted_card = (source or {}).get("imprinted_card_object")
    if isinstance(imprinted_card, dict):
        return shared_card_types(imprinted_card)
    return []


def chosen_card_type_options(effect_data):
    options = [
        str(value).lower()
        for value in _as_list((effect_data or {}).get("chosen_card_type_options"))
        if str(value or "").lower() in MTG_SHARED_CARD_TYPES
    ]
    if options:
        return options
    return ["artifact", "creature", "enchantment", "instant", "sorcery"]


def _card_type_choice_score(player, card_type, amount):
    total_reduction = 0
    matching_spell_count = 0
    highest_mana_value = 0
    for hand_card in getattr(player, "hand", []) or []:
        if not isinstance(hand_card, dict):
            continue
        if not _card_type_matches(hand_card, [card_type]):
            continue
        cost = card_mana_cost(hand_card)
        try:
            generic_cost = max(0, int(cost.get("generic", 0) or 0))
        except (TypeError, ValueError):
            generic_cost = 0
        applied_amount = min(generic_cost, max(0, int(amount or 0)))
        if applied_amount <= 0:
            continue
        total_reduction += applied_amount
        matching_spell_count += 1
        highest_mana_value = max(highest_mana_value, int(card_mana_value(hand_card) or 0))
    return total_reduction, matching_spell_count, highest_mana_value


def choose_card_type_for_cost_reducer(player, permanent, effect_data):
    options = chosen_card_type_options(effect_data)
    preferred = [
        str(value).lower()
        for value in _as_list((effect_data or {}).get("preferred_card_type_order"))
        if str(value or "").lower() in options
    ]
    preferred.extend(option for option in options if option not in preferred)
    preference_rank = {card_type: len(preferred) - index for index, card_type in enumerate(preferred)}
    amount = _static_cost_reduction_amount(permanent, effect_data, controller=player)
    scored = []
    for card_type in options:
        total, count, highest = _card_type_choice_score(player, card_type, amount)
        scored.append((total, count, highest, preference_rank.get(card_type, 0), card_type))
    best_total, best_count, _highest, _rank, chosen = max(scored)
    reason = "hand_maximize_reduction" if best_total > 0 and best_count > 0 else "preferred_default"
    return chosen, reason, {
        "estimated_reduction": best_total,
        "matching_spell_count": best_count,
    }


def resolve_chosen_card_type_cost_reducer(player, permanent, effect_data, turn=None):
    chosen, reason, score = choose_card_type_for_cost_reducer(player, permanent, effect_data)
    permanent["chosen_card_type"] = chosen
    permanent["chosen_card_type_reason"] = reason
    permanent["chosen_card_type_options"] = chosen_card_type_options(effect_data)
    emit_replay_event(
        "chosen_card_type_resolved",
        player=player.name,
        card=permanent.get("name", "?"),
        chosen_card_type=chosen,
        reason=reason,
        estimated_reduction=score.get("estimated_reduction", 0),
        matching_spell_count=score.get("matching_spell_count", 0),
        turn=turn,
        **replay_rule_fields(effect_data),
    )


def _static_cost_reduction_min_mana_value(effect_data):
    for key in (
        "minimum_mana_value",
        "min_mana_value",
        "mana_value_min",
        "minimum_cmc",
        "min_cmc",
        "cmc_min",
    ):
        if key not in effect_data:
            continue
        try:
            return max(0, int(float(effect_data.get(key) or 0)))
        except (TypeError, ValueError):
            return None
    if _static_cost_reduction_scope(effect_data) == POWER_BASED_INSTANT_SORCERY_COST_REDUCTION_SCOPE:
        return 4
    return None


def _static_cost_reduction_color_restrictions(source, effect_data):
    color_values = []
    for key in (
        "applies_to_spell_colors",
        "spell_colors",
        "spell_color",
        "applies_to_colors",
        "applies_to_color",
        "color",
    ):
        color_values.extend(_as_list(effect_data.get(key)))
    if not color_values:
        source_name = normalize_card_name(source.get("name", ""))
        medallion_symbol = MEDALLION_COLOR_RESTRICTIONS.get(source_name)
        if medallion_symbol:
            color_values.append(medallion_symbol)
    return {
        symbol
        for symbol in (_color_symbol(value) for value in color_values)
        if symbol in SYMBOL_TO_COLOR_NAME
    }


def _source_static_cost_reduction_effect(source):
    if not isinstance(source, dict):
        return {}
    direct_effect = str(source.get("effect") or "").strip()
    if direct_effect in STATIC_COST_REDUCTION_EFFECTS:
        return source
    try:
        effect_data = get_card_effect(source)
    except Exception:
        return {}
    if not isinstance(effect_data, dict):
        return {}
    if str(effect_data.get("effect") or "").strip() in STATIC_COST_REDUCTION_EFFECTS:
        return effect_data
    return {}


def _controlled_permanent_has_subtype(permanent, subtype):
    if not isinstance(permanent, dict) or not subtype:
        return False
    type_line = str(permanent.get("type_line") or "").lower()
    return bool(re.search(rf"\b{re.escape(str(subtype).lower())}\b", type_line))


def _controlled_creature_has_keyword(permanent, keyword):
    if not isinstance(permanent, dict) or not keyword or not is_battlefield_creature(permanent):
        return False
    normalized_keyword = str(keyword).strip().lower().replace(" ", "_")
    if bool(permanent.get(normalized_keyword)):
        return True
    return normalized_keyword in _keyword_values(permanent)


def _graveyard_card_type_set(player):
    card_types = {
        "artifact",
        "battle",
        "creature",
        "enchantment",
        "instant",
        "land",
        "planeswalker",
        "sorcery",
        "tribal",
    }
    seen = set()
    for card in getattr(player, "graveyard", []) or []:
        if not isinstance(card, dict):
            continue
        type_line = str(card.get("type_line") or "").lower()
        for card_type in card_types:
            if re.search(rf"\b{re.escape(card_type)}\b", type_line):
                seen.add(card_type)
    return seen


def _graveyard_card_type_count(player):
    return len(_graveyard_card_type_set(player))


def _cost_reduction_condition_satisfied(effect_data, controller):
    condition = str(effect_data.get("cost_reduction_condition") or "").strip().lower()
    if not condition:
        return True
    battlefield = getattr(controller, "battlefield", []) or []
    opponents = list(getattr(controller, "_current_opponents", []) or [])
    if condition == "control_wizard":
        return any(
            isinstance(permanent, dict) and "wizard" in str(permanent.get("type_line") or "").lower()
            for permanent in battlefield
        )
    if condition == "control_subtype":
        subtype = str(effect_data.get("cost_reduction_required_subtype") or "").strip().lower()
        return any(_controlled_permanent_has_subtype(permanent, subtype) for permanent in battlefield)
    if condition == "control_creature_with_keyword":
        keyword = str(effect_data.get("cost_reduction_required_keyword") or "").strip().lower()
        return any(_controlled_creature_has_keyword(permanent, keyword) for permanent in battlefield)
    if condition == "control_human_and_nonhuman_creature":
        controls_human = False
        controls_nonhuman = False
        for permanent in battlefield:
            if not isinstance(permanent, dict) or not is_battlefield_creature(permanent):
                continue
            if _controlled_permanent_has_subtype(permanent, "human"):
                controls_human = True
            else:
                controls_nonhuman = True
        return controls_human and controls_nonhuman
    if condition == "opponent_graveyard_cards_at_least":
        try:
            threshold = max(0, int(effect_data.get("cost_reduction_opponent_graveyard_cards_min") or 0))
        except (TypeError, ValueError):
            threshold = 0
        return any(len(getattr(opponent, "graveyard", []) or []) >= threshold for opponent in opponents)
    if condition == "opponent_poison_counters_at_least":
        try:
            threshold = max(0, int(effect_data.get("cost_reduction_opponent_poison_counters_min") or 0))
        except (TypeError, ValueError):
            threshold = 0
        for opponent in opponents:
            try:
                poison_count = int(getattr(opponent, "poison", getattr(opponent, "poison_counters", 0)) or 0)
            except (TypeError, ValueError):
                poison_count = 0
            if poison_count >= threshold:
                return True
        return False
    if condition == "delirium":
        try:
            threshold = max(0, int(effect_data.get("cost_reduction_graveyard_card_types_min") or 4))
        except (TypeError, ValueError):
            threshold = 4
        return _graveyard_card_type_count(controller) >= threshold
    if condition in {"control_creature_power_4_or_greater", "ferocious"}:
        for permanent in battlefield:
            if not isinstance(permanent, dict):
                continue
            type_line = str(permanent.get("type_line") or "").lower()
            if "creature" not in type_line:
                continue
            try:
                power = int(float(permanent.get("power") or 0))
            except (TypeError, ValueError):
                power = 0
            if power >= 4:
                return True
        return False
    return False


def _static_cost_reduction_matches_spell(source, effect_data, card, *, controller=None):
    amount = _static_cost_reduction_amount(source, effect_data, controller=controller)
    colored_symbols = _static_cost_reduction_color_symbols(effect_data)
    if amount <= 0 and not colored_symbols:
        return None
    if controller is not None and not _cost_reduction_condition_satisfied(effect_data, controller):
        return None
    colors = _static_cost_reduction_color_restrictions(source, effect_data)
    if colors and not any(_spell_has_color(card, color) for color in colors):
        return None
    applies_to = str(effect_data.get("cost_reduction_applies_to") or "").strip().lower()
    shared_types = []
    imprinted_types = []
    spell_types = []
    chosen_card_type = None
    if applies_to == SHARED_CARD_TYPE_COST_REDUCTION_APPLIES_TO:
        imprinted_types = source_imprinted_card_types(source)
        spell_types = shared_card_types(card)
        shared_types = sorted(set(imprinted_types) & set(spell_types))
        if not shared_types:
            return None
    if (
        applies_to == CHOSEN_CARD_TYPE_COST_REDUCTION_APPLIES_TO
        or effect_data.get("cost_reduction_uses_chosen_card_type")
    ):
        chosen_card_type = str(
            source.get("chosen_card_type") or effect_data.get("chosen_card_type") or ""
        ).strip().lower()
        if chosen_card_type not in chosen_card_type_options(effect_data):
            return None
    card_types = [chosen_card_type] if chosen_card_type else _static_cost_reduction_card_types(effect_data)
    if not shared_types and not _card_type_matches(card, card_types):
        return None
    subtypes = _static_cost_reduction_subtypes(effect_data)
    if subtypes and not _card_subtype_matches(card, subtypes):
        return None
    min_mana_value = _static_cost_reduction_min_mana_value(effect_data)
    if min_mana_value is not None and card_mana_value(card) < min_mana_value:
        return None
    scope = _static_cost_reduction_scope(effect_data)
    amount_source = _static_cost_reduction_amount_source(effect_data)
    return {
        "source": source.get("name", "unknown"),
        "amount": amount,
        "colored_symbols": list(colored_symbols),
        "scope": scope,
        "colors": sorted(colors),
        "applies_to_card_types": card_types,
        "applies_to_subtypes": subtypes,
        "minimum_mana_value": min_mana_value,
        "amount_source": amount_source or "fixed",
        "cost_reduction_applies_to": applies_to,
        "imprinted_card_types": imprinted_types,
        "spell_card_types": spell_types,
        "shared_card_types": shared_types,
        "chosen_card_type": chosen_card_type,
    }


def static_cost_reductions_for_spell(player, card):
    reductions = []
    for source in getattr(player, "battlefield", []) or []:
        if not isinstance(source, dict):
            continue
        effect_data = _source_static_cost_reduction_effect(source)
        if not effect_data:
            continue
        reduction = _static_cost_reduction_matches_spell(
            source,
            effect_data,
            card,
            controller=player,
        )
        if reduction:
            reductions.append(reduction)
    return reductions


def _static_cost_increase_amount(effect_data):
    for key in (
        "cost_increase_generic",
        "generic_cost_increase",
        "cost_increase_amount",
        "generic_increase",
        "amount",
    ):
        if key not in effect_data:
            continue
        try:
            return max(0, int(effect_data.get(key) or 0))
        except (TypeError, ValueError):
            return 0
    if str(effect_data.get("effect") or "") in STATIC_COST_INCREASE_EFFECTS:
        return 1
    return 0


def _static_cost_increase_color_symbols(effect_data):
    symbols = []
    for key in (
        "cost_increase_color_symbols",
        "cost_increase_colors",
        "cost_increase_colored_symbols",
        "colored_cost_increase_symbols",
    ):
        for value in _as_list(effect_data.get(key)):
            symbol = _color_symbol(value)
            if symbol in SYMBOL_TO_COLOR_NAME and symbol not in symbols:
                symbols.append(symbol)
    return symbols


def _source_static_cost_increase_effect(source):
    if not isinstance(source, dict):
        return {}
    direct_effect = str(source.get("effect") or "").strip()
    if direct_effect in STATIC_COST_INCREASE_EFFECTS:
        return source
    try:
        effect_data = get_card_effect(source)
    except Exception:
        return {}
    if not isinstance(effect_data, dict):
        return {}
    if str(effect_data.get("effect") or "").strip() in STATIC_COST_INCREASE_EFFECTS:
        return effect_data
    return {}


def _static_cost_increase_controller_matches(source_controller, caster, effect_data):
    applies_to = str(effect_data.get("cost_increase_applies_to") or "").strip().lower()
    if not applies_to:
        applies_to = "spells_each_player_cast"
    if applies_to in {"spells_each_player_cast", "spells_all_players_cast", "all_spells"}:
        return True
    if applies_to in {"spells_you_cast", "spells_controller_cast"}:
        return source_controller is caster
    if applies_to in {"spells_opponents_cast", "spells_opponents_casting"}:
        return source_controller is not caster
    return False


def _static_cost_increase_filter_specs(effect_data):
    filters = effect_data.get("cost_increase_filters")
    if isinstance(filters, list):
        result = [spec for spec in filters if isinstance(spec, dict)]
        if result:
            return result
    spec = {}
    for source_key, target_key in (
        ("applies_to_card_types", "applies_to_card_types"),
        ("applies_to_spell_types", "applies_to_card_types"),
        ("spell_types", "applies_to_card_types"),
        ("card_types", "applies_to_card_types"),
        ("excluded_card_types", "excluded_card_types"),
        ("excludes_card_types", "excluded_card_types"),
        ("applies_to_spell_colors", "applies_to_spell_colors"),
        ("spell_colors", "applies_to_spell_colors"),
        ("applies_to_colors", "applies_to_spell_colors"),
        ("applies_to_subtypes", "applies_to_subtypes"),
        ("spell_subtypes", "applies_to_subtypes"),
        ("subtypes", "applies_to_subtypes"),
    ):
        values = [str(value).lower() for value in _as_list(effect_data.get(source_key)) if value]
        if values:
            spec[target_key] = values
    return [spec]


def _static_cost_increase_filter_matches(card, spec):
    excluded_types = [str(value).lower() for value in _as_list(spec.get("excluded_card_types")) if value]
    if excluded_types and _card_type_matches(card, excluded_types):
        return False
    card_types = [str(value).lower() for value in _as_list(spec.get("applies_to_card_types")) if value]
    if card_types and not _card_type_matches(card, card_types):
        return False
    subtypes = [str(value).lower() for value in _as_list(spec.get("applies_to_subtypes")) if value]
    if subtypes and not _card_subtype_matches(card, subtypes):
        return False
    colors = {
        symbol
        for symbol in (_color_symbol(value) for value in _as_list(spec.get("applies_to_spell_colors")))
        if symbol in SYMBOL_TO_COLOR_NAME
    }
    if colors and not any(_spell_has_color(card, color) for color in colors):
        return False
    return True


def _static_cost_increase_matches_spell(source, effect_data, card, *, caster, source_controller):
    amount = _static_cost_increase_amount(effect_data)
    colored_symbols = _static_cost_increase_color_symbols(effect_data)
    if amount <= 0 and not colored_symbols:
        return None
    if not _static_cost_increase_controller_matches(source_controller, caster, effect_data):
        return None
    matching_filter = None
    for spec in _static_cost_increase_filter_specs(effect_data):
        if _static_cost_increase_filter_matches(card, spec):
            matching_filter = spec
            break
    if matching_filter is None:
        return None
    return {
        "source": source.get("name", "unknown"),
        "amount": amount,
        "colored_symbols": list(colored_symbols),
        "scope": str(effect_data.get("battle_model_scope") or STATIC_GENERIC_COST_INCREASE_SCOPE),
        "cost_increase_applies_to": str(
            effect_data.get("cost_increase_applies_to") or "spells_each_player_cast"
        ),
        "applies_to_card_types": [
            str(value).lower()
            for value in _as_list(matching_filter.get("applies_to_card_types"))
            if value
        ],
        "excluded_card_types": [
            str(value).lower()
            for value in _as_list(matching_filter.get("excluded_card_types"))
            if value
        ],
        "applies_to_spell_colors": sorted(
            symbol
            for symbol in (
                _color_symbol(value)
                for value in _as_list(matching_filter.get("applies_to_spell_colors"))
            )
            if symbol in SYMBOL_TO_COLOR_NAME
        ),
        "amount_source": str(effect_data.get("cost_increase_amount_source") or "fixed"),
    }


def static_cost_increases_for_spell(player, card):
    increases = []
    for source_controller in _table_players_for(player):
        for source in getattr(source_controller, "battlefield", []) or []:
            if not isinstance(source, dict):
                continue
            effect_data = _source_static_cost_increase_effect(source)
            if not effect_data:
                continue
            increase = _static_cost_increase_matches_spell(
                source,
                effect_data,
                card,
                caster=player,
                source_controller=source_controller,
            )
            if increase:
                increases.append(increase)
    return increases


UNSUPPORTED_SELF_COST_REDUCTION_AMOUNT_SOURCES = {
    "sacrificed_artifact_or_creature_count_this_turn",
    "creatures_tapped_as_additional_cost_while_casting",
}


def _card_self_cost_reduction_effect(card):
    if not isinstance(card, dict):
        return {}
    direct_applies_to = str(card.get("cost_reduction_applies_to") or "").strip()
    direct_amount_source = str(card.get("cost_reduction_amount_source") or "").strip().lower()
    if direct_applies_to == "this_spell" and direct_amount_source not in UNSUPPORTED_SELF_COST_REDUCTION_AMOUNT_SOURCES:
        return card
    try:
        effect_data = get_card_effect(card)
    except Exception:
        return {}
    if not isinstance(effect_data, dict):
        return {}
    applies_to = str(effect_data.get("cost_reduction_applies_to") or "").strip()
    amount_source = str(effect_data.get("cost_reduction_amount_source") or "").strip().lower()
    if applies_to != "this_spell":
        return {}
    if amount_source in UNSUPPORTED_SELF_COST_REDUCTION_AMOUNT_SOURCES:
        return {}
    if (
        effect_data.get("cost_reduction_generic") in (None, "", 0)
        and not amount_source
        and effect_data.get("cost_reduction_condition") in (None, "", False)
    ):
        return {}
    return effect_data


def apply_static_cost_reductions_to_cost(cost, reductions):
    if not reductions:
        return cost
    adjusted = copy.deepcopy(cost)
    starting_generic = max(0, int(adjusted.get("generic", 0) or 0))
    colored_cost = dict(adjusted.get("colored") or {})
    remaining_generic = starting_generic
    remaining_colored = {
        str(color): max(0, int(amount or 0))
        for color, amount in colored_cost.items()
    }
    applied = []
    applied_colored_symbols_all = []
    for reduction in reductions:
        amount = max(0, int(reduction.get("amount", 0) or 0))
        applied_amount = 0
        if amount > 0:
            applied_amount = min(remaining_generic, amount)
            remaining_generic -= applied_amount
        applied_colored_symbols = []
        for symbol in _as_list(reduction.get("colored_symbols")):
            symbol = _color_symbol(symbol)
            color_name = SYMBOL_TO_COLOR_NAME.get(symbol)
            if not color_name:
                continue
            available = max(0, int(remaining_colored.get(color_name, 0) or 0))
            if available <= 0:
                continue
            remaining_colored[color_name] = available - 1
            applied_colored_symbols.append(symbol)
            applied_colored_symbols_all.append(symbol)
        if applied_amount <= 0 and not applied_colored_symbols:
            continue
        applied_reduction = dict(reduction)
        applied_reduction["applied_amount"] = applied_amount
        if applied_colored_symbols:
            applied_reduction["applied_colored_symbols"] = list(applied_colored_symbols)
            applied_reduction["applied_colored_amount"] = len(applied_colored_symbols)
        applied.append(applied_reduction)
    if not applied:
        return cost
    adjusted["generic"] = remaining_generic
    adjusted["colored"] = remaining_colored
    adjusted["static_cost_reduction_total"] = (
        starting_generic - remaining_generic + len(applied_colored_symbols_all)
    )
    adjusted["static_cost_reduction_generic_total"] = starting_generic - remaining_generic
    if applied_colored_symbols_all:
        adjusted["static_cost_reduction_color_symbols"] = list(applied_colored_symbols_all)
    adjusted["static_cost_reductions"] = applied
    return adjusted


def _activated_ability_reduction_minimum_generic(effect_data, activation_colors):
    minimum_total = max(0, int(effect_data.get("cost_reduction_minimum_total_mana") or 0))
    colored_symbols = len([color for color in (activation_colors or []) if color])
    return max(0, minimum_total - colored_symbols)


def activated_ability_cost_reductions_for_permanent(
    player,
    permanent,
    base_generic_cost,
    *,
    activation_colors=None,
    is_mana_ability=False,
):
    if base_generic_cost <= 0 or not isinstance(permanent, dict):
        return []
    type_line = str(permanent.get("type_line") or "").lower()
    reductions = []
    for source in getattr(player, "battlefield", []) or []:
        if not isinstance(source, dict):
            continue
        effect_data = _source_static_cost_reduction_effect(source)
        if not effect_data:
            continue
        if _static_cost_reduction_scope(effect_data) != "static_activated_ability_cost_reduction_variant_v1":
            continue
        if is_mana_ability and effect_data.get("cost_reduction_excludes_mana_abilities"):
            continue
        applies_to = str(effect_data.get("cost_reduction_applies_to") or "")
        if applies_to == "activated_abilities_of_creatures_you_control":
            if "creature" not in type_line:
                continue
        elif applies_to == "activated_abilities_of_artifacts_you_control":
            if "artifact" not in type_line:
                continue
        elif applies_to != "activated_abilities_you_activate":
            continue
        amount = _static_cost_reduction_amount(source, effect_data)
        if amount <= 0:
            continue
        reductions.append(
            {
                "source": source.get("name", "unknown"),
                "amount": amount,
                "scope": "static_activated_ability_cost_reduction_variant_v1",
                "cost_reduction_applies_to": applies_to,
                "minimum_generic_after_reduction": _activated_ability_reduction_minimum_generic(
                    effect_data,
                    activation_colors,
                ),
            }
        )
    return reductions


def adjusted_activated_ability_generic_cost(
    player,
    permanent,
    base_generic_cost,
    *,
    activation_colors=None,
    is_mana_ability=False,
):
    try:
        remaining_generic = max(0, int(base_generic_cost or 0))
    except (TypeError, ValueError):
        return 0
    reductions = activated_ability_cost_reductions_for_permanent(
        player,
        permanent,
        remaining_generic,
        activation_colors=activation_colors,
        is_mana_ability=is_mana_ability,
    )
    for reduction in reductions:
        amount = max(0, int(reduction.get("amount", 0) or 0))
        floor_generic = max(0, int(reduction.get("minimum_generic_after_reduction", 0) or 0))
        reducible_generic = max(0, remaining_generic - floor_generic)
        if reducible_generic <= 0:
            continue
        remaining_generic -= min(amount, reducible_generic)
    return remaining_generic


def _player_sacrificed_artifact_or_creature_count_this_turn(player):
    turn_marker = CURRENT_REPLAY_TURN
    if turn_marker is not None and getattr(player, "_sacrificed_permanents_turn_marker", None) != turn_marker:
        player.sacrificed_permanents_this_turn = []
        player._sacrificed_permanents_turn_marker = turn_marker
    count = 0
    for permanent in getattr(player, "sacrificed_permanents_this_turn", []) or []:
        type_line = str((permanent or {}).get("type_line") or "").lower()
        if "artifact" in type_line or "creature" in type_line:
            count += 1
    return count


def _self_variable_spell_cost_reduction_supported(effect_data):
    if str(effect_data.get("effect") or "") != "static_cost_reduction":
        return False
    if str(effect_data.get("battle_model_scope") or "") != "static_variable_self_spell_cost_reduction_variant_v1":
        return False
    if str(effect_data.get("cost_reduction_applies_to") or "") != "this_spell":
        return False
    return bool(effect_data.get("cost_reduction_counts_additional_sacrifices_paid_while_casting"))


def _cost_reduction_candidate_rank(permanent):
    type_line = str(permanent.get("type_line") or "").lower()
    effect = str(permanent.get("effect") or "")
    score = 0
    if permanent.get("is_commander"):
        score += 1000
    if permanent.get("tag") == "token" or "token" in type_line:
        score -= 40
    if "artifact" in type_line and "creature" not in type_line:
        score -= 12
    if permanent.get("tapped"):
        score -= 4
    if permanent.get("is_mana_source") or effect in {"ramp_permanent", "land", "creature"}:
        score += 10
    score += int(float(permanent.get("cmc") or 0))
    score += int(float(permanent.get("power") or 0))
    return score


def _artifact_or_creature_cost_reduction_candidates(player, card):
    normalized_name = normalize_card_name(card.get("name", ""))
    candidates = []
    for permanent in getattr(player, "battlefield", []) or []:
        if not isinstance(permanent, dict):
            continue
        if permanent.get("is_commander"):
            continue
        if normalize_card_name(permanent.get("name", "")) == normalized_name:
            continue
        type_line = str(permanent.get("type_line") or "").lower()
        if "artifact" not in type_line and "creature" not in type_line:
            continue
        candidates.append(permanent)
    candidates.sort(
        key=lambda permanent: (
            _cost_reduction_candidate_rank(permanent),
            permanent.get("name", ""),
        )
    )
    return candidates


def build_variable_self_spell_cost_reduction_cast_plan(
    player,
    card,
    effect_data,
    *,
    additional_generic=0,
):
    if not _self_variable_spell_cost_reduction_supported(effect_data):
        return None
    base_cost = card_cost_for_player_state(player, card, additional_generic)
    base_generic = max(0, int(base_cost.get("generic", 0) or 0))
    previous_count = _player_sacrificed_artifact_or_creature_count_this_turn(player)
    candidates = _artifact_or_creature_cost_reduction_candidates(player, card)
    for sacrifice_count in range(0, len(candidates) + 1):
        reduction_amount = 2 * (previous_count + sacrifice_count)
        locked_cost = copy.deepcopy(base_cost)
        locked_cost["generic"] = max(0, base_generic - reduction_amount)
        if player.can_pay(locked_cost):
            return {
                "locked_cost": locked_cost,
                "cost_context": {
                    "sacrifice_artifact_or_creature": candidates[:sacrifice_count],
                    "previous_sacrificed_artifact_or_creature_count": previous_count,
                    "additional_sacrifice_count": sacrifice_count,
                },
            }
    return None


def effect_uses_x_cast_value(effect_data):
    if not isinstance(effect_data, dict):
        return False
    if str(effect_data.get("token_count_source") or "").strip().lower() == "x_value":
        return True
    if str(effect_data.get("treasure_count_source") or "").strip().lower() == "x_value":
        return True
    if str(effect_data.get("controller_gain_life_source") or effect_data.get("gain_life_source") or "").strip().lower() == "x_value":
        return True
    return any(
        effect_data.get(key)
        for key in (
            "target_mana_value_max_from_x",
            "target_mana_value_exact_from_x",
            "count_from_x",
            "target_count_from_x",
            "recursion_count_from_x",
        )
    )


def runtime_cast_plan_for_card(player, card, effect_data, *, additional_generic=0):
    variable_plan = build_variable_self_spell_cost_reduction_cast_plan(
        player,
        card,
        effect_data,
        additional_generic=additional_generic,
    )
    if variable_plan is not None:
        return variable_plan

    x_value = 0
    cost_context = {}
    additional_costs = []
    if effect_data.get("x_value_source") == "blight_greatest_toughness_controlled_creature":
        blight_plan = choose_blight_x_cost_plan(
            player,
            getattr(player, "_current_opponents", []),
            effect_data,
        )
        if blight_plan is None:
            return None
        x_value = int(blight_plan.get("x_value") or 0)
        cost_context["blight"] = blight_plan
        additional_costs.append(f"blight:{x_value}")
    uses_x_cast_value = effect_uses_x_cast_value(effect_data)
    if uses_x_cast_value:
        max_candidate_x = max(0, int(player.available_mana() or 0))
        chosen_x = None
        for candidate_x in range(max_candidate_x, -1, -1):
            candidate_cost = card_cost_for_player_state(
                player,
                card,
                additional_generic,
                x_value=candidate_x,
            )
            if player.can_pay(candidate_cost):
                chosen_x = candidate_x
                break
        if chosen_x is None:
            return None
        x_value = chosen_x

    kicker_costs, kicker_paid = mark_kicker_cast_choice(player, card, effect_data)
    additional_costs = merge_additional_costs(additional_costs, kicker_costs)
    locked_cost = card_cost_for_player_state(
        player,
        card,
        additional_generic,
        x_value=0
        if effect_data.get("x_value_source") == "blight_greatest_toughness_controlled_creature"
        else x_value,
        additional_costs=additional_costs,
    )
    if not player.can_pay(locked_cost):
        return None
    if not additional_card_costs_are_payable_for_spell_cast(
        player,
        card,
        effect_data,
        base_cost=locked_cost,
        cost_context=cost_context,
    ):
        return None
    modes = []
    if kicker_paid:
        modes.append(f"kicker:{effect_data.get('kicker_mana_cost')}")
    return {
        "locked_cost": locked_cost,
        "cost_context": cost_context,
        "x_value": x_value,
        "additional_costs": additional_costs,
        "modes": modes,
        "kicker_paid": bool(kicker_paid),
    }


def card_is_runtime_castable(player, card, effect_data, *, additional_generic=0):
    return runtime_cast_plan_for_card(
        player,
        card,
        effect_data,
        additional_generic=additional_generic,
    ) is not None


def card_cost_for_player_state(
    player,
    card,
    additional_generic=0,
    *,
    alternative_cost=None,
    x_value=0,
    additional_costs=None,
):
    increases = static_cost_increases_for_spell(player, card)
    static_tax = sum(max(0, int(increase.get("amount", 0) or 0)) for increase in increases)
    static_colored_tax = [
        symbol
        for increase in increases
        for symbol in _as_list(increase.get("colored_symbols"))
        if symbol in SYMBOL_TO_COLOR_NAME
    ]
    cost = card_mana_cost(
        card,
        additional_generic + static_tax,
        alternative_cost=alternative_cost,
        x_value=x_value,
        additional_costs=additional_costs,
    )
    for symbol in static_colored_tax:
        cost["colored"][SYMBOL_TO_COLOR_NAME[symbol]] += 1
    if increases:
        cost["static_cost_increase_total"] = static_tax + len(static_colored_tax)
        cost["static_cost_increase_generic_total"] = static_tax
        if static_colored_tax:
            cost["static_cost_increase_color_symbols"] = list(static_colored_tax)
        cost["static_cost_increases"] = increases
    reductions = static_cost_reductions_for_spell(player, card)
    self_effect = _card_self_cost_reduction_effect(card)
    if self_effect:
        self_reduction = _static_cost_reduction_matches_spell(
            card,
            self_effect,
            card,
            controller=player,
        )
        if self_reduction:
            reductions.append(self_reduction)
    return apply_static_cost_reductions_to_cost(cost, reductions)


def card_cost_for_effect(player, card, effect_data, additional_generic=0):
    alternative_cost, _alternative_cost_kind = alternative_cost_for_effect(player, card, effect_data)
    return card_cost_for_player_state(
        player,
        card,
        additional_generic,
        alternative_cost=alternative_cost,
    )


def can_pay_card_for_effect(player, card, effect_data, additional_generic=0):
    return player.can_pay(card_cost_for_effect(player, card, effect_data, additional_generic))


def card_cost_for_effect_with_additional_costs(
    player,
    card,
    effect_data,
    *,
    additional_costs=None,
    additional_generic=0,
):
    alternative_cost, _alternative_cost_kind = alternative_cost_for_effect(player, card, effect_data)
    return card_cost_for_player_state(
        player,
        card,
        additional_generic,
        alternative_cost=alternative_cost,
        additional_costs=additional_costs,
    )


def buyback_runtime_enabled(effect_data):
    if not isinstance(effect_data, dict):
        return False
    return str(effect_data.get("buyback_status") or "").lower() == "runtime_executor_v1"


def buyback_cost_for_effect(effect_data):
    if not buyback_runtime_enabled(effect_data):
        return None
    return effect_data.get("buyback_cost") or effect_data.get("buyback_additional_cost")


def buyback_replay_fields(effect_data):
    if not isinstance(effect_data, dict):
        return {}
    fields = {}
    if effect_data.get("buyback_status"):
        fields["buyback_status"] = effect_data.get("buyback_status")
    if effect_data.get("buyback_cost"):
        fields["buyback_cost"] = effect_data.get("buyback_cost")
    if effect_data.get("_buyback_paid") is not None:
        fields["buyback_paid"] = bool(effect_data.get("_buyback_paid"))
    return fields


def mark_buyback_cast_choice(player, card, effect_data):
    """Choose optional buyback when the full locked cost is payable."""
    if not buyback_runtime_enabled(effect_data):
        return [], False
    buyback_cost = buyback_cost_for_effect(effect_data)
    if not buyback_cost:
        effect_data["_buyback_paid"] = False
        return [], False
    additional_costs = [buyback_cost]
    full_cost = card_cost_for_effect_with_additional_costs(
        player,
        card,
        effect_data,
        additional_costs=additional_costs,
    )
    if player.can_pay(full_cost):
        effect_data["_buyback_paid"] = True
        effect_data["_buyback_additional_costs"] = additional_costs
        return additional_costs, True
    effect_data["_buyback_paid"] = False
    effect_data.pop("_buyback_additional_costs", None)
    return [], False


def buyback_was_paid(effect_data):
    return buyback_runtime_enabled(effect_data) and bool(effect_data.get("_buyback_paid"))


def kicker_runtime_enabled(effect_data):
    if not isinstance(effect_data, dict):
        return False
    return (
        str(effect_data.get("conditional_damage_condition") or "").strip().lower()
        == "spell_was_kicked"
        and bool(effect_data.get("kicker_mana_cost"))
    )


def mark_kicker_cast_choice(player, card, effect_data):
    """Choose optional kicker when the full locked cost is payable."""
    if not kicker_runtime_enabled(effect_data):
        return [], False
    kicker_cost = str(effect_data.get("kicker_mana_cost") or "").strip()
    if not kicker_cost:
        effect_data["_kicker_paid"] = False
        effect_data["_spell_was_kicked"] = False
        return [], False
    additional_costs = [kicker_cost]
    full_cost = card_cost_for_effect_with_additional_costs(
        player,
        card,
        effect_data,
        additional_costs=additional_costs,
    )
    if player.can_pay(full_cost):
        effect_data["_kicker_paid"] = True
        effect_data["_spell_was_kicked"] = True
        effect_data["_kicker_additional_costs"] = additional_costs
        return additional_costs, True
    effect_data["_kicker_paid"] = False
    effect_data["_spell_was_kicked"] = False
    effect_data.pop("_kicker_additional_costs", None)
    return [], False


def spree_runtime_enabled(effect_data):
    if not isinstance(effect_data, dict):
        return False
    return bool(effect_data.get("spree")) and str(
        effect_data.get("spree_additional_cost_status") or ""
    ).lower() == "runtime_executor_v1"


def spree_mode_cost_for_effect(effect_data, mode):
    if not spree_runtime_enabled(effect_data):
        return None
    mode_costs = effect_data.get("spree_mode_costs") or effect_data.get("mode_additional_costs")
    if isinstance(mode_costs, dict):
        return mode_costs.get(mode)
    default_cost = effect_data.get("spree_mode_cost") or effect_data.get("spree_additional_cost")
    return default_cost


def spree_replay_fields(effect_data):
    if not isinstance(effect_data, dict):
        return {}
    fields = {}
    if effect_data.get("spree_additional_cost_status"):
        fields["spree_additional_cost_status"] = effect_data.get("spree_additional_cost_status")
    if effect_data.get("_spree_selected_modes") is not None:
        fields["spree_selected_modes"] = list(effect_data.get("_spree_selected_modes") or [])
    if effect_data.get("_spree_additional_costs") is not None:
        fields["spree_additional_costs"] = list(effect_data.get("_spree_additional_costs") or [])
    if effect_data.get("_spree_additional_cost_paid") is not None:
        fields["spree_additional_cost_paid"] = bool(effect_data.get("_spree_additional_cost_paid"))
    return fields


def mark_spree_cast_choice(player, card, effect_data, mode):
    """Select the runtime mode cost for a spree response path when payable."""
    if not spree_runtime_enabled(effect_data):
        return [], False
    mode_cost = spree_mode_cost_for_effect(effect_data, mode)
    if not mode_cost:
        effect_data["_spree_selected_modes"] = [mode]
        effect_data["_spree_additional_costs"] = []
        effect_data["_spree_additional_cost_paid"] = False
        return [], False
    additional_costs = [mode_cost]
    full_cost = card_cost_for_effect_with_additional_costs(
        player,
        card,
        effect_data,
        additional_costs=additional_costs,
    )
    if player.can_pay(full_cost):
        effect_data["_spree_selected_modes"] = [mode]
        effect_data["_spree_additional_costs"] = additional_costs
        effect_data["_spree_additional_cost_paid"] = True
        return additional_costs, True
    effect_data["_spree_selected_modes"] = [mode]
    effect_data["_spree_additional_costs"] = additional_costs
    effect_data["_spree_additional_cost_paid"] = False
    return [], False


def merge_additional_costs(*cost_groups):
    costs = []
    for group in cost_groups:
        for cost in group or []:
            costs.append(cost)
    return costs


def _spell_has_x_in_mana_cost(card):
    if not isinstance(card, dict):
        return False
    mana_cost = str(card.get("mana_cost") or "")
    return bool(re.search(r"\{X\}", mana_cost, flags=re.I))


def _spell_mana_value_for_trigger(card):
    if not isinstance(card, dict):
        return 0
    return card_mana_value(card)


def mana_spent_cast_trigger_matches(card, effect_data, trigger):
    if not isinstance(trigger, dict):
        return False
    spell_filter = str(trigger.get("spell_filter") or "").strip().lower()
    if spell_filter == "dragon_creature_spell":
        return is_battlefield_creature(card) and permanent_has_subtype(card, "Dragon")
    if spell_filter == "mana_value_gte":
        return _spell_mana_value_for_trigger(card) >= int(trigger.get("mana_value_gte") or 0)
    if spell_filter == "x_mana_cost_spell":
        return _spell_has_x_in_mana_cost(card)
    return False


def _cast_x_value_for_trigger(card, effect_data):
    for source in (card, effect_data):
        if not isinstance(source, dict):
            continue
        cast_context = source.get("_cast_context")
        if isinstance(cast_context, dict) and cast_context.get("x_value") not in (None, ""):
            try:
                return max(0, int(float(cast_context.get("x_value") or 0)))
            except Exception:
                return 0
        if source.get("x_value") not in (None, ""):
            try:
                return max(0, int(float(source.get("x_value") or 0)))
            except Exception:
                return 0
    return 0


def _resolve_cast_trigger_effects(player, card, effect_data, trigger, *, phase=None):
    effect_results = []
    for trigger_effect in trigger.get("effects") or []:
        if not isinstance(trigger_effect, dict):
            continue
        effect_kind = str(trigger_effect.get("effect") or "").strip()
        if effect_kind == "draw_cards":
            count = max(0, int(trigger_effect.get("count") or 0))
            if count > 0:
                drawn = player.draw(count, random, phase=phase)
                effect_results.append({
                    "effect": effect_kind,
                    "count": count,
                    "drawn": [item.get("name", "?") for item in drawn if isinstance(item, dict)],
                })
        elif effect_kind == "gain_life":
            amount = max(0, int(trigger_effect.get("amount") or 0))
            if str(trigger_effect.get("amount_source") or "") == "half_x_rounded_down":
                amount = _cast_x_value_for_trigger(card, effect_data) // 2
            if amount > 0:
                before = int(getattr(player, "life", 0))
                gain_life(player, amount, cap=999)
                effect_results.append({
                    "effect": effect_kind,
                    "amount": amount,
                    "life_before": before,
                    "life_after": int(getattr(player, "life", before)),
                })
        elif effect_kind == "scry":
            count = max(0, int(trigger_effect.get("count") or 0))
            if count > 0:
                scry_result = scry_library_for_controller(player, count)
                effect_results.append({
                    "effect": effect_kind,
                    "count": count,
                    **scry_result,
                })
        elif effect_kind == "enter_with_counter_and_gain_keyword":
            counter_type = str(trigger_effect.get("counter_type") or "+1/+1")
            counter_count = max(0, int(trigger_effect.get("counter_count") or 0))
            keyword = str(trigger_effect.get("keyword") or "").strip().lower().replace(" ", "_")
            counters_before = int(card.get("plus_one_counters") or 0) if isinstance(card, dict) else 0
            counters_added = 0
            if isinstance(card, dict) and counter_count > 0:
                if counter_type == "+1/+1":
                    add_plus_one_counters(card, counter_count)
                    counters_added = counter_count
                elif counter_type == "-1/-1":
                    counters_added = add_minus_one_counters(card, counter_count) or 0
                else:
                    counters_added = add_named_counters(card, counter_type, counter_count) or 0
            keyword_granted = False
            if isinstance(card, dict) and keyword:
                card[keyword] = True
                keywords = card.get("keywords")
                if not isinstance(keywords, list):
                    keywords = []
                if keyword not in {str(value).lower().replace(" ", "_") for value in keywords}:
                    keywords.append(keyword)
                card["keywords"] = keywords
                if trigger_effect.get("duration"):
                    card[f"{keyword}_duration"] = trigger_effect.get("duration")
                keyword_granted = True
            if counters_added or keyword_granted:
                effect_results.append({
                    "effect": effect_kind,
                    "counter_type": counter_type,
                    "counter_count": counter_count,
                    "counters_before": counters_before,
                    "counters_added": counters_added,
                    "counters_after": int(card.get("plus_one_counters") or 0) if isinstance(card, dict) else 0,
                    "keyword": keyword,
                    "keyword_granted": keyword_granted,
                    "duration": trigger_effect.get("duration"),
                })
    return effect_results


def resolve_mana_spent_cast_triggers(player, card, effect_data, spent_sources, *, turn=None, phase=None):
    resolved = 0
    for spent in spent_sources or []:
        if not isinstance(spent, dict):
            continue
        trigger = spent.get("mana_spent_cast_trigger")
        if not trigger or not mana_spent_cast_trigger_matches(card, effect_data, trigger):
            continue
        effect_results = _resolve_cast_trigger_effects(player, card, effect_data, trigger, phase=phase)
        if effect_results:
            resolved += 1
            emit_replay_event(
                "mana_spent_cast_trigger_resolved",
                player=getattr(player, "name", "?"),
                card=spent.get("source"),
                cast_card=card.get("name", "?") if isinstance(card, dict) else str(card),
                spell_filter=trigger.get("spell_filter"),
                effects=effect_results,
                amount_paid=int(spent.get("amount_paid") or 0),
                turn=turn,
                phase=phase,
                **dict(spent.get("rule_fields") or {}),
            )
    return resolved


def record_mana_activation_cast_trigger(player, source, produced, *, turn=None):
    if not isinstance(source, dict) or not source.get("mana_activation_cast_trigger"):
        return False
    if not hasattr(player, "pending_mana_activation_cast_triggers"):
        player.pending_mana_activation_cast_triggers = []
    trigger = copy.deepcopy(source.get("mana_activation_cast_trigger") or {})
    if not isinstance(trigger, dict) or not trigger:
        return False
    source_object_id = id(source)
    for existing in player.pending_mana_activation_cast_triggers:
        if not isinstance(existing, dict):
            continue
        if existing.get("source_object_id") == source_object_id and existing.get("turn") == turn:
            return False
    entry = {
        "source": source.get("name", "?"),
        "source_object_id": source_object_id,
        "trigger": trigger,
        "amount_produced": max(0, int(produced or 0)),
        "rule_fields": replay_rule_fields(source),
        "turn": turn,
    }
    player.pending_mana_activation_cast_triggers.append(entry)
    emit_replay_event(
        "mana_activation_cast_trigger_created",
        player=getattr(player, "name", "?"),
        card=entry["source"],
        spell_filter=trigger.get("spell_filter"),
        amount_produced=entry["amount_produced"],
        turn=turn,
        **entry["rule_fields"],
    )
    return True


def resolve_mana_activation_cast_triggers(player, card, effect_data, *, turn=None, phase=None):
    pending = list(getattr(player, "pending_mana_activation_cast_triggers", []) or [])
    remaining = []
    resolved = 0
    for entry in pending:
        if not isinstance(entry, dict):
            continue
        if entry.get("turn") is not None and turn is not None and entry.get("turn") != turn:
            continue
        trigger = entry.get("trigger")
        if not trigger or not mana_spent_cast_trigger_matches(card, effect_data, trigger):
            remaining.append(entry)
            continue
        effect_results = _resolve_cast_trigger_effects(player, card, effect_data, trigger, phase=phase)
        if not effect_results:
            remaining.append(entry)
            continue
        resolved += 1
        emit_replay_event(
            "mana_activation_cast_trigger_resolved",
            player=getattr(player, "name", "?"),
            card=entry.get("source"),
            cast_card=card.get("name", "?") if isinstance(card, dict) else str(card),
            spell_filter=trigger.get("spell_filter"),
            effects=effect_results,
            amount_produced=int(entry.get("amount_produced") or 0),
            turn=turn,
            phase=phase,
            **dict(entry.get("rule_fields") or {}),
        )
    player.pending_mana_activation_cast_triggers = remaining
    return resolved


def begin_cast_context(
    player,
    card,
    phase,
    *,
    additional_generic=0,
    effect_data=None,
    role="normal",
    modes=None,
    alternative_cost=None,
    x_value=0,
    targets=None,
    additional_costs=None,
    source_zone="hand",
    alternative_cost_kind=None,
    locked_cost_override=None,
):
    """Announce and lock cost for a simplified CR 601.2 cast."""
    ctx = CastingContext(
        card,
        player,
        phase,
        additional_generic=additional_generic,
        role=role,
        modes=modes,
        alternative_cost=alternative_cost,
        x_value=x_value,
        targets=targets,
        additional_costs=additional_costs,
        source_zone=source_zone,
        alternative_cost_kind=alternative_cost_kind,
    )
    ctx.effect_data = effect_data or get_card_effect(card)
    ctx.is_legal = can_cast_in_phase(card, ctx.effect_data, phase, controller=player)
    ctx.locked_cost = (
        copy.deepcopy(locked_cost_override)
        if locked_cost_override is not None
        else card_cost_for_player_state(
            player,
            card,
            additional_generic,
            alternative_cost=alternative_cost,
            x_value=ctx.x_value,
            additional_costs=ctx.additional_costs,
        )
    )
    cast_context_fields = {
        "phase": phase,
        **ctx.to_replay_fields(),
    }
    store_cast_context_fields(ctx.effect_data, cast_context_fields)
    if isinstance(card, dict):
        card["_cast_context"] = copy.deepcopy(cast_context_fields)
    emit_replay_event(
        "cast_announced",
        player=player.name,
        card=card.get("name", "?"),
        effect=ctx.effect_data.get("effect", "unknown"),
        phase=phase,
        **ctx.to_replay_fields(),
        **replay_rule_fields(ctx.effect_data),
    )
    return ctx


def commit_cast_payment(ctx):
    """Pay the previously locked cost. Returns False without mutating hand/stack."""
    if not ctx.is_legal:
        emit_replay_event(
            "cast_illegal",
            player=ctx.controller.name,
            card=ctx.card.get("name", "?"),
            phase=ctx.phase,
            reason="illegal_timing_or_type",
            **ctx.to_replay_fields(),
        )
        return False
    if not ctx.controller.can_pay(ctx.locked_cost):
        emit_replay_event(
            "cast_illegal",
            player=ctx.controller.name,
            card=ctx.card.get("name", "?"),
            phase=ctx.phase,
            reason="cannot_pay_locked_cost",
            **ctx.to_replay_fields(),
        )
        return False
    mana_before = ctx.controller.available_mana()
    mana_pool_before = ctx.controller.mana_pool.snapshot()
    treasures_before = ctx.controller.treasures
    life_before = ctx.controller.life
    ctx.paid = ctx.controller.spend_mana(ctx.locked_cost)
    if not ctx.paid:
        return False
    ctx.controller.record_spell_cast(CURRENT_REPLAY_TURN, card=ctx.card)
    record_approach_cast_from_hand(ctx.controller, ctx.card, ctx.effect_data, phase=ctx.phase)
    emit_replay_event(
        "cost_paid",
        player=ctx.controller.name,
        card=ctx.card.get("name", "?"),
        effect=ctx.effect_data.get("effect", "unknown"),
        phase=ctx.phase,
        mana_before=mana_before,
        mana_after=ctx.controller.available_mana(),
        mana_pool_before=mana_pool_before,
        mana_pool_after=ctx.controller.mana_pool.snapshot(),
        treasures_before=treasures_before,
        treasures_after=ctx.controller.treasures,
        life_before=life_before,
        life_after=ctx.controller.life,
        life_paid=max(0, life_before - ctx.controller.life),
        spells_cast_this_turn=getattr(ctx.controller, "spells_cast_this_turn", 0),
        spell_mana_value_cast_this_turn=getattr(
            ctx.controller,
            "spell_mana_value_cast_this_turn",
            0,
        ),
        **ctx.to_replay_fields(),
        **replay_rule_fields(ctx.effect_data),
    )
    resolve_mana_spent_cast_triggers(
        ctx.controller,
        ctx.card,
        ctx.effect_data,
        getattr(ctx.controller, "last_conditional_mana_spent_sources", []),
        turn=CURRENT_REPLAY_TURN,
        phase=ctx.phase,
    )
    resolve_mana_activation_cast_triggers(
        ctx.controller,
        ctx.card,
        ctx.effect_data,
        turn=CURRENT_REPLAY_TURN,
        phase=ctx.phase,
    )
    return True


CONTINUOUS_SUBLAYER_ORDER = {
    "7a": 0,
    "7b": 1,
    "7c": 2,
    "7d": 3,
    "7e": 4,
}


class ContinuousEffect:
    """Serializable continuous effect record for deterministic layer ordering."""

    def __init__(
        self,
        effect_id,
        layer,
        effect_type,
        value=None,
        *,
        timestamp=0,
        sublayer=None,
        depends_on=None,
    ):
        self.effect_id = effect_id
        self.layer = layer
        self.effect_type = effect_type
        self.value = value
        self.timestamp = timestamp
        self.sublayer = sublayer
        self.depends_on = list(depends_on or [])


def _continuous_effect_from_raw(raw):
    if isinstance(raw, ContinuousEffect):
        return raw
    return ContinuousEffect(
        raw.get("effect_id") or raw.get("id") or raw.get("effect_type", "effect"),
        raw.get("layer"),
        raw.get("effect_type"),
        raw.get("value"),
        timestamp=raw.get("timestamp", 0),
        sublayer=raw.get("sublayer"),
        depends_on=raw.get("depends_on") or [],
    )


def order_continuous_effects(effects):
    """Order effects by layer/sublayer/dependency/timestamp (CR 613, simplified)."""
    normalized = [_continuous_effect_from_raw(effect) for effect in effects]
    ordered = []
    remaining = list(normalized)
    applied_ids = set()
    while remaining:
        ready = [
            effect
            for effect in remaining
            if all(dep in applied_ids for dep in effect.depends_on)
        ]
        if not ready:
            ready = list(remaining)
        ready.sort(
            key=lambda effect: (
                int(effect.layer or 0),
                CONTINUOUS_SUBLAYER_ORDER.get(str(effect.sublayer or ""), -1),
                int(effect.timestamp or 0),
                str(effect.effect_id),
            )
        )
        chosen = ready[0]
        ordered.append(chosen)
        applied_ids.add(chosen.effect_id)
        remaining.remove(chosen)
    return ordered


def _card_types(card):
    return [part.strip() for part in str(card.get("type_line") or "").split() if part.strip()]


def _set_card_types(card, types):
    card["type_line"] = " ".join(dict.fromkeys(types))


def _abilities(card):
    current = card.get("abilities", [])
    if isinstance(current, str):
        return [current]
    return list(current or [])


def _set_abilities(card, abilities):
    card["abilities"] = list(dict.fromkeys(abilities))


def is_planeswalker_permanent(card):
    return isinstance(card, dict) and "planeswalker" in str(card.get("type_line") or "").lower()


def is_battle_permanent(card):
    return isinstance(card, dict) and "battle" in str(card.get("type_line") or "").lower()


def handle_planeswalker_etb(card, controller=None):
    if not isinstance(card, dict):
        return card
    card["loyalty"] = int(card.get("loyalty", card.get("starting_loyalty", 3)) or 0)
    card["loyalty_used_this_turn"] = False
    if controller is not None:
        card["controller"] = controller.name
    return card


def can_activate_loyalty(player, planeswalker, phase, stack):
    return (
        is_planeswalker_permanent(planeswalker)
        and planeswalker in player.battlefield
        and not planeswalker.get("loyalty_used_this_turn")
        and phase in MAIN_PHASES
        and stack.empty()
    )


def activate_loyalty_ability(player, planeswalker, loyalty_delta, phase, stack):
    if not can_activate_loyalty(player, planeswalker, phase, stack):
        return False
    planeswalker["loyalty"] = int(planeswalker.get("loyalty", 0) or 0) + int(loyalty_delta)
    planeswalker["loyalty_used_this_turn"] = True
    emit_replay_event(
        "loyalty_ability_activated",
        player=player.name,
        card=planeswalker.get("name", "?"),
        loyalty_delta=loyalty_delta,
        loyalty_after=planeswalker.get("loyalty", 0),
        phase=phase,
    )
    return True


def damage_to_planeswalker(source, planeswalker, amount):
    if not is_planeswalker_permanent(planeswalker) or amount <= 0:
        return False
    mark_permanent_dealt_damage_this_turn(planeswalker, amount, CURRENT_REPLAY_TURN)
    planeswalker["loyalty"] = int(planeswalker.get("loyalty", 0) or 0) - int(amount)
    emit_replay_event(
        "planeswalker_damage",
        source=source.get("name", "?") if isinstance(source, dict) else source,
        card=planeswalker.get("name", "?"),
        amount=amount,
        loyalty_after=planeswalker.get("loyalty", 0),
    )
    return True


def handle_siege_etb(card, controller, opponents):
    if not isinstance(card, dict):
        return card
    card["defense"] = int(card.get("defense", card.get("starting_defense", 5)) or 0)
    card["protector"] = opponents[0].name if opponents else None
    card["controller"] = controller.name if controller is not None else card.get("controller")
    return card


def battle_takes_damage(battle_card, amount):
    if not is_battle_permanent(battle_card) or amount <= 0:
        return False
    battle_card["defense"] = int(battle_card.get("defense", 0) or 0) - int(amount)
    emit_replay_event(
        "battle_damage",
        card=battle_card.get("name", "?"),
        amount=amount,
        defense_after=battle_card.get("defense", 0),
        protector=battle_card.get("protector"),
    )
    return True


def resolve_battle_back_face(controller, battle_card):
    """Basic Siege reward: cast/put the back face onto the battlefield."""
    back_face = battle_card.get("back_face") if isinstance(battle_card, dict) else None
    if not isinstance(back_face, dict):
        return None
    permanent = prepare_entering_permanent(enrich_card(copy.deepcopy(back_face)))
    permanent["controller"] = controller.name
    permanent["cast_from_battle_back_face"] = True
    if is_creature_card(permanent):
        permanent["effect"] = "creature"
        permanent["haste"] = has_haste(permanent)
        permanent["summoning_sick"] = not permanent["haste"]
        permanent["tapped"] = False
    controller.battlefield.append(permanent)
    emit_replay_event(
        "battle_back_face_cast",
        player=controller.name,
        battle=battle_card.get("name", "?"),
        card=permanent.get("name", "?"),
        type_line=permanent.get("type_line", ""),
    )
    return permanent


def modern_ability_word_signals(card):
    """Telemetry-only detection for modern ability words.

    These words do not enforce rules by themselves; they mark cards that need
    spent-mana, zone-change or spell-targeting context.
    """
    if not isinstance(card, dict):
        return []
    text = str(card.get("oracle_text", "") or "").lower()
    signals = []
    for word in (
        "void",
        "repartee",
        "opus",
        "increment",
        "infusion",
        "converge",
    ):
        if re.search(rf"\b{word}\b", text):
            signals.append(word)
    return signals


def is_warp_card(card):
    return isinstance(card, dict) and bool(card.get("warp_cost") or card.get("warp"))


def cast_warp_spell_from_hand(player, card, turn, phase):
    """Cast a permanent for its warp cost and schedule end-step exile."""
    if phase not in MAIN_PHASES or not is_warp_card(card) or card not in player.hand:
        return False
    warp_cost = card.get("warp_cost") or card.get("warp")
    effect_data = get_card_effect(card)
    ctx = begin_cast_context(
        player,
        card,
        phase,
        effect_data=effect_data,
        role="warp",
        alternative_cost=warp_cost,
        source_zone="hand",
        alternative_cost_kind="warp",
    )
    if not commit_cast_payment(ctx):
        return False
    player.hand.remove(card)
    permanent = prepare_entering_permanent(enrich_card({**card, **effect_data}))
    permanent["_warped_this_turn"] = True
    permanent["_warp_pending_exile_turn"] = turn
    permanent["_warp_recast_available"] = False
    if is_creature_card(permanent):
        permanent["effect"] = "creature"
        permanent["haste"] = has_haste(permanent)
        permanent["summoning_sick"] = not permanent["haste"]
        permanent["tapped"] = False
    player.battlefield.append(permanent)
    emit_replay_event(
        "warp_cast",
        player=player.name,
        card=card.get("name", "?"),
        warp_cost=warp_cost,
        turn=turn,
        phase=phase,
        **ctx.to_replay_fields(),
        **replay_rule_fields(effect_data),
    )
    return True


def process_warp_end_step(player, turn):
    """Exile warped permanents at the next end step and allow future recast."""
    moved = []
    for permanent in list(player.battlefield):
        if not isinstance(permanent, dict) or not permanent.get("_warped_this_turn"):
            continue
        if permanent.get("_warp_pending_exile_turn") != turn:
            continue
        player.battlefield.remove(permanent)
        permanent["_warped_this_turn"] = False
        permanent["_warp_recast_available"] = True
        move_to_exile(player, permanent, reason="warp", turn=turn)
        moved.append(permanent.get("name", "?"))
    if moved:
        emit_replay_event("warp_exiled_end_step", player=player.name, cards=moved, turn=turn)
    return moved


def active_non_hand_cast_locks(player, turn=None):
    locks = []
    for lock in list(getattr(player, "non_hand_cast_locks", []) or []):
        if not isinstance(lock, dict):
            continue
        expires_at = lock.get("expires_at_turn")
        try:
            expires_at = int(expires_at) if expires_at is not None else None
        except (TypeError, ValueError):
            expires_at = None
        if turn is not None and expires_at is not None and expires_at <= int(turn):
            continue
        locks.append(lock)
    return locks


def non_hand_cast_locked(player, turn=None):
    return bool(active_non_hand_cast_locks(player, turn=turn))


def clear_expired_non_hand_cast_locks(active_player, all_players, turn):
    source_name = getattr(active_player, "name", None)
    for participant in all_players:
        locks = list(getattr(participant, "non_hand_cast_locks", []) or [])
        if not locks:
            continue
        kept = []
        for lock in locks:
            if not isinstance(lock, dict):
                continue
            try:
                expires_at = int(lock.get("expires_at_turn") or 0)
            except (TypeError, ValueError):
                expires_at = 0
            lock_source = lock.get("source_player")
            if lock_source == source_name and expires_at <= int(turn):
                continue
            if not lock_source and expires_at and expires_at <= int(turn):
                continue
            kept.append(lock)
        participant.non_hand_cast_locks = kept


def spell_type_cast_lock_for_card(player, card, effect_data=None):
    if player is None or not isinstance(card, dict):
        return None
    effect_data = effect_data or {}
    type_line = str(card.get("type_line") or "").lower()
    effect_name = str(effect_data.get("effect") or card.get("effect") or "").lower()
    card_types = set()
    if "creature" in type_line or effect_name == "creature" or is_creature_card(card):
        card_types.add("creature")
    if "planeswalker" in type_line or effect_name == "planeswalker":
        card_types.add("planeswalker")
    if not card_types:
        return None
    for lock in list(getattr(player, "spell_type_cast_locks", []) or []):
        if not isinstance(lock, dict):
            continue
        locked_types = {
            str(card_type).strip().lower()
            for card_type in lock.get("card_types", []) or []
            if str(card_type).strip()
        }
        if card_types & locked_types:
            return lock
    return None


def _spell_limit_scope_applies_to_card(scope, card, effect_data=None):
    scope = str(scope or "spells").lower()
    type_line = str(card.get("type_line") or "").lower() if isinstance(card, dict) else ""
    effect_name = str((effect_data or {}).get("effect") or card.get("effect") if isinstance(card, dict) else "").lower()
    is_creature_spell = (
        "creature" in type_line
        or effect_name == "creature"
        or (isinstance(card, dict) and is_creature_card(card))
    )
    is_artifact_spell = "artifact" in type_line or bool(isinstance(card, dict) and card.get("artifact"))
    is_phyrexian_spell = "phyrexian" in type_line or bool(
        isinstance(card, dict)
        and any(str(subtype).lower() == "phyrexian" for subtype in _as_list(card.get("subtypes")))
    )
    if scope == "noncreature_spells":
        return not is_creature_spell
    if scope == "nonartifact_spells":
        return not is_artifact_spell
    if scope == "nonphyrexian_spells":
        return not is_phyrexian_spell
    return True


def _spell_limit_count_for_scope(player, scope):
    scope = str(scope or "spells").lower()
    if scope == "noncreature_spells":
        return int(getattr(player, "noncreature_spells_cast_this_turn", 0) or 0)
    if scope == "nonartifact_spells":
        return int(getattr(player, "nonartifact_spells_cast_this_turn", 0) or 0)
    if scope == "nonphyrexian_spells":
        return int(getattr(player, "nonphyrexian_spells_cast_this_turn", 0) or 0)
    return int(getattr(player, "spells_cast_this_turn", 0) or 0)


def active_static_spell_limit_restrictions(player):
    return [
        restriction
        for restriction in getattr(player, "static_spell_limit_restrictions", []) or []
        if isinstance(restriction, dict)
    ]


def static_spell_limit_lock_for_card(player, card, effect_data=None):
    if player is None or not isinstance(card, dict):
        return None
    for restriction in active_static_spell_limit_restrictions(player):
        scope = restriction.get("restricted_spell_scope") or "spells"
        if not _spell_limit_scope_applies_to_card(scope, card, effect_data):
            continue
        limit = max(1, int(restriction.get("spell_limit_per_turn") or 1))
        if _spell_limit_count_for_scope(player, scope) >= limit:
            return restriction
    return None


def register_static_spell_limit_restriction(controller, source, all_players, turn=None):
    if controller is None or not isinstance(source, dict):
        return []
    if not source.get("static_rule_restriction") or not source.get("spell_limit_per_turn"):
        return []
    participants = list(all_players or [controller])
    scope = str(source.get("restriction_controller_scope") or "controller").lower()
    if scope not in {"each_player", "all_players"}:
        participants = [controller]
    restriction = {
        "source": source.get("name", "?"),
        "source_player": getattr(controller, "name", "?"),
        "spell_limit_per_turn": int(source.get("spell_limit_per_turn") or 1),
        "restricted_spell_scope": source.get("restricted_spell_scope") or "spells",
        "restriction_controller_scope": scope,
        "turn_registered": turn,
        "rule_logical_key": source.get("_rule_logical_key"),
    }
    registered = []
    for participant in participants:
        existing = [
            item
            for item in getattr(participant, "static_spell_limit_restrictions", []) or []
            if not (
                isinstance(item, dict)
                and item.get("source") == restriction["source"]
                and item.get("source_player") == restriction["source_player"]
            )
        ]
        participant.static_spell_limit_restrictions = [*existing, dict(restriction)]
        registered.append(getattr(participant, "name", "?"))
    emit_replay_event(
        "static_spell_limit_registered",
        player=getattr(controller, "name", "?"),
        card=source.get("name", "?"),
        affected_players=registered,
        spell_limit_per_turn=restriction["spell_limit_per_turn"],
        restricted_spell_scope=restriction["restricted_spell_scope"],
        turn=turn,
        **replay_rule_fields(source),
    )
    return registered


def add_spell_type_cast_lock(
    participant,
    *,
    source,
    source_player,
    started_turn,
    card_types,
    duration,
):
    lock = {
        "source": source,
        "source_player": source_player,
        "started_turn": int(started_turn),
        "expires_after_source_turn": int(started_turn) + 1,
        "restriction": "cannot_cast_spell_types",
        "card_types": list(card_types),
        "duration": duration,
    }
    participant.spell_type_cast_locks = list(getattr(participant, "spell_type_cast_locks", []) or [])
    participant.spell_type_cast_locks.append(lock)
    return lock


def clear_expired_spell_type_cast_locks_after_turn(active_player, all_players, turn):
    source_name = getattr(active_player, "name", None)
    for participant in all_players:
        locks = list(getattr(participant, "spell_type_cast_locks", []) or [])
        if not locks:
            continue
        kept = []
        for lock in locks:
            if not isinstance(lock, dict):
                continue
            try:
                expires_after = int(lock.get("expires_after_source_turn") or 0)
            except (TypeError, ValueError):
                expires_after = 0
            if lock.get("source_player") == source_name and expires_after <= int(turn):
                emit_replay_event(
                    "spell_type_cast_lock_expired",
                    player=getattr(participant, "name", "?"),
                    source=lock.get("source"),
                    source_player=source_name,
                    card_types=lock.get("card_types", []),
                    turn=turn,
                )
                continue
            kept.append(lock)
        participant.spell_type_cast_locks = kept


def remember_until_next_turn(card, key, *, source_player, turn):
    originals = card.setdefault("_until_next_turn_originals", {})
    if key not in originals:
        originals[key] = card.get(key, None)
    card["_until_next_turn_source_player"] = source_player
    card["_until_next_turn_granted_turn"] = int(turn)


def set_until_next_turn(card, key, value, *, source_player, turn):
    remember_until_next_turn(card, key, source_player=source_player, turn=turn)
    card[key] = value


def clear_until_next_turn_effects(active_player, turn, all_players=None):
    source_name = getattr(active_player, "name", None)
    participants = list(all_players or [active_player])
    for participant in participants:
        for zone in (participant.battlefield, participant.phased_out, participant.graveyard):
            for card in zone:
                if not isinstance(card, dict):
                    continue
                if card.get("_until_next_turn_source_player") != source_name:
                    continue
                try:
                    granted_turn = int(card.get("_until_next_turn_granted_turn") or 0)
                except (TypeError, ValueError):
                    granted_turn = 0
                if int(turn) <= granted_turn:
                    continue
                originals = card.pop("_until_next_turn_originals", {})
                for key, original in originals.items():
                    if original is None:
                        card.pop(key, None)
                    else:
                        card[key] = original
                card.pop("_until_next_turn_source_player", None)
                card.pop("_until_next_turn_granted_turn", None)


def apply_until_next_turn_to_card(card, updates, *, source_player, turn):
    for key, value in updates.items():
        set_until_next_turn(card, key, value, source_player=source_player, turn=turn)


def cast_warp_card_from_exile(player, card, turn, phase):
    """Recast a card previously exiled by warp using its normal cost."""
    if phase not in MAIN_PHASES or not isinstance(card, dict):
        return False
    if non_hand_cast_locked(player, turn=turn):
        return False
    if not card.get("_warp_recast_available") or card not in player.exile:
        return False
    effect_data = get_card_effect(card)
    ctx = begin_cast_context(
        player,
        card,
        phase,
        effect_data=effect_data,
        role="warp_recast",
        source_zone="exile",
    )
    if not commit_cast_payment(ctx):
        return False
    player.exile.remove(card)
    permanent = prepare_entering_permanent(enrich_card({**card, **effect_data}))
    permanent.pop("_warp_recast_available", None)
    permanent.pop("_exile_reason", None)
    if is_creature_card(permanent):
        permanent["effect"] = "creature"
        permanent["haste"] = has_haste(permanent)
        permanent["summoning_sick"] = not permanent["haste"]
        permanent["tapped"] = False
    player.battlefield.append(permanent)
    emit_replay_event(
        "warp_recast_from_exile",
        player=player.name,
        card=card.get("name", "?"),
        turn=turn,
        phase=phase,
        **ctx.to_replay_fields(),
        **replay_rule_fields(effect_data),
    )
    return True


def cast_airbend_card_from_exile(player, card, turn, phase):
    """Cast a creature exiled by airbend for the tracked generic alternative cost."""
    if phase not in MAIN_PHASES or not isinstance(card, dict):
        return False
    if non_hand_cast_locked(player, turn=turn):
        return False
    if not card.get("_airbend_available") or card not in player.exile:
        return False
    if not is_creature_card(card):
        return False
    airbend_cost = str(card.get("_airbend_recast_cost") or "{2}")
    effect_data = get_card_effect(card)
    cast_ctx = begin_cast_context(
        player,
        card,
        phase,
        effect_data=effect_data,
        role="airbend_recast",
        modes=["creature_from_exile"],
        source_zone="exile",
        alternative_cost=airbend_cost,
        alternative_cost_kind="airbend",
    )
    if not commit_cast_payment(cast_ctx):
        return False
    player.exile.remove(card)
    permanent = enrich_card({**card, **effect_data})
    permanent.pop("_airbend_available", None)
    permanent.pop("_airbend_recast_cost", None)
    permanent.pop("_airbend_source", None)
    permanent["effect"] = "creature"
    permanent["haste"] = has_haste(permanent)
    permanent["summoning_sick"] = not permanent["haste"]
    permanent["tapped"] = False
    player.battlefield.append(permanent)
    emit_replay_event(
        "airbend_creature_cast_from_exile",
        player=player.name,
        card=card.get("name", "?"),
        type_line=permanent.get("type_line", ""),
        turn=turn,
        phase=phase,
        **cast_ctx.to_replay_fields(),
        **replay_rule_fields(effect_data),
    )
    return True


def cast_radiant_scrollwielder_card_from_exile(
    player,
    card,
    opponents,
    all_players,
    turn,
    phase,
    stack,
    rng,
):
    """Cast an instant/sorcery exiled by Radiant Scrollwielder until EOT."""
    if not isinstance(card, dict) or card not in player.exile:
        return False
    if non_hand_cast_locked(player, turn=turn):
        return False
    try:
        available_turn = int(card.get("_radiant_scrollwielder_cast_available_until_turn") or -1)
    except (TypeError, ValueError):
        available_turn = -1
    if available_turn != int(turn):
        return False
    if not is_instant_or_sorcery_spell(card):
        return False
    if not is_instant(card) and not (is_sorcery(card) and phase in MAIN_PHASES):
        return False

    effect_data = get_card_effect(card)
    effect_data, declared_targets = prepare_declared_removal_targets(
        player,
        opponents,
        card,
        effect_data,
    )
    if missing_required_declared_removal_target(effect_data, declared_targets):
        return False
    ctx = begin_cast_context(
        player,
        card,
        phase,
        effect_data=effect_data,
        role="radiant_scrollwielder_recast",
        targets=declared_targets,
        source_zone="exile",
    )
    if not commit_cast_payment(ctx):
        return False

    player.exile.remove(card)
    cast_copy = copy.deepcopy(card)
    cast_copy["_exile_on_resolution"] = True
    cast_copy["_exile_on_resolution_reason"] = (
        card.get("_exile_on_resolution_reason") or "radiant_scrollwielder_replacement"
    )
    emit_replay_event(
        "radiant_scrollwielder_exile_cast",
        player=player.name,
        card=card.get("name", "?"),
        source=card.get("_radiant_scrollwielder_source"),
        cast_available_until_turn=available_turn,
        turn=turn,
        phase=phase,
        **ctx.to_replay_fields(),
        **replay_rule_fields(effect_data),
    )
    mark_cast_ledger_emitted(effect_data)
    trigger_spell_cast_engines(
        player, all_players, cast_copy, turn, phase, stack=stack, active_player=player
    )
    trigger_opponent_spell_draw_engines(
        player,
        opponents,
        cast_copy,
        turn,
        phase,
        rng,
        stack=stack,
        active_player=player,
        all_players=all_players,
    )
    stack.push(cast_copy, player, effect_data)
    return True


def cast_flashback_spell_from_graveyard(player, card, opponents, all_players, turn, phase, stack, rng):
    """Cast an instant/sorcery from graveyard for flashback, exiling on resolution."""
    if not isinstance(card, dict) or card not in player.graveyard:
        return False
    if non_hand_cast_locked(player, turn=turn):
        return False
    flashback_cost = card.get("flashback_cost") or card.get("flashback")
    if not flashback_cost:
        return False
    if not is_instant(card) and not (is_sorcery(card) and phase in MAIN_PHASES):
        return False
    effect_data = get_card_effect(card)
    effect_data, declared_targets = prepare_declared_removal_targets(
        player,
        opponents,
        card,
        effect_data,
    )
    if missing_required_declared_removal_target(effect_data, declared_targets):
        return False
    ctx = begin_cast_context(
        player,
        card,
        phase,
        effect_data=effect_data,
        role="flashback",
        alternative_cost=flashback_cost,
        targets=declared_targets,
        source_zone="graveyard",
        alternative_cost_kind="flashback",
    )
    if not commit_cast_payment(ctx):
        return False
    remove_cards_from_graveyard(
        player,
        [card],
        turn=turn,
        source_event="flashback_cast",
    )
    flashback_copy = copy.deepcopy(card)
    flashback_copy["_flashback_cast"] = True
    emit_replay_event(
        "flashback_cast",
        player=player.name,
        card=card.get("name", "?"),
        flashback_cost=flashback_cost,
        flashback_granted_by=card.get("_flashback_granted_by"),
        flashback_granted_rule_key=card.get("_flashback_granted_rule_key"),
        turn=turn,
        phase=phase,
        **ctx.to_replay_fields(),
        **replay_rule_fields(effect_data),
    )
    mark_cast_ledger_emitted(effect_data)
    trigger_spell_cast_engines(
        player, all_players, flashback_copy, turn, phase, stack=stack, active_player=player
    )
    trigger_opponent_spell_draw_engines(
        player,
        opponents,
        flashback_copy,
        turn,
        phase,
        rng,
        stack=stack,
        active_player=player,
        all_players=all_players,
    )
    stack.push(flashback_copy, player, effect_data)
    return True


def is_station_card(card):
    return isinstance(card, dict) and (
        "station" in str(card.get("type_line", "")).lower()
        or bool(card.get("station_threshold"))
        or bool(card.get("station_level_required"))
    )


def activate_station_ability(player, station, tapper, phase, stack):
    """Minimal station action: tap another creature and add charge counters."""
    if phase not in MAIN_PHASES or not stack.empty():
        return False
    if station not in player.battlefield or tapper not in player.battlefield:
        return False
    if station is tapper or not is_station_card(station) or not is_battlefield_creature(tapper):
        return False
    if tapper.get("tapped") or tapper.get("summoning_sick"):
        return False
    tapper["tapped"] = True
    resolve_controlled_dwarf_tap_treasure_triggers(
        player,
        tapper,
        CURRENT_REPLAY_TURN,
        phase=phase,
    )
    added = int(tapper.get("power") or 0)
    station["charge_counters"] = int(station.get("charge_counters") or 0) + max(0, added)
    threshold = int(station.get("station_threshold") or station.get("unlock_threshold") or 0)
    if threshold and station["charge_counters"] >= threshold:
        station["station_online"] = True
        if is_vehicle_or_spacecraft_card(station):
            station["effect"] = "creature"
    emit_replay_event(
        "station_activated",
        player=player.name,
        card=station.get("name", "?"),
        tapper=tapper.get("name", "?"),
        counters_added=max(0, added),
        total_counters=station["charge_counters"],
        station_online=bool(station.get("station_online")),
        phase=phase,
    )
    return True


def prepare_spell_copy(player, source_card, prepared_creature, turn):
    """Create a castable prepared copy in exile linked to a creature."""
    if not isinstance(source_card, dict) or not isinstance(prepared_creature, dict):
        return None
    prepared_copy = get_card_characteristics(source_card, "exile", cast_mode="prepare")
    prepared_copy["_prepared_copy"] = True
    prepared_copy["_prepared_source_name"] = source_card.get("name")
    prepared_copy["_prepared_creature_id"] = id(prepared_creature)
    prepared_copy["_prepared_available"] = True
    move_to_exile(player, prepared_copy, reason="prepare", turn=turn)
    emit_replay_event(
        "prepared_copy_created",
        player=player.name,
        source=source_card.get("name", "?"),
        card=prepared_copy.get("name", "?"),
        prepared_creature=prepared_creature.get("name", "?"),
        turn=turn,
    )
    return prepared_copy


def cleanup_prepared_copies(player, prepared_creature):
    """Remove prepared copies when the linked creature is no longer prepared."""
    removed = []
    creature_id = id(prepared_creature)
    for card in list(player.exile):
        if isinstance(card, dict) and card.get("_prepared_creature_id") == creature_id:
            player.exile.remove(card)
            removed.append(card.get("name", "?"))
    if removed:
        emit_replay_event(
            "prepared_copies_removed",
            player=player.name,
            prepared_creature=prepared_creature.get("name", "?"),
            cards=removed,
        )
    return removed


def resolve_paradigm_spell(player, card, turn):
    """Track a resolved Paradigm spell as a future first-main copy source."""
    if not isinstance(card, dict):
        return None
    paradigm_card = copy.deepcopy(card)
    paradigm_card["_paradigm_available"] = True
    move_to_exile(player, paradigm_card, reason="paradigm", turn=turn)
    emit_replay_event(
        "paradigm_exiled",
        player=player.name,
        card=card.get("name", "?"),
        turn=turn,
    )
    return paradigm_card


def create_lander_token(player, name="Lander Token"):
    token = create_creature_token(
        player,
        name=name,
        power=1,
        toughness=1,
        artifact=True,
    )
    token["subtype"] = "Lander"
    token["lander_token"] = True
    return token


def create_map_token(player, name="Map Token"):
    token = {
        "name": name,
        "cmc": 0,
        "tag": "token",
        "effect": "artifact_token",
        "type_line": "Artifact Token — Map",
        "artifact": True,
        "map_token": True,
        "tapped": False,
    }
    player.battlefield.append(token)
    return token


def finish_countered_spell(player, card):
    if isinstance(card, dict) and card.get("_countered_to_top_library"):
        counter_source = card.get("_countered_to_top_library_by")
        card.pop("_countered_to_top_library", None)
        card.pop("_countered_to_top_library_by", None)
        player.library.insert(0, card)
        emit_replay_event(
            "countered_spell_moved_to_library_top",
            player=getattr(player, "name", "?"),
            card=card.get("name", "?"),
            from_zone="stack",
            to_zone="library",
            destination="library_top",
            counter_source=counter_source,
            turn=CURRENT_REPLAY_TURN,
        )
        return
    if isinstance(card, dict) and card.get("_exile_on_resolution"):
        reason = card.get("_exile_on_resolution_reason") or "replacement_exile_countered"
        move_to_exile(player, card, reason=reason, turn=CURRENT_REPLAY_TURN)
        emit_replay_event(
            "countered_spell_moved_to_exile",
            player=getattr(player, "name", "?"),
            card=card.get("name", "?"),
            from_zone="stack",
            to_zone="exile",
            destination="exile",
            replacement_reason=reason,
            turn=CURRENT_REPLAY_TURN,
        )
        return
    graveyard_before = len(getattr(player, "graveyard", []) or [])
    exile_before = len(getattr(player, "exile", []) or [])
    result = _finish_countered_spell(player, card, move_to_exile_func=move_to_exile)
    if isinstance(card, dict):
        graveyard_after = len(getattr(player, "graveyard", []) or [])
        exile_after = len(getattr(player, "exile", []) or [])
        if graveyard_after > graveyard_before and card in getattr(player, "graveyard", []):
            emit_replay_event(
                "countered_spell_moved_to_graveyard",
                player=getattr(player, "name", "?"),
                card=card.get("name", "?"),
                from_zone="stack",
                to_zone="graveyard",
                destination="graveyard",
                turn=CURRENT_REPLAY_TURN,
            )
        elif exile_after > exile_before and card in getattr(player, "exile", []):
            emit_replay_event(
                "countered_spell_moved_to_exile",
                player=getattr(player, "name", "?"),
                card=card.get("name", "?"),
                from_zone="stack",
                to_zone="exile",
                destination="exile",
                turn=CURRENT_REPLAY_TURN,
            )
    return result


GOLIATH_DAYDREAMER_SCOPE = "instant_sorcery_from_hand_exile_dream_counter_attack_free_cast_v1"


def is_goliath_daydreamer_runtime_source(permanent):
    if not isinstance(permanent, dict):
        return False
    effect_data = permanent if permanent.get("battle_model_scope") else get_card_effect(permanent)
    return (
        effect_data.get("battle_model_scope") == GOLIATH_DAYDREAMER_SCOPE
        or bool(effect_data.get("goliath_daydreamer_exile_resolved_instant_sorcery"))
        or bool(effect_data.get("goliath_daydreamer_attack_cast_dream_counter"))
    )


def first_goliath_daydreamer_source(player):
    for permanent in list(getattr(player, "battlefield", []) or []):
        if is_goliath_daydreamer_runtime_source(permanent):
            return permanent
    return None


def mark_goliath_daydreamer_exile_on_resolution(player, card, effect_data, turn=None):
    if not isinstance(card, dict) or card.get("_exile_on_resolution"):
        return False
    if not is_instant_or_sorcery_spell(card):
        return False
    cast_context = {}
    if isinstance(effect_data, dict):
        cast_context = effect_data.get("_cast_context") or {}
    if not cast_context:
        cast_context = card.get("_cast_context") or {}
    source_zone = cast_context.get("source_zone") or _effect_source_zone(effect_data)
    if source_zone != "hand":
        return False
    source = first_goliath_daydreamer_source(player)
    if source is None:
        return False
    card["_exile_on_resolution"] = True
    card["_exile_on_resolution_reason"] = "goliath_daydreamer_dream_counter"
    card["_goliath_daydreamer_dream_counter"] = True
    card["_goliath_daydreamer_source"] = source.get("name", "Goliath Daydreamer")
    resolved_effect_data = effect_data if isinstance(effect_data, dict) and effect_data.get("effect") else None
    if resolved_effect_data is None and card.get("effect"):
        resolved_effect_data = card
    card["_goliath_daydreamer_effect_data"] = copy.deepcopy(resolved_effect_data or get_card_effect(card))
    emit_replay_event(
        "goliath_daydreamer_dream_counter_replacement_marked",
        player=player.name,
        card=card.get("name", "?"),
        source=source.get("name", "Goliath Daydreamer"),
        turn=turn,
        **replay_rule_fields(source),
    )
    return True


def finish_resolved_spell(player, card, turn=None, effect_data=None):
    mark_goliath_daydreamer_exile_on_resolution(player, card, effect_data, turn)
    if buyback_was_paid(effect_data or {}):
        player.hand.append(card)
        emit_replay_event(
            "buyback_returned_to_hand",
            player=player.name,
            card=card.get("name", "?") if isinstance(card, dict) else str(card),
            from_zone="stack",
            to_zone="hand",
            destination="hand",
            turn=turn,
            **buyback_replay_fields(effect_data or {}),
            **replay_rule_fields(effect_data or {}),
        )
        return
    if isinstance(card, dict) and card.get("_exile_on_resolution"):
        reason = card.get("_exile_on_resolution_reason") or "replacement_exile_on_resolution"
        move_to_exile(player, card, reason=reason, turn=turn)
        emit_replay_event(
            "replacement_exiled_on_resolution",
            player=player.name,
            card=card.get("name", "?"),
            replacement_reason=reason,
            turn=turn,
            **replay_rule_fields(effect_data or {}),
        )
        return
    if is_first_rebound_resolution(card, effect_data):
        if isinstance(card, dict):
            card["_rebound_pending"] = True
            card["_rebound_available_turn"] = (turn or 0) + 1
            card["_rebound_original_controller"] = player.name
            card["_rebound_effect_data"] = copy.deepcopy(effect_data or {})
        move_to_exile(player, card, reason="rebound", turn=turn)
        emit_replay_event(
            "rebound_exiled",
            player=player.name,
            card=card.get("name", "?") if isinstance(card, dict) else str(card),
            available_turn=(turn or 0) + 1,
            turn=turn,
            **replay_rule_fields(effect_data or {}),
        )
        return
    if (effect_data or {}).get("shuffle_self_into_library_on_resolution"):
        player.library.append(card)
        player.shuffle(random)
        emit_replay_event(
            "spell_shuffled_into_library_on_resolution",
            player=player.name,
            card=card.get("name", "?") if isinstance(card, dict) else str(card),
            from_zone="stack",
            to_zone="library",
            destination="library",
            zone_after="library",
            turn=turn,
            **replay_rule_fields(effect_data or {}),
        )
        return
    return _finish_resolved_spell(
        player,
        card,
        turn=turn,
        move_to_exile_func=move_to_exile,
        emit_replay_event=emit_replay_event,
        effect_data=effect_data,
    )


def is_approach_of_the_second_sun(card, effect_data=None):
    if isinstance(card, dict):
        name = normalize_card_name(card.get("name") or card.get("card_name") or "")
    else:
        name = normalize_card_name(str(card or ""))
    effect = (effect_data or {}).get("effect") if isinstance(effect_data, dict) else None
    return name == "approach of the second sun" or effect == "approach"


def record_approach_cast_from_hand(player, card, effect_data, *, phase=None):
    if not isinstance(effect_data, dict):
        return False
    if not is_approach_of_the_second_sun(card, effect_data):
        return False
    if isinstance(card, dict) and card.get("is_copy"):
        return False
    if effect_data.get("_copied_from_spell"):
        return False
    cast_context = effect_data.get("_cast_context") or {}
    source_zone = cast_context.get("source_zone") or effect_data.get("source_zone") or "hand"
    if source_zone != "hand":
        return False
    if effect_data.get("_approach_cast_count_recorded"):
        return False
    player.approach_count += 1
    effect_data["_approach_cast_count_recorded"] = True
    effect_data["_approach_cast_count_after_recorded"] = player.approach_count
    emit_replay_event(
        "approach_cast_tracked",
        player=player.name,
        card=(card.get("name", "?") if isinstance(card, dict) else str(card)),
        approach_count=player.approach_count,
        source_zone=source_zone,
        phase=phase,
        **replay_rule_fields(effect_data),
    )
    return True


def commander_origin_id(card, owner_name=None):
    """Stable identity for one physical commander across zone changes."""
    if not isinstance(card, dict):
        return "unknown"
    explicit = card.get("commander_origin_id") or card.get("_commander_origin_id")
    if explicit:
        return str(explicit)
    origin = (
        card.get("oracle_id")
        or card.get("scryfall_id")
        or f"{owner_name or card.get('owner') or '?'}:{card.get('name', '?')}"
    )
    card["_commander_origin_id"] = str(origin)
    return str(origin)


def commander_damage_key(defender_name, commander_card, owner_name=None):
    return f"{defender_name}::{commander_origin_id(commander_card, owner_name)}"


def commander_damage_target_from_key(key):
    return str(key).split("::", 1)[0]


def commander_damage_lethal_entries(player):
    ledger = getattr(player, "commander_damage_by_source", None)
    if ledger:
        for key, damage in ledger.items():
            if damage >= 21:
                yield commander_damage_target_from_key(key), damage, key
        return
    for target_name, damage in player.commander_damage.items():
        if damage >= 21:
            yield target_name, damage, None


def apply_continuous_effects(card, effects):
    """Return a characteristics snapshot after applying continuous effects."""
    result = copy.deepcopy(card)
    applied = []
    for effect in order_continuous_effects(effects):
        value = effect.value
        if effect.layer == 1 and effect.effect_type == "copy" and isinstance(value, dict):
            result.update(copy.deepcopy(value))
        elif effect.layer == 2 and effect.effect_type == "set_controller":
            result["controller"] = value
        elif effect.layer == 3 and effect.effect_type == "replace_text" and isinstance(value, dict):
            result["oracle_text"] = str(result.get("oracle_text") or "").replace(
                str(value.get("from", "")),
                str(value.get("to", "")),
            )
        elif effect.layer == 4:
            types = _card_types(result)
            if effect.effect_type == "set_type":
                types = list(value or [])
            elif effect.effect_type == "add_type":
                types.extend(list(value or []))
            elif effect.effect_type == "remove_type":
                remove = set(value or [])
                types = [card_type for card_type in types if card_type not in remove]
            _set_card_types(result, types)
        elif effect.layer == 5:
            colors = list(result.get("colors") or [])
            if effect.effect_type == "set_color":
                colors = list(value or [])
            elif effect.effect_type == "add_color":
                colors.extend(list(value or []))
            result["colors"] = list(dict.fromkeys(colors))
        elif effect.layer == 6:
            abilities = _abilities(result)
            if effect.effect_type == "add_ability":
                abilities.extend(list(value or []))
            elif effect.effect_type == "remove_ability":
                remove = set(value or [])
                abilities = [ability for ability in abilities if ability not in remove]
            _set_abilities(result, abilities)
        elif effect.layer == 7:
            if effect.effect_type in ("set_pt", "cda_set_pt") and isinstance(value, dict):
                result["power"] = value.get("power", result.get("power", 0))
                result["toughness"] = value.get("toughness", result.get("toughness", 0))
            elif effect.effect_type in ("modify_pt", "counter_pt") and isinstance(value, dict):
                result["power"] = int(result.get("power") or 0) + int(value.get("power", 0) or 0)
                result["toughness"] = int(result.get("toughness") or 0) + int(value.get("toughness", 0) or 0)
            elif effect.effect_type == "switch_pt":
                result["power"], result["toughness"] = result.get("toughness", 0), result.get("power", 0)
        applied.append(effect.effect_id)
    result["_continuous_effects_applied"] = applied
    return result


SELF_KEYWORD_ABILITIES = {
    "flying",
    "reach",
    "trample",
    "deathtouch",
    "first_strike",
    "double_strike",
    "lifelink",
    "indestructible",
    "haste",
    "vigilance",
    "hexproof",
    "shroud",
    "flash",
    "menace",
    "infect",
    "horsemanship",
}


def _keyword_values(card):
    keyword_values = card.get("keywords") or []
    if isinstance(keyword_values, str):
        keyword_values = read_json_list(keyword_values) or [keyword_values]
    return {
        str(value).lower().replace(" ", "_")
        for value in keyword_values
        if str(value).strip()
    }


def _oracle_self_keyword_values(card):
    oracle_text = str(card.get("oracle_text") or "").strip()
    if not oracle_text:
        return set()
    keywords = set()
    for line in oracle_text.splitlines():
        line = re.sub(r"\([^)]*\)", "", line).strip().rstrip(".")
        if not line:
            if keywords:
                break
            continue
        parts = [
            part.strip().lower().replace(" ", "_")
            for part in re.split(r"[,;]", line)
            if part.strip()
        ]
        if not parts:
            if keywords:
                break
            continue
        if any(part not in SELF_KEYWORD_ABILITIES for part in parts):
            break
        keywords.update(parts)
    return keywords


def enrich_card(card):
    """Preserve imported metadata and expose only self-owned combat keywords."""
    enriched = dict(card)
    keyword_values = _oracle_self_keyword_values(enriched)
    if enriched.get("_keywords_are_self") or not str(enriched.get("oracle_text") or "").strip():
        keyword_values |= _keyword_values(enriched)
    for keyword in SELF_KEYWORD_ABILITIES:
        if keyword in keyword_values:
            enriched[keyword] = True
    return enriched


def card_has_keyword(card, keyword):
    """Check explicit fields plus self-owned keyword abilities only."""
    if not isinstance(card, dict):
        return False
    normalized_keyword = str(keyword or "").lower().replace(" ", "_")
    if card.get(normalized_keyword):
        return True
    if normalized_keyword in _oracle_self_keyword_values(card):
        return True
    if card.get("_keywords_are_self") or not str(card.get("oracle_text") or "").strip():
        return normalized_keyword in _keyword_values(card)
    return False


def has_haste(card):
    return card_has_keyword(card, "haste")


def has_vigilance(card):
    return card_has_keyword(card, "vigilance")


def is_battlefield_creature(card):
    """Permanent-level creature check; effects can add extra roles."""
    if not isinstance(card, dict):
        return False
    if card.get("creature_type_suppressed"):
        return False
    return (
        card.get("effect") == "creature"
        or bool(card.get("is_creature_permanent"))
        or "creature" in str(card.get("type_line") or "").lower()
    )


def permanent_has_subtype(permanent, subtype):
    if not isinstance(permanent, dict) or not subtype:
        return False
    normalized_subtype = str(subtype).strip().lower()
    if (
        permanent.get("all_creature_types")
        or permanent.get("universal_creature_subtypes")
        or permanent.get("changeling")
    ):
        return True
    explicit_subtypes = permanent.get("subtypes") or permanent.get("subtype") or []
    if isinstance(explicit_subtypes, str):
        explicit_subtypes = [explicit_subtypes]
    if normalized_subtype in {str(value).strip().lower() for value in explicit_subtypes}:
        return True
    type_line = str(permanent.get("type_line") or "").lower()
    return normalized_subtype in type_line.replace("-", " ").replace("—", " ").split()


def permanent_has_card_type(permanent, card_type):
    if not isinstance(permanent, dict) or not card_type:
        return False
    normalized_card_type = str(card_type).strip().lower()
    explicit_types = permanent.get("card_types") or permanent.get("card_type") or []
    if isinstance(explicit_types, str):
        explicit_types = [explicit_types]
    if normalized_card_type in {str(value).strip().lower() for value in explicit_types}:
        return True
    return normalized_card_type in str(permanent.get("type_line") or "").lower().replace("—", " ").split()


def permanent_has_any_counter(permanent):
    if not isinstance(permanent, dict):
        return False
    counters = permanent.get("counters")
    if isinstance(counters, dict) and any(int(value or 0) > 0 for value in counters.values()):
        return True
    for key, value in permanent.items():
        if not str(key).endswith("_counters"):
            continue
        try:
            if int(value or 0) > 0:
                return True
        except (TypeError, ValueError):
            continue
    return False


def counter_names_on_permanent(permanent):
    if not isinstance(permanent, dict):
        return []
    names = []
    counters = permanent.get("counters")
    if isinstance(counters, dict):
        for name, value in counters.items():
            try:
                amount = int(value or 0)
            except (TypeError, ValueError):
                amount = 0
            if amount > 0 and str(name) not in names:
                names.append(str(name))
    special_keys = {
        "plus_one_counters": "+1/+1",
        "minus_one_counters": "-1/-1",
    }
    for key, value in permanent.items():
        if not str(key).endswith("_counters"):
            continue
        try:
            amount = int(value or 0)
        except (TypeError, ValueError):
            amount = 0
        if amount <= 0:
            continue
        name = special_keys.get(str(key), str(key)[: -len("_counters")])
        if name and name not in names:
            names.append(name)
    return names


def is_mana_source_permanent(source):
    if source == "land":
        return True
    if not isinstance(source, dict):
        return False
    if source.get("mana_source_contextual_only"):
        return False
    if source.get("effect") in ("land", "ramp_permanent"):
        return True
    if source.get("is_mana_source"):
        return True
    return source.get("effect") == "ramp_engine" and source.get("mana_produced") is not None


def bind_table_context(all_players):
    participants = [player for player in (all_players or []) if player is not None]
    if not participants:
        return []
    for participant in participants:
        try:
            participant._known_table_players = participants
        except Exception:
            continue
    return participants


def _table_players_for(player):
    table = getattr(player, "_known_table_players", None)
    if isinstance(table, list) and table:
        return table
    return [player] if player is not None else []


def _blood_moon_sources_for(player):
    sources = []
    for participant in _table_players_for(player):
        for permanent in getattr(participant, "battlefield", []) or []:
            if (
                isinstance(permanent, dict)
                and permanent.get("land_type_replacement") == "nonbasic_lands_are_mountains"
                and permanent.get("battle_model_scope") == "nonbasic_lands_are_mountains_static_v1"
            ):
                sources.append((participant, permanent))
    return sources


def is_nonbasic_land_for_blood_moon(source):
    if not isinstance(source, dict) or not is_effective_land(source):
        return False
    type_line = str(source.get("type_line") or "").lower()
    if "basic" in type_line:
        return False
    normalized_name = normalize_card_name(source.get("name", ""))
    return normalized_name not in {"plains", "island", "swamp", "mountain", "forest", "wastes"}


def blood_moon_applies_to_mana_source(player, source):
    return bool(_blood_moon_sources_for(player)) and is_nonbasic_land_for_blood_moon(source)


def _artifact_activation_lock_sources(player, all_players=None):
    if all_players is not None:
        bind_table_context(all_players)
    locks = []
    for participant in _table_players_for(player):
        if participant is player:
            continue
        for permanent in getattr(participant, "battlefield", []) or []:
            if (
                isinstance(permanent, dict)
                and permanent.get("opponent_artifact_activated_abilities_cant_be_activated")
            ):
                locks.append((participant, permanent))
    return locks


def artifact_activated_abilities_locked(player, permanent, all_players=None):
    return bool(is_artifact_permanent(permanent) and _artifact_activation_lock_sources(player, all_players))


def does_not_untap_in_untap_step(permanent):
    if not isinstance(permanent, dict):
        return False
    return bool(
        permanent.get("does_not_untap_in_untap_step")
        or permanent.get("does_not_untap_normally")
    )


def mark_mana_source_used_if_nonstandard_untap(source):
    if does_not_untap_in_untap_step(source):
        source["tapped"] = True


def mana_source_activation_turn_key(turn):
    return str(turn if turn is not None else "unknown")


def mana_source_activation_count(source, turn):
    if not isinstance(source, dict):
        return 0
    usage = source.get("_mana_source_activation_usage") or {}
    return int(usage.get(mana_source_activation_turn_key(turn)) or 0)


def mana_source_activation_limit_reached(source, turn):
    if not isinstance(source, dict):
        return False
    limit = int(source.get("activation_limit_per_turn") or 0)
    return limit > 0 and mana_source_activation_count(source, turn) >= limit


def record_mana_source_activation(source, turn):
    if not isinstance(source, dict):
        return
    limit = int(source.get("activation_limit_per_turn") or 0)
    if limit <= 0:
        return
    usage = source.setdefault("_mana_source_activation_usage", {})
    key = mana_source_activation_turn_key(turn)
    usage[key] = int(usage.get(key) or 0) + 1


def _controls_creature_token_any_color_mana_passive(player):
    if player is None:
        return False
    return any(
        isinstance(permanent, dict)
        and permanent.get("creature_tokens_tap_for_any_color")
        for permanent in getattr(player, "battlefield", []) or []
    )


def _controls_creature_any_color_mana_passive(player):
    if player is None:
        return False
    return any(
        isinstance(permanent, dict)
        and permanent.get("creatures_tap_for_any_color")
        for permanent in getattr(player, "battlefield", []) or []
    )


def _creature_token_has_any_color_mana_from_passive(player, source):
    return (
        isinstance(source, dict)
        and is_battlefield_creature(source)
        and is_token_permanent(source)
        and _controls_creature_token_any_color_mana_passive(player)
    )


def _creature_has_any_color_mana_from_passive(player, source):
    if not isinstance(source, dict) or not is_battlefield_creature(source):
        return False
    if _controls_creature_any_color_mana_passive(player):
        return True
    return (
        is_token_permanent(source)
        and _controls_creature_token_any_color_mana_passive(player)
    )


def player_mana_source_permanent(player, source):
    return is_mana_source_permanent(source) or _creature_has_any_color_mana_from_passive(player, source)


def _controlled_permanent_mana_colors(player):
    colors = set()
    for permanent in getattr(player, "battlefield", []) or []:
        if not isinstance(permanent, dict):
            continue
        for color in source_colors(permanent) or []:
            symbol = COLOR_NAME_TO_SYMBOL.get(str(color).lower(), str(color).upper())
            mapped = SYMBOL_TO_COLOR_NAME.get(symbol)
            if mapped:
                colors.add(mapped)
        try:
            for symbol in compute_color_identity(permanent) or []:
                mapped = SYMBOL_TO_COLOR_NAME.get(str(symbol).upper())
                if mapped:
                    colors.add(mapped)
        except Exception:
            continue
    return [
        color
        for color in ("white", "blue", "black", "red", "green")
        if color in colors
    ]


def _commander_identity_mana_colors_for_player(player):
    commanders = []
    commander = getattr(player, "commander", None)
    if isinstance(commander, dict):
        commanders.append(commander)
    for candidate in getattr(player, "command_zone", []) or []:
        if isinstance(candidate, dict) and candidate not in commanders:
            commanders.append(candidate)
    colors = []
    for commander_card in commanders:
        for value in compute_color_identity(commander_card) or []:
            raw = str(value or "").strip()
            color = raw.lower() if raw.lower() in COLOR_NAME_TO_SYMBOL else None
            if color is None:
                color = SYMBOL_TO_COLOR_NAME.get(raw.upper())
            if color and color not in colors:
                colors.append(color)
    return colors


def _has_untapped_mana_support_permanent(
    player,
    source,
    *,
    allow_artifact=False,
    include_source=False,
):
    return _untapped_mana_support_permanent(
        player,
        source,
        allow_artifact=allow_artifact,
        include_source=include_source,
    ) is not None


def _untapped_mana_support_permanent(
    player,
    source,
    *,
    allow_artifact=False,
    include_source=False,
):
    for permanent in getattr(player, "battlefield", []) or []:
        if not isinstance(permanent, dict):
            continue
        if permanent is source and not include_source:
            continue
        if permanent.get("tapped"):
            continue
        if is_battlefield_creature(permanent):
            return permanent
        if allow_artifact and is_artifact_permanent(permanent):
            return permanent
    return None


def _mana_source_support_can_include_source(source):
    if not isinstance(source, dict):
        return False
    if "mana_source_support_can_include_source" in source:
        return bool(source.get("mana_source_support_can_include_source"))
    return not bool(
        source.get("mana_activation_requires_tap")
        or source.get("activation_requires_tap")
    )


def _required_mana_support_tap_cost(player, source):
    if not isinstance(source, dict):
        return None, None
    support_count = int(source.get("mana_activation_tap_support_count") or 0)
    if support_count <= 0 and (
        source.get("mana_source_requires_untapped_creature")
        or source.get("mana_source_requires_untapped_artifact_or_creature")
    ):
        support_count = 1
    if support_count <= 0:
        return None, None
    if support_count != 1:
        return None, "unsupported_tap_support_count"
    if source.get("mana_source_requires_untapped_creature"):
        support = _untapped_mana_support_permanent(
            player,
            source,
            allow_artifact=False,
            include_source=False,
        )
        return support, "creature"
    if source.get("mana_source_requires_untapped_artifact_or_creature"):
        support = _untapped_mana_support_permanent(
            player,
            source,
            allow_artifact=True,
            include_source=_mana_source_support_can_include_source(source),
        )
        return support, "artifact_or_creature"
    return None, None


def mana_source_colors_for_state(player, source):
    if blood_moon_applies_to_mana_source(player, source):
        return ["red"]
    if _creature_has_any_color_mana_from_passive(player, source):
        return ["wildcard"]
    if isinstance(source, dict) and source.get("commander_identity_mana_source"):
        commander_colors = _commander_identity_mana_colors_for_player(player)
        if commander_colors:
            return commander_colors
    if isinstance(source, dict) and source.get("mana_colors_from_controlled_permanents"):
        colors = _controlled_permanent_mana_colors(player)
        if colors:
            return colors
    return source_colors(source)


GENERIC_RUNTIME_EXECUTOR_STATUSES = {
    "runtime_executor_v1",
    "runtime_executor",
    "executable",
    "enabled",
}

CONDITIONAL_MANA_RUNTIME_STATUSES = set(GENERIC_RUNTIME_EXECUTOR_STATUSES)


def runtime_executor_status_enabled(value):
    return str(value or "").strip().lower() in GENERIC_RUNTIME_EXECUTOR_STATUSES


def _mana_runtime_status_enabled(value):
    return str(value or "").strip().lower() in CONDITIONAL_MANA_RUNTIME_STATUSES


def _mana_mode_color(value):
    raw = str(value or "").strip()
    if not raw:
        return None
    upper = raw.upper()
    if upper in MANA_SYMBOL_TO_POOL:
        return MANA_SYMBOL_TO_POOL[upper]
    lowered = raw.lower()
    aliases = {
        "w": "white",
        "u": "blue",
        "b": "black",
        "r": "red",
        "g": "green",
        "c": "colorless",
        "any": "wildcard",
        "any_color": "wildcard",
    }
    lowered = aliases.get(lowered, lowered)
    if lowered in {"white", "blue", "black", "red", "green", "colorless", "generic", "wildcard"}:
        return lowered
    return None


def _source_explicit_mana_colors(source):
    if not isinstance(source, dict):
        return []
    if source.get("commander_identity_mana_source"):
        return []
    explicit = (
        source.get("produces")
        or source.get("produced_mana")
        or source.get("color_identity")
    )
    if isinstance(explicit, str):
        explicit = re.findall(r"[WUBRGC]", explicit.upper())
    elif not isinstance(explicit, list):
        explicit = _as_list(explicit)
    colors = []
    for value in explicit or []:
        color = _mana_mode_color(value)
        if color and color not in colors:
            colors.append(color)
    return colors


def _ordered_mana_colors(colors):
    ordered = []
    for color in ("white", "blue", "black", "red", "green", "colorless", "wildcard", "generic"):
        if color in colors and color not in ordered:
            ordered.append(color)
    for color in colors:
        if color not in ordered:
            ordered.append(color)
    return ordered


def _land_mana_colors_for_controller(controller, land):
    if not isinstance(land, dict):
        return []
    colors = []
    if land.get("commander_identity_mana_source"):
        colors.extend(_commander_identity_mana_colors_for_player(controller))
    colors.extend(_source_explicit_mana_colors(land))
    if not colors:
        for color in source_colors(land) or []:
            if color == "wildcard":
                colors.extend(["white", "blue", "black", "red", "green"])
            elif color in {
                "white",
                "blue",
                "black",
                "red",
                "green",
                "colorless",
                "generic",
            }:
                colors.append(color)
    return _ordered_mana_colors(colors)


def _opponent_land_mana_colors_for_player(player):
    colors = []
    for opponent in _table_players_for(player):
        if opponent is player:
            continue
        if hasattr(opponent, "is_alive") and not opponent.is_alive():
            continue
        for permanent in getattr(opponent, "battlefield", []) or []:
            if not isinstance(permanent, dict) or not is_effective_land(permanent):
                continue
            for color in _land_mana_colors_for_controller(opponent, permanent):
                if color not in colors:
                    colors.append(color)
    return _ordered_mana_colors(colors)


def _controller_land_mana_colors_for_player(player):
    colors = []
    for permanent in getattr(player, "battlefield", []) or []:
        if not isinstance(permanent, dict) or not is_effective_land(permanent):
            continue
        for color in _land_mana_colors_for_controller(player, permanent):
            if color not in colors:
                colors.append(color)
    return _ordered_mana_colors(colors)


def _filter_land_dependency_mana_colors(colors, source):
    filtered = list(colors or [])
    if isinstance(source, dict) and source.get("land_mana_dependency_allows_colorless") is False:
        filtered = [
            color
            for color in filtered
            if color not in {"colorless", "generic"}
        ]
    return _ordered_mana_colors(filtered)


def _read_conditional_mana_modes(source):
    modes = source.get("conditional_mana_modes") if isinstance(source, dict) else None
    if isinstance(modes, str):
        decoded = read_json_list(modes)
        if decoded is None:
            try:
                decoded = json.loads(modes)
            except Exception:
                decoded = None
        modes = decoded
    return [mode for mode in _as_list(modes) if isinstance(mode, dict)]


def _player_controls_any_subtype(player, subtypes):
    subtype_values = [str(value).strip() for value in _as_list(subtypes) if str(value).strip()]
    if not subtype_values:
        return True
    for permanent in getattr(player, "battlefield", []) or []:
        if not isinstance(permanent, dict):
            continue
        if any(permanent_has_subtype(permanent, subtype) for subtype in subtype_values):
            return True
    return False


def _conditional_mana_mode_conditions_met(player, mode):
    required_subtypes = (
        mode.get("requires_control_subtypes")
        or mode.get("requires_control_land_subtypes")
        or mode.get("requires_control_basic_land_subtypes")
    )
    if required_subtypes and not _player_controls_any_subtype(player, required_subtypes):
        return False
    return True


def _conditional_mana_source_entry(source, amount, modes, source_kind):
    available_modes = []
    seen = set()
    for mode in modes:
        color = _mana_mode_color(mode.get("color") or mode.get("mana") or mode.get("produces"))
        if not color:
            continue
        key = (
            color,
            str(mode.get("restriction") or mode.get("spend_restriction") or "").strip().lower(),
            str(mode.get("mode") or mode.get("condition") or "").strip().lower(),
        )
        if key in seen:
            continue
        seen.add(key)
        available_modes.append(
            {
                "color": color,
                "restriction": mode.get("restriction") or mode.get("spend_restriction") or "any_spell",
                "mode": mode.get("mode") or mode.get("condition") or source_kind,
                "life_loss_on_spend": int(mode.get("life_loss_on_spend") or 0),
                "life_loss_kind": mode.get("life_loss_kind") or mode.get("life_payment_kind") or "life_loss",
                "life_loss_status": mode.get("life_loss_status") or mode.get("status"),
            }
        )
    if not available_modes:
        return None
    entry = {
        "source": source.get("name", "?") if isinstance(source, dict) else str(source),
        "amount": max(0, int(amount or 0)),
        "remaining": max(0, int(amount or 0)),
        "modes": available_modes,
        "source_kind": source_kind,
        "same_color_choice": bool(source.get("conditional_mana_same_color_choice")),
        "rule_fields": replay_rule_fields(source) if isinstance(source, dict) else {},
    }
    if isinstance(source, dict) and source.get("mana_spent_cast_trigger"):
        entry["mana_spent_cast_trigger"] = copy.deepcopy(source.get("mana_spent_cast_trigger") or {})
    return entry


def _configured_conditional_mana_source_for_state(player, source, produced):
    if not isinstance(source, dict):
        return None
    modes = _read_conditional_mana_modes(source)
    if not modes and source.get("mana_spent_cast_trigger"):
        colors = _source_explicit_mana_colors(source) or source_colors(source) or ["generic"]
        modes = [
            {
                "color": color,
                "restriction": "any_spell",
                "mode": "mana_spent_cast_trigger",
                "status": "runtime_executor_v1",
            }
            for color in colors
        ]
    if not modes:
        return None
    overall_runtime_enabled = _mana_runtime_status_enabled(source.get("conditional_mana_modes_status"))
    active_modes = []
    for mode in modes:
        mode_status = mode.get("status")
        if mode_status and not _mana_runtime_status_enabled(mode_status):
            continue
        if not mode_status and not overall_runtime_enabled:
            continue
        if not _conditional_mana_mode_conditions_met(player, mode):
            continue
        active_modes.append(mode)
    if not active_modes:
        return None
    return _conditional_mana_source_entry(
        source,
        produced,
        active_modes,
        "configured_conditional_mana_modes",
    )


def conditional_mana_source_for_state(player, source, produced):
    if blood_moon_applies_to_mana_source(player, source):
        return None
    configured = _configured_conditional_mana_source_for_state(player, source, produced)
    if configured:
        return configured
    if isinstance(source, dict) and source.get("commander_identity_mana_source"):
        commander_colors = _commander_identity_mana_colors_for_player(player)
        if commander_colors:
            return _conditional_mana_source_entry(
                source,
                produced,
                [
                    {
                        "color": color,
                        "restriction": "any_spell",
                        "mode": "commander_color_identity",
                    }
                    for color in commander_colors
                ],
                "commander_identity_mana_source",
            )
    if isinstance(source, dict) and source.get("mana_produced_from_colors_among_permanents"):
        return None
    if isinstance(source, dict) and source.get("conditionally_produces_controller_land_colors"):
        controller_land_colors = _filter_land_dependency_mana_colors(
            _controller_land_mana_colors_for_player(player),
            source,
        )
        if controller_land_colors:
            return _conditional_mana_source_entry(
                source,
                produced,
                [
                    {
                        "color": color,
                        "restriction": "any_spell",
                        "mode": "controller_land_color_dependency",
                    }
                    for color in controller_land_colors
                ],
                "controller_land_color_mana_source",
            )
    if isinstance(source, dict) and source.get("conditionally_produces_opponent_land_colors"):
        opponent_land_colors = _filter_land_dependency_mana_colors(
            _opponent_land_mana_colors_for_player(player),
            source,
        )
        if opponent_land_colors:
            return _conditional_mana_source_entry(
                source,
                produced,
                [
                    {
                        "color": color,
                        "restriction": "any_spell",
                        "mode": "opponent_land_color_dependency",
                    }
                    for color in opponent_land_colors
                ],
                "opponent_land_color_mana_source",
            )
    explicit_colors = _source_explicit_mana_colors(source)
    if len(explicit_colors) <= 1:
        return None
    life_for_colored_mana = int(source.get("life_for_colored_mana") or 0) if isinstance(source, dict) else 0
    return _conditional_mana_source_entry(
        source,
        produced,
        [
            {
                "color": color,
                "restriction": "any_spell",
                "mode": "explicit_mana_choice",
                "life_loss_on_spend": (
                    life_for_colored_mana if color not in {"colorless", "generic"} else 0
                ),
                "life_loss_kind": "life_loss",
                "life_loss_status": (
                    "pain_mana_runtime_v1"
                    if life_for_colored_mana and color not in {"colorless", "generic"}
                    else None
                ),
            }
            for color in explicit_colors
        ],
        "explicit_mana_choices",
    )


def replay_conditional_mana_source(source):
    if not isinstance(source, dict):
        return {}
    modes = source.get("modes") or []
    return {
        "source": source.get("source"),
        "amount": int(source.get("remaining", source.get("amount", 0)) or 0),
        "colors": sorted({mode.get("color") for mode in modes if mode.get("color")}),
        "modes": [
            {
                "color": mode.get("color"),
                "restriction": mode.get("restriction"),
                "mode": mode.get("mode"),
                "life_loss_on_spend": int(mode.get("life_loss_on_spend") or 0),
                "life_loss_kind": mode.get("life_loss_kind"),
            }
            for mode in modes
        ],
        "source_kind": source.get("source_kind"),
        "same_color_choice": bool(source.get("same_color_choice")),
        "chosen_color": source.get("chosen_color"),
    }


def replay_conditional_mana_sources(player):
    return [
        replay_conditional_mana_source(source)
        for source in getattr(player, "conditional_mana_sources", []) or []
        if int(source.get("remaining", 0) or 0) > 0
    ]


def add_plus_one_counters(permanent, count=1):
    if not isinstance(permanent, dict):
        return
    added = max(0, int(count or 0))
    if added <= 0:
        return
    permanent["plus_one_counters"] = int(permanent.get("plus_one_counters") or 0) + added
    counters = permanent.get("counters")
    if isinstance(counters, dict):
        counters["+1/+1"] = permanent["plus_one_counters"]
    if is_battlefield_creature(permanent):
        permanent["power"] = int(float(permanent.get("power") or 0)) + added
        permanent["toughness"] = int(float(permanent.get("toughness") or 0)) + added


def remove_plus_one_counters(permanent, count=1):
    if not isinstance(permanent, dict):
        return 0
    current = max(0, int(permanent.get("plus_one_counters") or 0))
    if current <= 0:
        return 0
    removed = max(0, min(current, int(count or 0)))
    if removed <= 0:
        return 0
    permanent["plus_one_counters"] = current - removed
    counters = permanent.get("counters")
    if isinstance(counters, dict):
        counters["+1/+1"] = permanent["plus_one_counters"]
    if is_battlefield_creature(permanent):
        permanent["power"] = int(float(permanent.get("power") or 0)) - removed
        permanent["toughness"] = int(float(permanent.get("toughness") or 0)) - removed
    return removed


def add_minus_one_counters(permanent, count=1):
    if not isinstance(permanent, dict):
        return 0
    added = max(0, int(count or 0))
    if added <= 0:
        return 0
    permanent["minus_one_counters"] = int(permanent.get("minus_one_counters") or 0) + added
    counters = permanent.get("counters")
    if isinstance(counters, dict):
        counters["-1/-1"] = permanent["minus_one_counters"]
    if is_battlefield_creature(permanent):
        permanent["power"] = int(float(permanent.get("power") or 0)) - added
        permanent["toughness"] = int(float(permanent.get("toughness") or 0)) - added
    return added


def remove_minus_one_counters(permanent, count=1):
    if not isinstance(permanent, dict):
        return 0
    current = max(0, int(permanent.get("minus_one_counters") or 0))
    if current <= 0:
        return 0
    removed = max(0, min(current, int(count or 0)))
    if removed <= 0:
        return 0
    permanent["minus_one_counters"] = current - removed
    counters = permanent.get("counters")
    if isinstance(counters, dict):
        counters["-1/-1"] = permanent["minus_one_counters"]
    if is_battlefield_creature(permanent):
        permanent["power"] = int(float(permanent.get("power") or 0)) + removed
        permanent["toughness"] = int(float(permanent.get("toughness") or 0)) + removed
    return removed


def get_named_counter_count(permanent, counter_name):
    if not isinstance(permanent, dict):
        return 0
    key = f"{counter_name}_counters"
    if key in permanent:
        return max(0, int(permanent.get(key) or 0))
    counters = permanent.get("counters")
    if isinstance(counters, dict):
        return max(0, int(counters.get(counter_name) or 0))
    return 0


def add_named_counters(permanent, counter_name, count=1):
    if not isinstance(permanent, dict):
        return 0
    added = max(0, int(count or 0))
    if added <= 0:
        return 0
    key = f"{counter_name}_counters"
    permanent[key] = get_named_counter_count(permanent, counter_name) + added
    counters = permanent.get("counters")
    if isinstance(counters, dict):
        counters[counter_name] = permanent[key]
    return added


def add_one_counter_by_name(permanent, counter_name):
    normalized = str(counter_name or "").strip()
    if normalized == "+1/+1":
        add_plus_one_counters(permanent, 1)
        return 1
    if normalized == "-1/-1":
        return add_minus_one_counters(permanent, 1)
    return add_named_counters(permanent, normalized, 1)


def player_counter_names(player):
    names = []
    if player is None:
        return names
    counters = getattr(player, "counters", None)
    if isinstance(counters, dict):
        for name, value in counters.items():
            try:
                amount = int(value or 0)
            except (TypeError, ValueError):
                amount = 0
            if amount > 0 and str(name) not in names:
                names.append(str(name))
    try:
        poison = int(getattr(player, "poison", 0) or 0)
    except (TypeError, ValueError):
        poison = 0
    if poison > 0 and "poison" not in names:
        names.append("poison")
    return names


def add_one_player_counter_by_name(player, counter_name):
    if player is None:
        return 0
    normalized = str(counter_name or "").strip()
    if not normalized:
        return 0
    if normalized == "poison":
        player.poison = int(getattr(player, "poison", 0) or 0) + 1
        counters = getattr(player, "counters", None)
        if counters is None:
            counters = {}
            player.counters = counters
        if isinstance(counters, dict):
            counters["poison"] = int(counters.get("poison") or 0) + 1
        return 1
    counters = getattr(player, "counters", None)
    if counters is None:
        counters = {}
        player.counters = counters
    if isinstance(counters, dict):
        counters[normalized] = int(counters.get(normalized) or 0) + 1
        return 1
    return 0


def remove_named_counters(permanent, counter_name, count=None):
    if not isinstance(permanent, dict):
        return 0
    key = f"{counter_name}_counters"
    current = get_named_counter_count(permanent, counter_name)
    if current <= 0:
        return 0
    removed = current if count is None else max(0, min(current, int(count or 0)))
    permanent[key] = max(0, current - removed)
    counters = permanent.get("counters")
    if isinstance(counters, dict):
        counters[counter_name] = permanent[key]
    return removed


def add_counters_target_type(effect_data):
    return (
        str((effect_data or {}).get("target") or "").lower()
        or _target_type_from_constraints(effect_data)
        or "creature"
    )


def add_counters_candidate_targets(player, opponents, card, effect_data):
    target_type = add_counters_target_type(effect_data)
    target_controller = str((effect_data or {}).get("target_controller") or "any").lower()
    targeting_source = target_constraint_source(card if isinstance(card, dict) else {}, effect_data)
    participants = []
    if target_controller in {"self", "you", "controller", "controlled"}:
        participants = [player]
    elif target_controller in {"opponent", "opponents"}:
        participants = list(opponents or [])
    else:
        participants = [player] + list(opponents or [])
    candidates = []
    for owner in participants:
        for permanent in list(getattr(owner, "battlefield", []) or []):
            if not is_battlefield_creature(permanent):
                continue
            if _target_constraints_dict(effect_data).get("exclude_source") and permanent is card:
                continue
            if not is_legal_target(
                targeting_source,
                permanent,
                player,
                target_type=target_type,
                target_controller=owner,
            ):
                continue
            candidates.append((owner, permanent))
    return candidates


def choose_add_counters_target(player, opponents, card, effect_data):
    selected, target_options = choose_add_counters_targets(player, opponents, card, effect_data)
    if not selected:
        return None, None, target_options
    owner, target = selected[0]
    return owner, target, target_options


def add_counters_target_count_max(effect_data):
    try:
        return max(1, int((effect_data or {}).get("target_count_max") or (effect_data or {}).get("target_count") or 1))
    except Exception:
        return 1


def add_counters_is_up_to_count(effect_data):
    if not isinstance(effect_data, dict):
        return False
    if effect_data.get("up_to_count"):
        return True
    try:
        return int(effect_data.get("target_count_min") or 1) == 0 and add_counters_target_count_max(effect_data) > 1
    except Exception:
        return False


def choose_add_counters_targets(player, opponents, card, effect_data):
    candidates = add_counters_candidate_targets(player, opponents, card, effect_data)
    if not candidates:
        return [], []
    counter_type = str((effect_data or {}).get("counter_type") or "+1/+1")
    target_controller = str((effect_data or {}).get("target_controller") or "any").lower()
    forced_self = target_controller in {"self", "you", "controller", "controlled"}
    forced_opponent = target_controller in {"opponent", "opponents"}
    max_targets = add_counters_target_count_max(effect_data)
    up_to_count = add_counters_is_up_to_count(effect_data)
    if counter_type == "-1/-1":
        if forced_self:
            ordered = sorted(candidates, key=lambda item: target_priority(item[1]))
            return ordered[:max_targets], [target for _owner, target in candidates]
        preferred = [(owner, target) for owner, target in candidates if owner is not player]
        if not preferred and (up_to_count or (effect_data or {}).get("optional")):
            return [], [target for _owner, target in candidates]
    else:
        if forced_opponent:
            preferred = candidates
        else:
            preferred = [(owner, target) for owner, target in candidates if owner is player]
            if not preferred and up_to_count:
                return [], [target for _owner, target in candidates]
    if not preferred:
        preferred = candidates
    ordered = sorted(preferred, key=lambda item: target_priority(item[1]), reverse=True)
    return ordered[:max_targets], [target for _owner, target in candidates]


def resolve_add_counters_target_effect(
    player,
    opponents,
    card,
    effect_data,
    turn,
    *,
    finish_spell=True,
    event_name="add_counters_resolved",
    trigger=None,
    phase=None,
):
    counter_type = str(effect_data.get("counter_type") or "+1/+1")
    count = max(0, int(effect_data.get("counter_count") or effect_data.get("count") or 1))
    selected_targets, target_options = choose_add_counters_targets(
        player,
        opponents,
        card,
        effect_data,
    )
    if not selected_targets or count <= 0:
        event_payload = dict(
            player=player.name,
            card=card.get("name", "?"),
            counter_type=counter_type,
            counters_added=0,
            target_type=add_counters_target_type(effect_data),
            result="no_legal_target",
            turn=turn,
            **replay_rule_fields(effect_data),
        )
        if trigger:
            event_payload["trigger"] = trigger
            event_payload["effect"] = "add_counters"
        if phase:
            event_payload["phase"] = phase
        emit_replay_event(event_name, **event_payload)
        if finish_spell:
            finish_resolved_spell(player, card, turn=turn, effect_data=effect_data)
        return None

    resolved_targets = []
    for target_owner, target in selected_targets:
        tapped_before = bool(target.get("tapped"))
        power_before = _numeric_card_stat(target, "power")
        toughness_before = _numeric_card_stat(target, "toughness", "power")
        counters_before = (
            int(target.get("plus_one_counters") or 0)
            if counter_type == "+1/+1"
            else int(target.get("minus_one_counters") or 0)
            if counter_type == "-1/-1"
            else get_named_counter_count(target, counter_type)
        )
        if counter_type == "+1/+1":
            added = add_plus_one_counters(target, count) or count
        elif counter_type == "-1/-1":
            added = add_minus_one_counters(target, count)
        else:
            added = add_named_counters(target, counter_type, count)
        power_after = _numeric_card_stat(target, "power")
        toughness_after = _numeric_card_stat(target, "toughness", "power")
        destination = None
        result = "counters_added"
        if counter_type == "-1/-1" and is_battlefield_creature(target) and toughness_after <= 0:
            destination = move_creature_from_battlefield(
                target_owner,
                target,
                reason="zero_toughness",
                source=card,
            )
            result = "creature_put_into_graveyard_zero_toughness"
        target_untapped = False
        if effect_data.get("untap_target") and destination is None:
            target["tapped"] = False
            target_untapped = tapped_before and not bool(target.get("tapped"))
        decision = targeting_decision(
            card if isinstance(card, dict) else effect_data,
            target,
            player,
            target_controller=target_owner,
            target_type=add_counters_target_type(effect_data),
        )
        event_payload = dict(
            player=player.name,
            card=card.get("name", "?"),
            target_player=target_owner.name,
            target=target.get("name", "?"),
            target_power_before=power_before,
            target_power_after=power_after,
            target_toughness_before=toughness_before,
            target_toughness_after=toughness_after,
            counter_type=counter_type,
            counters_before=counters_before,
            counters_added=added,
            counters_after=counters_before + added,
            target_tapped_before=tapped_before,
            target_tapped_after=bool(target.get("tapped")),
            target_untapped=target_untapped,
            result=result,
            destination=destination,
            selected_target_count=len(selected_targets),
            available_targets=len(target_options),
            **target_selection_replay_fields(target, target_options),
            turn=turn,
            **decision,
            **replay_rule_fields(effect_data),
        )
        if trigger:
            event_payload["trigger"] = trigger
            event_payload["effect"] = "add_counters"
        if phase:
            event_payload["phase"] = phase
        emit_replay_event(event_name, **event_payload)
        resolved_targets.append(target)
    if finish_spell:
        finish_resolved_spell(player, card, turn=turn, effect_data=effect_data)
    return resolved_targets[0] if len(resolved_targets) == 1 else resolved_targets


def resolve_add_counters_source_effect(
    player,
    permanent,
    effect_data,
    turn,
    *,
    event_name="self_add_counters_resolved",
    phase=None,
    extra_event_fields=None,
):
    counter_type = str(
        effect_data.get("activated_add_counters_counter_type")
        or effect_data.get("counter_type")
        or "+1/+1"
    )
    count = max(
        0,
        int(
            effect_data.get("activated_add_counters_count")
            or effect_data.get("counter_count")
            or effect_data.get("count")
            or 1
        ),
    )
    if count <= 0 or permanent not in getattr(player, "battlefield", []):
        emit_replay_event(
            event_name,
            player=player.name,
            card=permanent.get("name", "?"),
            counter_type=counter_type,
            counters_added=0,
            result="source_not_on_battlefield_or_zero_count",
            phase=phase,
            turn=turn,
            **replay_rule_fields(effect_data),
        )
        return None

    power_before = _numeric_card_stat(permanent, "power")
    toughness_before = _numeric_card_stat(permanent, "toughness", "power")
    counters_before = (
        int(permanent.get("plus_one_counters") or 0)
        if counter_type == "+1/+1"
        else int(permanent.get("minus_one_counters") or 0)
        if counter_type == "-1/-1"
        else get_named_counter_count(permanent, counter_type)
    )
    if counter_type == "+1/+1":
        added = add_plus_one_counters(permanent, count) or count
    elif counter_type == "-1/-1":
        added = add_minus_one_counters(permanent, count)
    else:
        added = add_named_counters(permanent, counter_type, count)

    destination = None
    result = "counters_added"
    toughness_after = _numeric_card_stat(permanent, "toughness", "power")
    if counter_type == "-1/-1" and is_battlefield_creature(permanent) and toughness_after <= 0:
        destination = move_creature_from_battlefield(
            player,
            permanent,
            reason="zero_toughness",
            source=permanent,
        )
        result = "source_put_into_graveyard_zero_toughness"

    emit_replay_event(
        event_name,
        player=player.name,
        card=permanent.get("name", "?"),
        target=permanent.get("name", "?"),
        target_player=player.name,
        target_type="self",
        counter_type=counter_type,
        counters_before=counters_before,
        counters_added=added,
        counters_after=counters_before + added,
        target_power_before=power_before,
        target_power_after=_numeric_card_stat(permanent, "power"),
        target_toughness_before=toughness_before,
        target_toughness_after=_numeric_card_stat(permanent, "toughness", "power"),
        result=result,
        destination=destination,
        phase=phase,
        turn=turn,
        **(extra_event_fields or {}),
        **replay_rule_fields(effect_data),
    )
    return permanent


def resolve_add_counters_target_spell(player, opponents, card, effect_data, turn):
    return resolve_add_counters_target_effect(
        player,
        opponents,
        card,
        effect_data,
        turn,
        finish_spell=True,
    )


def resolve_etb_add_counters_target(player, opponents, permanent, effect_data, turn, *, phase="battlefield_etb"):
    etb_effect = {
        **effect_data,
        "effect": "add_counters",
        "target": effect_data.get("etb_add_counters_target") or effect_data.get("target") or "creature",
        "target_constraints": effect_data.get("target_constraints") or {"card_types": ["creature"]},
        "target_controller": effect_data.get("target_controller") or "any",
        "counter_type": (
            effect_data.get("etb_add_counters_counter_type")
            or effect_data.get("counter_type")
            or "+1/+1"
        ),
        "counter_count": int(
            effect_data.get("etb_add_counters_count")
            or effect_data.get("counter_count")
            or effect_data.get("count")
            or 1
        ),
    }
    if effect_data.get("target_count_max"):
        etb_effect["target_count_max"] = int(effect_data.get("target_count_max") or 1)
    if effect_data.get("target_count_min") is not None:
        etb_effect["target_count_min"] = int(effect_data.get("target_count_min") or 0)
    if effect_data.get("up_to_count"):
        etb_effect["up_to_count"] = True
    return resolve_add_counters_target_effect(
        player,
        opponents,
        permanent,
        etb_effect,
        turn,
        finish_spell=False,
        event_name="trigger_resolved",
        trigger="enters_battlefield",
        phase=phase,
    )


def resolve_etb_target_stat_modifier(player, opponents, permanent, effect_data, turn, *, phase="battlefield_etb"):
    etb_effect = {
        **effect_data,
        "effect": "stat_modifier_until_eot",
        "target": effect_data.get("target") or "creature",
        "target_constraints": effect_data.get("target_constraints") or {"card_types": ["creature"]},
        "target_controller": effect_data.get("target_controller") or "any",
        "power_delta": int(effect_data.get("power_delta") or effect_data.get("power_boost") or 0),
        "toughness_delta": int(effect_data.get("toughness_delta") or effect_data.get("toughness_boost") or 0),
        "power_boost": int(effect_data.get("power_boost") or effect_data.get("power_delta") or 0),
        "toughness_boost": int(effect_data.get("toughness_boost") or effect_data.get("toughness_delta") or 0),
        "duration": "until_end_of_turn",
    }
    return resolve_stat_modifier_until_eot_spell(
        player,
        opponents,
        permanent,
        etb_effect,
        turn,
        finish=False,
    )


def stat_modifier_is_harmful(effect_data):
    power_delta = int((effect_data or {}).get("power_delta") or (effect_data or {}).get("power_boost") or 0)
    toughness_delta = int((effect_data or {}).get("toughness_delta") or (effect_data or {}).get("toughness_boost") or 0)
    return toughness_delta < 0 or (power_delta < 0 and toughness_delta <= 0)


def stat_modifier_candidate_targets(player, opponents, card, effect_data):
    target_type = str((effect_data or {}).get("target") or "").lower() or _target_type_from_constraints(effect_data) or "creature"
    target_controller = str((effect_data or {}).get("target_controller") or "any").lower()
    allow_noncreature_targets = bool((effect_data or {}).get("untap_target")) and (
        (effect_data or {}).get("modifies_stats") is False
    )
    participants = []
    if target_controller in {"self", "you", "controller", "controlled"}:
        participants = [player]
    elif target_controller in {"opponent", "opponents"}:
        participants = list(opponents or [])
    else:
        participants = [player] + list(opponents or [])
    candidates = []
    for owner in participants:
        for permanent in list(getattr(owner, "battlefield", []) or []):
            if not allow_noncreature_targets and not is_battlefield_creature(permanent):
                continue
            if not is_legal_target(
                card if isinstance(card, dict) else effect_data,
                permanent,
                player,
                target_type=target_type,
                target_controller=owner,
            ):
                continue
            candidates.append((owner, permanent))
    return candidates


def choose_stat_modifier_target(player, opponents, card, effect_data):
    candidates = stat_modifier_candidate_targets(player, opponents, card, effect_data)
    if not candidates:
        return None, None, []
    harmful = stat_modifier_is_harmful(effect_data)
    preferred = [
        (owner, target)
        for owner, target in candidates
        if (owner is not player if harmful else owner is player)
    ]
    if not preferred:
        preferred = candidates
    owner, target = max(preferred, key=lambda item: target_priority(item[1]))
    return owner, target, [target for _owner, target in candidates]


def stat_modifier_target_count(effect_data):
    return max(
        1,
        int(
            (effect_data or {}).get("target_count_max")
            or (effect_data or {}).get("max_targets")
            or (effect_data or {}).get("target_count")
            or 1
        ),
    )


def choose_stat_modifier_targets(player, opponents, card, effect_data):
    candidates = stat_modifier_candidate_targets(player, opponents, card, effect_data)
    if not candidates:
        return []
    requested_count = stat_modifier_target_count(effect_data)
    up_to_count = bool((effect_data or {}).get("up_to_count"))
    minimum_count = int((effect_data or {}).get("target_count_min") or (0 if up_to_count else requested_count))
    minimum_count = max(0 if up_to_count else 1, minimum_count)
    if len(candidates) < minimum_count:
        return []
    harmful = stat_modifier_is_harmful(effect_data)
    preferred = [
        (owner, target)
        for owner, target in candidates
        if (owner is not player if harmful else owner is player)
    ]
    if not preferred:
        preferred = candidates
    preferred.sort(
        key=lambda item: (
            target_priority(item[1]),
            str(getattr(item[0], "name", "")),
            str(item[1].get("name") or ""),
        ),
        reverse=True,
    )
    if not up_to_count and len(preferred) < requested_count and len(candidates) >= requested_count:
        remaining = [item for item in candidates if item not in preferred]
        remaining.sort(
            key=lambda item: (
                target_priority(item[1]),
                str(getattr(item[0], "name", "")),
                str(item[1].get("name") or ""),
            ),
            reverse=True,
        )
        preferred = [*preferred, *remaining]
    if not up_to_count and len(preferred) < requested_count:
        return []
    return preferred[: min(requested_count, len(preferred))]


def resolve_stat_modifier_until_eot_untap_target_spell(player, opponents, card, effect_data, turn, *, finish=True):
    power_delta = int(effect_data.get("power_delta") or effect_data.get("power_boost") or 0)
    toughness_delta = int(effect_data.get("toughness_delta") or effect_data.get("toughness_boost") or 0)
    modifies_stats = bool(effect_data.get("modifies_stats", True))
    target_type = str(effect_data.get("target") or "").lower() or _target_type_from_constraints(effect_data) or "creature"
    target_colors_until_eot = stat_modifier_target_colors_until_eot(effect_data)
    candidates = stat_modifier_candidate_targets(player, opponents, card, effect_data)
    selected = choose_stat_modifier_targets(player, opponents, card, effect_data)
    requested_count = stat_modifier_target_count(effect_data)
    if not selected:
        emit_replay_event(
            "stat_modifier_until_eot_untap_target_resolved",
            player=player.name,
            card=card.get("name", "?"),
            power_delta=power_delta,
            toughness_delta=toughness_delta,
            target_type=target_type,
            requested_target_count=requested_count,
            available_targets=len(candidates),
            target_count=0,
            targets_untapped_count=0,
            target_colors_until_eot=target_colors_until_eot,
            result="no_legal_target",
            turn=turn,
            **replay_rule_fields(effect_data),
        )
        if finish:
            finish_resolved_spell(player, card, turn=turn, effect_data=effect_data)
        return []

    details = []
    for target_owner, target in selected:
        decision = targeting_decision(
            card if isinstance(card, dict) else effect_data,
            target,
            player,
            target_controller=target_owner,
            target_type=target_type,
        )
        if not decision["target_legal"]:
            continue
        power_before = _numeric_card_stat(target, "power")
        toughness_before = _numeric_card_stat(target, "toughness", "power")
        target_colors_before = ordered_card_color_symbols(target)
        tapped_before = bool(target.get("tapped"))
        if modifies_stats:
            remember_until_eot(target, "power")
            remember_until_eot(target, "toughness")
            target["power"] = power_before + power_delta
            target["toughness"] = toughness_before + toughness_delta
        granted_keywords = [
            str(keyword or "").strip()
            for keyword in (effect_data.get("granted_keywords_until_eot") or [])
            if str(keyword or "").strip()
        ]
        if granted_keywords:
            current_keywords = list(target.get("keywords") or [])
            merged_keywords = list(dict.fromkeys([*current_keywords, *granted_keywords]))
            set_until_eot(target, "keywords", merged_keywords)
            for keyword in granted_keywords:
                set_until_eot(target, keyword, True)
        if effect_data.get("untap_target"):
            target["tapped"] = False
        if target_colors_until_eot:
            set_until_eot(target, "colors", target_colors_until_eot)
        details.append(
            {
                "target": target.get("name", "?"),
                "target_player": target_owner.name,
                "target_power_before": power_before,
                "target_power_after": _numeric_card_stat(target, "power"),
                "target_toughness_before": toughness_before,
                "target_toughness_after": _numeric_card_stat(target, "toughness", "power"),
                "target_stats_modified": modifies_stats,
                "target_tapped_before": tapped_before,
                "target_tapped_after": bool(target.get("tapped")),
                "target_untapped": tapped_before and not bool(target.get("tapped")),
                "target_colors_before": target_colors_before,
                "target_colors_after": ordered_card_color_symbols(target),
                "target_colors_until_eot": target_colors_until_eot,
                "granted_keywords_until_eot": granted_keywords,
                **decision,
            }
        )

    result = "stat_modifier_until_eot_untap_target_applied" if details else "no_legal_target"
    granted_keywords = [
        str(keyword or "").strip()
        for keyword in (effect_data.get("granted_keywords_until_eot") or [])
        if str(keyword or "").strip()
    ]
    emit_replay_event(
        "stat_modifier_until_eot_untap_target_resolved",
        player=player.name,
        card=card.get("name", "?"),
        target_type=target_type,
        target_count=len(details),
        requested_target_count=requested_count,
        available_targets=len(candidates),
        targets=details,
        targets_untapped_count=sum(1 for detail in details if detail.get("target_untapped")),
        power_delta=power_delta,
        toughness_delta=toughness_delta,
        granted_keywords_until_eot=granted_keywords,
        target_colors_until_eot=target_colors_until_eot,
        result=result,
        turn=turn,
        **replay_rule_fields(effect_data),
    )
    if finish:
        finish_resolved_spell(player, card, turn=turn, effect_data=effect_data)
    return [target for _owner, target in selected]


def gain_control_untap_haste_candidate_targets(player, opponents, card, effect_data):
    target_type = str(effect_data.get("target") or "").lower() or _target_type_from_constraints(effect_data) or "creature"
    source = target_constraint_source(card, effect_data)
    candidates = []
    for owner in prioritize_evaluation_target_opponents(player, opponents or []):
        for permanent in list(getattr(owner, "battlefield", []) or []):
            if not isinstance(permanent, dict):
                continue
            permanent.setdefault("controller", getattr(owner, "name", None))
            if is_legal_target(
                source,
                permanent,
                player,
                target_type=target_type,
                target_controller=owner,
            ):
                candidates.append((owner, permanent))
    candidates.sort(
        key=lambda item: (
            target_priority(item[1]),
            str(getattr(item[0], "name", "")),
            str(item[1].get("name") or ""),
        ),
        reverse=True,
    )
    return candidates


def resolve_gain_control_untap_haste_until_eot_spell(player, opponents, card, effect_data, turn):
    target_type = str(effect_data.get("target") or "").lower() or _target_type_from_constraints(effect_data) or "creature"
    candidates = gain_control_untap_haste_candidate_targets(player, opponents, card, effect_data)
    if not candidates:
        emit_replay_event(
            "gain_control_untap_haste_until_eot_resolved",
            player=player.name,
            card=card.get("name", "?"),
            target_type=target_type,
            available_targets=0,
            target_count=0,
            result="no_legal_target",
            turn=turn,
            **replay_rule_fields(effect_data),
        )
        finish_resolved_spell(player, card, turn=turn, effect_data=effect_data)
        return []

    original_owner, target = candidates[0]
    source = target_constraint_source(card, effect_data)
    decision = targeting_decision(
        source,
        target,
        player,
        target_controller=original_owner,
        target_type=target_type,
    )
    decision_fields = {
        key: value
        for key, value in decision.items()
        if key not in {"target_type", "target_controller"}
    }
    if not decision["target_legal"]:
        emit_replay_event(
            "gain_control_untap_haste_until_eot_resolved",
            player=player.name,
            card=card.get("name", "?"),
            target_type=target_type,
            available_targets=len(candidates),
            target_count=0,
            result="target_became_illegal",
            turn=turn,
            **decision_fields,
            **replay_rule_fields(effect_data),
        )
        finish_resolved_spell(player, card, turn=turn, effect_data=effect_data)
        return []

    original_controller_name = target.get("controller") or getattr(original_owner, "name", None)
    tapped_before = bool(target.get("tapped"))
    remember_until_eot(target, "controller")
    remember_until_eot(target, "keywords")
    remember_until_eot(target, "haste")
    remember_until_eot(target, "summoning_sick")
    if target in getattr(original_owner, "battlefield", []):
        original_owner.battlefield.remove(target)
    target["_until_eot_control_return_player_ref"] = original_owner
    target["_until_eot_control_return_player_name"] = original_controller_name
    target["controller"] = player.name
    if effect_data.get("untap_target", True):
        target["tapped"] = False
    granted_keywords = {
        str(keyword or "").strip().lower().replace(" ", "_")
        for keyword in (effect_data.get("granted_keywords_until_eot") or ["haste"])
        if str(keyword or "").strip()
    }
    if not granted_keywords:
        granted_keywords = {"haste"}
    keywords = sorted(_keyword_values(target) | granted_keywords)
    target["keywords"] = keywords
    target["haste"] = "haste" in granted_keywords
    target["summoning_sick"] = False
    if target not in player.battlefield:
        player.battlefield.append(target)

    emit_replay_event(
        "gain_control_untap_haste_until_eot_resolved",
        player=player.name,
        card=card.get("name", "?"),
        target=target.get("name", "?"),
        target_type=target_type,
        original_controller=original_controller_name,
        new_controller=player.name,
        target_tapped_before=tapped_before,
        target_tapped_after=bool(target.get("tapped")),
        target_untapped=tapped_before and not bool(target.get("tapped")),
        haste_granted="haste" in granted_keywords,
        granted_keywords_until_eot=sorted(granted_keywords),
        control_duration=effect_data.get("control_duration") or "until_end_of_turn",
        available_targets=len(candidates),
        target_count=1,
        result="control_gained_until_eot",
        turn=turn,
        **decision_fields,
        **replay_rule_fields(effect_data),
    )
    finish_resolved_spell(player, card, turn=turn, effect_data=effect_data)
    return [target]


def stat_modifier_target_colors_until_eot(effect_data):
    colors = []
    for value in _as_list(effect_data.get("target_colors_until_eot") or effect_data.get("colors_until_eot")):
        symbol = _color_symbol(value)
        if symbol in SYMBOL_TO_COLOR_NAME and symbol not in colors:
            colors.append(symbol)
    return colors


def ordered_card_color_symbols(card):
    symbols = _symbols_from_value((card or {}).get("colors"))
    return [symbol for symbol in ("W", "U", "B", "R", "G") if symbol in symbols]


def resolve_stat_modifier_until_eot_spell(player, opponents, card, effect_data, turn, *, finish=True):
    power_delta = int(effect_data.get("power_delta") or effect_data.get("power_boost") or 0)
    toughness_delta = int(effect_data.get("toughness_delta") or effect_data.get("toughness_boost") or 0)
    dynamic_deltas, dynamic_replay_fields = dynamic_stat_modifier_deltas(player, opponents, effect_data)
    if dynamic_deltas is not None:
        power_delta, toughness_delta = dynamic_deltas
        effect_data = {**effect_data, "power_delta": power_delta, "toughness_delta": toughness_delta}
    requested_count = stat_modifier_target_count(effect_data)
    target_colors_until_eot = stat_modifier_target_colors_until_eot(effect_data)
    if requested_count > 1 or effect_data.get("up_to_count"):
        candidates = stat_modifier_candidate_targets(player, opponents, card, effect_data)
        selected = choose_stat_modifier_targets(player, opponents, card, effect_data)
        target_type = str(effect_data.get("target") or "").lower() or _target_type_from_constraints(effect_data) or "creature"
        granted_keywords = [
            str(keyword or "").strip()
            for keyword in (effect_data.get("granted_keywords_until_eot") or [])
            if str(keyword or "").strip()
        ]
        if not selected:
            emit_replay_event(
                "stat_modifier_until_eot_resolved",
                player=player.name,
                card=card.get("name", "?"),
                power_delta=power_delta,
                toughness_delta=toughness_delta,
                target_type=target_type,
                requested_target_count=requested_count,
                available_targets=len(candidates),
                target_count=0,
                granted_keywords_until_eot=granted_keywords,
                target_colors_until_eot=target_colors_until_eot,
                result="no_legal_target",
                turn=turn,
                **dynamic_replay_fields,
                **replay_rule_fields(effect_data),
            )
            if finish:
                finish_resolved_spell(player, card, turn=turn, effect_data=effect_data)
            return []

        details = []
        moved = []
        for target_owner, target in selected:
            decision = targeting_decision(
                card if isinstance(card, dict) else effect_data,
                target,
                player,
                target_controller=target_owner,
                target_type=target_type,
            )
            if not decision["target_legal"]:
                continue
            power_before = _numeric_card_stat(target, "power")
            toughness_before = _numeric_card_stat(target, "toughness", "power")
            target_colors_before = ordered_card_color_symbols(target)
            remember_until_eot(target, "power")
            remember_until_eot(target, "toughness")
            target["power"] = power_before + power_delta
            target["toughness"] = toughness_before + toughness_delta
            if granted_keywords:
                current_keywords = list(target.get("keywords") or [])
                merged_keywords = list(dict.fromkeys([*current_keywords, *granted_keywords]))
                set_until_eot(target, "keywords", merged_keywords)
                for keyword in granted_keywords:
                    set_until_eot(target, keyword, True)
            if target_colors_until_eot:
                set_until_eot(target, "colors", target_colors_until_eot)
            power_after = _numeric_card_stat(target, "power")
            toughness_after = _numeric_card_stat(target, "toughness", "power")
            target_colors_after = ordered_card_color_symbols(target)
            destination = None
            result = "stat_modifier_until_eot_applied"
            if toughness_after <= 0 and is_battlefield_creature(target):
                destination = move_creature_from_battlefield(
                    target_owner,
                    target,
                    reason="zero_toughness",
                    source=card,
                )
                moved.append(target.get("name", "?"))
                result = "creature_put_into_graveyard_zero_toughness"
            details.append(
                {
                    "target": target.get("name", "?"),
                    "target_player": target_owner.name,
                    "target_power_before": power_before,
                    "target_power_after": power_after,
                    "target_toughness_before": toughness_before,
                    "target_toughness_after": toughness_after,
                    "power_delta": power_delta,
                    "toughness_delta": toughness_delta,
                    "granted_keywords_until_eot": granted_keywords,
                    "target_colors_before": target_colors_before,
                    "target_colors_after": target_colors_after,
                    "target_colors_until_eot": target_colors_until_eot,
                    "destination": destination,
                    "result": result,
                    **decision,
                }
            )
        result = "stat_modifier_until_eot_applied" if details else "no_legal_target"
        emit_replay_event(
            "stat_modifier_until_eot_resolved",
            player=player.name,
            card=card.get("name", "?"),
            target_type=target_type,
            target_count=len(details),
            requested_target_count=requested_count,
            available_targets=len(candidates),
            targets=details,
            moved_to_graveyard=moved,
            power_delta=power_delta,
            toughness_delta=toughness_delta,
            granted_keywords_until_eot=granted_keywords,
            target_colors_until_eot=target_colors_until_eot,
            **dynamic_replay_fields,
            result=result,
            turn=turn,
            **replay_rule_fields(effect_data),
        )
        if finish:
            finish_resolved_spell(player, card, turn=turn, effect_data=effect_data)
        return [target for _owner, target in selected]
    target_owner, target, target_options = choose_stat_modifier_target(
        player,
        opponents,
        card,
        effect_data,
    )
    target_type = str(effect_data.get("target") or "").lower() or _target_type_from_constraints(effect_data) or "creature"
    if target is None or target_owner is None:
        emit_replay_event(
            "stat_modifier_until_eot_resolved",
            player=player.name,
            card=card.get("name", "?"),
            power_delta=power_delta,
            toughness_delta=toughness_delta,
            target_type=target_type,
            target_colors_until_eot=target_colors_until_eot,
            result="no_legal_target",
            turn=turn,
            **dynamic_replay_fields,
            **replay_rule_fields(effect_data),
        )
        if finish:
            finish_resolved_spell(player, card, turn=turn, effect_data=effect_data)
        return None

    power_before = _numeric_card_stat(target, "power")
    toughness_before = _numeric_card_stat(target, "toughness", "power")
    target_colors_before = ordered_card_color_symbols(target)
    remember_until_eot(target, "power")
    remember_until_eot(target, "toughness")
    target["power"] = power_before + power_delta
    target["toughness"] = toughness_before + toughness_delta
    granted_keywords = [
        str(keyword or "").strip()
        for keyword in (effect_data.get("granted_keywords_until_eot") or [])
        if str(keyword or "").strip()
    ]
    if granted_keywords:
        current_keywords = list(target.get("keywords") or [])
        merged_keywords = list(dict.fromkeys([*current_keywords, *granted_keywords]))
        set_until_eot(target, "keywords", merged_keywords)
        for keyword in granted_keywords:
            set_until_eot(target, keyword, True)
    if target_colors_until_eot:
        set_until_eot(target, "colors", target_colors_until_eot)
    power_after = _numeric_card_stat(target, "power")
    toughness_after = _numeric_card_stat(target, "toughness", "power")
    target_colors_after = ordered_card_color_symbols(target)
    destination = None
    result = "stat_modifier_until_eot_applied"
    if toughness_after <= 0 and is_battlefield_creature(target):
        destination = move_creature_from_battlefield(
            target_owner,
            target,
            reason="zero_toughness",
            source=card,
        )
        result = "creature_put_into_graveyard_zero_toughness"
    decision = targeting_decision(
        card if isinstance(card, dict) else effect_data,
        target,
        player,
        target_controller=target_owner,
        target_type=target_type,
    )
    emit_replay_event(
        "stat_modifier_until_eot_resolved",
        player=player.name,
        card=card.get("name", "?"),
        target_player=target_owner.name,
        target=target.get("name", "?"),
        target_power_before=power_before,
        target_power_after=power_after,
        target_toughness_before=toughness_before,
        target_toughness_after=toughness_after,
        power_delta=power_delta,
        toughness_delta=toughness_delta,
        granted_keywords_until_eot=granted_keywords,
        target_colors_before=target_colors_before,
        target_colors_after=target_colors_after,
        target_colors_until_eot=target_colors_until_eot,
        **dynamic_replay_fields,
        result=result,
        destination=destination,
        available_targets=len(target_options),
        **target_selection_replay_fields(target, target_options),
        turn=turn,
        **decision,
        **replay_rule_fields(effect_data),
    )
    if finish:
        finish_resolved_spell(player, card, turn=turn, effect_data=effect_data)
    return target


def resolve_controlled_stat_modifier_until_eot_spell(player, opponents, card, effect_data, turn):
    power_delta = int(effect_data.get("power_delta") or effect_data.get("power_boost") or 0)
    toughness_delta = int(effect_data.get("toughness_delta") or effect_data.get("toughness_boost") or 0)
    target_constraints = effect_data.get("target_constraints") or {}
    if not isinstance(target_constraints, dict):
        target_constraints = {}
    creature_filter = effect_data.get("creature_filter") or target_constraints.get("creature_filter") or {}
    if not isinstance(creature_filter, dict):
        creature_filter = {}
    affected = []
    moved = []
    for target in list(getattr(player, "battlefield", []) or []):
        if not is_battlefield_creature(target):
            continue
        if creature_filter and not global_stat_modifier_creature_filter_matches(target, creature_filter):
            continue
        power_before = _numeric_card_stat(target, "power")
        toughness_before = _numeric_card_stat(target, "toughness", "power")
        remember_until_eot(target, "power")
        remember_until_eot(target, "toughness")
        target["power"] = power_before + power_delta
        target["toughness"] = toughness_before + toughness_delta
        record = {
            "target": target.get("name", "?"),
            "power_before": power_before,
            "toughness_before": toughness_before,
            "power_after": target.get("power"),
            "toughness_after": target.get("toughness"),
        }
        affected.append(record)
        if int(float(target.get("toughness") or 0)) <= 0:
            destination = move_creature_from_battlefield(
                player,
                target,
                reason="zero_toughness",
                source=card,
            )
            record["destination"] = destination
            moved.append(target.get("name", "?"))
    result = "stat_modifier_until_eot_applied" if affected else "no_affected_creatures"
    emit_replay_event(
        "controlled_stat_modifier_until_eot_resolved",
        player=player.name,
        card=card.get("name", "?"),
        affected_count=len(affected),
        affected=[dict(item) for item in affected],
        moved_to_graveyard=moved,
        creature_filter=creature_filter,
        power_delta=power_delta,
        toughness_delta=toughness_delta,
        result=result,
        turn=turn,
        **replay_rule_fields(effect_data),
    )
    finish_resolved_spell(player, card, turn=turn, effect_data=effect_data)
    return affected


def global_stat_modifier_creature_filter_matches(target, creature_filter):
    if not creature_filter:
        return True
    combat_state = str(creature_filter.get("combat_state") or "").lower()
    if combat_state == "attacking" and not bool(target.get("attacking")):
        return False
    if combat_state == "blocked" and not bool(target.get("blocked")):
        return False
    if combat_state == "blocking" and not bool(target.get("blocking")):
        return False
    if combat_state == "attacking_or_blocking" and not (
        bool(target.get("attacking")) or bool(target.get("blocking"))
    ):
        return False
    colors = [str(color).strip() for color in _as_list(creature_filter.get("colors")) if str(color).strip()]
    if colors and not any(card_has_color(target, color) for color in colors):
        return False
    excluded_colors = [
        str(color).strip() for color in _as_list(creature_filter.get("exclude_colors")) if str(color).strip()
    ]
    if excluded_colors and any(card_has_color(target, color) for color in excluded_colors):
        return False
    subtypes = [
        str(subtype).strip() for subtype in _as_list(creature_filter.get("subtypes")) if str(subtype).strip()
    ]
    if subtypes and not any(permanent_has_subtype(target, subtype) for subtype in subtypes):
        return False
    excluded_subtypes = [
        str(subtype).strip()
        for subtype in _as_list(creature_filter.get("exclude_subtypes"))
        if str(subtype).strip()
    ]
    if excluded_subtypes and any(permanent_has_subtype(target, subtype) for subtype in excluded_subtypes):
        return False
    required_card_types = [
        str(card_type).strip()
        for card_type in _as_list(creature_filter.get("card_types"))
        if str(card_type).strip()
    ]
    if required_card_types and not all(permanent_has_card_type(target, card_type) for card_type in required_card_types):
        return False
    excluded_card_types = [
        str(card_type).strip()
        for card_type in _as_list(creature_filter.get("exclude_card_types"))
        if str(card_type).strip()
    ]
    if excluded_card_types and any(permanent_has_card_type(target, card_type) for card_type in excluded_card_types):
        return False
    if creature_filter.get("token") and not (target.get("token") or target.get("is_token")):
        return False
    if creature_filter.get("no_counters") and permanent_has_any_counter(target):
        return False
    return True


def resolve_global_stat_modifier_until_eot_spell(player, opponents, card, effect_data, turn, *, finish=True):
    power_delta = int(effect_data.get("power_delta") or effect_data.get("power_boost") or 0)
    toughness_delta = int(effect_data.get("toughness_delta") or effect_data.get("toughness_boost") or 0)
    creature_filter = effect_data.get("creature_filter") or {}
    controller_scope = str(effect_data.get("target_controller") or "all").lower()
    if controller_scope in {"opponent", "opponents"}:
        participants = list(opponents or [])
    elif controller_scope in {"self", "you", "controller", "controlled"}:
        participants = [player]
    else:
        participants = [player] + list(opponents or [])
        controller_scope = "all"
    affected = []
    moved = []
    for owner in participants:
        for target in list(getattr(owner, "battlefield", []) or []):
            if not is_battlefield_creature(target):
                continue
            if not global_stat_modifier_creature_filter_matches(target, creature_filter):
                continue
            power_before = _numeric_card_stat(target, "power")
            toughness_before = _numeric_card_stat(target, "toughness", "power")
            remember_until_eot(target, "power")
            remember_until_eot(target, "toughness")
            target["power"] = power_before + power_delta
            target["toughness"] = toughness_before + toughness_delta
            record = {
                "target_player": owner.name,
                "target": target.get("name", "?"),
                "power_before": power_before,
                "toughness_before": toughness_before,
                "power_after": target.get("power"),
                "toughness_after": target.get("toughness"),
            }
            affected.append(record)
            if int(float(target.get("toughness") or 0)) <= 0:
                destination = move_creature_from_battlefield(
                    owner,
                    target,
                    reason="zero_toughness",
                    source=card,
                )
                record["destination"] = destination
                moved.append({"target_player": owner.name, "target": target.get("name", "?")})
    result = "stat_modifier_until_eot_applied" if affected else "no_affected_creatures"
    emit_replay_event(
        "global_stat_modifier_until_eot_resolved",
        player=player.name,
        card=card.get("name", "?"),
        target_controller=controller_scope,
        affected_count=len(affected),
        affected=[dict(item) for item in affected],
        moved_to_graveyard=moved,
        power_delta=power_delta,
        toughness_delta=toughness_delta,
        creature_filter=creature_filter,
        result=result,
        turn=turn,
        **replay_rule_fields(effect_data),
    )
    if finish:
        finish_resolved_spell(player, card, turn=turn, effect_data=effect_data)
    return affected


def transform_permanent_to_face(
    player,
    permanent,
    transform_to,
    *,
    turn=None,
    phase=None,
    opponents=None,
    all_players=None,
):
    if not isinstance(player, Player) or not isinstance(permanent, dict) or not isinstance(transform_to, dict):
        return None
    transformed_payload = enrich_card(copy.deepcopy(transform_to))
    transformed_payload.setdefault("effect", transform_to.get("effect") or "creature")
    all_players_for_entry = all_players or [player, *(opponents or [])]
    if permanent in player.battlefield:
        player.battlefield.remove(permanent)
        player.exile.append(permanent)
    transformed = prepare_entering_permanent(
        transformed_payload,
        controller=player,
        all_players=all_players_for_entry,
        turn=turn,
    )
    player.battlefield.append(transformed)
    emit_replay_event(
        "permanent_transformed",
        player=player.name,
        card=permanent.get("name", "?"),
        transformed_to=transformed.get("name", "?"),
        turn=turn,
        phase=phase,
        **replay_rule_fields(permanent),
    )
    return transformed


def resolve_creature_cards_leave_graveyard_triggers(
    player,
    leaving_cards,
    *,
    turn,
    source_event="graveyard_exit",
):
    active_permanents = [
        permanent
        for permanent in getattr(player, "battlefield", []) or []
        if isinstance(permanent, dict)
        and permanent.get("creature_cards_leave_your_graveyard_create_plant_token")
    ]
    creature_cards = [
        card
        for card in leaving_cards or []
        if isinstance(card, dict) and is_creature_card(card)
    ]
    if not active_permanents or not creature_cards:
        return []

    triggered = []
    for permanent in active_permanents:
        token = create_creature_token(
            player,
            name=permanent.get("token_name") or "Plant Token",
            power=int(permanent.get("token_power") or 0),
            toughness=int(permanent.get("token_toughness") or 1),
            subtype=permanent.get("token_subtype") or "Plant",
            colors=list(permanent.get("token_colors") or ["G"]),
        )
        buffed = []
        for plant in player.battlefield:
            if not isinstance(plant, dict):
                continue
            if "plant" not in str(plant.get("type_line") or "").lower():
                continue
            add_plus_one_counters(plant, 1)
            buffed.append(plant.get("name", "?"))
        emit_replay_event(
            "trigger_resolved",
            player=player.name,
            card=permanent.get("name", "?"),
            trigger="creature_cards_leave_graveyard",
            source_event=source_event,
            effect="create_plant_token_plus_counters",
            creature_cards_left_graveyard=[card.get("name", "?") for card in creature_cards],
            token_created=token.get("name", "?"),
            plants_buffed=len(buffed),
            turn=turn,
            **replay_rule_fields(permanent),
        )
        triggered.append(token)
    return triggered


def resolve_land_cards_enter_graveyard_triggers(
    player,
    entered_cards,
    *,
    turn,
    source_event="land_card_enter_graveyard",
):
    land_cards = [
        card
        for card in entered_cards or []
        if isinstance(card, dict) and is_effective_land(card)
    ]
    if not land_cards:
        return []

    triggered = []
    for permanent in list(getattr(player, "battlefield", []) or []):
        if not isinstance(permanent, dict):
            continue
        if not permanent.get("land_cards_to_your_graveyard_create_token"):
            continue
        if permanent.get("land_graveyard_trigger_last_turn") == turn:
            emit_replay_event(
                "trigger_skipped",
                player=player.name,
                card=permanent.get("name", "?"),
                trigger="land_cards_to_your_graveyard",
                reason="once_each_turn_limit",
                source_event=source_event,
                turn=turn,
                **replay_rule_fields(permanent),
            )
            continue
        permanent["land_graveyard_trigger_last_turn"] = turn
        token = create_creature_token(
            player,
            name=permanent.get("land_graveyard_token_name") or permanent.get("token_name") or "Token",
            power=int(permanent.get("land_graveyard_token_power") or permanent.get("token_power") or 1),
            toughness=int(
                permanent.get("land_graveyard_token_toughness")
                or permanent.get("token_toughness")
                or permanent.get("land_graveyard_token_power")
                or permanent.get("token_power")
                or 1
            ),
            subtype=permanent.get("land_graveyard_token_subtype") or permanent.get("token_subtype"),
            colors=list(permanent.get("land_graveyard_token_colors") or permanent.get("token_colors") or []),
        )
        emit_replay_event(
            "trigger_resolved",
            player=player.name,
            card=permanent.get("name", "?"),
            trigger="land_cards_to_your_graveyard",
            source_event=source_event,
            effect="create_token",
            land_cards_entered_graveyard=[card.get("name", "?") for card in land_cards],
            token_created=token.get("name", "?"),
            turn=turn,
            **replay_rule_fields(permanent),
        )
        triggered.append(token)
    return triggered


def remove_cards_from_graveyard(player, grave_cards, *, turn, source_event="graveyard_exit"):
    removed = []
    for grave_card in grave_cards or []:
        if grave_card in getattr(player, "graveyard", []):
            player.graveyard.remove(grave_card)
            removed.append(grave_card)
    if removed:
        resolve_creature_cards_leave_graveyard_triggers(
            player,
            removed,
            turn=turn,
            source_event=source_event,
        )
    return removed


def is_legendary_creature_or_planeswalker_permanent(card):
    if not isinstance(card, dict):
        return False
    type_line = str(card.get("type_line") or "").lower()
    return "legendary" in type_line and (
        "creature" in type_line or "planeswalker" in type_line
    )


def _permanent_matches_dynamic_mana_count(permanent, card_types, subtypes):
    if not isinstance(permanent, dict):
        return False
    type_line = str(permanent.get("type_line") or "").lower()
    for card_type in _as_list(card_types):
        wanted = str(card_type or "").strip().lower()
        if wanted and wanted not in type_line:
            return False
    for subtype in _as_list(subtypes):
        wanted = str(subtype or "").strip()
        if wanted and not permanent_has_subtype(permanent, wanted):
            return False
    return True


def _battlefield_permanent_count_for_dynamic_mana(player, source):
    scope = str(source.get("dynamic_mana_battlefield_count_scope") or "controller_battlefield").lower()
    card_types = source.get("dynamic_mana_battlefield_count_card_types") or []
    subtypes = source.get("dynamic_mana_battlefield_count_subtypes") or []
    players = [player]
    if scope == "all_battlefield":
        players = _table_players_for(player) or [player]
    total = 0
    for participant in players:
        for permanent in getattr(participant, "battlefield", []) or []:
            if _permanent_matches_dynamic_mana_count(permanent, card_types, subtypes):
                total += 1
    return total


def _card_matches_dynamic_mana_graveyard_count(card, card_types):
    if not isinstance(card, dict):
        return False
    type_line = str(card.get("type_line") or "").lower()
    for card_type in _as_list(card_types):
        wanted = str(card_type or "").strip().lower()
        if wanted and wanted not in type_line:
            return False
    return True


def _controller_graveyard_card_count_for_dynamic_mana(player, source):
    card_types = source.get("dynamic_mana_graveyard_count_card_types") or []
    return sum(
        1
        for card in getattr(player, "graveyard", []) or []
        if _card_matches_dynamic_mana_graveyard_count(card, card_types)
    )


def devotion_to_color(player, symbol):
    target = str(symbol or "").strip().upper()
    if target not in {"W", "U", "B", "R", "G"}:
        return 0
    devotion = 0
    for permanent in getattr(player, "battlefield", []) or []:
        if not isinstance(permanent, dict):
            continue
        mana_cost = str(permanent.get("mana_cost") or "")
        devotion += mana_cost.count(f"{{{target}}}")
        devotion += mana_cost.count(f"{{{target}/P}}")
        for hybrid in re.findall(r"\{([^}]+)\}", mana_cost):
            parts = [part.strip().upper() for part in hybrid.split("/")]
            if target in parts and target != hybrid.strip().upper():
                devotion += 1
    return devotion


def _dynamic_mana_source_production_for_state(player, source):
    amount_source = str(source.get("dynamic_mana_amount_source") or "").strip().lower()
    if not amount_source:
        return None
    if amount_source == "battlefield_permanent_count":
        return _battlefield_permanent_count_for_dynamic_mana(player, source)
    if amount_source == "controller_graveyard_card_count":
        return _controller_graveyard_card_count_for_dynamic_mana(player, source)
    if amount_source == "devotion_to_green":
        return devotion_to_color(player, "G")
    if amount_source == "source_power":
        return _source_power_value(source)
    return 0


def _controls_creature_with_power_at_least(player, threshold):
    minimum = int(threshold or 0)
    if minimum <= 0:
        return False
    for permanent in getattr(player, "battlefield", []) or []:
        if not isinstance(permanent, dict) or not is_battlefield_creature(permanent):
            continue
        try:
            power = int(float(permanent.get("power") or 0))
        except (TypeError, ValueError):
            power = 0
        if power >= minimum:
            return True
    return False


def _controlled_creature_count(player):
    return sum(
        1
        for permanent in getattr(player, "battlefield", []) or []
        if isinstance(permanent, dict) and is_battlefield_creature(permanent)
    )


def _conditional_mana_source_production_for_state(player, source):
    power_threshold = int(source.get("conditional_mana_controlled_creature_power_gte") or 0)
    count_threshold = int(source.get("conditional_mana_controlled_creature_count_gte") or 0)
    if power_threshold <= 0 and count_threshold <= 0:
        return None
    condition_met = False
    if power_threshold > 0:
        condition_met = _controls_creature_with_power_at_least(player, power_threshold)
    if count_threshold > 0:
        condition_met = condition_met or _controlled_creature_count(player) >= count_threshold
    if condition_met:
        return int(source.get("conditional_mana_produced_when_condition_met") or source.get("mana_produced") or 0)
    return int(source.get("mana_produced") or 0)


def mana_source_production_for_state(player, source):
    if source == "land":
        return 1
    if not isinstance(source, dict):
        return 0
    if artifact_activated_abilities_locked(player, source):
        return 0
    if _creature_has_any_color_mana_from_passive(player, source):
        return max(1, int(source.get("mana_produced") or 1))
    normalized_name = normalize_card_name(source.get("name", ""))
    if (
        source.get("mana_source_requires_untapped_creature")
        and not _has_untapped_mana_support_permanent(player, source, allow_artifact=False)
    ):
        return 0
    if (
        source.get("mana_source_requires_untapped_artifact_or_creature")
        and not _has_untapped_mana_support_permanent(
            player,
            source,
            allow_artifact=True,
            include_source=_mana_source_support_can_include_source(source),
        )
    ):
        return 0
    if normalized_name == "mox amber":
        if not any(
            is_legendary_creature_or_planeswalker_permanent(permanent)
            for permanent in player.battlefield
            if isinstance(permanent, dict)
        ):
            return 0
    if source.get("metalcraft_required") or normalized_name == "mox opal":
        threshold = int(source.get("metalcraft_artifact_threshold") or 3)
        if controlled_artifact_count(player) < threshold:
            return 0
    if source.get("mana_produced_from_controlled_creatures"):
        return sum(
            1
            for permanent in player.battlefield
            if isinstance(permanent, dict) and is_battlefield_creature(permanent)
        )
    if source.get("mana_produced_from_greatest_power_controlled_creatures"):
        powers = [
            int(float(permanent.get("power") or 0))
            for permanent in player.battlefield
            if isinstance(permanent, dict) and is_battlefield_creature(permanent)
        ]
        return max([0, *powers])
    counter_scaled_mana = source.get("mana_produced_if_plus_one_counter")
    if counter_scaled_mana not in (None, "") and (
        get_named_counter_count(source, "+1/+1") > 0
        or int(source.get("plus_one_counters") or 0) > 0
    ):
        return max(0, int(counter_scaled_mana or 0))
    if source.get("mana_produced_from_colors_among_permanents"):
        return len(_controlled_permanent_mana_colors(player))
    dynamic_produced = _dynamic_mana_source_production_for_state(player, source)
    if dynamic_produced is not None:
        return max(0, int(dynamic_produced or 0))
    conditional_produced = _conditional_mana_source_production_for_state(player, source)
    if conditional_produced is not None:
        return max(0, int(conditional_produced or 0))
    life_payment_divisor = int(source.get("mana_produced_from_life_payment_divisor") or 0)
    if life_payment_divisor > 0:
        return max(0, int(getattr(player, "life", 0) or 0) // life_payment_divisor)
    return int(source.get("mana_produced", 1) or 0)


def add_distributed_controlled_color_mana_to_pool(player, source, produced):
    if not isinstance(source, dict) or not source.get("mana_produced_from_colors_among_permanents"):
        return False
    colors = _controlled_permanent_mana_colors(player)
    if not colors:
        return False
    for color in colors[: max(0, int(produced or 0))]:
        player.mana_pool.add(color, 1)
    return True


def produced_mana_symbols_for_source(source):
    if not isinstance(source, dict):
        return []
    symbols = source.get("produced_mana_symbols")
    if isinstance(symbols, str):
        decoded = read_json_list(symbols)
        if decoded is None:
            try:
                decoded = json.loads(symbols)
            except Exception:
                decoded = None
        symbols = decoded if decoded is not None else re.findall(r"[WUBRGC]", symbols.upper())
    symbols = _as_list(symbols)
    parsed = []
    for symbol in symbols:
        upper = str(symbol or "").strip().upper()
        if upper in MANA_SYMBOL_TO_POOL:
            parsed.append(upper)
    return parsed


def add_fixed_produced_mana_symbols_to_pool(player, source, produced):
    symbols = produced_mana_symbols_for_source(source)
    if not symbols:
        return False
    max_symbols = max(0, int(produced or 0))
    for symbol in symbols[:max_symbols]:
        player.mana_pool.add(MANA_SYMBOL_TO_POOL[symbol], 1)
    return True


def add_player_mana_source_to_pool(player, source, turn=None):
    if not hasattr(player, "conditional_mana_sources"):
        player.conditional_mana_sources = []
    produced = mana_source_production_for_state(player, source)
    if produced <= 0:
        return False
    configured_conditional_source = _configured_conditional_mana_source_for_state(
        player,
        source,
        produced,
    )
    if configured_conditional_source:
        player.conditional_mana_sources.append(configured_conditional_source)
        resolve_mana_source_activation_life_gain(player, source, turn=turn)
        return True
    if add_fixed_produced_mana_symbols_to_pool(player, source, produced):
        resolve_mana_source_activation_life_gain(player, source, turn=turn)
        return True
    if add_distributed_controlled_color_mana_to_pool(player, source, produced):
        resolve_mana_source_activation_life_gain(player, source, turn=turn)
        return True
    conditional_source = conditional_mana_source_for_state(player, source, produced)
    if conditional_source:
        player.conditional_mana_sources.append(conditional_source)
        resolve_mana_source_activation_life_gain(player, source, turn=turn)
        return True
    colors = mana_source_colors_for_state(player, source)
    color = colors[0] if len(colors) == 1 else "generic"
    player.mana_pool.add(color, produced)
    resolve_mana_source_activation_life_gain(player, source, turn=turn)
    return True


def _live_opponent_count(opponents):
    count = 0
    for opponent in opponents or []:
        if hasattr(opponent, "is_alive") and not opponent.is_alive():
            continue
        count += 1
    return count


def _split_card_back_face_name(card):
    if not isinstance(card, dict):
        return None
    name = str(card.get("name") or "")
    if " // " not in name:
        return None
    back_name = name.split(" // ", 1)[1].strip()
    return back_name or None


def mdfc_land_face_for_card(card, effect_data):
    if not isinstance(card, dict) or not isinstance(effect_data, dict):
        return None
    face = effect_data.get("mdfc_land_face") or effect_data.get("back_face_land")
    if isinstance(face, str):
        try:
            face = json.loads(face)
        except Exception:
            face = None
    if not isinstance(face, dict):
        return None
    result = dict(face)
    result.setdefault("name", _split_card_back_face_name(card) or card.get("name", "?"))
    result.setdefault("type_line", "Land")
    result.setdefault("effect", "land")
    result.setdefault("mana_produced", 1)
    result["modal_dfc_parent_name"] = card.get("name")
    result["played_face"] = "back"
    return result


def land_enter_untapped_life_cost(land):
    if not isinstance(land, dict):
        return 0
    raw = (
        land.get("may_pay_life_to_enter_untapped")
        or land.get("enters_tapped_unless_pay_life")
        or land.get("enters_untapped_life_cost")
    )
    if raw in (None, "", False):
        oracle_text = str(land.get("oracle_text") or "").lower()
        match = re.search(r"may pay (\d+) life\. if you don't, it enters tapped", oracle_text)
        raw = match.group(1) if match else 0
    try:
        return max(0, int(raw or 0))
    except (TypeError, ValueError):
        return 0


def maybe_pay_life_for_untapped_land(player, land):
    cost = land_enter_untapped_life_cost(land)
    if cost <= 0:
        return 0
    land["enters_tapped_unless_pay_life"] = cost
    if player is None or getattr(player, "life_cant_change", False) or getattr(player, "life", 0) <= cost:
        land["enters_tapped"] = True
        land["life_paid_to_enter_untapped"] = 0
        return 0
    change_life(player, -cost)
    land["enters_tapped"] = False
    land["life_paid_to_enter_untapped"] = cost
    return cost


def land_enters_tapped_for_state(land, player=None, opponents=None):
    if not isinstance(land, dict):
        return False
    life_cost = land_enter_untapped_life_cost(land)
    if life_cost > 0:
        return int(land.get("life_paid_to_enter_untapped") or 0) <= 0
    if land.get("enters_tapped") or land.get("land_enters_tapped"):
        return True
    conditional = conditional_land_enters_tapped_for_state(land, player=player)
    if conditional is not None:
        return conditional
    opponent_lands_threshold = land.get("enters_tapped_unless_opponents_control_lands_count")
    if opponent_lands_threshold not in (None, "", 0):
        try:
            required_opponent_lands = max(0, int(opponent_lands_threshold))
        except (TypeError, ValueError):
            required_opponent_lands = 0
        opponent_lands = sum(controlled_land_count(opponent) for opponent in opponents or [])
        condition_met = opponent_lands >= required_opponent_lands
        land["conditional_enters_tapped_status"] = (
            land.get("conditional_enters_tapped_status") or "runtime_executor_v1"
        )
        land["conditional_enters_tapped_profile"] = (
            land.get("conditional_enters_tapped_profile") or "opponents_control_lands_count"
        )
        land["conditional_enters_tapped_condition_met"] = condition_met
        land["conditional_enters_tapped_land_count"] = opponent_lands
        land["conditional_enters_tapped_reason"] = (
            "opponents_control_required_land_count"
            if condition_met
            else "opponents_below_required_land_count"
        )
        return not condition_met
    threshold = land.get("enters_tapped_unless_opponent_count")
    oracle_text = str(land.get("oracle_text") or "").lower()
    if threshold in (None, "", 0) and re.search(
        r"enters tapped unless you have (two|2) or more opponents",
        oracle_text,
    ):
        threshold = 2
    if threshold in (None, "", 0):
        return False
    try:
        required_opponents = max(0, int(threshold))
    except (TypeError, ValueError):
        return False
    return _live_opponent_count(opponents) < required_opponents


def conditional_land_enters_tapped_for_state(land, player=None):
    if not isinstance(land, dict):
        return None
    status = str(land.get("conditional_enters_tapped_status") or "").strip().lower()
    if status != "runtime_executor_v1":
        return None
    other_land_count = controlled_land_count(player) if player is not None else 0
    land["conditional_enters_tapped_land_count"] = other_land_count
    required_subtypes = (
        land.get("enters_tapped_unless_control_land_subtypes")
        or land.get("enters_tapped_unless_control_subtypes")
    )
    if required_subtypes:
        condition_met = _player_controls_any_subtype(player, required_subtypes)
        land["conditional_enters_tapped_condition_met"] = condition_met
        land["conditional_enters_tapped_reason"] = (
            "controlled_required_land_subtype" if condition_met else "missing_required_land_subtype"
        )
        return not condition_met
    if land.get("enters_tapped_if_control_lands_min") not in (None, ""):
        try:
            threshold = int(land.get("enters_tapped_if_control_lands_min") or 0)
        except (TypeError, ValueError):
            threshold = 0
        enters_tapped = other_land_count >= threshold
        land["conditional_enters_tapped_condition_met"] = not enters_tapped
        land["conditional_enters_tapped_reason"] = (
            "land_count_below_tapped_threshold" if not enters_tapped else "land_count_at_or_above_tapped_threshold"
        )
        return enters_tapped
    if land.get("enters_tapped_unless_control_lands_min") not in (None, ""):
        try:
            threshold = int(land.get("enters_tapped_unless_control_lands_min") or 0)
        except (TypeError, ValueError):
            threshold = 0
        condition_met = other_land_count >= threshold
        land["conditional_enters_tapped_condition_met"] = condition_met
        land["conditional_enters_tapped_reason"] = (
            "land_count_met_untapped_threshold" if condition_met else "land_count_below_untapped_threshold"
        )
        return not condition_met
    land["conditional_enters_tapped_condition_met"] = True
    land["conditional_enters_tapped_reason"] = "no_runtime_condition"
    return False


def pay_mana_source_activation_costs(player, source, turn=None):
    if not isinstance(source, dict):
        return True
    discard_count = max(0, int(source.get("activation_discard_count") or 0))
    discard_target = source.get("activation_discard_target") or "any_card"
    discard_cards = []
    if discard_count > 0:
        discard_cards = _choose_activation_discard_cost_cards(
            player,
            discard_count,
            discard_target,
            random_discard=bool(source.get("activation_discard_random")),
        )
        if len(discard_cards) != discard_count:
            emit_replay_event(
                "mana_source_activation_skipped",
                player=getattr(player, "name", "?"),
                card=source.get("name", "?"),
                reason="insufficient_hand_for_discard_cost",
                activation_discard_count=discard_count,
                activation_discard_target=discard_target,
                hand_count=len(getattr(player, "hand", []) or []),
                turn=turn,
                **replay_rule_fields(source),
            )
            return False
    support_to_tap, support_type_or_error = _required_mana_support_tap_cost(player, source)
    if support_type_or_error == "unsupported_tap_support_count":
        emit_replay_event(
            "mana_source_activation_skipped",
            player=getattr(player, "name", "?"),
            card=source.get("name", "?"),
            reason="unsupported_tap_support_count",
            mana_activation_tap_support_count=source.get("mana_activation_tap_support_count"),
            turn=turn,
            **replay_rule_fields(source),
        )
        return False
    if support_type_or_error and support_to_tap is None:
        emit_replay_event(
            "mana_source_activation_skipped",
            player=getattr(player, "name", "?"),
            card=source.get("name", "?"),
            reason="missing_untapped_support_permanent",
            mana_activation_tap_support_type=support_type_or_error,
            turn=turn,
            **replay_rule_fields(source),
        )
        return False
    activation_mana_cost = source.get("activation_mana_cost")
    if activation_mana_cost:
        if not player.can_pay(activation_mana_cost):
            emit_replay_event(
                "mana_source_activation_skipped",
                player=getattr(player, "name", "?"),
                card=source.get("name", "?"),
                reason="insufficient_mana_for_activation_cost",
                activation_mana_cost=activation_mana_cost,
                available_mana=player.available_mana(),
                turn=turn,
                **replay_rule_fields(source),
            )
            return False
        if not player.spend_mana(activation_mana_cost):
            emit_replay_event(
                "mana_source_activation_skipped",
                player=getattr(player, "name", "?"),
                card=source.get("name", "?"),
                reason="failed_to_pay_activation_mana_cost",
                activation_mana_cost=activation_mana_cost,
                available_mana=player.available_mana(),
                turn=turn,
                **replay_rule_fields(source),
            )
            return False
        emit_replay_event(
            "mana_source_activation_cost_paid",
            player=getattr(player, "name", "?"),
            card=source.get("name", "?"),
            activation_mana_cost=activation_mana_cost,
            available_mana_after=player.available_mana(),
            turn=turn,
            **replay_rule_fields(source),
        )
    mill_count = int(source.get("mana_activation_mill_count") or 0)
    if mill_count > 0:
        library = getattr(player, "library", []) or []
        if len(library) < mill_count:
            emit_replay_event(
                "mana_source_activation_skipped",
                player=getattr(player, "name", "?"),
                card=source.get("name", "?"),
                reason="insufficient_library_for_mill_cost",
                required_mill_count=mill_count,
                library_count=len(library),
                turn=turn,
                **replay_rule_fields(source),
            )
            return False
        milled = []
        for _ in range(mill_count):
            milled_card = player.library.pop(0)
            player.graveyard.append(milled_card)
            milled.append(milled_card)
        resolve_land_cards_enter_graveyard_triggers(
            player,
            milled,
            turn=turn,
            source_event="mana_source_mill_cost",
        )
        refresh_graveyard_count_creature_statics_for_player(
            player,
            turn=turn,
            phase="mana_source_activation",
            emit_events=True,
        )
        emit_replay_event(
            "mana_source_mill_cost_paid",
            player=getattr(player, "name", "?"),
            card=source.get("name", "?"),
            milled=[card.get("name", "?") for card in milled if isinstance(card, dict)],
            mill_count=len(milled),
            graveyard_count=len(getattr(player, "graveyard", []) or []),
            turn=turn,
            **replay_rule_fields(source),
        )
    life_cost = max(
        0,
        int(source.get("activation_life_cost") or source.get("mana_activation_life_cost") or 0),
    )
    if life_cost > 0:
        if getattr(player, "life_cant_change", False):
            emit_replay_event(
                "mana_source_activation_skipped",
                player=getattr(player, "name", "?"),
                card=source.get("name", "?"),
                reason="life_payment_forbidden",
                activation_life_cost=life_cost,
                life=getattr(player, "life", None),
                turn=turn,
                **replay_rule_fields(source),
            )
            return False
        if getattr(player, "life", 0) <= life_cost + 1:
            emit_replay_event(
                "mana_source_activation_skipped",
                player=getattr(player, "name", "?"),
                card=source.get("name", "?"),
                reason="insufficient_life_for_activation_cost",
                activation_life_cost=life_cost,
                life=getattr(player, "life", None),
                turn=turn,
                **replay_rule_fields(source),
            )
            return False
        life_before = player.life
        change_life(player, -life_cost)
        emit_replay_event(
            "mana_source_activation_life_cost_paid",
            player=getattr(player, "name", "?"),
            card=source.get("name", "?"),
            activation_life_cost=life_cost,
            life_paid=life_cost,
            life_before=life_before,
            life_after=player.life,
            turn=turn,
            **replay_rule_fields(source),
        )
    discarded = []
    if discard_cards:
        removed_cards = _remove_exact_cards_from_hand(player, discard_cards)
        if len(removed_cards) != len(discard_cards):
            emit_replay_event(
                "mana_source_activation_skipped",
                player=getattr(player, "name", "?"),
                card=source.get("name", "?"),
                reason="failed_to_remove_discard_cost_from_hand",
                activation_discard_count=discard_count,
                activation_discard_target=discard_target,
                turn=turn,
                **replay_rule_fields(source),
            )
            return False
        discard_resolution = resolve_effect_discard_cards(
            player,
            removed_cards,
            top_limit=0,
            opponents=[],
            turn=turn,
            phase="mana_source_activation",
            rng=random,
        )
        discarded = [
            card.get("name", "?")
            for card in discard_resolution.get("to_graveyard", removed_cards)
            if isinstance(card, dict)
        ]
        emit_replay_event(
            "mana_source_activation_discard_cost_paid",
            player=getattr(player, "name", "?"),
            card=source.get("name", "?"),
            activation_discard_count=len(discarded),
            activation_discard_target=discard_target,
            discarded=discarded,
            discard_to_graveyard=[
                card.get("name", "?")
                for card in discard_resolution.get("to_graveyard") or []
                if isinstance(card, dict)
            ],
            discard_to_library_top=[
                card.get("name", "?")
                for card in discard_resolution.get("to_top") or []
                if isinstance(card, dict)
            ],
            discard_replacement_used=bool(discard_resolution.get("used_replacement")),
            turn=turn,
            **replay_rule_fields(source),
        )
    if support_to_tap is not None:
        support_to_tap["tapped"] = True
        emit_replay_event(
            "mana_source_support_tapped",
            player=getattr(player, "name", "?"),
            card=source.get("name", "?"),
            support=support_to_tap.get("name", "?"),
            support_type=support_type_or_error,
            turn=turn,
            **replay_rule_fields(source),
        )
    if source.get("mana_activation_requires_tap"):
        source["tapped"] = True
    return True


def resolve_mana_source_activation_life_gain(player, source, turn=None):
    if not isinstance(source, dict):
        return 0
    amount = max(
        0,
        int(
            source.get("mana_activation_life_gain")
            or source.get("mana_source_activation_life_gain")
            or 0
        ),
    )
    if amount <= 0:
        return 0
    life_before = int(getattr(player, "life", 0))
    gain_life(player, amount, cap=999)
    life_after = int(getattr(player, "life", life_before))
    life_gained = max(0, life_after - life_before)
    emit_replay_event(
        "mana_source_activation_life_gain_resolved",
        player=getattr(player, "name", "?"),
        card=source.get("name", "?"),
        life_gain_requested=amount,
        life_gained=life_gained,
        life_before=life_before,
        life_after=life_after,
        turn=turn,
        **replay_rule_fields(source),
    )
    return life_gained


def numeric_stat(value):
    if value is None or value == "":
        return None
    try:
        return int(value)
    except (TypeError, ValueError):
        return None


def load_card_oracle_cache(conn, names):
    """Load production card metadata previously synced into local SQLite."""
    normalized_names = sorted({normalize_card_name(name) for name in names if name})
    if not normalized_names:
        return {}
    table = conn.execute(
        "SELECT 1 FROM sqlite_master WHERE type='table' AND name='card_oracle_cache'"
    ).fetchone()
    if not table:
        return {}

    cache = {}
    for index in range(0, len(normalized_names), 500):
        chunk = normalized_names[index:index + 500]
        placeholders = ",".join("?" for _ in chunk)
        rows = conn.execute(f"""
            SELECT normalized_name, name, mana_cost, colors_json,
                   color_identity_json, type_line, oracle_text, cmc, power,
                   toughness, keywords_json, scryfall_id
            FROM card_oracle_cache
            WHERE normalized_name IN ({placeholders})
        """, chunk).fetchall()
        for row in rows:
            cache[row["normalized_name"]] = {
                "oracle_name": row["name"],
                "mana_cost": row["mana_cost"],
                "colors": read_json_list(row["colors_json"]),
                "color_identity": read_json_list(row["color_identity_json"]),
                "type_line": row["type_line"],
                "oracle_text": row["oracle_text"],
                "cmc": row["cmc"],
                "power": numeric_stat(row["power"]),
                "toughness": numeric_stat(row["toughness"]),
                "keywords": read_json_list(row["keywords_json"]),
                "scryfall_id": row["scryfall_id"],
            }
    return cache


def merge_oracle_metadata(card, oracle_cache):
    metadata = oracle_cache.get(normalize_card_name(card.get("name")))
    if not metadata:
        return card
    enriched = dict(card)
    for key in (
        "mana_cost",
        "type_line",
        "oracle_text",
        "cmc",
        "power",
        "toughness",
        "scryfall_id",
        "oracle_name",
    ):
        value = metadata.get(key)
        if value is not None and value != "":
            enriched[key] = value
    for key in ("colors", "color_identity", "keywords"):
        value = metadata.get(key)
        if value:
            enriched[key] = value
    return enriched


