def manual_runtime_waiver_inventory():
    inventory = []
    for card_name in sorted(MANUAL_RULE_RUNTIME_WAIVERS):
        rule = HANDCRAFTED_KNOWN_CARD_RULES[card_name]
        metadata = MANUAL_RULE_RUNTIME_WAIVER_METADATA[card_name]
        inventory.append(
            {
                "card": card_name,
                "effect": rule.get("effect"),
                "rule_logical_key": rule.get("_rule_logical_key"),
                **metadata,
            }
        )
    return inventory


TAG_EFFECTS = {
    "ramp": {"effect": "ramp_permanent", "mana_produced": 1},
    "ritual": {"effect": "ramp_ritual", "mana_produced": 3},
    "draw": {"effect": "draw_cards", "count": 2},
    "removal": {"effect": "remove_creature"},
    "board_wipe": {"effect": "board_wipe"},
    "protection": {"effect": "indestructible", "duration": 1},
    "token_maker": {"effect": "token_maker", "token_count": 5, "token_power": 2},
    "wincon": {"effect": "finisher"},
    "tutor": {"effect": "tutor", "target": "any"},
    "recursion": {"effect": "recursion", "count": 2},
    "pump": {"effect": "pump_one", "power_boost": 3},
    "loot": {"effect": "loot", "count": 1},
}


def replay_card_identity_fields(card):
    """Return stable card identity fields already present on the card object."""
    fields = {}
    card_id = card.get("card_id") or card.get("card_uuid")
    semantic_hash = card.get("semantic_hash") or card.get("semantics_hash")
    if card_id:
        fields["card_id"] = card_id
    if semantic_hash:
        fields["semantic_hash"] = semantic_hash
    return fields


def annotate_effect_identity(card, effect_data):
    annotated = dict(effect_data)
    for key, value in replay_card_identity_fields(card).items():
        annotated.setdefault(key, value)
    return annotated


def apply_oracle_effect_normalization(effect_data, effect, *, target=None):
    previous_effect = effect_data.get("effect")
    previous_target = effect_data.get("target")
    if previous_effect and previous_effect != effect:
        effect_data["_rule_oracle_normalized_effect_from"] = previous_effect
        effect_data["_rule_oracle_normalized_effect_to"] = effect
    effect_data["effect"] = effect
    if target is not None:
        if previous_target and previous_target != target:
            effect_data["_rule_oracle_normalized_target_from"] = previous_target
            effect_data["_rule_oracle_normalized_target_to"] = target
        effect_data["target"] = target
    runtime_selection = effect_data.get("_rule_runtime_selection")
    if isinstance(runtime_selection, dict):
        selection = dict(runtime_selection)
        selection["selected_effect"] = effect_data.get("effect")
        if effect_data.get("target") is not None:
            selection["selected_target"] = effect_data.get("target")
        effect_data["_rule_runtime_selection"] = selection
    return effect_data


def normalize_effect_by_oracle(card, effect_data):
    """Correct broad generated/tag mistakes using imported oracle metadata."""
    normalized = annotate_effect_identity(card, effect_data)
    effect = normalized.get("effect", "unknown")
    normalized_name = normalize_card_name(card.get("name", ""))
    type_line = str(card.get("type_line") or "")
    oracle_text = str(card.get("oracle_text") or "")
    text = f"{type_line}\n{oracle_text}".lower()

    if effect == "worldfire_reset":
        return normalized

    if effect == "counter_spell":
        normalized = apply_oracle_effect_normalization(normalized, "counter")
        normalized["instant"] = True
        return normalized

    if (
        "exile all permanents" in text
        and "exile all cards from all hands and graveyards" in text
        and "life total becomes 1" in text
    ):
        normalized["effect"] = "worldfire_reset"
        return normalized

    type_line_lower = type_line.lower()
    is_split_spell_land = "//" in type_line and any(
        spell_kind in type_line_lower
        for spell_kind in ("instant", "sorcery", "creature", "artifact", "enchantment")
    )
    if "land" in type_line_lower and not is_split_spell_land:
        normalized["effect"] = "land"
        normalized.pop("instant", None)
        normalized.pop("miracle", None)
        if normalized_name == "ancient tomb":
            # Under the current pooled-mana abstraction, Ancient Tomb cannot
            # expose {C}{C} passively or it becomes free fast mana. Model it as
            # one baseline colorless source plus one contextual bonus mana that
            # costs life only when the simulator chooses to use it.
            normalized["produces"] = "C"
            normalized["mana_produced"] = 1
            normalized["ancient_tomb_bonus_mana"] = 1
            normalized["ancient_tomb_bonus_life_cost"] = 2
            normalized["utility_land_profile"] = "ancient_tomb_contextual_fast_mana_v1"
        return normalized

    if (
        normalized_name == "rise of the eldrazi"
        and "destroy target permanent" in text
        and "draws four cards" in text
        and "extra turn" in text
        and "exile rise of the eldrazi" in text
    ):
        metadata = {
            key: value
            for key, value in normalized.items()
            if key.startswith("_rule_")
            or key in {"card_id", "semantic_hash", "semantics_hash"}
        }
        components = []
        for component in (
            {
                "effect": "remove_permanent",
                "target": "permanent",
                "compose_on_resolution": True,
            },
            {
                "effect": "draw_cards",
                "count": 4,
                "target_player_draw": True,
                "compose_on_resolution": True,
            },
            {
                "effect": "extra_turn",
                "turns": 1,
                "compose_on_resolution": True,
            },
        ):
            component_with_metadata = dict(metadata)
            component_with_metadata.update(component)
            components.append(component_with_metadata)
        normalized["effect"] = "composite_resolution"
        normalized["uncounterable"] = True
        normalized["exiles_self"] = True
        normalized["_composite_rule_components"] = components
        return normalized

    if (
        re.search(r"\bdeals?\s+\d+\s+damage\s+to\s+target\s+player\s+or\s+planeswalker\b", text)
        and "each creature that player" in text
        and "controller controls" in text
        and normalized.get("battle_model_scope") != "canonical_snapshot_rule_not_runtime_safe"
    ):
        amount_match = re.search(r"\bdeals?\s+(\d+)\s+damage\b", text)
        amount = int(amount_match.group(1)) if amount_match else int(normalized.get("amount") or 4)
        normalized["effect"] = "damage_player_and_creatures"
        normalized["amount"] = amount
        normalized["target"] = "player_or_planeswalker_controller"
        normalized["battle_model_scope"] = "target_player_and_controller_creatures"
        normalized.pop("instant", None)
        return normalized

    if (
        re.search(r"\bdeals?\s+\d+\s+damage\s+to\s+each\s+creature\b", text)
        and normalized.get("battle_model_scope") != "canonical_snapshot_rule_not_runtime_safe"
    ):
        amount_match = re.search(r"\bdeals?\s+(\d+)\s+damage\b", text)
        amount = int(amount_match.group(1)) if amount_match else int(normalized.get("damage") or 0)
        normalized["effect"] = "damage_wipe"
        normalized["damage"] = amount
        normalized["damage_scope"] = "each_creature"
        normalized["battle_model_scope"] = (
            normalized.get("battle_model_scope")
            or "oracle_damage_each_creature_wipe_v1"
        )
        normalized.pop("instant", None)
        return normalized

    if "counter target" in text:
        normalized["effect"] = "counter"
        normalized["instant"] = True
        return normalized

    if "return target spell" in text:
        normalized["effect"] = "counter"
        normalized["instant"] = True
        return normalized

    if (
        "reveal cards from the top of it until you reveal a nonland card" in text
        and "may cast the exiled card without paying its mana cost" in text
        and normalized.get("battle_model_scope") != "canonical_snapshot_rule_not_runtime_safe"
    ):
        normalized["effect"] = "exile_top_nonland_free_cast"
        normalized["shuffle_before_reveal"] = True
        normalized["revealed_card_cast_without_paying_mana"] = True
        normalized["demonstrate"] = "demonstrate" in text
        normalized["battle_model_scope"] = (
            normalized.get("battle_model_scope")
            or "shuffle_reveal_top_nonland_exile_free_cast_with_demonstrate_v1"
        )
        normalized.pop("instant", None)
        return normalized

    if (
        "gift a card" in text
        and "you and permanents you control gain hexproof until end of turn" in text
        and "permanents you control also gain indestructible until end of turn" in text
        and normalized.get("battle_model_scope") != "canonical_snapshot_rule_not_runtime_safe"
    ):
        normalized["effect"] = "gift_hexproof_indestructible"
        normalized["instant"] = True
        normalized["gift"] = "card"
        normalized["gift_default_promised"] = True
        normalized["gift_card_draw"] = True
        normalized["gift_choice_model"] = "lowest_visible_threat_opponent"
        normalized["grants_player_hexproof"] = True
        normalized["grants_permanents_hexproof"] = True
        normalized["gift_grants_permanents_indestructible"] = True
        normalized["target_scope"] = "you_and_permanents_you_control"
        normalized["battle_model_scope"] = (
            normalized.get("battle_model_scope")
            or "gift_card_you_and_permanents_hexproof_gifted_indestructible_v1"
        )
        return normalized

    if (
        "vow counter" in text
        and "sacrifices the rest" in text
        and "can't attack you or planeswalkers you control" in text
        and normalized.get("battle_model_scope") != "canonical_snapshot_rule_not_runtime_safe"
    ):
        normalized["effect"] = "vow_counter_each_player_sacrifice_rest"
        normalized["sorcery"] = True
        normalized["counter_type"] = "vow"
        normalized["choice_scope"] = "each_player_one_creature_they_control"
        normalized["sacrifice_scope"] = "other_creatures"
        normalized["attack_restriction"] = (
            "cant_attack_source_controller_or_planeswalkers_while_vow_counter"
        )
        normalized["battle_model_scope"] = (
            normalized.get("battle_model_scope")
            or "each_player_choose_creature_vow_counter_sacrifice_other_creatures_attack_restriction_v1"
        )
        normalized.pop("instant", None)
        return normalized

    if (
        "gift a card" in text
        and "destroy all creatures" in text
        and "return a creature card put into your graveyard this way to the battlefield under your control" in text
        and normalized.get("battle_model_scope") != "canonical_snapshot_rule_not_runtime_safe"
    ):
        normalized["effect"] = "gift_destroy_all_creatures_return_own_destroyed_creature"
        normalized["sorcery"] = True
        normalized["gift"] = "card"
        normalized["gift_default_promised"] = True
        normalized["gift_card_draw"] = True
        normalized["gift_choice_model"] = "lowest_visible_threat_opponent"
        normalized["destroy_scope"] = "all_creatures"
        normalized["return_scope"] = "own_creature_destroyed_this_way"
        normalized["return_destination"] = "battlefield_under_your_control"
        normalized["battle_model_scope"] = (
            normalized.get("battle_model_scope")
            or "gift_card_destroy_all_creatures_return_one_own_creature_destroyed_this_way_v1"
        )
        normalized.pop("instant", None)
        return normalized

    if (
        "whenever you discard a card" in text
        and "choose one that hasn't been chosen this turn" in text
        and "draw a card" in text
        and "create a treasure token" in text
        and "each opponent loses 3 life" in text
        and normalized.get("battle_model_scope") != "canonical_snapshot_rule_not_runtime_safe"
    ):
        normalized["effect"] = "discard_trigger_modal_draw_treasure_opponent_life_loss"
        normalized["trigger_event"] = "discard"
        normalized["turn_limited_unique_modes"] = True
        normalized["discard_trigger_modes"] = list(DISCARD_MODAL_MONUMENT_MODES)
        normalized["battle_model_scope"] = (
            normalized.get("battle_model_scope")
            or DISCARD_MODAL_MONUMENT_SCOPE
        )
        return normalized

    if (
        "indestructible" in text
        and "{t}: add {w}" in text
        and "harness the mind stone" in text
        and "at the beginning of your end step" in text
        and "exile up to one other target nonland permanent you control" in text
        and "return that card to the battlefield under its owner's control" in text
        and normalized.get("battle_model_scope") != "canonical_snapshot_rule_not_runtime_safe"
    ):
        normalized["effect"] = "ramp_permanent"
        normalized["indestructible"] = True
        normalized["mana_produced"] = 1
        normalized["produces"] = "W"
        normalized["harness_activation_cost"] = "{5}{W}"
        normalized["harness_activation_requires_tap"] = True
        normalized["harnessed_end_step_blink"] = True
        normalized["harnessed_blink_target_scope"] = "other_nonland_permanent_you_control"
        normalized["battle_model_scope"] = (
            normalized.get("battle_model_scope")
            or THE_MIND_STONE_SCOPE
        )
        return normalized

    if (
        "target creature you control and target creature an opponent controls each gain indestructible until end of turn" in text
        and "then destroy all creatures" in text
        and normalized.get("battle_model_scope") != "canonical_snapshot_rule_not_runtime_safe"
    ):
        normalized["effect"] = "fated_clash_protect_then_destroy"
        normalized["sorcery"] = True
        normalized["conditional_flash_if_attacking_and_blocking"] = (
            "as though it had flash" in text
            and "a creature is attacking and a creature is blocking" in text
        )
        normalized["target_scope"] = "own_creature_and_opponent_creature"
        normalized["grants_targets_indestructible_until_eot"] = True
        normalized["then_destroy_all_creatures"] = True
        normalized["battle_model_scope"] = (
            normalized.get("battle_model_scope")
            or "own_and_opponent_creature_indestructible_then_destroy_all_creatures_v1"
        )
        normalized.pop("instant", None)
        return normalized

    if (
        "for each player, you choose from among the permanents that player controls an artifact, a creature, an enchantment, and a planeswalker" in text
        and "each player sacrifices all other nonland permanents they control" in text
        and normalized.get("battle_model_scope") != "canonical_snapshot_rule_not_runtime_safe"
    ):
        normalized["effect"] = "selective_nonland_sacrifice"
        normalized["sorcery"] = True
        normalized["controller_chooses_for_each_player"] = True
        normalized["choice_types"] = ["artifact", "creature", "enchantment", "planeswalker"]
        normalized["sacrifice_scope"] = "other_nonland_permanents"
        normalized["battle_model_scope"] = (
            normalized.get("battle_model_scope")
            or "controller_chooses_artifact_creature_enchantment_planeswalker_per_player_sacrifice_other_nonlands_v1"
        )
        normalized.pop("instant", None)
        return normalized

    if (
        normalized_name == "ephemerate"
        and "exile target creature you control" in text
        and "return it to the battlefield" in text
    ):
        normalized["effect"] = "blink"
        normalized["target"] = "creature_you_control"
        normalized["blink_target_scope"] = "creature_you_control"
        normalized["zone_transition"] = "exile_then_return"
        normalized["destination"] = "battlefield"
        normalized["return_timing"] = "immediate_or_same_resolution"
        normalized["instant"] = True
        normalized["rebound"] = "rebound" in text
        return normalized

    if (
        normalized_name == "spelltwine"
        and "copy those cards" in text
        and "cast the copies" in text
    ):
        normalized["effect"] = "copy_spell"
        normalized["target"] = "instant_or_sorcery_graveyards"
        normalized["copy_own_and_opponent_graveyard_spell"] = True
        normalized["casts_copies_without_paying_mana"] = True
        normalized["exiles_target_cards"] = True
        normalized["exiles_self"] = True
        return normalized

    if (
        normalized_name == "surge to victory"
        and "exile target instant or sorcery card from your graveyard" in text
        and "creatures you control get +x/+0 until end of turn" in text
        and "whenever a creature you control deals combat damage to a player this turn" in text
        and "copy the exiled card" in text
        and "cast the copy without paying its mana cost" in text
        and normalized.get("battle_model_scope") != "canonical_snapshot_rule_not_runtime_safe"
    ):
        normalized["effect"] = "pump_all"
        normalized["sorcery"] = True
        normalized["target"] = "instant_or_sorcery_graveyard"
        normalized["exiles_target_from_graveyard"] = True
        normalized["pump_power_from_exiled_card_mana_value"] = True
        normalized["combat_damage_player_copies_exiled_card"] = True
        normalized["casts_copies_without_paying_mana"] = True
        normalized["battle_model_scope"] = (
            normalized.get("battle_model_scope")
            or SURGE_TO_VICTORY_SCOPE
        )
        normalized.pop("instant", None)
        return normalized

    if re.search(r"\b(destroy|exile)\s+target\b", text):
        is_immediate_spell = "instant" in type_line.lower() or "sorcery" in type_line.lower()
        if (
            not is_immediate_spell
            and effect not in ("remove_creature", "remove_permanent", "remove_artifact_or_3dmg")
        ):
            return normalized
        if (
            normalized.get("effect") == "overload_recursion"
            and "graveyard" in text
            and ("instant" in text or "sorcery" in text)
        ):
            return normalized
        if normalized.get("effect") == "remove_artifact_or_3dmg":
            return normalized
        if re.search(r"\b(destroy|exile)\s+target\s+artifact\s+or\s+enchantment\b", text):
            normalized["effect"] = "remove_permanent"
            normalized["target"] = "artifact_or_enchantment"
            return normalized
        if re.search(r"\b(destroy|exile)\s+target\s+artifact(?:[.;\n]|$)", text):
            normalized["effect"] = "remove_permanent"
            normalized["target"] = "artifact"
            return normalized
        if re.search(r"\b(destroy|exile)\s+target\s+enchantment(?:[.;\n]|$)", text):
            normalized["effect"] = "remove_permanent"
            normalized["target"] = "enchantment"
            return normalized
        if "target nonland permanent" in text:
            normalized["effect"] = "remove_permanent"
            normalized["target"] = "nonland_permanent"
            return normalized
        if re.search(
            r"\b(destroy|exile)\s+target\s+creature,\s+enchantment,\s+or\s+planeswalker\b",
            text,
        ):
            normalized["effect"] = "remove_permanent"
            normalized["target"] = "creature_enchantment_or_planeswalker"
            return normalized
        if "target creature" in text:
            normalized["effect"] = "remove_creature"
            normalized["target"] = "creature"
        else:
            normalized["effect"] = "remove_permanent"
        return normalized

    if "graveyard" in text and re.search(r"\breturn target\b", text):
        is_immediate_spell = "instant" in type_line.lower() or "sorcery" in type_line.lower()
        if not is_immediate_spell and effect not in ("recursion", "overload_recursion"):
            return normalized
        return apply_oracle_effect_normalization(normalized, "recursion")

    if re.search(r"\breturn target\s+creature\b", text):
        return apply_oracle_effect_normalization(
            normalized,
            "remove_creature",
            target="creature",
        )

    if re.search(r"\breturn target\b", text):
        normalized["effect"] = "remove_permanent"
        return normalized

    if (
        ("return each" in text or "return all" in text)
        and "nonland permanent" in text
    ):
        normalized["effect"] = "board_wipe"
        return normalized

    if (
        "exile all creatures except those that share a creature type with a creature that convoked this spell" in text
        and "all artifacts" in text
        and "all enchantments" in text
    ):
        normalized["effect"] = "exile_artifact_enchantment_creature_convoke_wipe"
        normalized["destination"] = "exile"
        normalized["exile_creatures_except_convoked_types"] = True
        normalized["exile_artifacts"] = True
        normalized["exile_enchantments"] = True
        normalized["convoke_exception"] = "share_creature_type_with_convoked_creature"
        normalized["convoke_creature_type_source"] = normalized.get(
            "convoke_creature_type_source",
            "explicit_or_controller_creature_inference",
        )
        normalized["battle_model_scope"] = (
            normalized.get("battle_model_scope")
            or "exile_creatures_except_convoked_types_artifacts_enchantments_v1"
        )
        return normalized

    if (
        "airbend all other creatures" in text
        and str(normalized.get("_rule_execution_status") or "auto").lower()
        not in {"review_only", "disabled"}
        and str(normalized.get("_rule_review_status") or "verified").lower()
        in {"verified", "active", "heuristic", "fact"}
        and normalized.get("battle_model_scope") != "canonical_snapshot_rule_not_runtime_safe"
    ):
        normalized["effect"] = "airbend_other_creatures"
        normalized["target"] = "creature"
        normalized["target_choice"] = "up_to_one_creature_to_spare"
        normalized["target_scope"] = "any_creature"
        normalized["airbend_scope"] = "all_other_creatures"
        normalized["destination"] = "exile"
        normalized["exile_creatures"] = True
        normalized["airbend_recast_cost"] = normalized.get("airbend_recast_cost") or "{2}"
        normalized["airbend_recast_permission"] = (
            normalized.get("airbend_recast_permission")
            or "owner_may_cast_from_exile"
        )
        normalized["airbend_recast_permission_status"] = (
            normalized.get("airbend_recast_permission_status")
            or "tracked_for_cast_from_exile"
        )
        normalized["opponents_non_hand_cast_lock"] = True
        normalized["opponents_non_hand_cast_lock_duration"] = "until_your_next_turn"
        normalized["exiles_self"] = True
        normalized["sorcery"] = True
        normalized["battle_model_scope"] = (
            normalized.get("battle_model_scope")
            or "avatars_wrath_airbend_all_other_creatures_nonhand_lock_self_exile_v1"
        )
        return normalized

    if (
        effect == "silence_opponents"
        and "can't be countered" in text
        and not re.search(r"opponents? can't cast", text)
        and "can't cast spells" not in text
    ):
        if "creature" in type_line.lower():
            normalized["effect"] = "creature"
        else:
            normalized["effect"] = "unknown"

    ritual_scope = str(normalized.get("battle_model_scope") or "")
    if normalized.get("effect") == "ramp_ritual" and ritual_scope in {
        "single_shot_red_ritual_v1",
        "rite_of_flame_singleton_baseline_red_ritual_v1",
    }:
        normalized.setdefault("produces", "R")
        normalized["mana_color_status"] = "abstracted_to_generic_pool_runtime"
        normalized["pg058_l3b_simple_red_ritual_family"] = "deck6_simple_red_rituals"
        if ritual_scope == "rite_of_flame_singleton_baseline_red_ritual_v1":
            normalized["singleton_commander_baseline"] = True
            normalized["graveyard_named_copy_scaling_status"] = "annotation_only"
            normalized["oracle_runtime_scope"] = (
                "single_shot_red_ritual_runtime_graveyard_copy_scaling_annotation_only"
            )

    if normalized_name == "angel's grace" and normalized.get("effect") == "cannot_lose_turn":
        normalized["battle_model_scope"] = (
            "split_second_cannot_lose_opponents_cannot_win_damage_life_floor_v1"
        )
        normalized["oracle_runtime_scope"] = (
            "cannot_lose_opponents_cannot_win_damage_life_floor_split_second_annotation"
        )
        normalized["opponents_cant_win_this_turn"] = True
        normalized["split_second"] = True
        normalized["life_floor_on_damage"] = int(normalized.get("life_floor_on_damage") or 1)

    runtime_selection = normalized.get("_rule_runtime_selection")
    if isinstance(runtime_selection, dict):
        selection = dict(runtime_selection)
        selection["selected_effect"] = normalized.get("effect")
        if normalized.get("target") is not None:
            selection["selected_target"] = normalized.get("target")
        normalized["_rule_runtime_selection"] = selection
    return normalized


def with_rule_metadata(
    effect_data,
    *,
    source,
    review_status="heuristic",
    execution_status="auto",
    confidence=0.0,
    rule_version=None,
    logical_rule_key=None,
    oracle_hash=None,
):
    annotated = dict(effect_data)
    annotated.setdefault("_rule_source", source)
    annotated.setdefault("_rule_review_status", review_status)
    annotated.setdefault("_rule_execution_status", execution_status)
    annotated.setdefault("_rule_confidence", confidence)
    if rule_version is not None:
        annotated.setdefault("_rule_version", rule_version)
    if logical_rule_key:
        annotated.setdefault("_rule_logical_key", logical_rule_key)
    if oracle_hash:
        annotated.setdefault("_rule_oracle_hash", oracle_hash)
    return annotated


def replay_rule_fields(effect_data):
    """Expose rule provenance in structured replay events."""
    fields = {
        "rule_source": effect_data.get("_rule_source", "unknown"),
        "rule_review_status": effect_data.get("_rule_review_status", "unknown"),
        "rule_execution_status": effect_data.get("_rule_execution_status", "auto"),
        "rule_confidence": effect_data.get("_rule_confidence", 0.0),
        "rule_version": effect_data.get("_rule_version"),
    }
    optional_fields = {
        "card_id": effect_data.get("card_id"),
        "semantic_hash": effect_data.get("semantic_hash")
        or effect_data.get("semantics_hash"),
        "rule_logical_key": effect_data.get("_rule_logical_key"),
        "rule_oracle_hash": effect_data.get("_rule_oracle_hash"),
        "rule_oracle_normalized_effect_from": effect_data.get(
            "_rule_oracle_normalized_effect_from"
        ),
        "rule_oracle_normalized_effect_to": effect_data.get(
            "_rule_oracle_normalized_effect_to"
        ),
        "rule_oracle_normalized_target_from": effect_data.get(
            "_rule_oracle_normalized_target_from"
        ),
        "rule_oracle_normalized_target_to": effect_data.get(
            "_rule_oracle_normalized_target_to"
        ),
        "variant_kind": effect_data.get("variant_kind"),
        "alternative_cost_kind": effect_data.get("alternative_cost_kind")
        or effect_data.get("alternate_cost_kind"),
    }
    for key, value in optional_fields.items():
        if value not in (None, "", [], {}):
            fields[key] = value
    rule_alternative_count = len(effect_data.get("_rule_alternatives") or [])
    if rule_alternative_count:
        fields["rule_alternative_count"] = rule_alternative_count
    blocked_alternative_count = len(effect_data.get("_rule_blocked_alternatives") or [])
    if blocked_alternative_count:
        fields["rule_blocked_alternative_count"] = blocked_alternative_count
    runtime_selection = effect_data.get("_rule_runtime_selection") or {}
    selection_mode = runtime_selection.get("selection_mode")
    if selection_mode:
        fields["rule_runtime_selection_mode"] = selection_mode
    merged_annotation_count = runtime_selection.get("merged_annotation_count")
    if merged_annotation_count:
        fields["rule_merged_annotation_count"] = merged_annotation_count
    composite_component_count = len(effect_data.get("_composite_rule_components") or [])
    if composite_component_count:
        fields["composite_rule_component_count"] = composite_component_count
    return fields


