def _normalize_color_symbol(color):
    text = str(color or "").strip().lower()
    aliases = {
        "w": "white",
        "u": "blue",
        "b": "black",
        "r": "red",
        "g": "green",
    }
    return aliases.get(text, text)


def target_matches_type(target, target_type):
    """Minimal target selector matcher used before spell resolution."""
    target_type = str(target_type or "").lower()
    if not target_type:
        return True
    if target_type in ("player", "opponent"):
        return False
    if target_type in ("player_or_planeswalker", "opponent_or_planeswalker"):
        return is_planeswalker_permanent(target)
    if target_type == "any_target":
        return (
            is_battlefield_creature(target)
            or is_planeswalker_permanent(target)
            or is_battle_permanent(target)
        )
    if target_type in ("creature", "target_creature"):
        return is_battlefield_creature(target)
    if target_type in ("artifact", "artifact_permanent"):
        return is_artifact_permanent(target)
    if target_type in ("enchantment", "enchantment_permanent"):
        return is_enchantment_permanent(target)
    if target_type in ("artifact_or_enchantment", "artifact_enchantment"):
        return is_artifact_permanent(target) or is_enchantment_permanent(target)
    if target_type == "artifact_or_creature":
        return is_artifact_permanent(target) or is_battlefield_creature(target)
    if target_type == "artifact_creature_or_land":
        return (
            is_artifact_permanent(target)
            or is_battlefield_creature(target)
            or is_effective_land(target)
        )
    if target_type == "creature_or_enchantment":
        return is_battlefield_creature(target) or is_enchantment_permanent(target)
    if target_type in ("creature_or_planeswalker", "creature_planeswalker"):
        return is_battlefield_creature(target) or is_planeswalker_permanent(target)
    if target_type in ("planeswalker", "planeswalker_permanent"):
        return "planeswalker" in str(target.get("type_line") or "").lower()
    if target_type in ("land", "land_permanent"):
        return is_effective_land(target)
    if target_type in (
        "creature_enchantment_or_planeswalker",
        "creature_or_enchantment_or_planeswalker",
    ):
        return (
            is_battlefield_creature(target)
            or is_enchantment_permanent(target)
            or "planeswalker" in str(target.get("type_line") or "").lower()
        )
    if target_type == "colored_permanent":
        return is_colored_permanent(target)
    if target_type in ("nonland", "nonland_permanent"):
        return not is_effective_land(target)
    if target_type in ("permanent", "any"):
        return True
    return True


def card_is_blue(card):
    colors = card.get("colors") or card.get("color_identity") or []
    if isinstance(colors, str):
        colors = read_json_list(colors) or [colors]
    normalized = {_normalize_color_symbol(color) for color in colors}
    if "blue" in normalized or "u" in normalized:
        return True
    mana_cost = str(card.get("mana_cost") or "").upper()
    return "{U}" in mana_cost or "{U/" in mana_cost or "/U}" in mana_cost


def card_has_color(card, color):
    if not isinstance(card, dict):
        return False
    wanted = _normalize_color_symbol(color)
    if not wanted:
        return False
    colors = card.get("colors") or card.get("color_identity") or []
    if isinstance(colors, str):
        colors = read_json_list(colors) or [colors]
    normalized = {_normalize_color_symbol(value) for value in colors if str(value).strip()}
    if wanted in normalized:
        return True
    mana_cost = str(card.get("mana_cost") or "").upper()
    symbol = {
        "white": "W",
        "blue": "U",
        "black": "B",
        "red": "R",
        "green": "G",
        "w": "W",
        "u": "U",
        "b": "B",
        "r": "R",
        "g": "G",
    }.get(wanted, str(color or "").upper())
    return bool(symbol) and (f"{{{symbol}}}" in mana_cost or f"{{{symbol}/" in mana_cost or f"/{symbol}}}" in mana_cost)


def card_color_symbol_set(card):
    if not isinstance(card, dict):
        return set()
    return {
        symbol
        for symbol in ("W", "U", "B", "R", "G")
        if card_has_color(card, symbol)
    }


def card_mana_value(card):
    if not isinstance(card, dict):
        return 0
    for key in ("mana_value", "cmc", "converted_mana_cost"):
        value = card.get(key)
        if value in (None, ""):
            continue
        try:
            return int(float(value))
        except (TypeError, ValueError):
            continue
    return 0


def target_constraint_source(source, effect_data):
    if not isinstance(effect_data, dict):
        return source
    merged = dict(effect_data)
    if isinstance(source, dict):
        for key in ("name", "colors", "color_identity", "mana_cost", "oracle_text", "type_line"):
            if merged.get(key) in (None, "", [], {}):
                merged[key] = source.get(key)
    return merged


def is_legal_target(spell, target, controller, all_players=None, target_type=None, target_controller=None):
    """v9: Check if a target is still legal for a spell/ability (CR 608.2b)."""
    if not isinstance(target, dict):
        return False
    if target_type and not target_matches_type(target, target_type):
        return False
    if target.get("protection_from_everything"):
        return False
    if target.get("eliminated"):
        return False
    constraints = _target_constraints_dict(spell)
    if constraints.get("exclude_source") and target is spell:
        return False
    # Hexproof: can't be targeted by opponents
    target_controller_name = (
        target.get("controller")
        or target.get("owner")
        or getattr(target_controller, "name", None)
    )
    required_controller = str(
        constraints.get("controller")
        or constraints.get("controller_scope")
        or constraints.get("target_controller")
        or ""
    ).lower()
    if required_controller in {"self", "you", "controller", "controlled"}:
        if target_controller_name != getattr(controller, "name", None):
            return False
    elif required_controller in {"opponent", "opponents"}:
        if target_controller_name == getattr(controller, "name", None):
            return False
    if bool(constraints.get("requires_owner_and_controller")):
        controller_name = getattr(controller, "name", None)
        if target_controller_name != controller_name or target.get("owner") != controller_name:
            return False
    if target.get("hexproof") and controller.name != target_controller_name:
        return False
    # Shroud: can't be targeted at all
    if target.get("shroud"):
        return False
    # Protection from source's color
    protections = target.get("protection_from", [])
    if isinstance(protections, str):
        protections = [protections]
    protections = {_normalize_color_symbol(color) for color in protections}
    source_colors = spell.get("colors") or spell.get("color_identity") or []
    if isinstance(source_colors, str):
        source_colors = read_json_list(source_colors) or [source_colors]
    source_colors = {_normalize_color_symbol(color) for color in source_colors}
    if not source_colors and isinstance(spell, dict):
        source_colors = set(protection_colors_for_source(spell))
    if any(c in protections for c in source_colors):
        return False
    protection_profile = str(target.get("protection_from_color_profile") or "").strip().lower()
    if protection_profile:
        source_profile_colors = {
            color
            for color in protection_colors_for_source(spell)
            if _normalize_color_symbol(color) != "colorless"
        }
        if protection_profile == "multicolored" and len(source_profile_colors) >= 2:
            return False
        if protection_profile == "monocolored" and len(source_profile_colors) == 1:
            return False
    protection_mana_value_min = target.get("protection_from_mana_value_min")
    if protection_mana_value_min not in (None, ""):
        try:
            if card_mana_value(spell) >= int(protection_mana_value_min):
                return False
        except (TypeError, ValueError):
            pass
    protected_card_types = {
        str(card_type or "").strip().lower()
        for card_type in _as_list(target.get("protection_from_card_types"))
        if str(card_type or "").strip()
    }
    if protected_card_types and any(target_matches_type(spell, card_type) for card_type in protected_card_types):
        return False
    protected_subtypes = {
        str(subtype or "").strip().lower()
        for subtype in _as_list(target.get("protection_from_subtypes"))
        if str(subtype or "").strip()
    }
    if protected_subtypes and any(permanent_has_subtype(spell, subtype) for subtype in protected_subtypes):
        return False
    any_of = constraints.get("any_of")
    if isinstance(any_of, list) and any_of:
        base_constraints = dict(constraints)
        base_constraints.pop("any_of", None)
        for option in any_of:
            if not isinstance(option, dict):
                continue
            nested_spell = dict(spell or {})
            nested_constraints = dict(base_constraints)
            nested_constraints.update(option)
            nested_spell["target_constraints"] = nested_constraints
            if is_legal_target(
                nested_spell,
                target,
                controller,
                all_players=all_players,
                target_type=target_type,
                target_controller=target_controller,
            ):
                return True
        return False
    allowed_types = _constraint_card_types(spell)
    if allowed_types and "permanent" not in allowed_types:
        if constraints.get("all_card_types_required"):
            if not all(target_matches_type(target, allowed_type) for allowed_type in allowed_types):
                return False
        elif not any(target_matches_type(target, allowed_type) for allowed_type in allowed_types):
            return False
    excluded_types = {
        str(value or "").strip().lower()
        for value in _as_list(constraints.get("exclude_card_types"))
        if str(value or "").strip()
    }
    if excluded_types and any(target_matches_type(target, excluded_type) for excluded_type in excluded_types):
        return False
    combat_state = str(constraints.get("combat_state") or "").lower()
    if combat_state == "attacking" and not bool(target.get("attacking")):
        return False
    if combat_state == "blocked" and not bool(target.get("blocked")):
        return False
    if combat_state == "blocking" and not bool(target.get("blocking")):
        return False
    if combat_state == "attacking_or_blocking" and not (
        bool(target.get("attacking")) or bool(target.get("blocking"))
    ):
        return False
    attacking_defender_scope = str(
        constraints.get("attacking_defender_scope")
        or constraints.get("attacking_player_scope")
        or ""
    ).lower()
    if attacking_defender_scope in {"self", "controller", "self_or_planeswalker_you_control"}:
        controller_name = getattr(controller, "name", None)
        attacking_player = (
            target.get("attacking_player")
            or target.get("attacking_defender")
            or target.get("defending_player")
        )
        planeswalker_controller = (
            target.get("attacking_planeswalker_controller")
            or target.get("defending_planeswalker_controller")
        )
        if not controller_name or (
            attacking_player != controller_name
            and planeswalker_controller != controller_name
        ):
            return False
    tapped_state = str(constraints.get("tapped_state") or constraints.get("tap_state") or "").lower()
    if tapped_state == "tapped" and not bool(target.get("tapped")):
        return False
    if tapped_state == "untapped" and bool(target.get("tapped")):
        return False
    if bool(
        constraints.get("damaged_this_turn")
        or constraints.get("was_dealt_damage_this_turn")
        or constraints.get("dealt_damage_this_turn")
    ) and not permanent_was_dealt_damage_this_turn(target, CURRENT_REPLAY_TURN):
        return False
    if bool(
        constraints.get("token")
        or constraints.get("is_token")
        or constraints.get("token_only")
        or constraints.get("target_token")
    ) and not is_token_permanent(target):
        return False
    if bool(
        constraints.get("non_token")
        or constraints.get("nontoken")
        or constraints.get("target_non_token")
    ) and is_token_permanent(target):
        return False
    if bool(
        constraints.get("requires_counter")
        or constraints.get("with_counter")
        or constraints.get("target_has_counter")
    ) and not permanent_has_any_counter(target):
        return False
    if bool(constraints.get("enchanted") or constraints.get("is_enchanted")):
        enchanted = bool(
            target.get("enchanted")
            or target.get("enchanted_by")
            or target.get("attached_aura")
            or target.get("auras_attached")
        )
        if not enchanted:
            return False
    required_keywords = [
        str(value or "").strip().lower().replace(" ", "_")
        for value in _as_list(constraints.get("required_keywords") or constraints.get("target_keywords"))
        if str(value or "").strip()
    ]
    if required_keywords and not all(card_has_keyword(target, keyword) for keyword in required_keywords):
        return False
    if constraints.get("requires_activated_ability_with_tap_cost") and not bool(
        target.get("has_activated_ability_with_tap_cost")
        or target.get("activated_ability_with_tap_cost")
    ):
        return False
    excluded_keywords = [
        str(value or "").strip().lower().replace(" ", "_")
        for value in _as_list(constraints.get("excluded_keywords") or constraints.get("exclude_keywords"))
        if str(value or "").strip()
    ]
    if excluded_keywords and any(card_has_keyword(target, keyword) for keyword in excluded_keywords):
        return False
    target_colors = [
        value
        for value in _as_list(constraints.get("target_colors") or constraints.get("colors"))
        if str(value or "").strip()
    ]
    if target_colors and not any(card_has_color(target, color) for color in target_colors):
        return False
    excluded_colors = [
        value
        for value in _as_list(constraints.get("exclude_colors") or constraints.get("excluded_colors"))
        if str(value or "").strip()
    ]
    if excluded_colors and any(card_has_color(target, color) for color in excluded_colors):
        return False
    required_supertypes = {
        str(value or "").strip().lower()
        for value in _as_list(constraints.get("required_supertypes") or constraints.get("target_supertypes"))
        if str(value or "").strip()
    }
    if required_supertypes:
        type_line = str(target.get("type_line") or "").lower()
        for supertype in required_supertypes:
            if supertype not in type_line and not bool(target.get(supertype)):
                return False
    excluded_supertypes = {
        str(value or "").strip().lower()
        for value in _as_list(constraints.get("exclude_supertypes") or constraints.get("excluded_supertypes"))
        if str(value or "").strip()
    }
    if excluded_supertypes:
        type_line = str(target.get("type_line") or "").lower()
        for supertype in excluded_supertypes:
            if supertype in type_line or bool(target.get(supertype)):
                return False
    required_subtypes = [
        str(value or "").strip().lower()
        for value in _as_list(
            constraints.get("required_subtypes")
            or constraints.get("target_subtypes")
            or constraints.get("subtypes")
        )
        if str(value or "").strip()
    ]
    if required_subtypes:
        match_mode = str(
            constraints.get("required_subtype_match")
            or constraints.get("target_subtype_match")
            or "any"
        ).lower()
        if match_mode == "all":
            if not all(permanent_has_subtype(target, subtype) for subtype in required_subtypes):
                return False
        elif not any(permanent_has_subtype(target, subtype) for subtype in required_subtypes):
            return False
    excluded_subtypes = [
        str(value or "").strip().lower()
        for value in _as_list(
            constraints.get("exclude_subtypes")
            or constraints.get("excluded_subtypes")
            or constraints.get("target_exclude_subtypes")
        )
        if str(value or "").strip()
    ]
    if excluded_subtypes and any(permanent_has_subtype(target, subtype) for subtype in excluded_subtypes):
        return False
    color_count_exact = first_present_value(constraints, ("color_count_exact", "target_color_count_exact"))
    if color_count_exact is not None:
        try:
            if len(card_color_symbol_set(target)) != int(float(color_count_exact)):
                return False
        except Exception:
            return False
    color_count_min = first_present_value(constraints, ("color_count_min", "target_color_count_min"))
    if color_count_min is not None:
        try:
            if len(card_color_symbol_set(target)) < int(float(color_count_min)):
                return False
        except Exception:
            return False
    color_count_max = first_present_value(constraints, ("color_count_max", "target_color_count_max"))
    if color_count_max is not None:
        try:
            if len(card_color_symbol_set(target)) > int(float(color_count_max)):
                return False
        except Exception:
            return False
    power_min = first_present_value(constraints, ("power_min", "target_power_min"))
    if power_min is not None:
        try:
            if int(target.get("power") or 0) < int(float(power_min)):
                return False
        except Exception:
            return False
    power_max = first_present_value(constraints, ("power_max", "target_power_max"))
    if power_max is not None:
        try:
            if int(target.get("power") or 0) > int(float(power_max)):
                return False
        except Exception:
            return False
    toughness_min = first_present_value(constraints, ("toughness_min", "target_toughness_min"))
    if toughness_min is not None:
        try:
            if int(target.get("toughness") or 0) < int(float(toughness_min)):
                return False
        except Exception:
            return False
    toughness_max = first_present_value(constraints, ("toughness_max", "target_toughness_max"))
    if toughness_max is not None:
        try:
            if int(target.get("toughness") or 0) > int(float(toughness_max)):
                return False
        except Exception:
            return False
    if bool(
        constraints.get("power_toughness_not_equal")
        or constraints.get("power_toughness_unequal")
        or constraints.get("power_not_equal_toughness")
    ):
        try:
            if int(target.get("power") or 0) == int(target.get("toughness") or target.get("power") or 0):
                return False
        except Exception:
            return False
    mana_value_min = first_present_value(constraints, ("mana_value_min", "target_mana_value_min", "cmc_min", "target_cmc_min"))
    if mana_value_min is not None:
        try:
            if card_mana_value(target) < int(float(mana_value_min)):
                return False
        except Exception:
            return False
    mana_value_max = first_present_value(constraints, ("mana_value_max", "target_mana_value_max", "cmc_max", "target_cmc_max"))
    if mana_value_max is not None:
        try:
            if card_mana_value(target) > int(float(mana_value_max)):
                return False
        except Exception:
            return False
    dynamic_mana_value_source = str(
        constraints.get("target_mana_value_source")
        or constraints.get("target_cmc_source")
        or spell.get("target_mana_value_source")
        or spell.get("target_cmc_source")
        or ""
    ).strip().lower()
    if dynamic_mana_value_source == "x_value":
        try:
            x_value = x_value_from_effect_context(spell)
            if card_mana_value(target) != int(float(x_value or 0)):
                return False
        except Exception:
            return False
    # Ward: doesn't affect legality, only triggers on cast
    return True


def targeting_decision(spell, target, controller, *, target_controller=None, target_type=None):
    legal = is_legal_target(
        spell,
        target,
        controller,
        target_type=target_type,
        target_controller=target_controller,
    )
    return {
        "targeting_pipeline": "targeting_formal_minimal",
        "target_name": target.get("name", "?") if isinstance(target, dict) else "?",
        "target_type": target_type or "any",
        "target_legal": legal,
        "target_controller": getattr(target_controller, "name", None),
    }


TARGETED_REMOVAL_EFFECTS = {"remove_creature", "remove_permanent", "remove_artifact_or_3dmg"}


def removal_exile_targets_stack(effect_data):
    if not isinstance(effect_data, dict):
        return False
    constraints = effect_data.get("target_constraints") or {}
    if isinstance(constraints, str):
        try:
            constraints = json.loads(constraints)
        except Exception:
            constraints = {"raw": constraints}
    if isinstance(constraints, dict) and str(constraints.get("zone") or "").lower() == "stack":
        return True
    target_text = " ".join(
        str(effect_data.get(key) or "")
        for key in ("target", "target_type", "battle_model_scope")
    ).lower()
    return "stack" in target_text or "spell" in target_text


def _target_constraints_dict(effect_data):
    constraints = (effect_data or {}).get("target_constraints") or {}
    if isinstance(constraints, str):
        try:
            constraints = json.loads(constraints)
        except Exception:
            constraints = {"raw": constraints}
    return constraints if isinstance(constraints, dict) else {}


def _constraint_card_types(effect_data):
    constraints = _target_constraints_dict(effect_data)
    raw_types = constraints.get("card_types") or constraints.get("target_card_types") or []
    if isinstance(raw_types, str):
        raw_types = [raw_types]
    return {str(value or "").strip().lower() for value in raw_types if str(value or "").strip()}


def _target_type_from_constraints(effect_data):
    card_types = _constraint_card_types(effect_data)
    if {"creature", "enchantment", "planeswalker"}.issubset(card_types):
        return "creature_enchantment_or_planeswalker"
    if {"artifact", "creature", "land"}.issubset(card_types):
        return "artifact_creature_or_land"
    if {"artifact", "enchantment"}.issubset(card_types):
        return "artifact_or_enchantment"
    if "artifact" in card_types and "creature" in card_types:
        return "artifact_or_creature"
    if "creature" in card_types and "planeswalker" in card_types:
        return "creature_or_planeswalker"
    if "creature" in card_types and "enchantment" in card_types:
        return "creature_or_enchantment"
    for candidate in ("creature", "artifact", "enchantment", "planeswalker", "land", "permanent"):
        if candidate in card_types:
            return candidate
    return ""


def removal_target_type(effect_data):
    target_type = str((effect_data or {}).get("target") or "").lower()
    if target_type:
        return target_type
    constrained_type = _target_type_from_constraints(effect_data)
    if constrained_type:
        return constrained_type
    return (
        "creature"
        if (effect_data or {}).get("effect") == "remove_creature"
        else "nonland_permanent"
    )


def removal_destination(effect_data):
    if not isinstance(effect_data, dict):
        return "graveyard"
    explicit_destination = effect_data.get("destination")
    if explicit_destination:
        return str(explicit_destination).lower()
    if effect_data.get("exile_target"):
        return "exile"
    return "graveyard"


def direct_damage_targets_player(effect_data):
    constraints = _target_constraints_dict(effect_data)
    if str(constraints.get("scope") or "").lower() == "any_target":
        return True
    target = str((effect_data or {}).get("target") or "").lower()
    if target in {"player", "opponent", "any_target", "player_or_planeswalker", "opponent_or_planeswalker"}:
        return True
    return False


def direct_damage_target_participants(player, opponents, effect_data):
    target_controller = str((effect_data or {}).get("target_controller") or "").lower()
    constraint_scope = str(_target_constraints_dict(effect_data).get("controller_scope") or "").lower()
    if target_controller in {"self", "you", "controller", "controlled"} or constraint_scope in {
        "self",
        "you",
        "controller",
        "controlled",
    }:
        return [player]
    return list(opponents or [])


def removal_annotation_replay_fields(effect_data):
    fields = {}
    if not isinstance(effect_data, dict):
        return fields
    if effect_data.get("target_controller_basic_land_tapped") is not None:
        fields["target_controller_basic_land_tapped"] = bool(
            effect_data.get("target_controller_basic_land_tapped")
        )
    if effect_data.get("basic_land_compensation_status"):
        fields["basic_land_compensation_status"] = effect_data.get(
            "basic_land_compensation_status"
        )
    map_tokens = (
        effect_data.get("target_controller_map_tokens")
        if effect_data.get("target_controller_map_tokens") is not None
        else effect_data.get("map_tokens_created")
    )
    if map_tokens is not None:
        fields["target_controller_map_tokens"] = int(map_tokens or 0)
        fields["map_token_status"] = effect_data.get(
            "map_token_status"
        ) or effect_data.get(
            "map_token_activation_status",
            "annotation_only_explore_activation_not_autorun",
        )
    creature_tokens = (
        effect_data.get("target_controller_creature_tokens")
        if effect_data.get("target_controller_creature_tokens") is not None
        else effect_data.get("compensation_creature_tokens")
    )
    if creature_tokens is not None:
        fields["target_controller_creature_tokens"] = numeric_stat(creature_tokens) or 0
        fields["compensation_token_name"] = (
            effect_data.get("target_controller_token_name")
            or effect_data.get("compensation_token_name")
            or "Token"
        )
        fields["compensation_token_power"] = numeric_stat(
            effect_data.get("target_controller_token_power")
            or effect_data.get("compensation_token_power")
            or 1
        ) or 1
        fields["compensation_token_toughness"] = numeric_stat(
            effect_data.get("target_controller_token_toughness")
            or effect_data.get("compensation_token_toughness")
            or fields["compensation_token_power"]
        ) or fields["compensation_token_power"]
        fields["compensation_token_status"] = effect_data.get(
            "compensation_token_status",
            "dynamic_creature_token_executor",
        )
    return fields


def _removal_controller_battlefield_life_gain_count(effect_data, source_controller, target=None, target_controller=None):
    if source_controller is None:
        return 0
    scope = str((effect_data or {}).get("battlefield_count_scope") or "controller_battlefield").lower()
    if scope != "controller_battlefield":
        return 0
    count = 0
    for permanent in getattr(source_controller, "battlefield", []) or []:
        if permanent is target and target_controller is source_controller and removal_destination(effect_data) == "graveyard":
            continue
        if _battlefield_count_card_matches(permanent, effect_data):
            count += 1
    return count


def removal_life_gain_requested(effect_data, target, source_controller=None, target_controller=None):
    if not isinstance(effect_data, dict):
        return 0
    if effect_data.get("controller_gains_life"):
        try:
            return max(0, int(effect_data.get("controller_gains_life") or 0))
        except Exception:
            return 0
    controller_gain_life_source = str(
        effect_data.get("controller_gain_life_source")
        or effect_data.get("gain_life_source")
        or effect_data.get("life_gain_amount_source")
        or ""
    ).strip().lower()
    if controller_gain_life_source == "target_mana_value":
        return max(0, int(card_mana_value(target)))
    if controller_gain_life_source == "x_value":
        return max(0, int(x_value_from_effect_context(effect_data)))
    if controller_gain_life_source in {"battlefield_permanent_count", "controller_battlefield_count"}:
        count = _removal_controller_battlefield_life_gain_count(
            effect_data,
            source_controller,
            target=target,
            target_controller=target_controller,
        )
        base = max(0, int(effect_data.get("life_gain_base_amount") or 0))
        per = max(0, int(effect_data.get("life_gain_per_count") or 1))
        return base + count * per
    if effect_data.get("target_controller_life_gain_equal_target_power"):
        try:
            return max(0, int((target or {}).get("power") or 0))
        except Exception:
            return 0
    if effect_data.get("target_controller_gains_life"):
        try:
            return max(0, int(effect_data.get("target_controller_gains_life") or 0))
        except Exception:
            return 0
    return 0


def removal_life_gain_recipient(effect_data, source_controller, target_controller):
    controller_gain_life_source = ""
    if isinstance(effect_data, dict):
        controller_gain_life_source = str(
            effect_data.get("controller_gain_life_source")
            or effect_data.get("gain_life_source")
            or effect_data.get("life_gain_amount_source")
            or ""
        ).strip().lower()
    if isinstance(effect_data, dict) and (
        effect_data.get("controller_gains_life")
        or controller_gain_life_source in {"target_mana_value", "x_value", "battlefield_permanent_count", "controller_battlefield_count"}
    ):
        return source_controller
    return target_controller


def apply_removal_life_gain(effect_data, target_controller, target, source_controller=None):
    requested = removal_life_gain_requested(
        effect_data,
        target,
        source_controller=source_controller,
        target_controller=target_controller,
    )
    recipient = removal_life_gain_recipient(effect_data, source_controller, target_controller)
    if requested <= 0 or recipient is None:
        return requested, 0
    before = int(getattr(recipient, "life", 0) or 0)
    gain_life(recipient, requested)
    after = int(getattr(recipient, "life", 0) or 0)
    return requested, max(0, after - before)


def removal_target_controller_life_loss_requested(effect_data):
    if not isinstance(effect_data, dict):
        return 0
    try:
        return max(
            0,
            int(
                effect_data.get("target_controller_life_loss_on_destroy")
                or effect_data.get("life_loss_on_destroy")
                or 0
            ),
        )
    except Exception:
        return 0


def apply_removal_target_controller_life_loss(
    effect_data,
    target_controller,
    source_card,
    target,
    destination,
    turn,
):
    requested = removal_target_controller_life_loss_requested(effect_data)
    if requested <= 0 or target_controller is None or str(destination or "").lower() != "graveyard":
        return requested, 0
    before = int(getattr(target_controller, "life", 0) or 0)
    change_life(target_controller, -requested)
    after = int(getattr(target_controller, "life", 0) or 0)
    lost = max(0, before - after)
    emit_replay_event(
        "life_loss_on_destroy_resolved",
        player=getattr(target_controller, "name", None),
        card=source_card.get("name", "?") if isinstance(source_card, dict) else "?",
        target=target.get("name", "?") if isinstance(target, dict) else "?",
        target_controller=getattr(target_controller, "name", None),
        destination=destination,
        life_loss_on_destroy=requested,
        target_controller_life_loss_on_destroy=requested,
        target_controller_life_before=before,
        target_controller_life_after=after,
        target_controller_life_lost=lost,
        turn=turn,
        **replay_rule_fields(effect_data),
    )
    return requested, lost


