def cant_block_runtime_enabled(effect_data):
    if not isinstance(effect_data, dict):
        return False
    return str(effect_data.get("cant_block_mode_status") or "").lower() == "runtime_executor_v1"


def cant_block_runtime_replay_fields(effect_data):
    fields = {}
    if not isinstance(effect_data, dict):
        return fields
    if effect_data.get("cant_block_mode_status"):
        fields["cant_block_mode_status"] = effect_data.get("cant_block_mode_status")
    if effect_data.get("cant_block_target_restriction"):
        fields["cant_block_target_restriction"] = effect_data.get("cant_block_target_restriction")
    return fields


def _cant_block_restriction_matches(creature, restriction):
    if not is_battlefield_creature(creature):
        return False
    restriction = str(restriction or "target_creature").lower()
    if restriction == "creatures_without_flying":
        return not bool(creature.get("flying"))
    return True


def cant_block_mode_target_candidates(player, opponents, card, effect_data):
    if not cant_block_runtime_enabled(effect_data):
        return []
    modes = {str(mode or "").lower() for mode in _as_list(effect_data.get("modes"))}
    if "cant_block" not in modes:
        return []
    candidates = []
    for opponent in prioritize_evaluation_target_opponents(player, opponents):
        for permanent in getattr(opponent, "battlefield", []) or []:
            if not _cant_block_restriction_matches(permanent, "target_creature"):
                continue
            if creature_cannot_block(permanent):
                continue
            if not is_legal_target(
                card,
                permanent,
                player,
                target_type="creature",
                target_controller=opponent,
            ):
                continue
            candidates.append((opponent, permanent))
    candidates.sort(key=lambda item: target_priority(item[1]), reverse=True)
    return candidates


def apply_cant_block_until_eot_runtime(
    player,
    opponents,
    card,
    effect_data,
    turn,
    *,
    target_controller=None,
    target=None,
    all_players=None,
):
    if not cant_block_runtime_enabled(effect_data):
        return []
    players = list(all_players or [player, *(opponents or [])])
    restriction = str(effect_data.get("cant_block_target_restriction") or "").lower()
    selected_mode = str(effect_data.get("_selected_mode") or "").lower()
    affected = []
    if restriction == "creatures_without_flying":
        for controller in players:
            for permanent in getattr(controller, "battlefield", []) or []:
                if _cant_block_restriction_matches(permanent, restriction):
                    affected.append((controller, permanent))
    elif selected_mode == "cant_block" and target_controller is not None and target is not None:
        if _cant_block_restriction_matches(target, "target_creature"):
            affected.append((target_controller, target))
    else:
        return []

    unique = []
    seen = set()
    for controller, creature in affected:
        marker = id(creature)
        if marker in seen:
            continue
        seen.add(marker)
        set_until_eot(creature, "cant_block", True)
        set_until_eot(creature, "cant_block_source", card.get("name", "?"))
        unique.append(
            {
                "controller": getattr(controller, "name", "?"),
                "card": creature.get("name", "?"),
                "flying": bool(creature.get("flying")),
            }
        )
    if unique:
        emit_replay_event(
            "cant_block_until_eot_resolved",
            player=player.name,
            card=card.get("name", "?"),
            selected_mode=selected_mode or None,
            affected_count=len(unique),
            affected=unique,
            duration="until_end_of_turn",
            turn=turn,
            **cant_block_runtime_replay_fields(effect_data),
            **replay_rule_fields(effect_data),
        )
    return unique


def is_permanent_card(card):
    if not isinstance(card, dict):
        return False
    type_line = str(card.get("type_line") or "").lower()
    permanent_types = (
        "artifact",
        "battle",
        "creature",
        "enchantment",
        "land",
        "planeswalker",
    )
    return any(card_type in type_line for card_type in permanent_types)


def is_token_permanent(card):
    if not isinstance(card, dict):
        return False
    return bool(card.get("token")) or "token" in str(card.get("type_line") or "").lower()


def move_permanent_to_library_then_reveal(
    target_controller,
    target,
    source_card,
    effect_data,
    turn,
    rng,
    *,
    all_players=None,
):
    if target_controller is None or not isinstance(target, dict):
        return "library"
    battlefield = getattr(target_controller, "battlefield", [])
    live_target = battlefield_object_for_target(target_controller, target)
    if live_target is not None:
        target = live_target
    if target in battlefield:
        battlefield.remove(target)
    elif live_target is not None and live_target in battlefield:
        battlefield.remove(live_target)

    library_before = len(getattr(target_controller, "library", []) or [])
    target_vanished = is_token_permanent(target)
    if not target_vanished:
        target_controller.library.append(target)
    target_controller.shuffle(rng)

    revealed = target_controller.library[0] if target_controller.library else None
    revealed_is_permanent = is_permanent_card(revealed)
    put_onto_battlefield = False
    if revealed_is_permanent and revealed in target_controller.library:
        target_controller.library.remove(revealed)
        permanent = prepare_entering_permanent(
            revealed,
            controller=target_controller,
            all_players=all_players or [target_controller],
            turn=turn,
        )
        target_controller.battlefield.append(permanent)
        put_onto_battlefield = True

    emit_replay_event(
        "chaos_warp_reveal_resolved",
        player=getattr(target_controller, "name", None),
        source=source_card.get("name", "?") if isinstance(source_card, dict) else "?",
        target=target.get("name", "?"),
        target_vanished=target_vanished,
        library_before=library_before,
        library_after=len(getattr(target_controller, "library", []) or []),
        revealed_card=revealed.get("name", "?") if isinstance(revealed, dict) else None,
        revealed_type_line=revealed.get("type_line", "") if isinstance(revealed, dict) else "",
        revealed_is_permanent=revealed_is_permanent,
        put_onto_battlefield=put_onto_battlefield,
        turn=turn,
        **replay_rule_fields(effect_data),
    )
    return "library"


def _is_basic_land_card(card):
    if not isinstance(card, dict):
        return False
    type_line = str(card.get("type_line") or "").lower()
    return "basic" in type_line and "land" in type_line


def resolve_basic_land_compensation(effect_data, target_controller, source_card, turn, rng, *, all_players=None):
    if not isinstance(effect_data, dict) or target_controller is None:
        return None
    if str(effect_data.get("basic_land_compensation_status") or "").lower() != "runtime_executor_v1":
        return None
    try:
        count = max(0, int(effect_data.get("basic_land_compensation_count") or 1))
    except Exception:
        count = 1
    if count <= 0:
        return None
    destination = str(effect_data.get("basic_land_compensation_destination") or "battlefield_tapped")
    found = []
    for candidate in list(getattr(target_controller, "library", []) or []):
        if len(found) >= count:
            break
        if _is_basic_land_card(candidate):
            found.append(candidate)
    moved = []
    for basic_land in found:
        if basic_land not in target_controller.library:
            continue
        target_controller.library.remove(basic_land)
        permanent = enrich_card({**basic_land, "effect": "land"})
        if destination == "battlefield_tapped" or effect_data.get("target_controller_basic_land_tapped"):
            permanent["enters_tapped"] = True
        permanent = prepare_entering_permanent(
            permanent,
            controller=target_controller,
            all_players=all_players or [target_controller],
            turn=turn,
        )
        initialize_special_land_runtime_state(permanent, turn=turn)
        target_controller.battlefield.append(permanent)
        moved.append(permanent)
    if effect_data.get("shuffle_after_basic_land_compensation") and hasattr(target_controller, "shuffle"):
        target_controller.shuffle(rng)
    emit_replay_event(
        "basic_land_compensation_resolved",
        player=getattr(target_controller, "name", "?"),
        source=source_card.get("name", "?") if isinstance(source_card, dict) else "?",
        searched_count=count,
        moved_count=len(moved),
        moved_cards=[card.get("name", "?") for card in moved],
        destination=destination,
        tapped=bool(destination == "battlefield_tapped" or effect_data.get("target_controller_basic_land_tapped")),
        basic_land_compensation_status=effect_data.get("basic_land_compensation_status"),
        library_remaining=len(getattr(target_controller, "library", []) or []),
        turn=turn,
        **replay_rule_fields(effect_data),
    )
    return moved


def _remove_battlefield_object(owner, permanent):
    battlefield = getattr(owner, "battlefield", None)
    if not isinstance(battlefield, list):
        return None
    for index, candidate in enumerate(battlefield):
        if candidate is permanent:
            return battlefield.pop(index)
    for index, candidate in enumerate(battlefield):
        if candidate == permanent:
            return battlefield.pop(index)
    if isinstance(permanent, dict):
        target_name = permanent.get("name") or permanent.get("card_name")
        if target_name:
            matches = [
                (index, candidate)
                for index, candidate in enumerate(battlefield)
                if isinstance(candidate, dict)
                and (candidate.get("name") or candidate.get("card_name")) == target_name
            ]
            if len(matches) == 1:
                index, candidate = matches[0]
                del battlefield[index]
                return candidate
    return None


def _clear_battlefield_only_state(permanent):
    if not isinstance(permanent, dict):
        return
    for key in (
        "attacking",
        "blocking",
        "blocked",
        "blockers",
        "damage_marked",
        "summoning_sick",
        "tapped",
        "until_eot",
    ):
        permanent.pop(key, None)
    clear_permanent_damage_this_turn_flags(permanent)


def clear_permanent_damage_this_turn_flags(permanent):
    if not isinstance(permanent, dict):
        return
    for key in (
        "damaged_this_turn",
        "was_dealt_damage_this_turn",
        "damage_marked_this_turn",
        "dealt_damage_this_turn",
        "last_damage_turn",
    ):
        permanent.pop(key, None)


def mark_permanent_dealt_damage_this_turn(permanent, amount, turn):
    if not isinstance(permanent, dict) or int(amount or 0) <= 0:
        return
    current = int(permanent.get("damage_marked_this_turn") or 0)
    permanent["damage_marked_this_turn"] = current + int(amount or 0)
    permanent["damaged_this_turn"] = True
    permanent["was_dealt_damage_this_turn"] = True
    if turn is not None:
        permanent["last_damage_turn"] = int(turn)


def permanent_was_dealt_damage_this_turn(permanent, turn=None):
    if not isinstance(permanent, dict):
        return False
    if bool(permanent.get("damaged_this_turn") or permanent.get("was_dealt_damage_this_turn")):
        return True
    for key in ("damage_marked_this_turn", "damage_marked", "dealt_damage_this_turn"):
        try:
            if int(permanent.get(key) or 0) > 0:
                return True
        except Exception:
            continue
    if turn is not None:
        try:
            return int(permanent.get("last_damage_turn") or -1) == int(turn)
        except Exception:
            return False
    return False


def move_permanent_from_battlefield_to_hand(owner, permanent, *, reason=None, source=None, turn=None):
    if not isinstance(permanent, dict):
        return "none"
    permanent = battlefield_object_for_target(owner, permanent) or permanent
    moved = _remove_battlefield_object(owner, permanent)
    if moved is None:
        return "none"
    moved["_lki_snapshot"] = {
        "name": moved.get("name", moved.get("card_name", "")),
        "power": moved.get("power", 0),
        "toughness": moved.get("toughness", 0),
        "cmc": moved.get("cmc", 0),
        "type_line": moved.get("type_line", ""),
        "is_commander": moved.get("is_commander", False),
        "owner": moved.get("owner", moved.get("controller", "")),
    }
    moved["_zone_id"] = moved.get("_zone_id", 0) + 1
    moved["_last_zone"] = "battlefield"
    destination = "hand"
    if moved.get("is_commander"):
        event = ReplacementRegistry.process_event(
            ReplacementEvent(
                "zone_change",
                affected_player=owner,
                card=moved,
                from_zone="battlefield",
                to_zone="hand",
                source=source,
                reason=reason,
            )
        )
        destination = event.to_zone
    if moved.get("tag") == "token" or "token" in str(moved.get("type_line") or "").lower():
        destination = "vanished_token"
    elif destination == "command_zone":
        owner.command_zone.append(moved)
    else:
        _clear_battlefield_only_state(moved)
        owner.hand.append(moved)
        destination = "hand"
    emit_replay_event(
        "permanent_moved_from_battlefield",
        player=getattr(owner, "name", "?"),
        card=moved.get("name", "?"),
        permanent_type="permanent",
        from_zone="battlefield",
        to_zone=destination,
        destination=destination,
        reason=reason,
        source=source.get("name", "?") if isinstance(source, dict) else source,
        turn=turn if turn is not None else CURRENT_REPLAY_TURN,
    )
    resolve_leave_battlefield_treasure_trigger(
        owner,
        moved,
        destination=destination,
        reason=reason,
        source=source,
    )
    refresh_controlled_static_indestructible(
        owner,
        turn=turn if turn is not None else CURRENT_REPLAY_TURN,
        phase="leave_battlefield",
        emit_events=True,
    )
    refresh_controlled_static_power_toughness_bonuses(
        owner,
        turn=turn if turn is not None else CURRENT_REPLAY_TURN,
        phase="leave_battlefield",
        emit_events=True,
    )
    refresh_controlled_static_keywords(
        owner,
        turn=turn if turn is not None else CURRENT_REPLAY_TURN,
        phase="leave_battlefield",
        emit_events=True,
    )
    return destination


def move_permanent_from_battlefield_to_library(owner, permanent, *, destination, reason=None, source=None, turn=None):
    if owner is None or not isinstance(permanent, dict):
        return "none"
    destination = str(destination or "library_top").lower()
    if destination not in {"library_top", "library_bottom"}:
        destination = "library_top"
    permanent = battlefield_object_for_target(owner, permanent) or permanent
    moved = _remove_battlefield_object(owner, permanent)
    if moved is None:
        return "none"
    moved["_lki_snapshot"] = {
        "name": moved.get("name", moved.get("card_name", "")),
        "power": moved.get("power", 0),
        "toughness": moved.get("toughness", 0),
        "cmc": moved.get("cmc", 0),
        "type_line": moved.get("type_line", ""),
        "is_commander": moved.get("is_commander", False),
        "owner": moved.get("owner", moved.get("controller", "")),
    }
    moved["_zone_id"] = moved.get("_zone_id", 0) + 1
    moved["_last_zone"] = "battlefield"
    final_destination = destination
    if moved.get("is_commander"):
        event = ReplacementRegistry.process_event(
            ReplacementEvent(
                "zone_change",
                affected_player=owner,
                card=moved,
                from_zone="battlefield",
                to_zone="library",
                source=source,
                reason=reason,
            )
        )
        if event.to_zone == "command_zone":
            final_destination = "command_zone"
    if moved.get("tag") == "token" or "token" in str(moved.get("type_line") or "").lower():
        final_destination = "vanished_token"
    elif final_destination == "command_zone":
        owner.command_zone.append(moved)
    else:
        _clear_battlefield_only_state(moved)
        if final_destination == "library_bottom":
            owner.library.append(moved)
        else:
            owner.library.insert(0, moved)
            final_destination = "library_top"
    emit_replay_event(
        "permanent_moved_from_battlefield",
        player=getattr(owner, "name", "?"),
        card=moved.get("name", "?"),
        permanent_type="permanent",
        from_zone="battlefield",
        to_zone=final_destination,
        destination=final_destination,
        reason=reason,
        source=source.get("name", "?") if isinstance(source, dict) else source,
        turn=turn if turn is not None else CURRENT_REPLAY_TURN,
    )
    emit_replay_event(
        "permanent_put_on_library",
        player=getattr(owner, "name", "?"),
        card=moved.get("name", "?"),
        destination=final_destination,
        requested_destination=destination,
        source=source.get("name", "?") if isinstance(source, dict) else source,
        vanished_token=final_destination == "vanished_token",
        turn=turn if turn is not None else CURRENT_REPLAY_TURN,
    )
    resolve_leave_battlefield_treasure_trigger(
        owner,
        moved,
        destination=final_destination,
        reason=reason,
        source=source,
    )
    refresh_controlled_static_indestructible(
        owner,
        turn=turn if turn is not None else CURRENT_REPLAY_TURN,
        phase="leave_battlefield",
        emit_events=True,
    )
    refresh_controlled_static_power_toughness_bonuses(
        owner,
        turn=turn if turn is not None else CURRENT_REPLAY_TURN,
        phase="leave_battlefield",
        emit_events=True,
    )
    refresh_controlled_static_keywords(
        owner,
        turn=turn if turn is not None else CURRENT_REPLAY_TURN,
        phase="leave_battlefield",
        emit_events=True,
    )
    return final_destination


def move_removed_permanent_to_destination(
    target_controller,
    target,
    source_card,
    effect_data,
    turn,
    rng,
    *,
    all_players=None,
):
    destination = removal_destination(effect_data)
    if destination == "exile":
        move_zone_object_to_exile(
            target_controller,
            "battlefield",
            target,
            reason="removal",
            source=source_card,
            turn=turn,
        )
    elif destination == "library":
        move_permanent_to_library_then_reveal(
            target_controller,
            target,
            source_card,
            effect_data,
            turn,
            rng,
            all_players=all_players,
        )
    elif destination in {"library_top", "library_bottom"}:
        destination = move_permanent_from_battlefield_to_library(
            target_controller,
            target,
            destination=destination,
            reason="put_on_library",
            source=source_card,
            turn=turn,
        )
    elif destination == "hand":
        move_permanent_from_battlefield_to_hand(
            target_controller,
            target,
            reason="bounce",
            source=source_card,
            turn=turn,
        )
    else:
        if isinstance(target, dict) and target.get("indestructible"):
            emit_replay_event(
                "removal_prevented_by_indestructible",
                player=getattr(target_controller, "name", "?"),
                card=source_card.get("name", "?") if isinstance(source_card, dict) else "?",
                target=target.get("name", "?"),
                destination=destination,
                turn=turn,
                **replay_rule_fields(effect_data),
            )
            return "none"
        destination = move_permanent_from_battlefield(
            target_controller,
            target,
            reason="destroy",
            source=source_card,
        )
    resolve_basic_land_compensation(
        effect_data,
        target_controller,
        source_card,
        turn,
        rng,
        all_players=all_players,
    )
    return destination


def declared_target_replay_entry(decision):
    return {
        "target": decision.get("target_name"),
        "target_controller": decision.get("target_controller"),
        "target_type": decision.get("target_type"),
        "target_legal": decision.get("target_legal"),
        "targeting_pipeline": decision.get("targeting_pipeline"),
    }


def replay_fields_for_declared_targets(effect_data):
    replay_targets = []
    for entry in (effect_data or {}).get("declared_targets") or []:
        target = entry.get("target") if isinstance(entry, dict) else entry
        controller = entry.get("controller") if isinstance(entry, dict) else None
        target_type = (
            entry.get("target_type")
            if isinstance(entry, dict)
            else removal_target_type(effect_data)
        )
        decision = targeting_decision(
            effect_data,
            target,
            entry.get("declared_by") if isinstance(entry, dict) else None,
            target_controller=controller,
            target_type=target_type,
        )
        replay_targets.append(declared_target_replay_entry(decision))
    if not replay_targets:
        return {}
    return {"targets": replay_targets} | replay_primary_target_fields(replay_targets)


def prepare_declared_removal_targets(player, opponents, card, effect_data):
    if (effect_data or {}).get("effect") not in TARGETED_REMOVAL_EFFECTS:
        return effect_data, []
    if (effect_data or {}).get("declared_targets"):
        replay = replay_fields_for_declared_targets(effect_data).get("targets", [])
        return effect_data, replay

    target_type = removal_target_type(effect_data)
    try:
        max_targets = int(
            first_present_value(
                effect_data,
                ("max_targets", "max_target_count", "target_count"),
            )
            or 1
        )
    except Exception:
        max_targets = 1
    max_targets = max(1, max_targets)
    target_controller_scope = str((effect_data or {}).get("target_controller") or "opponent").lower()
    if target_controller_scope in {"self", "you", "controller", "controlled"}:
        target_controllers = [player]
    elif target_controller_scope in {"any", "any_player", "all"}:
        target_controllers = prioritize_evaluation_target_opponents(player, opponents) + [player]
    else:
        target_controllers = prioritize_evaluation_target_opponents(player, opponents)
    for target_controller in target_controllers:
        candidates = removal_target_candidates(
            target_controller,
            effect_data,
            controller=player,
            source=card,
        )
        if not candidates:
            continue
        ranked_targets = sorted(candidates, key=target_priority, reverse=True)[:max_targets]
        declared_targets = []
        replay = []
        for target in ranked_targets:
            decision = targeting_decision(
                card,
                target,
                player,
                target_controller=target_controller,
                target_type=target_type,
            )
            declared_targets.append(
                {
                    "target": target,
                    "controller": target_controller,
                    "target_type": target_type,
                    "declared_by": player,
                }
            )
            replay.append(declared_target_replay_entry(decision))
        return {**effect_data, "declared_targets": declared_targets}, replay
    cant_block_candidates = cant_block_mode_target_candidates(player, opponents, card, effect_data)
    if cant_block_candidates:
        opponent, target = cant_block_candidates[0]
        decision = targeting_decision(
            card,
            target,
            player,
            target_controller=opponent,
            target_type="creature",
        )
        return {
            **effect_data,
            "_selected_mode": "cant_block",
            "declared_targets": [
                {
                    "target": target,
                    "controller": opponent,
                    "target_type": "creature",
                    "declared_by": player,
                }
            ],
        }, [declared_target_replay_entry(decision)]
    return effect_data, []


def missing_required_declared_removal_target(effect_data, declared_targets):
    return (effect_data or {}).get("effect") in TARGETED_REMOVAL_EFFECTS and not declared_targets


def battlefield_object_for_target(player, target):
    battlefield = getattr(player, "battlefield", [])
    if not isinstance(battlefield, list) or not isinstance(target, dict):
        return None
    for permanent in battlefield:
        if permanent is target:
            return permanent
    for permanent in battlefield:
        if permanent == target:
            return permanent
    target_name = target.get("name") or target.get("card_name")
    if target_name:
        name_matches = [
            permanent
            for permanent in battlefield
            if isinstance(permanent, dict)
            and (permanent.get("name") or permanent.get("card_name")) == target_name
        ]
        if len(name_matches) == 1:
            return name_matches[0]
    return None


def controller_for_target(players, target):
    for candidate in players:
        if battlefield_object_for_target(candidate, target) is not None:
            return candidate
    return None


def declared_target_controller(players, target, entry_controller=None):
    live_controller = controller_for_target(players, target)
    if live_controller is not None:
        return live_controller
    for candidate in players:
        if candidate is entry_controller:
            return candidate
    return None


def resolve_multi_target_removal(player, opponents, card, effect_data, turn, rng):
    """Resolve declared removal targets independently (CR 608.2b partial resolution)."""
    declared_targets = effect_data.get("declared_targets") or []
    if not declared_targets:
        return False
    target_type = str(effect_data.get("target") or "").lower()
    if not target_type:
        target_type = "creature" if effect_data.get("effect") == "remove_creature" else "nonland_permanent"

    resolved = []
    illegal = []
    ward_countered = []
    players = [player] + list(opponents)
    for entry in declared_targets:
        target = entry.get("target") if isinstance(entry, dict) else entry
        entry_controller = entry.get("controller") if isinstance(entry, dict) else None
        target_controller = declared_target_controller(
            players,
            target,
            entry_controller=entry_controller,
        )
        live_target = (
            battlefield_object_for_target(target_controller, target)
            if target_controller is not None
            else None
        )
        if live_target is not None:
            target = live_target
        decision = targeting_decision(
            card,
            target,
            player,
            target_controller=target_controller,
            target_type=target_type,
        )
        target_still_present = target_controller is not None and live_target is not None
        if not decision["target_legal"] or not target_still_present:
            illegal.append(decision["target_name"])
            continue
        resolve_spell_target_treasure_trigger(
            target_controller,
            target,
            card,
            turn,
            phase="resolution",
        )
        if check_ward(target, card, player, rng):
            ward_countered.append(decision["target_name"])
            continue
        destination = move_removed_permanent_to_destination(
            target_controller,
            target,
            card,
            effect_data,
            turn,
            rng,
            all_players=players,
        )
        apply_removal_target_controller_life_loss(
            effect_data,
            target_controller,
            card,
            target,
            destination,
            turn,
        )
        apply_removal_target_controller_life_loss_on_resolve(
            effect_data,
            target_controller,
            card,
            target,
            turn,
            phase="resolution",
        )
        apply_removal_target_controller_damage(
            effect_data,
            target_controller,
            player,
            card,
            target,
            turn,
            phase="resolution",
        )
        create_removal_compensation_tokens(effect_data, target_controller, card, turn)
        create_controller_treasures_after_removal(effect_data, player, card, turn)
        resolved.append(decision["target_name"])

    if resolved:
        apply_removal_source_controller_penalty(
            effect_data,
            player,
            card,
            turn,
            phase="resolution",
        )

    emit_replay_event(
        "multi_target_resolution",
        player=player.name,
        card=card.get("name", "?"),
        target_type=target_type,
        declared=len(declared_targets),
        resolved=resolved,
        illegal=illegal,
        ward_countered=ward_countered,
        turn=turn,
    )
    return True


def resolve_declared_single_removal(player, opponents, card, effect_data, turn, rng):
    declared_targets = effect_data.get("declared_targets") or []
    if len(declared_targets) != 1:
        return False

    entry = declared_targets[0]
    target = entry.get("target") if isinstance(entry, dict) else entry
    players = [player] + list(opponents)
    entry_controller = entry.get("controller") if isinstance(entry, dict) else None
    target_controller = declared_target_controller(
        players,
        target,
        entry_controller=entry_controller,
    )
    live_target = (
        battlefield_object_for_target(target_controller, target)
        if target_controller is not None
        else None
    )
    if live_target is not None:
        target = live_target
    target_type = (
        entry.get("target_type") if isinstance(entry, dict) else None
    ) or removal_target_type(effect_data)
    decision = targeting_decision(
        card,
        target,
        player,
        target_controller=target_controller,
        target_type=target_type,
    )
    target_name = decision.get("target_name") or "?"
    target_still_present = target_controller is not None and live_target is not None
    if not decision["target_legal"] or not target_still_present:
        emit_replay_event(
            "removal_resolved",
            player=player.name,
            card=card.get("name", "?"),
            target_player=getattr(target_controller, "name", None),
            target=target_name,
            available_targets=1,
            result="no_legal_target",
            turn=turn,
            **decision,
        )
        return True

    resolve_spell_target_treasure_trigger(
        target_controller,
        target,
        card,
        turn,
        phase="resolution",
    )

    if check_ward(target, card, player, rng):
        emit_replay_event(
            "removal_countered_by_ward",
            player=player.name,
            card=card.get("name", "?"),
            target_player=target_controller.name,
            target=target_name,
            turn=turn,
            **decision,
        )
        return True

    if str(effect_data.get("_selected_mode") or "").lower() == "cant_block":
        applied = apply_cant_block_until_eot_runtime(
            player,
            opponents,
            card,
            effect_data,
            turn,
            target_controller=target_controller,
            target=target,
            all_players=players,
        )
        if not applied:
            emit_replay_event(
                "cant_block_until_eot_resolved",
                player=player.name,
                card=card.get("name", "?"),
                selected_mode="cant_block",
                affected_count=0,
                affected=[],
                result="no_legal_target",
                turn=turn,
                **cant_block_runtime_replay_fields(effect_data),
                **replay_rule_fields(effect_data),
            )
        return True

    life_gain_requested, life_gained = apply_removal_life_gain(
        effect_data,
        target_controller,
        target,
        source_controller=player,
    )

    if effect_data.get("uses_stat_modifier_removal"):
        try:
            power_delta = int(effect_data.get("power_boost") or 0)
        except Exception:
            power_delta = 0
        try:
            toughness_delta = int(effect_data.get("toughness_boost") or 0)
        except Exception:
            toughness_delta = 0
        remember_until_eot(target, "power")
        remember_until_eot(target, "toughness")
        target["power"] = int(target.get("power") or 0) + power_delta
        target["toughness"] = int(target.get("toughness") or 0) + toughness_delta
        emit_replay_event(
            "removal_resolved",
            player=player.name,
            card=card.get("name", "?"),
            target_player=target_controller.name,
            target=target_name,
            target_effect=get_card_effect(target).get("effect", target.get("effect")),
            target_power=target.get("power"),
            target_toughness=target.get("toughness"),
            target_is_creature=is_battlefield_creature(target),
            target_type_line=target.get("type_line", ""),
            available_targets=1,
            result="stat_modifier_until_eot_applied",
            power_delta=power_delta,
            toughness_delta=toughness_delta,
            turn=turn,
            **decision,
        )
        return True

    emit_replay_event(
        "removal_resolved",
        player=player.name,
        card=card.get("name", "?"),
        target_player=target_controller.name,
        target=target_name,
        target_effect=get_card_effect(target).get("effect", target.get("effect")),
        target_power=target.get("power"),
        target_toughness=target.get("toughness"),
        target_is_creature=is_battlefield_creature(target),
        target_type_line=target.get("type_line", ""),
        available_targets=1,
        destination=removal_destination(effect_data),
        turn=turn,
        **decision,
        **removal_annotation_replay_fields(effect_data),
        **removal_life_gain_replay_fields(
            effect_data,
            life_gain_requested,
            life_gained,
        ),
        **replay_rule_fields(effect_data),
    )
    destination = move_removed_permanent_to_destination(
        target_controller,
        target,
        card,
        effect_data,
        turn,
        rng,
        all_players=players,
    )
    apply_removal_target_controller_life_loss(
        effect_data,
        target_controller,
        card,
        target,
        destination,
        turn,
    )
    apply_removal_target_controller_life_loss_on_resolve(
        effect_data,
        target_controller,
        card,
        target,
        turn,
        phase="resolution",
    )
    apply_removal_target_controller_damage(
        effect_data,
        target_controller,
        player,
        card,
        target,
        turn,
        phase="resolution",
    )
    apply_removal_source_controller_penalty(
        effect_data,
        player,
        card,
        turn,
        phase="resolution",
    )
    apply_cant_block_until_eot_runtime(
        player,
        opponents,
        card,
        effect_data,
        turn,
        target_controller=target_controller,
        target=target,
        all_players=players,
    )
    create_removal_compensation_tokens(effect_data, target_controller, card, turn)
    create_controller_treasures_after_removal(effect_data, player, card, turn)
    return True


def redirectable_stack_context(redirector, all_players, stack_item):
    if stack_item is None or redirector is getattr(stack_item, "controller", None):
        return None
    effect_data = getattr(stack_item, "effect_data", None) or {}
    if effect_data.get("effect") not in TARGETED_REMOVAL_EFFECTS:
        return None
    declared_targets = effect_data.get("declared_targets") or []
    if len(declared_targets) != 1:
        return None

    entry = declared_targets[0]
    old_target = entry.get("target") if isinstance(entry, dict) else entry
    entry_controller = entry.get("controller") if isinstance(entry, dict) else None
    old_controller = declared_target_controller(
        all_players,
        old_target,
        entry_controller=entry_controller,
    )
    target_type = (
        entry.get("target_type") if isinstance(entry, dict) else None
    ) or removal_target_type(effect_data)

    candidates = []
    seen_targets = set()
    for candidate_controller in all_players:
        for candidate in removal_target_candidates(
            candidate_controller,
            effect_data,
            controller=stack_item.controller,
            source=stack_item.card,
        ):
            if candidate is old_target or id(candidate) in seen_targets:
                continue
            seen_targets.add(id(candidate))
            candidates.append({
                "target": candidate,
                "controller": candidate_controller,
            })

    if not candidates:
        return {
            "stack_item": stack_item,
            "declared_entry": entry,
            "old_target": old_target,
            "old_controller": old_controller,
            "target_type": target_type,
            "legal_redirect_opportunity": False,
            "result": "no_legal_new_target",
        }

    preferred_candidates = [
        candidate
        for candidate in candidates
        if candidate["controller"] is not redirector
    ]
    target_pool = preferred_candidates or candidates
    chosen_target = choose_best_creature_target([candidate["target"] for candidate in target_pool])
    chosen = next(candidate for candidate in target_pool if candidate["target"] is chosen_target)
    return {
        "stack_item": stack_item,
        "declared_entry": entry,
        "old_target": old_target,
        "old_controller": old_controller,
        "new_target": chosen["target"],
        "new_controller": chosen["controller"],
        "target_type": target_type,
        "legal_redirect_opportunity": True,
        "result": "redirected",
    }


def effect_can_change_single_stack_target(effect_data):
    if not isinstance(effect_data, dict):
        return False
    if effect_data.get("effect") == "redirect_removal":
        return True
    modes = {str(mode or "").lower() for mode in _as_list(effect_data.get("modes"))}
    redirect_status = str(effect_data.get("redirect_target_mode_status") or "").lower()
    change_status = str(effect_data.get("change_target_mode_status") or "").lower()
    return (
        ("redirect_target" in modes and redirect_status == "runtime_executor_v1")
        or ("change_single_target" in modes and change_status == "runtime_executor_v1")
    )


def target_change_runtime_replay_fields(effect_data):
    fields = {}
    if not isinstance(effect_data, dict):
        return fields
    for key in ("redirect_target_mode_status", "change_target_mode_status"):
        if effect_data.get(key):
            fields[key] = effect_data.get(key)
    if fields:
        fields["target_change_pipeline"] = "single_target_stack_object_redirect_runtime_v1"
    return fields


def resolve_redirect_removal(player, all_players, card, effect_data, turn, phase=None):
    context = (effect_data or {}).get("_redirect_context") or {}
    stack_item = context.get("stack_item")
    if not context or stack_item is None:
        emit_replay_event(
            "redirect_removal_resolved",
            player=player.name,
            card=card.get("name", "?"),
            redirected_object=None,
            old_target=None,
            new_target=None,
            target_type=None,
            legal_redirect_opportunity=False,
            target_change_applied=False,
            result="no_redirect_target",
            turn=turn,
            phase=phase,
            **target_change_runtime_replay_fields(effect_data or {}),
            **spree_replay_fields(effect_data or {}),
            **replay_rule_fields(effect_data or {}),
        )
        finish_resolved_spell(player, card, turn=turn, effect_data=effect_data)
        return False

    old_target = context.get("old_target")
    new_target = context.get("new_target")
    target_type = context.get("target_type")
    redirected_object = (getattr(stack_item, "card", None) or {}).get("name", "?")
    if not new_target:
        emit_replay_event(
            "redirect_removal_resolved",
            player=player.name,
            card=card.get("name", "?"),
            redirected_object=redirected_object,
            old_target=old_target.get("name", "?") if isinstance(old_target, dict) else None,
            new_target=None,
            target_type=target_type,
            legal_redirect_opportunity=False,
            target_change_applied=False,
            result=context.get("result") or "no_legal_new_target",
            turn=turn,
            phase=phase,
            **target_change_runtime_replay_fields(effect_data or {}),
            **spree_replay_fields(effect_data or {}),
            **replay_rule_fields(effect_data or {}),
        )
        finish_resolved_spell(player, card, turn=turn, effect_data=effect_data)
        return False

    entry = context["declared_entry"]
    if isinstance(entry, dict):
        entry["target"] = new_target
        entry["controller"] = context.get("new_controller")
        entry["target_type"] = target_type
        entry["declared_by"] = stack_item.controller
    old_target_name = old_target.get("name", "?") if isinstance(old_target, dict) else None
    new_target_name = new_target.get("name", "?") if isinstance(new_target, dict) else None
    emit_replay_event(
        "redirect_removal_resolved",
        player=player.name,
        card=card.get("name", "?"),
        redirected_object=redirected_object,
        old_target=old_target_name,
        old_target_controller=getattr(context.get("old_controller"), "name", None),
        new_target=new_target_name,
        new_target_controller=getattr(context.get("new_controller"), "name", None),
        target_type=target_type,
        legal_redirect_opportunity=True,
        target_change_applied=True,
        result="redirected",
        turn=turn,
        phase=phase,
        **target_change_runtime_replay_fields(effect_data or {}),
        **spree_replay_fields(effect_data or {}),
        **replay_rule_fields(effect_data or {}),
    )
    finish_resolved_spell(player, card, turn=turn, effect_data=effect_data)
    return True


def game_winner(all_players):
    for player in all_players:
        if not player.has_won():
            continue
        blocked = any(
            opponent is not player
            and opponent.is_alive()
            and getattr(opponent, "cannot_lose_this_turn", False)
            for opponent in all_players
        )
        if not blocked:
            return player
    return None


MAIN_PHASES = {"precombat_main", "postcombat_main"}
SILENCE_PROTECTED_PAYOFF_EFFECTS = {
    "airbend_other_creatures",
    "approach",
    "board_wipe",
    "brain_freeze",
    "damage_each_opponent_and_opponent_creatures",
    "damage_player_and_creatures",
    "damage_wipe",
    "damage_wipe_treasure",
    "exile_artifact_enchantment_creature_convoke_wipe",
    "exile_top_nonland_free_cast",
    "extra_turn",
    "fated_clash_protect_then_destroy",
    "finisher",
    "gift_destroy_all_creatures_return_own_destroyed_creature",
    "graveyard_flashback_grant",
    "life_total_change",
    "overload_recursion",
    "redistribute_life_totals",
    "steal_all_creatures",
    "thassa_oracle",
    "wincon",
    "worldfire_reset",
}


def _restore_payoff_snapshot(player, pool_snapshot, restricted_snapshot, treasures_snapshot, life_snapshot):
    for color, amount in pool_snapshot.items():
        setattr(player.mana_pool, color, amount)
    player.restricted_mana = restricted_snapshot
    player.treasures = treasures_snapshot
    player.life = life_snapshot


def silence_payoff_plan(player, phase, silence_card=None):
    if phase not in MAIN_PHASES:
        return None
    pool_snapshot = player.mana_pool.snapshot()
    restricted_snapshot = copy.deepcopy(player.restricted_mana)
    treasures_snapshot = player.treasures
    life_snapshot = player.life
    if silence_card is not None:
        if not player.can_pay_card(silence_card):
            return None
        if not player.spend_card_mana(silence_card):
            _restore_payoff_snapshot(
                player,
                pool_snapshot,
                restricted_snapshot,
                treasures_snapshot,
                life_snapshot,
            )
            return None
    best = None
    for candidate in getattr(player, "hand", []) or []:
        if (
            candidate is silence_card
            or not isinstance(candidate, dict)
            or is_effective_land(candidate)
        ):
            continue
        effect = str(get_card_effect(candidate).get("effect") or "").lower()
        if (
            effect in COUNTERLIKE_EFFECTS
            or effect in SILENCE_WINDOW_EFFECTS
            or effect in RESPONSE_WINDOW_ONLY_EFFECTS
            or effect not in SILENCE_PROTECTED_PAYOFF_EFFECTS
        ):
            continue
        effect_data = get_card_effect(candidate)
        if not can_cast_in_phase(candidate, effect_data, phase, controller=player):
            continue
        if should_hold_squee_for_lorehold_recursion(player, candidate, phase):
            continue
        if not spell_has_required_library_target(player, effect_data):
            continue
        cast_plan = runtime_cast_plan_for_card(player, candidate, effect_data)
        if cast_plan is None:
            continue
        if not additional_card_costs_are_payable(
            player,
            candidate,
            effect_data,
            cast_plan.get("cost_context"),
        ):
            continue
        all_players = [player] + [
            opponent
            for opponent in getattr(player, "_current_opponents", []) or []
            if opponent is not player
        ]
        score = threat_score(
            effect,
            candidate.get("name", ""),
            player,
            all_players,
            CURRENT_REPLAY_TURN or 0,
        )
        if effect == "approach" and getattr(player, "approach_count", 0) >= 1:
            score = max(score, 100)
        plan = {
            "payoff_card": candidate.get("name", "?"),
            "payoff_effect": effect,
            "payoff_score": score,
            "payoff_cmc": candidate.get("cmc", 0),
        }
        if best is None or score > best["payoff_score"]:
            best = plan
    _restore_payoff_snapshot(
        player,
        pool_snapshot,
        restricted_snapshot,
        treasures_snapshot,
        life_snapshot,
    )
    return best


def has_immediate_silence_payoff(player, phase, silence_card=None):
    return silence_payoff_plan(player, phase, silence_card=silence_card) is not None


def should_hold_for_response_window(player, card, effect_data, phase):
    effect = str((effect_data or {}).get("effect") or card.get("effect") or "").lower()
    if effect in COUNTERLIKE_EFFECTS:
        return True
    if effect == "removal_exile" and removal_exile_targets_stack(effect_data):
        return True
    if effect == "copy_spell" and is_instant_or_sorcery_spell(card):
        return True
    if effect in RESPONSE_WINDOW_ONLY_EFFECTS:
        return True
    if effect == "silence_opponents" and not is_instant(card):
        return False
    if effect in SILENCE_WINDOW_EFFECTS and not has_immediate_silence_payoff(
        player,
        phase,
        silence_card=card,
    ):
        return True
    return False


SURVIVAL_RESPONSE_RESERVE_LIFE_TOTAL = 15
SURVIVAL_RESPONSE_EFFECTS = {"phase_out", "cannot_lose_turn", "gift_hexproof_indestructible", "damage_prevention_shield"}
PROACTIVE_COMBAT_DEFENSE_EFFECTS = {"attack_limit", "attack_tax", "equipment_static_attachment"}
SURVIVAL_RESERVATION_EXEMPT_EFFECTS = {
    "phase_out",
    "cannot_lose_turn",
    "airbend_other_creatures",
    "board_wipe",
    "damage_wipe",
    "exile_artifact_enchantment_creature_convoke_wipe",
    "fated_clash_protect_then_destroy",
    "gift_destroy_all_creatures_return_own_destroyed_creature",
    "selective_nonland_sacrifice",
    "vow_counter_each_player_sacrifice_rest",
    "damage_player_and_creatures",
    "remove_creature",
    "remove_permanent",
    "approach",
    "finisher",
    "worldfire_reset",
}


def is_the_one_ring(card_or_name):
    if isinstance(card_or_name, dict):
        name = card_or_name.get("name", "")
    else:
        name = card_or_name
    return normalize_card_name(name) == "the one ring"


def grants_protection_from_everything_on_enter(card, effect_data=None):
    effect_data = effect_data or {}
    return bool(
        effect_data.get("protection_from_everything_on_enter")
        or effect_data.get("one_ring_protection_on_enter")
        or is_the_one_ring(card)
    )


def is_orims_chant(card_or_name):
    if isinstance(card_or_name, dict):
        name = card_or_name.get("name", "")
    else:
        name = card_or_name
    return normalize_card_name(name) == "orim's chant"


def orims_chant_kicker_costs():
    return ["{W}"]


def grants_kicked_attack_prevention(card, effect_data=None):
    effect_data = effect_data or {}
    return bool(
        effect_data.get("kicker_prevent_attacks")
        or effect_data.get("kicked_prevent_attacks")
        or effect_data.get("prevent_attacks_if_kicked")
        or is_orims_chant(card)
    )


def can_pay_orims_chant_kicked(player, card):
    return player.can_pay(card_mana_cost(card, additional_costs=orims_chant_kicker_costs()))


def proactive_combat_defense_cards_in_hand(player, phase):
    if phase not in ("precombat_main", "postcombat_main"):
        return []
    defense_cards = []
    for candidate in getattr(player, "hand", []) or []:
        if not isinstance(candidate, dict) or is_effective_land(candidate):
            continue
        candidate_effect = get_card_effect(candidate)
        effect = str(candidate_effect.get("effect") or candidate.get("effect") or "").lower()
        if (
            effect not in PROACTIVE_COMBAT_DEFENSE_EFFECTS
            and not grants_protection_from_everything_on_enter(candidate, candidate_effect)
        ):
            continue
        if not can_cast_in_phase(candidate, candidate_effect, phase, controller=player):
            continue
        if not player.can_pay_card(candidate):
            continue
        defense_cards.append((candidate, candidate_effect))
    return defense_cards


def should_prioritize_proactive_combat_defense(player, card, effect_data=None, phase=None):
    if phase not in ("precombat_main", "postcombat_main"):
        return False
    if getattr(player, "life", 0) > SURVIVAL_RESPONSE_RESERVE_LIFE_TOTAL:
        return False
    effect = str((effect_data or {}).get("effect") or card.get("effect") or "").lower()
    if effect in {"approach", "wincon"}:
        return False
    if effect in PROACTIVE_COMBAT_DEFENSE_EFFECTS or grants_protection_from_everything_on_enter(card, effect_data):
        return False
    return bool(proactive_combat_defense_cards_in_hand(player, phase))


def survival_response_cards_in_hand(player, *, exclude_card=None):
    response_cards = []
    for candidate in getattr(player, "hand", []) or []:
        if candidate is exclude_card or not isinstance(candidate, dict):
            continue
        if not is_instant(candidate):
            continue
        candidate_effect = get_card_effect(candidate)
        effect = str(candidate_effect.get("effect") or "").lower()
        if effect in SURVIVAL_RESPONSE_EFFECTS:
            response_cards.append((candidate, candidate_effect))
    return response_cards


def _can_pay_any_survival_response_from_state(
    player,
    response_cards,
    pool_snapshot,
    treasures,
    restricted_mana,
    life,
    conditional_mana_sources=None,
):
    original_pool = player.mana_pool.snapshot()
    original_treasures = player.treasures
    original_restricted = copy.deepcopy(player.restricted_mana)
    original_conditional = copy.deepcopy(getattr(player, "conditional_mana_sources", []))
    original_life = player.life
    try:
        for color, amount in pool_snapshot.items():
            setattr(player.mana_pool, color, amount)
        player.treasures = treasures
        player.restricted_mana = copy.deepcopy(restricted_mana)
        player.conditional_mana_sources = copy.deepcopy(conditional_mana_sources or [])
        player.life = life
        return any(player.can_pay_card(card) for card, _effect in response_cards)
    finally:
        for color, amount in original_pool.items():
            setattr(player.mana_pool, color, amount)
        player.treasures = original_treasures
        player.restricted_mana = original_restricted
        player.conditional_mana_sources = original_conditional
        player.life = original_life


def survival_response_reservation_context(player, card, effect_data=None, additional_generic=0):
    """Prevent low-life pilots from spending mana reserved for instant survival."""
    if getattr(player, "life", 0) > SURVIVAL_RESPONSE_RESERVE_LIFE_TOTAL:
        return None
    effect = str((effect_data or {}).get("effect") or card.get("effect") or "").lower()
    if grants_protection_from_everything_on_enter(card, effect_data):
        return None
    if effect in SURVIVAL_RESERVATION_EXEMPT_EFFECTS:
        return None
    response_cards = survival_response_cards_in_hand(player, exclude_card=card)
    if not response_cards:
        return None
    currently_payable = [
        (response_card, response_effect)
        for response_card, response_effect in response_cards
        if player.can_pay_card(response_card)
    ]
    if not currently_payable:
        return None
    payment_plan = player._payment_plan(card_mana_cost(card, additional_generic))
    if payment_plan is None:
        return None
    (
        pool_after,
        treasures_after,
        life_payment,
        restricted_after,
        conditional_after,
        _conditional_life_payments,
    ) = payment_plan
    life_after = player.life - life_payment
    if _can_pay_any_survival_response_from_state(
        player,
        currently_payable,
        pool_after,
        treasures_after,
        restricted_after,
        life_after,
        conditional_after,
    ):
        return None
    return {
        "reserved_response_cards": [response_card.get("name", "?") for response_card, _ in currently_payable],
        "reserved_response_effects": [response_effect.get("effect", "unknown") for _, response_effect in currently_payable],
        "life_before": player.life,
        "candidate": card.get("name", "?"),
        "candidate_effect": effect,
        "reason": "preserve_survival_response_mana_at_low_life",
    }


def should_reserve_survival_response_mana(player, card, effect_data=None, phase=None, additional_generic=0):
    if phase not in ("precombat_main", "postcombat_main"):
        return False
    return survival_response_reservation_context(
        player,
        card,
        effect_data,
        additional_generic=additional_generic,
    ) is not None


def _numeric_effect_amount(value, default=0):
    try:
        return int(value)
    except (TypeError, ValueError):
        return default


def cannot_lose_turn_stack_response_context(player, top_item):
    if not top_item or top_item.controller is player:
        return None
    effect_data = top_item.effect_data or {}
    top_effect = str(effect_data.get("effect") or "").lower()
    if top_effect == "approach" and getattr(top_item.controller, "approach_count", 0) >= 1:
        return {
            "immediate_loss_source": "approach_second_cast",
            "reason": "prevent_opponent_immediate_win",
        }
    if top_effect == "damage_player_and_creatures":
        amount = _numeric_effect_amount(effect_data.get("amount"), 4)
        if player.life <= amount:
            return {
                "immediate_loss_source": "lethal_damage_spell",
                "projected_damage": amount,
                "life_before": player.life,
                "reason": "prevent_lethal_damage_spell",
            }
    if top_effect == "deal_damage":
        amount = _numeric_effect_amount(effect_data.get("amount"), 0)
        target = str(effect_data.get("target") or "").lower()
        if amount > 0 and target in {"any", "player", "opponent", "player_or_planeswalker"} and player.life <= amount:
            return {
                "immediate_loss_source": "lethal_direct_damage",
                "projected_damage": amount,
                "life_before": player.life,
                "reason": "prevent_lethal_damage_spell",
            }
    return None


def stack_spell_damage_prevention_context(player, top_item):
    if not top_item or top_item.controller is player:
        return None
    source_card = getattr(top_item, "card", None) or {}
    effect_data = getattr(top_item, "effect_data", None) or {}
    if not is_instant_or_sorcery_spell(source_card):
        return None
    top_effect = str(effect_data.get("effect") or "").lower()
    projected_damage = 0
    affects_player = False
    if top_effect == "damage_player_and_creatures":
        projected_damage = _numeric_effect_amount(effect_data.get("amount"), 4)
        affects_player = True
    elif top_effect in {"damage_each_opponent", "damage_each_opponent_and_opponent_creatures"}:
        projected_damage = _numeric_effect_amount(
            effect_data.get("amount") or effect_data.get("damage"),
            0,
        )
        affects_player = True
    elif top_effect in {"deal_damage", "direct_damage"}:
        projected_damage = _numeric_effect_amount(
            effect_data.get("amount") or effect_data.get("damage"),
            0,
        )
        affects_player = projected_damage > 0 and direct_damage_targets_player(effect_data)
    if not affects_player or projected_damage <= 0:
        return None
    return {
        "source_card": source_card,
        "source_name": source_card.get("name", "?"),
        "source_controller": getattr(getattr(top_item, "controller", None), "name", None),
        "source_effect": top_effect,
        "projected_damage": projected_damage,
        "lethal": projected_damage >= max(1, int(getattr(player, "life", 0) or 0)),
        "reason": "prevent_target_instant_or_sorcery_spell_damage",
    }


def best_hand_to_top_card_for_spell_prevention(player, context):
    hand_cards = [card for card in getattr(player, "hand", []) or [] if isinstance(card, dict)]
    if not hand_cards:
        return None, []
    miracle_candidates = [card for card in hand_cards if miracle_card_scope_allows(player, card)]
    candidates = miracle_candidates or (hand_cards if context.get("lethal") else [])
    scored = sorted(
        (
            {
                "card": card,
                "score": lorehold_draw_priority(card, player),
            }
            for card in candidates
        ),
        key=lambda item: (
            -item["score"],
            -int(_opening_hand_card_cmc(item["card"]) or 0),
            item["card"].get("name", "?"),
        ),
    )
    if not scored:
        return None, []
    chosen = scored[0]
    if context.get("lethal"):
        return chosen, scored
    top_before = player.library[0] if getattr(player, "library", None) else None
    top_before_score = lorehold_draw_priority(top_before, player) if top_before else -999
    if chosen["score"] < 130 or chosen["score"] <= top_before_score:
        return None, scored
    return chosen, scored


def activate_stack_spell_damage_prevention_permanent(player, permanent, top_item, context, turn, phase):
    effect_data = {**get_card_effect(permanent), **permanent}
    if effect_data.get("effect") != "damage_prevention_shield":
        return False
    if permanent.get("utility_artifact_used_this_turn"):
        return False
    if not effect_data.get("activated_prevent_damage_from_target_spell"):
        return False
    if not effect_data.get("spell_target_required"):
        return False
    if effect_data.get("prevent_damage_target_type") != "instant_or_sorcery_spell":
        return False
    if effect_data.get("activation_requires_tap") and permanent.get("tapped"):
        return False
    chosen, scored = best_hand_to_top_card_for_spell_prevention(player, context)
    if chosen is None:
        return False
    payment_card = chosen["card"]
    activation_cost_generic = int(effect_data.get("activation_cost_generic") or 0)
    activation_colors = list(effect_data.get("activation_cost_colors") or [])
    activation_cost_text = ""
    if activation_cost_generic > 0:
        activation_cost_text += "{%d}" % activation_cost_generic
    activation_cost_text += "".join("{%s}" % color for color in activation_colors)
    if not activation_cost_text:
        activation_cost_text = "{0}"
    if not player.can_pay(activation_cost_text) or not player.spend_mana(activation_cost_text):
        return False
    top_before = player.library[0] if getattr(player, "library", None) else None
    player.hand.remove(payment_card)
    player.library.insert(0, payment_card)
    permanent["utility_artifact_used_this_turn"] = True
    if effect_data.get("activation_requires_tap"):
        permanent["tapped"] = True
    add_damage_prevention_shield(
        player,
        int(effect_data.get("prevent_damage_amount") or 999),
        source=permanent.get("name", "damage_prevention_shield"),
        source_match="chosen_source",
        chosen_source_name=context.get("source_name"),
        chosen_source_controller=context.get("source_controller"),
        consume_once=True,
        turn=turn,
    )
    fields = replay_rule_fields(effect_data)
    emit_decision_trace(
        decision_type="response",
        player=player,
        turn=turn,
        phase=phase,
        available_options=[
            decision_card_option(
                item["card"],
                score=item["score"],
                action="put_card_from_hand_on_top",
                effect="target_spell_damage_prevention",
            )
            for item in scored[:8]
        ],
        chosen_option=decision_card_option(
            payment_card,
            score=chosen["score"],
            action="activate_target_spell_damage_prevention",
            effect="target_spell_damage_prevention",
        ),
        rejected_options=[
            decision_card_option(
                item["card"],
                score=item["score"],
                action="leave_in_hand",
                effect="target_spell_damage_prevention",
            )
            for item in scored[1:8]
        ],
        score_components={
            "projected_damage": context.get("projected_damage"),
            "life_before_damage": player.life,
            "lethal": int(bool(context.get("lethal"))),
            "top_before": top_before.get("name", "?") if top_before else None,
            "top_after": payment_card.get("name", "?"),
            "target_spell": context.get("source_name"),
            "target_spell_controller": context.get("source_controller"),
        },
        rule_source=fields.get("rule_source", "battle_heuristic"),
        rule_status=fields.get("rule_review_status", "heuristic"),
        confidence="medium",
        expected_benefit_score=max(int(context.get("projected_damage") or 0), chosen["score"]),
        actual_outcome="target_spell_damage_prevention_shield_created",
        reason=context.get("reason"),
        strategic_principle="use target-spell prevention only when a legal instant or sorcery damage source is on the stack",
        heuristic_version=DECISION_STRATEGY_VERSION,
        risk_flags=["requires_target_spell_on_stack", "hand_card_moved_to_library"],
    )
    emit_replay_event(
        "activated_ability",
        player=player.name,
        card=permanent.get("name", "?"),
        effect=effect_data.get("effect", "unknown"),
        activation_kind="put_card_from_hand_on_top_library_prevent_target_spell_damage",
        activation_cost=effect_data.get("activation_cost", "put_card_from_hand_on_top_of_library"),
        target_spell=context.get("source_name"),
        target_spell_controller=context.get("source_controller"),
        projected_damage=context.get("projected_damage"),
        topdecked_card=payment_card.get("name", "?"),
        turn=turn,
        phase=phase,
        **fields,
    )
    emit_replay_event(
        "damage_prevention_shield_created",
        player=player.name,
        card=permanent.get("name", "?"),
        chosen_source=context.get("source_name"),
        chosen_source_controller=context.get("source_controller"),
        prevention_amount=int(effect_data.get("prevent_damage_amount") or 999),
        topdecked_card=payment_card.get("name", "?"),
        turn=turn,
        phase=phase,
        **fields,
    )
    emit_replay_event(
        "hand_to_topdeck_activation",
        player=player.name,
        card=permanent.get("name", "?"),
        activation_kind="put_card_from_hand_on_top_for_target_spell_prevention",
        top_before=top_before.get("name", "?") if top_before else None,
        top_after=payment_card.get("name", "?"),
        hand_to_top=payment_card.get("name", "?"),
        activation_cost=activation_cost_text,
        phase=phase,
        turn=turn,
        **fields,
    )
    return True


def blue_devotion(player):
    devotion = 0
    for permanent in getattr(player, "battlefield", []) or []:
        if not isinstance(permanent, dict):
            continue
        mana_cost = str(permanent.get("mana_cost") or "")
        devotion += mana_cost.count("{U}")
        devotion += mana_cost.count("{U/P}")
        for hybrid in ("{W/U}", "{U/B}", "{G/U}", "{U/R}", "{2/U}"):
            devotion += mana_cost.count(hybrid)
    return devotion


def brain_freeze_copy_count(player):
    return max(1, int(getattr(player, "spells_cast_this_turn", 0) or 0))


def brain_freeze_total_mill(player, effect_data):
    per_copy = int((effect_data or {}).get("mill_count") or 3)
    return max(0, per_copy) * brain_freeze_copy_count(player)


def choose_mill_target(player, opponents, total_mill):
    alive_opponents = [opponent for opponent in opponents if opponent.is_alive()]
    if not alive_opponents:
        return player
    lethal_targets = [
        opponent
        for opponent in alive_opponents
        if len(getattr(opponent, "library", []) or []) <= total_mill
    ]
    if lethal_targets:
        return min(lethal_targets, key=lambda opponent: (len(opponent.library), opponent.life, opponent.name))
    return min(alive_opponents, key=lambda opponent: (len(opponent.library), opponent.life, opponent.name))


def graveyard_distinct_card_type_count(player):
    card_types = set()
    for card in getattr(player, "graveyard", []) or []:
        if not isinstance(card, dict):
            continue
        type_line = str(card.get("type_line") or "").lower()
        for card_type in (
            "artifact",
            "battle",
            "creature",
            "enchantment",
            "instant",
            "land",
            "planeswalker",
            "sorcery",
            "tribal",
        ):
            if card_type in type_line:
                card_types.add(card_type)
    return len(card_types)


def priority_order_from(active_player, all_players):
    if active_player in all_players:
        idx = all_players.index(active_player)
        ordered = [all_players[(idx + i) % len(all_players)] for i in range(len(all_players))]
    else:
        ordered = list(all_players)
    return [player for player in ordered if player.is_alive()]


def emit_priority_pass_sequence(active_player, all_players, turn, phase=None, reason=None, stack_item=None):
    order = priority_order_from(active_player, all_players)
    record_engine_metric("priority_passes", len(order))
    stack_top = None
    if stack_item is not None:
        stack_top = stack_item.card.get("name", "?") if isinstance(stack_item.card, dict) else str(stack_item.card)
    for index, player in enumerate(order, start=1):
        emit_replay_event(
            "priority_pass",
            active_player=active_player.name,
            player=player.name,
            pass_index=index,
            phase=phase,
            reason=reason,
            stack_top=stack_top,
            turn=turn,
        )
    return order


def protection_colors_for_source(source):
    if not isinstance(source, dict):
        return []
    colors = source.get("colors") or source.get("color_identity") or []
    if isinstance(colors, str):
        colors = read_json_list(colors) or [colors]
    normalized = sorted({_normalize_color_symbol(color) for color in colors if color})
    if normalized:
        return normalized
    type_line = str(source.get("type_line") or "").lower()
    mana_cost = str(source.get("mana_cost") or "")
    if "artifact" in type_line or (not re.search(r"\{[WUBRG]", mana_cost.upper())):
        return ["colorless"]
    return []


def targeted_stack_protection_context(player, stack_item):
    if stack_item is None or getattr(stack_item, "controller", None) is player:
        return None
    effect_data = getattr(stack_item, "effect_data", {}) or {}
    if effect_data.get("effect") not in TARGETED_REMOVAL_EFFECTS:
        return None
    source_colors = protection_colors_for_source(getattr(stack_item, "card", None))
    if not source_colors:
        return None
    for entry in effect_data.get("declared_targets") or []:
        if not isinstance(entry, dict):
            continue
        target = entry.get("target")
        controller = entry.get("controller")
        if controller is not player and getattr(controller, "name", None) != player.name:
            continue
        if target not in getattr(player, "battlefield", []):
            continue
        if not is_battlefield_creature(target):
            continue
        return {
            "target": target,
            "target_name": target.get("name", "?"),
            "source_card": (getattr(stack_item, "card", None) or {}).get("name", "?"),
            "source_object": getattr(stack_item, "card", None),
            "source_colors": source_colors,
            "target_is_commander": bool(target.get("is_commander")),
        }
    return None


def protection_card_can_cover_stack_context(card, effect_data, context):
    if not context:
        return False
    effect = (effect_data or {}).get("effect")
    if (effect_data or {}).get("can_make_source_white_for_protection"):
        return True
    if effect == "grant_protection_from_chosen_color":
        return any(color != "colorless" for color in context.get("source_colors") or [])
    choices = {
        str(choice or "").strip().lower()
        for choice in (effect_data or {}).get("protection_choices") or []
    }
    source_colors = set(context.get("source_colors") or [])
    return (
        "chosen_color" in choices
        and any(color != "colorless" for color in source_colors)
    ) or ("colorless" in choices and "colorless" in source_colors)


def targeted_protection_effect_data_for_permanent(permanent):
    effect_data = dict(get_card_effect(permanent))
    if isinstance(permanent, dict):
        effect_data.update(permanent)
    return effect_data


def activate_permanent_targeted_protection_response(player, permanent, context, turn, phase=None):
    effect_data = targeted_protection_effect_data_for_permanent(permanent)
    if not protection_card_can_cover_stack_context(permanent, effect_data, context):
        return False
    target = context.get("target")
    if effect_data.get("protection_target") == "another_creature_you_control" and target is permanent:
        return False
    requires_tap = bool(effect_data.get("tap_activation") or effect_data.get("activation_requires_tap"))
    if requires_tap and (permanent.get("tapped") or permanent.get("summoning_sick")):
        return False
    activation_mana_cost = (
        effect_data.get("targeted_protection_activation_mana_cost")
        or effect_data.get("protection_activation_mana_cost")
    )
    if activation_mana_cost:
        if not player.can_pay(activation_mana_cost):
            emit_replay_event(
                "targeted_protection_activation_skipped",
                player=player.name,
                card=permanent.get("name", "?"),
                reason="insufficient_mana_for_activation_cost",
                activation_mana_cost=activation_mana_cost,
                available_mana=player.available_mana(),
                turn=turn,
                **replay_rule_fields(effect_data),
            )
            return False
        if not player.spend_mana(activation_mana_cost):
            emit_replay_event(
                "targeted_protection_activation_skipped",
                player=player.name,
                card=permanent.get("name", "?"),
                reason="failed_to_pay_activation_mana_cost",
                activation_mana_cost=activation_mana_cost,
                available_mana=player.available_mana(),
                turn=turn,
                **replay_rule_fields(effect_data),
            )
            return False
    if effect_data.get("can_make_source_white_for_protection"):
        colors = ["white"]
        source_color_changed_to = "white"
        source_object = context.get("source_object")
        if isinstance(source_object, dict):
            source_object.setdefault("_colors_before_targeted_protection_change", source_object.get("colors"))
            source_object["colors"] = ["W"]
    else:
        colors = list(context.get("source_colors") or [])
        source_color_changed_to = None
    existing = target.get("protection_from") or []
    if isinstance(existing, str):
        existing = [existing]
    merged = sorted({_normalize_color_symbol(color) for color in existing if color} | set(colors))
    set_until_eot(target, "protection_from", merged)
    if requires_tap:
        permanent["tapped"] = True
    emit_replay_event(
        "activated_ability",
        player=player.name,
        card=permanent.get("name", "?"),
        activation_kind="targeted_protection_response",
        target=context.get("target_name"),
        protection_from=colors,
        response_to=context.get("source_card"),
        source_color_changed_to=source_color_changed_to,
        activation_mana_cost=activation_mana_cost,
        tapped=bool(permanent.get("tapped")),
        phase=phase,
        turn=turn,
        **replay_rule_fields(effect_data),
    )
    emit_replay_event(
        "targeted_protection_granted",
        player=player.name,
        card=permanent.get("name", "?"),
        target=context.get("target_name"),
        protection_from=colors,
        target_found=True,
        activation_kind="targeted_protection_response",
        response_to=context.get("source_card"),
        source_color_changed_to=source_color_changed_to,
        activation_mana_cost=activation_mana_cost,
        turn=turn,
        **replay_rule_fields(effect_data),
    )
    return True


def _is_reactive_interaction_card(card, effect_data):
    effect = str(effect_data.get("effect") or card.get("effect") or "").lower()
    if effect in (
        "counter",
        "counter_spell",
        "phase_out",
        "indestructible",
        "cannot_lose_turn",
        "modal_boros_charm",
        "remove_creature",
        "remove_permanent",
        "remove_artifact_or_enchantment",
        "bounce",
    ):
        return True
    return is_instant(card) or card_has_functional_tag(card, "counter", "protection", "removal")


def _pass_option_trace_score(card, effect_data, *, payable, phase_legal, reactive, main_phase_relevant):
    cmc = int(float(card.get("cmc") or 0))
    effect = str(effect_data.get("effect") or card.get("effect") or card.get("tag") or "").lower()
    score = 0.0
    if payable:
        score += 3.0
    else:
        score -= max(1.0, float(cmc))
    if phase_legal:
        score += 3.0
    if reactive:
        score += 2.0
    if effect in OPENING_HAND_RAMP_EFFECTS:
        score += 2.5
    elif effect in OPENING_HAND_CARD_FLOW_EFFECTS:
        score += 2.0
    elif effect in OPENING_HAND_REACTIVE_EFFECTS:
        score += 1.5
    elif effect in HIGH_IMPACT_PAYOFF_EFFECTS:
        score += 1.0
    if main_phase_relevant and not reactive and phase_legal:
        score += 1.0
    return round(score, 2)


def describe_pass_no_action(player, phase):
    nonland_cards = [
        card
        for card in player.hand
        if isinstance(card, dict) and not is_effective_land(card)
    ]
    available_options = [{"action": "pass"}]
    alternatives = []
    castable_now = []
    reactive_options = []
    affordable_cards = []
    main_phase_relevant = phase in MAIN_PHASES
    minimum_cmc = None

    for card in nonland_cards:
        effect_data = get_card_effect(card)
        cmc = int(float(card.get("cmc") or 0))
        payable = bool(player.can_pay_card(card))
        phase_legal = bool(can_cast_in_phase(card, effect_data, phase, controller=player))
        if minimum_cmc is None or cmc < minimum_cmc:
            minimum_cmc = cmc
        option_score = _pass_option_trace_score(
            card,
            effect_data,
            payable=payable,
            phase_legal=phase_legal,
            reactive=_is_reactive_interaction_card(card, effect_data),
            main_phase_relevant=main_phase_relevant,
        )
        option = decision_card_option(
            card,
            effect_data,
            action="consider",
            score=option_score,
            payable=payable,
            phase_legal=phase_legal,
            reactive=_is_reactive_interaction_card(card, effect_data),
        )
        alternatives.append(option)
        if payable:
            affordable_cards.append(option)
        if payable and phase_legal:
            castable_now.append(option)
        if payable and _is_reactive_interaction_card(card, effect_data):
            reactive_options.append(option)

    score_components = {
        "stack_empty": 1,
        "main_phase_action_taken": 0,
        "phase_is_main": 1 if main_phase_relevant else 0,
        "hand_nonland_count": len(nonland_cards),
        "affordable_card_count": len(affordable_cards),
        "castable_now_count": len(castable_now),
        "reactive_option_count": len(reactive_options),
        "available_mana": player.available_mana(),
        "minimum_hand_cmc": minimum_cmc or 0,
    }
    risk_flags = []

    if main_phase_relevant:
        if castable_now:
            available_options.extend(castable_now[:8])
            if castable_now and len(castable_now) == len(reactive_options):
                reason = "hold_instant_speed_interaction"
                risk_flags.append("holding_instant_speed_interaction")
            else:
                reason = "defer_low_value_main_phase_action"
                risk_flags.append("low_value_main_phase_lines_only")
        elif reactive_options:
            available_options.extend(reactive_options[:8])
            reason = "hold_instant_speed_interaction"
            risk_flags.append("holding_instant_speed_interaction")
        elif affordable_cards:
            reason = "phase_or_heuristic_restriction_blocks_line"
            risk_flags.append("phase_restricted_action")
        elif nonland_cards:
            reason = "no_affordable_nonland_action"
            risk_flags.append("mana_constrained_hand")
        else:
            reason = "no_nonland_resources_available"
            risk_flags.append("empty_nonland_hand")
    else:
        if reactive_options:
            available_options.extend(reactive_options[:8])
            reason = "reactive_window_held"
            risk_flags.append("holding_instant_speed_interaction")
        elif nonland_cards:
            reason = "no_reactive_action_in_window"
            risk_flags.append("phase_restricted_action")
        else:
            reason = "no_nonland_resources_available"
            risk_flags.append("empty_nonland_hand")

    chosen_option = {"action": "pass", "reason": reason, "score": 0}
    rejected_options = [
        {**option, "action": "defer"}
        for option in available_options[1:9]
    ]
    return {
        "available_options": available_options,
        "chosen_option": chosen_option,
        "rejected_options": rejected_options,
        "alternatives_considered": alternatives[:12],
        "score_components": score_components,
        "risk_flags": sorted(set(risk_flags)),
        "reason": reason,
    }


def own_approach_to_top_counters(player, top_item):
    if top_item is None or getattr(top_item, "controller", None) is not player:
        return []
    return [
        counter
        for counter in player.counterspell_cards(
            castable_only=True,
            target_card=getattr(top_item, "card", None),
            stack_item=top_item,
        )
        if get_card_effect(counter).get("counter_own_approach_to_top")
        and get_card_effect(counter).get("countered_spell_to_top_library")
    ]


def should_lapse_own_approach_to_top(player, top_item):
    if top_item is None or getattr(top_item, "controller", None) is not player:
        return False
    if not is_approach_of_the_second_sun(
        getattr(top_item, "card", None),
        getattr(top_item, "effect_data", None),
    ):
        return False
    if int(getattr(player, "approach_count", 0) or 0) != 1:
        return False
    return bool(own_approach_to_top_counters(player, top_item))


def priority_round(active_player, all_players, stack, turn, rng, phase=None):
    """v9: Priority round with optional empty-stack window during main phases."""
    record_engine_metric("priority_rounds")
    flush_triggers_in_apnap(active_player, all_players, stack)

    if stack.empty():
        if phase in MAIN_PHASES and active_player.is_alive():
            opponents = [p for p in all_players if p != active_player and p.is_alive()]
            acted = cast_spells_v8(
                active_player,
                opponents,
                all_players,
                turn,
                phase,
                stack,
                rng,
                max_actions=1,
            )
            if acted:
                check_sbas_until_stable(all_players)
                flush_triggers_in_apnap(active_player, all_players, stack)
                return True
            if activate_best_generic_destroy_permanent(
                active_player,
                opponents,
                all_players,
                turn,
                rng,
                phase=phase,
            ):
                check_sbas_until_stable(all_players)
                flush_triggers_in_apnap(active_player, all_players, stack)
                return True
            if activate_best_generic_bounce_permanent(
                active_player,
                opponents,
                all_players,
                turn,
                rng,
                phase=phase,
            ):
                check_sbas_until_stable(all_players)
                flush_triggers_in_apnap(active_player, all_players, stack)
                return True
            if activate_best_generic_tap_target_permanent(
                active_player,
                opponents,
                all_players,
                turn,
                rng,
                phase=phase,
            ):
                check_sbas_until_stable(all_players)
                flush_triggers_in_apnap(active_player, all_players, stack)
                return True
            if activate_best_generic_untap_target_permanent(
                active_player,
                opponents,
                all_players,
                turn,
                rng,
                phase=phase,
            ):
                check_sbas_until_stable(all_players)
                flush_triggers_in_apnap(active_player, all_players, stack)
                return True
            if activate_best_gate_tap_untap_source(
                active_player,
                all_players,
                turn,
                rng,
                phase=phase,
            ):
                check_sbas_until_stable(all_players)
                flush_triggers_in_apnap(active_player, all_players, stack)
                return True
            if activate_best_gate_land_animation_permanent(
                active_player,
                all_players,
                turn,
                rng,
                phase=phase,
            ):
                check_sbas_until_stable(all_players)
                flush_triggers_in_apnap(active_player, all_players, stack)
                return True
            if activate_best_generic_tap_damage_permanent(
                active_player,
                opponents,
                all_players,
                turn,
                rng,
                phase=phase,
            ):
                check_sbas_until_stable(all_players)
                flush_triggers_in_apnap(active_player, all_players, stack)
                return True
            if activate_best_generic_token_maker_permanent(
                active_player,
                opponents,
                all_players,
                turn,
                rng,
                phase=phase,
            ):
                check_sbas_until_stable(all_players)
                flush_triggers_in_apnap(active_player, all_players, stack)
                return True
            if activate_best_generic_self_boost_permanent(
                active_player,
                all_players,
                turn,
                rng,
                phase=phase,
            ):
                check_sbas_until_stable(all_players)
                flush_triggers_in_apnap(active_player, all_players, stack)
                return True
            if activate_best_generic_self_keyword_permanent(
                active_player,
                all_players,
                turn,
                rng,
                phase=phase,
            ):
                check_sbas_until_stable(all_players)
                flush_triggers_in_apnap(active_player, all_players, stack)
                return True
            if activate_best_generic_add_counters_target_permanent(
                active_player,
                opponents,
                all_players,
                turn,
                rng,
                phase=phase,
            ):
                check_sbas_until_stable(all_players)
                flush_triggers_in_apnap(active_player, all_players, stack)
                return True
            if activate_best_generic_target_boost_permanent(
                active_player,
                opponents,
                all_players,
                turn,
                rng,
                phase=phase,
            ):
                check_sbas_until_stable(all_players)
                flush_triggers_in_apnap(active_player, all_players, stack)
                return True
            if activate_best_generic_target_keyword_permanent(
                active_player,
                opponents,
                all_players,
                turn,
                rng,
                phase=phase,
            ):
                check_sbas_until_stable(all_players)
                flush_triggers_in_apnap(active_player, all_players, stack)
                return True
        emit_priority_pass_sequence(
            active_player,
            all_players,
            turn,
            phase=phase,
            reason="empty_stack",
        )
        pass_context = describe_pass_no_action(active_player, phase)
        emit_decision_trace(
            decision_type="pass_no_action",
            player=active_player,
            turn=turn,
            phase=phase,
            available_options=pass_context["available_options"],
            chosen_option=pass_context["chosen_option"],
            rejected_options=pass_context["rejected_options"],
            score_components=pass_context["score_components"],
            rule_source="battle_heuristic",
            rule_status="heuristic",
            confidence="medium",
            expected_benefit_score=0,
            actual_outcome="priority_pass",
            reason=pass_context["reason"],
            heuristic_version=DECISION_STRATEGY_VERSION,
            risk_flags=pass_context["risk_flags"],
            alternatives_considered=pass_context["alternatives_considered"],
            rejected_reason="preserve_resources_or_no_profitable_line",
        )
        return False

    order = priority_order_from(active_player, all_players)

    # v8.2: Score the top spell
    top_item = stack.items[-1] if stack.items else None
    if not top_item:
        return False
    if phase is None:
        phase = (
            (top_item.effect_data.get("_cast_context") or {}).get("phase")
            or (top_item.effect_data.get("_resolution_context") or {}).get("phase")
        )
    ensure_stack_cast_ledger_event(top_item, turn, phase)
    if top_item.countered:
        stack.resolve_top()
        return False
    score = threat_score(top_item.effect_data.get("effect", ""), top_item.card.get("name", ""),
                         top_item.controller, all_players, turn)

    for player in order:
        if not player.is_alive():
            continue
        if player == top_item.controller and should_lapse_own_approach_to_top(player, top_item):
            counters = own_approach_to_top_counters(player, top_item)
            counter = counters[0] if counters else None
            if counter is not None:
                used_counter = player.use_counterspell(
                    turn,
                    top_item.card,
                    stack_item=top_item,
                    stack_depth=len(stack.items),
                    phase=phase,
                    priority_window="own_approach_topdeck_combo",
                    preferred_counter=counter,
                    all_players=all_players,
                )
                if used_counter:
                    fields = replay_rule_fields(get_card_effect(used_counter))
                    emit_decision_trace(
                        decision_type="response",
                        player=player,
                        turn=turn,
                        phase=phase,
                        available_options=[
                            decision_card_option(
                                option_card,
                                get_card_effect(option_card),
                                action="counter_own_approach_to_top",
                            )
                            for option_card in counters[:8]
                        ],
                        chosen_option=decision_card_option(
                            used_counter,
                            get_card_effect(used_counter),
                            action="counter_own_approach_to_top",
                        ),
                        rejected_options=[],
                        score_components={
                            "approach_count": getattr(player, "approach_count", 0),
                            "available_own_approach_top_counters": len(counters),
                        },
                        rule_source=fields.get("rule_source", "battle_heuristic"),
                        rule_status=fields.get("rule_review_status", "heuristic"),
                        confidence="medium",
                        expected_benefit_score=85,
                        actual_outcome="own_approach_countered_to_top",
                        reason="counter_first_approach_to_setup_second_cast_miracle",
                    )
                    if not used_counter.get("_counter_tax_paid"):
                        stack.items[-1].countered = True
                    return True
        if player != top_item.controller and (
            top_item.controller.silenced_opponents
            or top_item.controller.silenced_opponents_until_eot
        ):
            continue
        if player != top_item.controller:
            instants = [c for c in player.hand if is_instant(c)]
            for c in instants:
                eff = get_card_effect(c)
                if not effect_can_change_single_stack_target(eff):
                    continue
                if not can_pay_card_for_effect(player, c, eff):
                    continue
                redirect_context = redirectable_stack_context(player, all_players, top_item)
                if not redirect_context or not redirect_context.get("new_target"):
                    continue
                spree_additional_costs, spree_paid = mark_spree_cast_choice(
                    player,
                    c,
                    eff,
                    "change_single_target",
                )
                if spree_runtime_enabled(eff) and not spree_paid:
                    continue
                fields = replay_rule_fields(eff)
                alternative_cost, alternative_cost_kind = alternative_cost_for_effect(player, c, eff)
                locked_cost = card_cost_for_effect_with_additional_costs(
                    player,
                    c,
                    eff,
                    additional_costs=spree_additional_costs,
                )
                emit_decision_trace(
                    decision_type="response",
                    player=player,
                    turn=turn,
                    phase=phase,
                    available_options=[
                        decision_card_option(
                            option_card,
                            get_card_effect(option_card),
                            action="respond",
                        )
                        for option_card in instants[:8]
                    ],
                    chosen_option=decision_card_option(c, eff, action="redirect"),
                    rejected_options=[
                        decision_card_option(
                            option_card,
                            get_card_effect(option_card),
                            action="reject_response",
                        )
                        for option_card in instants
                        if option_card is not c
                    ][:8],
                    score_components={
                        "stack_threat_score": score,
                        "available_instants": len(instants),
                        "redirectable_stack_target": 1,
                        "spree_additional_cost_paid": int(spree_paid),
                    },
                    rule_source=fields.get("rule_source", "battle_heuristic"),
                    rule_status=fields.get("rule_review_status", "heuristic"),
                    confidence="medium",
                    expected_benefit_score=score,
                    actual_outcome="redirect_response_cast",
                    reason="redirect_targeted_stack_object",
                )
                if not player.spend_mana(locked_cost):
                    continue
                player.hand.remove(c)
                emit_replay_event(
                    "spell_cast",
                    player=player.name,
                    card=c.get("name", "?"),
                    effect=eff.get("effect", "unknown"),
                    type_line=c.get("type_line", ""),
                    cmc=c.get("cmc", 0),
                    turn=turn,
                    phase=phase,
                    role="response",
                    response_to=top_item.card.get("name", "?"),
                    locked_cost=replay_cost_snapshot(locked_cost),
                    additional_costs=list(spree_additional_costs or []),
                    alternative_cost=alternative_cost,
                    alternative_cost_kind=alternative_cost_kind,
                    **spree_replay_fields(eff),
                    **fields,
                )
                resolve_redirect_removal(
                    player,
                    all_players,
                    c,
                    {**eff, "_redirect_context": redirect_context},
                    turn,
                    phase=phase,
                )
                return True
        instants = [c for c in player.hand if is_instant(c)]
        for c in instants:
            eff = get_card_effect(c)
            if eff.get("effect") != "copy_spell":
                continue
            if not can_pay_card_for_effect(player, c, eff):
                continue
            copy_target = copy_spell_stack_target_context(player, top_item, eff)
            if not copy_target:
                continue
            fields = replay_rule_fields(eff)
            alternative_cost, alternative_cost_kind = alternative_cost_for_effect(player, c, eff)
            spree_additional_costs, spree_paid = mark_spree_cast_choice(
                player,
                c,
                eff,
                "copy_instant_or_sorcery_spell",
            )
            if spree_runtime_enabled(eff) and not spree_paid:
                continue
            buyback_additional_costs, buyback_paid = mark_buyback_cast_choice(player, c, eff)
            additional_costs = merge_additional_costs(
                spree_additional_costs,
                buyback_additional_costs,
            )
            locked_cost = card_cost_for_effect_with_additional_costs(
                player,
                c,
                eff,
                additional_costs=additional_costs,
            )
            emit_decision_trace(
                decision_type="response",
                player=player,
                turn=turn,
                phase=phase,
                available_options=[
                    decision_card_option(
                        option_card,
                        get_card_effect(option_card),
                        action="respond",
                    )
                    for option_card in instants[:8]
                ],
                chosen_option=decision_card_option(c, eff, action="copy_spell"),
                rejected_options=[
                    decision_card_option(
                        option_card,
                        get_card_effect(option_card),
                        action="reject_response",
                    )
                    for option_card in instants
                    if option_card is not c
                ][:8],
                score_components={
                    "stack_threat_score": score,
                    "available_instants": len(instants),
                    "copyable_stack_target": 1,
                    "spree_additional_cost_paid": int(spree_paid),
                    "buyback_paid": int(buyback_paid),
                },
                rule_source=fields.get("rule_source", "battle_heuristic"),
                rule_status=fields.get("rule_review_status", "heuristic"),
                confidence="medium",
                expected_benefit_score=max(10, score),
                actual_outcome="copy_spell_response_cast",
                reason="copy_target_instant_or_sorcery_stack_spell",
            )
            if not player.spend_mana(locked_cost):
                continue
            player.hand.remove(c)
            emit_replay_event(
                "spell_cast",
                player=player.name,
                card=c.get("name", "?"),
                effect=eff.get("effect", "unknown"),
                type_line=c.get("type_line", ""),
                cmc=c.get("cmc", 0),
                turn=turn,
                phase=phase,
                role="response",
                response_to=top_item.card.get("name", "?"),
                locked_cost=replay_cost_snapshot(locked_cost),
                additional_costs=list(additional_costs or []),
                alternative_cost=alternative_cost,
                alternative_cost_kind=alternative_cost_kind,
                may_choose_new_targets_for_target_spell=bool(
                    eff.get("may_choose_new_targets_for_target_spell")
                ),
                choose_new_targets_for_target_spell_status=eff.get(
                    "choose_new_targets_for_target_spell_status"
                ),
                **copy_target,
                **spree_replay_fields(eff),
                **buyback_replay_fields(eff),
                **fields,
            )
            mark_cast_ledger_emitted(eff)
            if eff.get("etb_copy_spell"):
                store_cast_context_fields(
                    eff,
                    {
                        "phase": phase,
                        "priority_window": "copy_spell_response_cast",
                        "stack_object": c.get("name", "?"),
                        "source_zone": "hand",
                        "cast_pipeline": "response_stack_cast_minimal",
                        "locked_cost": replay_cost_snapshot(locked_cost),
                        "additional_costs": list(additional_costs or []),
                        "alternative_cost": alternative_cost,
                        "alternative_cost_kind": alternative_cost_kind,
                        "targets": [copy_target],
                        "role": "response",
                    },
                )
                stack.push(c, player, eff)
                return True
            copied_item = copy_spell_on_stack(
                top_item.card,
                player,
                stack,
                original_effect_data=top_item.effect_data,
                source_card=c,
                source_effect_data=eff,
                all_players=all_players,
            )
            emit_replay_event(
                "spell_copied",
                player=player.name,
                card=c.get("name", "?"),
                copied_spell=top_item.card.get("name", "?"),
                copied_spell_controller=getattr(top_item.controller, "name", None),
                copy_controller=player.name,
                copy_is_cast=False,
                copy_stack_depth=len(stack.items),
                may_choose_new_targets=bool(eff.get("may_choose_new_targets")),
                choose_new_targets_status=eff.get("choose_new_targets_status"),
                may_choose_new_targets_for_target_spell=bool(
                    eff.get("may_choose_new_targets_for_target_spell")
                ),
                choose_new_targets_for_target_spell_status=eff.get(
                    "choose_new_targets_for_target_spell_status"
                ),
                turn=turn,
                phase=phase,
                **copy_target,
                **copy_spell_target_selection_replay_fields(copied_item),
                **spree_replay_fields(eff),
                **buyback_replay_fields(eff),
                **fields,
            )
            attach_direct_resolution_context(
                eff,
                c,
                phase,
                priority_window="copy_spell_response",
                locked_cost=replay_cost_snapshot(locked_cost),
                alternative_cost=alternative_cost,
                alternative_cost_kind=alternative_cost_kind,
                targets=[copy_target],
            )
            emit_replay_event(
                "spell_resolved",
                player=player.name,
                card=c.get("name", "?"),
                cmc=c.get("cmc", 0),
                type_line=c.get("type_line", ""),
                effect=eff.get("effect", "unknown"),
                copied_spell=top_item.card.get("name", "?"),
                copied_stack_object=getattr(copied_item, "card", {}).get("name", "?") if copied_item else None,
                turn=turn,
                **spell_resolution_context_fields(c, eff, eff.get("effect", "unknown")),
                **spree_replay_fields(eff),
                **buyback_replay_fields(eff),
                **fields,
            )
            finish_resolved_spell(player, c, turn=turn, effect_data=eff)
            return True
        if player.is_human:
            # Lorehold: use protection in response to high-threat spells
            top_effect = top_item.effect_data.get("effect", "")
            spell_damage_context = stack_spell_damage_prevention_context(player, top_item)
            if spell_damage_context:
                prevention_permanents = [
                    permanent
                    for permanent in player.battlefield
                    if isinstance(permanent, dict)
                    and (
                        permanent.get("activated_prevent_damage_from_target_spell")
                        or get_card_effect(permanent).get("activated_prevent_damage_from_target_spell")
                    )
                ]
                for permanent in prevention_permanents:
                    if activate_stack_spell_damage_prevention_permanent(
                        player,
                        permanent,
                        top_item,
                        spell_damage_context,
                        turn,
                        phase,
                    ):
                        return True
            targeted_protection_context = targeted_stack_protection_context(player, top_item)
            own_stack_protection_targets = {
                "board_wipe",
                "damage_wipe",
                "damage_player_and_creatures",
                "worldfire_reset",
            }
            should_consider_protection = (
                score >= 40
                and (
                    player != top_item.controller
                    or top_effect in own_stack_protection_targets
                )
            ) or bool(
                targeted_protection_context
                and targeted_protection_context.get("target_is_commander")
            )
            if should_consider_protection:
                if targeted_protection_context:
                    protection_permanents = [
                        permanent
                        for permanent in player.battlefield
                        if isinstance(permanent, dict)
                        and protection_card_can_cover_stack_context(
                            permanent,
                            targeted_protection_effect_data_for_permanent(permanent),
                            targeted_protection_context,
                        )
                    ]
                    for permanent in protection_permanents:
                        if activate_permanent_targeted_protection_response(
                            player,
                            permanent,
                            targeted_protection_context,
                            turn,
                            phase=phase,
                        ):
                            permanent_fields = replay_rule_fields(
                                targeted_protection_effect_data_for_permanent(permanent)
                            )
                            emit_decision_trace(
                                decision_type="response",
                                player=player,
                                turn=turn,
                                phase=phase,
                                available_options=[
                                    decision_card_option(
                                        option,
                                        targeted_protection_effect_data_for_permanent(option),
                                        action="activate_protection",
                                        target=targeted_protection_context.get("target_name"),
                                    )
                                    for option in protection_permanents[:8]
                                ],
                                chosen_option=decision_card_option(
                                    permanent,
                                    targeted_protection_effect_data_for_permanent(permanent),
                                    action="activate_protection",
                                    target=targeted_protection_context.get("target_name"),
                                ),
                                rejected_options=[
                                    decision_card_option(
                                        option,
                                        targeted_protection_effect_data_for_permanent(option),
                                        action="reject_protection_activation",
                                    )
                                    for option in protection_permanents
                                    if option is not permanent
                                ][:8],
                                score_components={
                                    "stack_threat_score": score,
                                    "targeted_protection_available": len(protection_permanents),
                                    "target_is_commander": int(
                                        bool(targeted_protection_context.get("target_is_commander"))
                                    ),
                                },
                                rule_source=permanent_fields.get("rule_source", "battle_heuristic"),
                                rule_status=permanent_fields.get("rule_review_status", "heuristic"),
                                confidence="high",
                                expected_benefit_score=max(score, 45),
                                actual_outcome="targeted_protection_activation",
                                reason="protect_targeted_creature_from_stack_removal",
                            )
                            return True
                instants = [c for c in player.hand if is_instant(c)]
                for c in instants:
                    eff = get_card_effect(c)
                    protection_effect = eff.get("effect")
                    cannot_lose_context = None
                    if protection_effect == "cannot_lose_turn":
                        cannot_lose_context = cannot_lose_turn_stack_response_context(player, top_item)
                        if cannot_lose_context is None:
                            continue
                    elif protection_effect not in (
                        "phase_out",
                        "gift_hexproof_indestructible",
                        "indestructible",
                        "modal_boros_charm",
                        "grant_protection_from_chosen_color",
                    ):
                        continue
                    targeted_spell_context = None
                    if protection_effect == "grant_protection_from_chosen_color":
                        targeted_spell_context = targeted_protection_context
                        if not protection_card_can_cover_stack_context(c, eff, targeted_spell_context):
                            continue
                    if protection_effect in (
                        "phase_out",
                        "gift_hexproof_indestructible",
                        "indestructible",
                        "modal_boros_charm",
                        "cannot_lose_turn",
                        "grant_protection_from_chosen_color",
                    ):
                        if can_pay_card_for_effect(player, c, eff):
                            alternative_cost, alternative_cost_kind = alternative_cost_for_effect(player, c, eff)
                            locked_cost = card_cost_for_effect(player, c, eff)
                            response_effect = dict(eff)
                            if targeted_spell_context:
                                response_effect["_response_protect_target"] = targeted_spell_context.get("target")
                                response_effect["protection_colors"] = targeted_spell_context.get("source_colors")
                            fields = replay_rule_fields(eff)
                            score_components = {
                                "stack_threat_score": score,
                                "available_instants": len(instants),
                            }
                            if cannot_lose_context:
                                score_components.update(cannot_lose_context)
                            if targeted_spell_context:
                                score_components.update(
                                    {
                                        "targeted_protection_response": 1,
                                        "target_is_commander": int(
                                            bool(targeted_spell_context.get("target_is_commander"))
                                        ),
                                    }
                                )
                            emit_decision_trace(
                                decision_type="response",
                                player=player,
                                turn=turn,
                                phase=phase,
                                available_options=[
                                    decision_card_option(
                                        option_card,
                                        get_card_effect(option_card),
                                        action="respond",
                                    )
                                    for option_card in instants[:8]
                                ],
                                chosen_option=decision_card_option(c, eff, action="protect"),
                                rejected_options=[
                                    decision_card_option(
                                        option_card,
                                        get_card_effect(option_card),
                                        action="reject_response",
                                    )
                                    for option_card in instants
                                    if option_card is not c
                                ][:8],
                                score_components=score_components,
                                rule_source=fields.get("rule_source", "battle_heuristic"),
                                rule_status=fields.get("rule_review_status", "heuristic"),
                                confidence="medium",
                                expected_benefit_score=score,
                                actual_outcome=(
                                    "cannot_lose_response_cast"
                                    if protection_effect == "cannot_lose_turn"
                                    else "protective_response_cast"
                                ),
                                reason=(
                                    (cannot_lose_context or {}).get("reason")
                                    or (
                                        "protect_targeted_creature_from_stack_removal"
                                        if targeted_spell_context
                                        else "high_threat_stack_response"
                                    )
                                ),
                            )
                            if not player.spend_mana(locked_cost):
                                continue
                            player.hand.remove(c)
                            c["_response_to_effect"] = top_item.effect_data.get("effect")
                            emit_replay_event(
                                "spell_cast",
                                player=player.name,
                                card=c.get("name", "?"),
                                effect=eff.get("effect", "unknown"),
                                type_line=c.get("type_line", ""),
                                cmc=c.get("cmc", 0),
                                turn=turn,
                                phase=phase,
                                role="response",
                                response_to=top_item.card.get("name", "?"),
                                locked_cost=replay_cost_snapshot(locked_cost),
                                alternative_cost=alternative_cost,
                                alternative_cost_kind=alternative_cost_kind,
                                **replay_rule_fields(eff),
                            )
                            attach_direct_resolution_context(
                                eff,
                                c,
                                phase,
                                priority_window="response_direct_resolution",
                                locked_cost=replay_cost_snapshot(locked_cost),
                                alternative_cost=alternative_cost,
                                alternative_cost_kind=alternative_cost_kind,
                            )
                            apply_effect_immediate(
                                player,
                                [p for p in all_players if p != player],
                                c,
                                turn,
                                rng,
                                effect_data_override=response_effect,
                            )
                            return True
        else:
            if player != top_item.controller:
                stack_exile_options = []
                for c in [candidate for candidate in player.hand if is_instant(candidate)]:
                    eff = get_card_effect(c)
                    if eff.get("effect") != "removal_exile":
                        continue
                    if not removal_exile_stack_target_context(player, top_item, eff):
                        continue
                    if not can_pay_card_for_effect(player, c, eff):
                        continue
                    stack_exile_options.append(c)
                if stack_exile_options and stack_exile_worth(score, rng):
                    c = min(stack_exile_options, key=lambda card: card.get("cmc", 0))
                    eff = get_card_effect(c)
                    fields = replay_rule_fields(eff)
                    target_context = removal_exile_stack_target_context(player, top_item, eff) or {}
                    locked_cost = card_cost_for_effect(player, c, eff)
                    emit_decision_trace(
                        decision_type="response",
                        player=player,
                        turn=turn,
                        phase=phase,
                        available_options=[
                            decision_card_option(
                                option_card,
                                get_card_effect(option_card),
                                action="exile_stack_spell",
                            )
                            for option_card in stack_exile_options[:8]
                        ],
                        chosen_option=decision_card_option(c, eff, action="exile_stack_spell"),
                        rejected_options=[
                            decision_card_option(
                                option_card,
                                get_card_effect(option_card),
                                action="reject_stack_exile",
                            )
                            for option_card in stack_exile_options
                            if option_card is not c
                        ][:8],
                        score_components={
                            "stack_threat_score": score,
                            "stack_exile_available": len(stack_exile_options),
                            "target_stack_depth": len(stack.items),
                        },
                        rule_source=fields.get("rule_source", "battle_heuristic"),
                        rule_status=fields.get("rule_review_status", "heuristic"),
                        confidence="medium",
                        expected_benefit_score=score,
                        actual_outcome="stack_spell_exiled",
                        reason="exile_high_threat_spell_from_stack",
                    )
                    if not player.spend_mana(locked_cost):
                        return False
                    player.hand.remove(c)
                    player.graveyard.append(c)
                    emit_replay_event(
                        "spell_cast",
                        player=player.name,
                        card=c.get("name", "?"),
                        effect=eff.get("effect", "unknown"),
                        type_line=c.get("type_line", ""),
                        cmc=c.get("cmc", 0),
                        turn=turn,
                        phase=phase,
                        role="response",
                        response_to=top_item.card.get("name", "?"),
                        locked_cost=replay_cost_snapshot(locked_cost),
                        targets=[target_context],
                        **target_context,
                        **fields,
                    )
                    resolve_removal_exile_stack_target(
                        player,
                        stack,
                        top_item,
                        c,
                        eff,
                        turn,
                        phase=phase,
                    )
                    return True
            # v8.2: Smart counter decision based on threat score
            if player != top_item.controller and counter_worth(score, player, rng):
                counters = player.counterspell_cards(
                    castable_only=True,
                    target_card=top_item.card,
                    stack_item=top_item,
                )
                counter = player.use_counterspell(
                    turn,
                    top_item.card,
                    stack_item=top_item,
                    stack_depth=len(stack.items),
                    phase=phase,
                    priority_window="stack_response",
                    all_players=all_players,
                )
                if counter:
                    fields = replay_rule_fields(get_card_effect(counter))
                    emit_decision_trace(
                        decision_type="response",
                        player=player,
                        turn=turn,
                        phase=phase,
                        available_options=[
                            decision_card_option(
                                option_card,
                                get_card_effect(option_card),
                                action="counter",
                            )
                            for option_card in counters[:8]
                        ],
                        chosen_option=decision_card_option(counter, get_card_effect(counter), action="counter"),
                        rejected_options=[
                            decision_card_option(
                                option_card,
                                get_card_effect(option_card),
                                action="reject_counter",
                            )
                            for option_card in counters
                            if option_card is not counter
                        ][:8],
                        score_components={
                            "stack_threat_score": score,
                            "counter_worth": 1,
                            "available_counters": len(counters),
                        },
                        rule_source=fields.get("rule_source", "battle_heuristic"),
                        rule_status=fields.get("rule_review_status", "heuristic"),
                        confidence="medium",
                        expected_benefit_score=score,
                        actual_outcome=(
                            "counterspell_tax_paid"
                            if counter.get("_counter_tax_paid")
                            else "counterspell_used"
                        ),
                        reason="counter_high_threat_spell",
                    )
                    if not counter.get("_counter_tax_paid"):
                        stack.items[-1].countered = True
                    return True

    # No one responded — resolve
    emit_priority_pass_sequence(
        active_player,
        all_players,
        turn,
        phase=phase,
        reason="stack_top_no_response",
        stack_item=top_item,
    )
    stack_depth_before_resolution = len(stack.items)
    item = stack.resolve_top()
    if item:
        if isinstance(item.card, dict) and item.card.get("_possibility_storm_replaced"):
            emit_replay_event(
                "spell_resolution_skipped",
                player=item.controller.name,
                card=item.card.get("name", "?"),
                reason="possibility_storm_replaced_original_spell",
                turn=turn,
                phase=phase,
                **replay_rule_fields(item.effect_data),
            )
            check_sbas_until_stable(all_players)
            flush_triggers_in_apnap(active_player, all_players, stack)
            return True
        if item.effect_data.get("effect") == "triggered_ability":
            resolver = item.effect_data.get("resolver")
            if callable(resolver):
                resolver()
            if game_winner(all_players):
                return True
            check_sbas_until_stable(all_players)
            flush_triggers_in_apnap(active_player, all_players, stack)
            return True
        controller = item.controller
        opponents = [p for p in all_players if p != controller]
        attach_stack_resolution_context(
            item.effect_data,
            item,
            phase,
            stack_depth_before_resolution,
        )
        apply_effect_immediate(
            controller,
            opponents,
            item.card,
            turn,
            rng,
            effect_data_override=item.effect_data,
            stack=stack,
            phase=phase,
        )
        if game_winner(all_players):
            return True
        check_sbas_until_stable(all_players)
        flush_triggers_in_apnap(active_player, all_players, stack)
        if game_winner(all_players):
            return True
    return False


def run_priority_loop(active_player, all_players, stack, turn, phase, rng, max_empty_actions=3):
    """Run a bounded priority loop, including main-phase actions from empty stack.

    This keeps the simulator's current AI action model, but routes main-phase
    spell decisions through priority instead of bypassing `priority_round`.
    """
    acted = False
    empty_actions = 0

    while True:
        if turn_ended_by_effect(active_player):
            return acted
        if game_winner(all_players):
            return acted
        if stack.empty() and not _pending_triggers:
            if phase not in MAIN_PHASES or empty_actions >= max_empty_actions:
                return acted
            if not priority_round(active_player, all_players, stack, turn, rng, phase=phase):
                return acted
            acted = True
            empty_actions += 1
            continue

        if priority_round(active_player, all_players, stack, turn, rng):
            acted = True
            if turn_ended_by_effect(active_player):
                return acted
            continue
        return acted

def threat_score(effect_name, card_name, controller, all_players, turn):
    """v8.2: Calculate how threatening a spell is (0-100).
    Opponents use this to decide if they should respond."""
    score = 0

    # ── INSTANT WIN ──
    if effect_name == "approach":
        if controller.approach_count >= 1:
            return 100  # MUST counter (2nd cast = instant win)
        return 85  # v10.2: was 70 — higher counter priority

    if effect_name == "worldfire_reset":
        return 92

    if effect_name == "thassa_oracle":
        if len(getattr(controller, "library", []) or []) <= max(2, blue_devotion(controller)):
            return 100
        return 25

    if effect_name == "brain_freeze":
        total_mill = brain_freeze_total_mill(controller, {"mill_count": 3})
        for opponent in all_players:
            if opponent != controller and opponent.is_alive() and len(getattr(opponent, "library", []) or []) <= total_mill:
                return 80
        if total_mill >= 15:
            return 45
        return 25

    if effect_name == "aetherflux_reservoir":
        if getattr(controller, "spells_cast_this_turn", 0) >= 3:
            return 55
        return 35

    # ── MASSIVE BOARD IMPACT ──
    if effect_name in BOARD_WIPE_LIKE_EFFECTS:
        # Higher threat if caster has protection (asymmetric wipe)
        if controller.indestructible or controller.protection_from_everything:
            return 85
        # Higher threat if opponents have more creatures than caster
        caster_creatures = len(controller.untapped_creatures())
        opp_creatures = sum(len(o.untapped_creatures()) for o in all_players if o != controller and o.is_alive())
        if opp_creatures > caster_creatures * 2:
            return 75  # devastating for opponents
        return 45  # symmetric, fair

    if effect_name == "damage_player_and_creatures":
        alive_opponents = [
            player
            for player in all_players
            if player != controller and player.is_alive()
        ]
        if not alive_opponents:
            return 10
        amount = 4
        best_score = max(
            _player_and_creatures_damage_target_score(opponent, amount)[0]
            for opponent in alive_opponents
        )
        if best_score >= 90:
            return 70
        if best_score >= 45:
            return 52
        return 32

    if effect_name == "steal_all_creatures":
        total_stolen = sum(len([c for c in o.battlefield if is_battlefield_creature(c)])
                          for o in all_players if o != controller and o.is_alive())
        if total_stolen > 10:
            return 90
        return 65

    # ── WINCON SETUP ──
    if effect_name == "pump_all":
        creatures = [c for c in controller.battlefield if is_battlefield_creature(c)]
        total_power = sum(c.get("power", 2) for c in creatures)
        if total_power > 30:
            return 70  # lethal pump
        if total_power > 15:
            return 50
        return 30

    if effect_name == "copy_creature_token":
        creatures = [c for c in controller.battlefield if is_battlefield_creature(c)]
        return 45 if creatures else 10

    if effect_name == "copy_permanent_etb":
        permanents = [c for c in controller.battlefield if isinstance(c, dict)]
        return 45 if permanents else 10

    if effect_name == "token_maker":
        # How many tokens? If Storm Herd (life_total), it's a lot.
        if controller.life > 30:
            return 60  # Storm Herd = 15+ tokens
        return 35

    if effect_name == "life_total_change":
        opposing_power = sum(
            table_visible_board_power(player)
            for player in all_players
            if player != controller and player.is_alive()
        )
        if getattr(controller, "life", 40) <= 20 or opposing_power >= max(1, getattr(controller, "life", 40)):
            return 55
        return 28

    if effect_name == "overload_recursion":
        spells_in_grave = sum(1 for c in controller.graveyard if isinstance(c, dict) and c.get("cmc", 0) > 0)
        if spells_in_grave > 10:
            return 80
        if spells_in_grave > 5:
            return 50
        return 30

    if effect_name in ("attack_limit", "attack_tax"):
        opposing_power = sum(
            table_visible_board_power(player)
            for player in all_players
            if player != controller and player.is_alive()
        )
        if player_is_evaluation_target(controller) and opposing_power >= max(1, controller.life):
            return 68
        if opposing_power >= max(8, controller.life // 2):
            return 55
        return 35

    if is_the_one_ring(card_name):
        opposing_power = sum(
            table_visible_board_power(player)
            for player in all_players
            if player != controller and player.is_alive()
        )
        if player_is_evaluation_target(controller) and (
            controller.life <= 20 or opposing_power >= max(1, controller.life)
        ):
            return 82
        if controller.life <= 12:
            return 72
        return 35

    # ── REMOVAL ──
    if effect_name in ("remove_creature", "remove_permanent", "remove_artifact_or_3dmg"):
        # Counter-worthy only if it targets a key piece
        for opp in all_players:
            if opp == controller: continue
            if opp.is_alive():
                key_creatures = [c for c in opp.battlefield if isinstance(c, dict) and (
                    c.get("is_commander") or c.get("power", 0) > 5)]
                if key_creatures:
                    return 40  # targeting a key creature
        return 15  # minor removal

    # ── RAMP / DRAW ──
    if effect_name in ("ramp_permanent", "ramp_engine", "ramp_ritual"):
        mana_produced = 1 if effect_name == "ramp_permanent" else 3
        if turn <= 3:
            return 20  # early ramp is worth countering
        return 5  # late ramp, not worth

    if effect_name == "draw_engine":
        return controller.approach_count > 0 and 50 or 25  # higher threat if Approach was cast

    if effect_name in ("draw_cards", "hand_filter", "cantrip_mana_filter_artifact"):
        count = 2
        if controller.approach_count > 0 and count >= 2:
            return 45  # digging for Approach
        return 15

    if effect_name == "tutor":
        if controller.approach_count > 0:
            return 55  # tutoring for Approach
        return 25

    if effect_name == "extra_turn":
        return 65

    if effect_name == "extra_combat":
        return 45

    # ── PROTECTION ──
    if effect_name in ("phase_out", "indestructible"):
        # Cast in response to a wipe on the stack? High value
        return 30  # protection itself isn't threatening, but enables threats

    if effect_name == "finisher":
        return 60  # generic finisher, always dangerous

    if effect_name in ("silence_opponents", "silence_spell"):
        if controller.approach_count > 0:
            return 80  # silencing before Approach = can't counter
        return 50

    return 15  # default: minor threat

def counter_worth(threat_score, opp, rng):
    """v8.2: Should this opponent spend a counterspell on this threat?
    Returns True/False based on threat score and opponent's resources."""
    if not opp.has_counterspell():
        return False

    # Critical: Approach 2nd cast or lethal — always counter
    if threat_score >= 90:
        return True

    # High threat — counter if we have enough counterspells
    if threat_score >= 70:
        return rng.random() < 0.85

    # Medium threat — counter if we're not the target or have spare
    if threat_score >= 40:
        return rng.random() < 0.5

    # Low threat — only counter if we have many to spare
    if threat_score >= 20:
        return rng.random() < 0.2

    return False


def stack_exile_worth(threat_score, rng):
    if threat_score >= 90:
        return True
    if threat_score >= 70:
        return rng.random() < 0.85
    if threat_score >= 40:
        return rng.random() < 0.5
    if threat_score >= 20:
        return rng.random() < 0.2
    return False


def remember_until_eot(card, key):
    originals = card.setdefault("_until_eot_originals", {})
    if key not in originals:
        originals[key] = card.get(key, None)


def set_until_eot(card, key, value):
    remember_until_eot(card, key)
    card[key] = value


def clear_until_eot(player):
    """Restore temporary card changes at cleanup."""
    def restore_card(card):
        originals = card.pop("_until_eot_originals", {})
        for key, original in originals.items():
            if original is None:
                card.pop(key, None)
            else:
                card[key] = original
        card.pop("_landfall_triggers_this_turn", None)
        clear_permanent_damage_this_turn_flags(card)

    for card in list(player.battlefield):
        if not isinstance(card, dict):
            continue
        return_player = card.pop("_until_eot_control_return_player_ref", None)
        return_controller_name = card.pop("_until_eot_control_return_player_name", None)
        if return_player is not None and return_player is not player:
            restore_card(card)
            if return_controller_name and not card.get("controller"):
                card["controller"] = return_controller_name
            if card in player.battlefield:
                player.battlefield.remove(card)
            if card not in getattr(return_player, "battlefield", []):
                return_player.battlefield.append(card)
            emit_replay_event(
                "temporary_control_returned",
                player=player.name,
                returned_to=getattr(return_player, "name", return_controller_name),
                card=card.get("name", "?"),
                result="returned_until_eot_controlled_permanent",
            )
            continue
        restore_card(card)

    for zone in (player.phased_out, player.graveyard):
        for card in zone:
            if not isinstance(card, dict):
                continue
            restore_card(card)
    player.indestructible = False
    player.hexproof = False
    player.hexproof_source = None
    player.silenced_opponents_until_eot = False
    player.creatures_cant_attack_this_turn = False
    player.creatures_cant_attack_source = None
    player.cannot_lose_this_turn = False
    player.damage_life_floor = None
    player.damage_prevention_shields = []
    player.combat_damage_prevention_effects = []


