def lands_have_nonmana_abilities_suppressed(all_players=None, *, player=None):
    participants = list(all_players or [])
    if not participants and player is not None:
        participants = [player]
    for participant in participants:
        for permanent in getattr(participant, "battlefield", []) or []:
            if (
                isinstance(permanent, dict)
                and permanent.get("effect") == "passive"
                and permanent.get("suppresses_land_nonmana_abilities")
            ):
                return True
    return False


def _eldrazi_confluence_pump_target(opponents, legal_target_ids=None):
    candidates = []
    for opponent in opponents or []:
        if not opponent.is_alive():
            continue
        for permanent in getattr(opponent, "battlefield", []) or []:
            if not is_battlefield_creature(permanent):
                continue
            if legal_target_ids is not None and id(permanent) not in legal_target_ids:
                continue
            remaining_toughness = int(permanent.get("toughness") or 0) - 3
            kill_bonus = 100 if remaining_toughness <= 0 else 0
            score = (kill_bonus, *target_priority(permanent))
            candidates.append((score, opponent, permanent))
    if not candidates:
        return None, None, None
    candidates.sort(key=lambda item: item[0], reverse=True)
    return candidates[0]


def _eldrazi_confluence_blink_target(player, all_players, used_target_ids, legal_target_ids=None):
    candidates = []
    for participant in all_players or []:
        if participant is None or not getattr(participant, "is_alive", lambda: True)():
            continue
        for permanent in getattr(participant, "battlefield", []) or []:
            if not isinstance(permanent, dict):
                continue
            if id(permanent) in used_target_ids:
                continue
            if legal_target_ids is not None and id(permanent) not in legal_target_ids:
                continue
            type_line = str(permanent.get("type_line") or "").lower()
            if "land" in type_line:
                continue
            if participant is player:
                score = 40 + max(0, _harnessed_blink_target_score(permanent))
            else:
                score = 15 + int(permanent.get("cmc") or 0) * 3
                if is_battlefield_creature(permanent):
                    score += int(permanent.get("power") or 0) + int(permanent.get("toughness") or 0)
                if permanent.get("effect") in {"draw_engine", "ramp_engine", "passive", "creature"}:
                    score += 8
            if score <= 20:
                continue
            candidates.append((score, participant, permanent))
    if not candidates:
        return None, None, None
    candidates.sort(key=lambda item: (-item[0], item[2].get("name", "?")))
    return candidates[0]


def resolve_eldrazi_confluence(player, opponents, card, effect_data, turn, rng, *, all_players):
    selected_modes = []
    blink_target_ids = set()
    mode_count = max(1, int(effect_data.get("modal_choose_count") or 3))
    legal_pump_target_ids = {
        id(permanent)
        for opponent in opponents or []
        if opponent is not None and getattr(opponent, "is_alive", lambda: True)()
        for permanent in getattr(opponent, "battlefield", []) or []
        if is_battlefield_creature(permanent)
    }
    legal_blink_target_ids = {
        id(permanent)
        for participant in all_players or []
        if participant is not None and getattr(participant, "is_alive", lambda: True)()
        for permanent in getattr(participant, "battlefield", []) or []
        if isinstance(permanent, dict)
        and "land" not in str(permanent.get("type_line") or "").lower()
    }

    for _ in range(mode_count):
        scored_modes = []
        pump_score, pump_controller, pump_target = _eldrazi_confluence_pump_target(
            opponents,
            legal_pump_target_ids,
        )
        if pump_target is not None:
            scored_modes.append(("pump", pump_score, pump_controller, pump_target))
        blink_score, blink_controller, blink_target = _eldrazi_confluence_blink_target(
            player,
            all_players,
            blink_target_ids,
            legal_blink_target_ids,
        )
        if blink_target is not None:
            scored_modes.append(("blink", (blink_score,), blink_controller, blink_target))
        scored_modes.append(("scion", (20,), player, None))
        scored_modes.sort(key=lambda item: item[1], reverse=True)
        mode_name, _score, controller, target = scored_modes[0]

        if mode_name == "pump" and target is not None:
            remember_until_eot(target, "power")
            remember_until_eot(target, "toughness")
            target["power"] = int(target.get("power") or 0) + 3
            target["toughness"] = int(target.get("toughness") or 0) - 3
            selected_modes.append(
                {
                    "mode": "target_creature_plus_three_minus_three",
                    "target_player": getattr(controller, "name", "?"),
                    "target": target.get("name", "?"),
                    "target_score": list(target_priority(target)),
                }
            )
            check_sbas_until_stable(all_players)
            continue

        if mode_name == "blink" and target is not None:
            blink_target_ids.add(id(target))
            if target in controller.battlefield:
                controller.battlefield.remove(target)
            target_effect = get_card_effect(target)
            reentry_payload = {**target_effect, **target, "enters_tapped": True}
            for transient_key in (
                "tapped",
                "summoning_sick",
                "utility_artifact_used_this_turn",
                "utility_land_used_this_turn",
                "discard_modal_modes_used_this_turn",
            ):
                reentry_payload.pop(transient_key, None)
            returned = prepare_entering_permanent(
                enrich_card(reentry_payload),
                controller=controller,
                all_players=all_players,
                turn=turn,
            )
            controller.battlefield.append(returned)
            resolve_generic_permanent_etb(
                controller,
                [participant for participant in all_players if participant is not controller],
                returned,
                reentry_payload,
                turn,
                rng,
            )
            selected_modes.append(
                {
                    "mode": "blink_target_nonland_permanent_tapped",
                    "target_player": getattr(controller, "name", "?"),
                    "target": target.get("name", "?"),
                    "returned_tapped": True,
                }
            )
            continue

        scion = create_creature_token(
            player,
            name=effect_data.get("token_name", "Eldrazi Scion Token"),
            power=int(effect_data.get("token_power") or 1),
            toughness=int(effect_data.get("token_toughness") or 1),
            subtype=effect_data.get("token_subtype", "Eldrazi Scion"),
            colors=list(effect_data.get("token_colors") or []),
            opponents=opponents,
            turn=turn,
            source_event="eldrazi_confluence_token",
            active_player=player,
            all_players=all_players,
        )
        scion["sacrifice_for_colorless_mana"] = bool(effect_data.get("token_sacrifice_for_colorless_mana"))
        selected_modes.append(
            {
                "mode": "create_eldrazi_scion",
                "created": scion.get("name", "?"),
            }
        )

    emit_replay_event(
        "modal_spell_resolved",
        player=player.name,
        card=card.get("name", "?"),
        selected_modes=selected_modes,
        mode_count=len(selected_modes),
        turn=turn,
        **replay_rule_fields(effect_data),
    )
    finish_resolved_spell(player, card, turn=turn)


def _harnessed_blink_target_score(permanent):
    if not isinstance(permanent, dict):
        return -999
    type_line = str(permanent.get("type_line") or "").lower()
    if "land" in type_line:
        return -999
    if permanent.get("is_token") or permanent.get("tag") == "token" or "token" in type_line:
        return -999

    score = 0
    if permanent.get("etb_draw_count"):
        score += 18 * int(permanent.get("etb_draw_count") or 1)
    if permanent.get("etb_library_look_count"):
        score += 16 * int(permanent.get("etb_library_pick_count") or 1)
    if permanent.get("etb_tutor_target"):
        score += 28
    if permanent.get("etb_land_ramp_count"):
        score += 22
    if permanent.get("etb_remove_target") or permanent.get("etb_removal_target"):
        score += 24
    if permanent.get("etb_recursion_count"):
        score += 24
    if permanent.get("etb_token_count"):
        score += 12 * int(permanent.get("etb_token_count") or 1)
    if permanent.get("trigger") in {"spell_cast", "noncreature_spell_cast"}:
        score += 6
    if permanent.get("tapped"):
        score += 4
    if permanent.get("utility_artifact_used_this_turn"):
        score += 3
    if permanent.get("effect") in {"passive", "ramp_permanent"} and score == 0:
        score -= 8
    return score


BLINK_TRANSIENT_KEYS = (
    "tapped",
    "summoning_sick",
    "utility_artifact_used_this_turn",
    "utility_land_used_this_turn",
    "discard_modal_modes_used_this_turn",
)


def _blink_target_is_token(permanent):
    type_line = str(permanent.get("type_line") or "").lower()
    return bool(permanent.get("is_token") or permanent.get("tag") == "token" or "token" in type_line)


def blink_target_matches_scope(permanent, source_effect, *, source_permanent=None):
    if not isinstance(permanent, dict):
        return False
    if _blink_target_is_token(permanent) and not source_effect.get("blink_tokens_can_return"):
        return False
    scope = str(
        source_effect.get("blink_target_scope")
        or source_effect.get("target")
        or "permanent_you_control"
    ).lower()
    type_line = str(permanent.get("type_line") or "").lower()
    is_creature = is_battlefield_creature(permanent)
    if "another" in scope and source_permanent is not None and permanent is source_permanent:
        return False
    if "nonland" in scope and "land" in type_line:
        return False
    if "creature" in scope and not is_creature:
        return False
    return True


def choose_blink_target(player, source_effect, *, source_permanent=None):
    candidates = []
    for permanent in getattr(player, "battlefield", []) or []:
        if not blink_target_matches_scope(
            permanent,
            source_effect,
            source_permanent=source_permanent,
        ):
            continue
        score = _harnessed_blink_target_score(permanent)
        if is_battlefield_creature(permanent):
            score += 10
        if permanent is source_permanent:
            score += 2
        if source_effect.get("blink_optional") and score <= 0:
            continue
        candidates.append((score, permanent))
    if not candidates:
        return None, 0
    candidates.sort(key=lambda item: (-item[0], item[1].get("name", "?")))
    return candidates[0][1], candidates[0][0]


def resolve_blink_permanent(
    player,
    opponents,
    source_card,
    source_effect,
    target,
    turn,
    rng,
    *,
    all_players=None,
    phase="resolution",
    trigger_spell=None,
):
    all_players = all_players or [player, *(opponents or [])]
    if target is None or target not in getattr(player, "battlefield", []):
        emit_replay_event(
            "blink_skipped",
            player=player.name,
            card=source_card.get("name", "?") if isinstance(source_card, dict) else str(source_card),
            reason="target_missing",
            turn=turn,
            phase=phase,
            **replay_rule_fields(source_effect),
        )
        return None

    target_name = target.get("name", "?")
    player.battlefield.remove(target)
    target_effect = get_card_effect(target)
    reentry_payload = {**target_effect, **target}
    for transient_key in BLINK_TRANSIENT_KEYS:
        reentry_payload.pop(transient_key, None)
    if source_effect.get("return_tapped"):
        reentry_payload["enters_tapped"] = True
    returned = prepare_entering_permanent(
        enrich_card(reentry_payload),
        controller=player,
        all_players=all_players,
        turn=turn,
    )
    player.battlefield.append(returned)
    other_players = [participant for participant in all_players if participant is not player]
    resolve_generic_permanent_etb(
        player,
        other_players,
        returned,
        reentry_payload,
        turn,
        rng,
        all_players=all_players,
        phase=phase,
    )
    if is_battlefield_creature(returned):
        process_controlled_creature_enters_triggers(
            player,
            other_players,
            returned,
            turn,
            source_event="blink",
            all_players=all_players,
        )
        process_opponent_controlled_creature_enters_triggers(
            player,
            returned,
            turn,
            source_event="blink",
            all_players=all_players,
        )
    emit_replay_event(
        "blink_resolved",
        player=player.name,
        card=source_card.get("name", "?") if isinstance(source_card, dict) else str(source_card),
        target=target_name,
        returned=returned.get("name", "?"),
        trigger_spell=trigger_spell.get("name", "?") if isinstance(trigger_spell, dict) else None,
        return_tapped=bool(source_effect.get("return_tapped")),
        zone_transition=source_effect.get("zone_transition", "exile_then_return"),
        destination=source_effect.get("destination", "battlefield"),
        turn=turn,
        phase=phase,
        **replay_rule_fields(source_effect),
    )
    check_sbas_until_stable(all_players)
    return returned


def resolve_blink_effect(
    player,
    opponents,
    card,
    effect_data,
    turn,
    rng,
    *,
    all_players=None,
    phase="resolution",
):
    target, target_score = choose_blink_target(player, effect_data)
    if target is None:
        emit_replay_event(
            "blink_skipped",
            player=player.name,
            card=card.get("name", "?"),
            reason="no_valid_blink_target",
            target_scope=effect_data.get("blink_target_scope") or effect_data.get("target"),
            turn=turn,
            phase=phase,
            **replay_rule_fields(effect_data),
        )
        return None
    returned = resolve_blink_permanent(
        player,
        opponents,
        card,
        effect_data,
        target,
        turn,
        rng,
        all_players=all_players,
        phase=phase,
    )
    if returned is not None:
        returned["_blink_target_score"] = target_score
    return returned


def _choose_harnessed_blink_target(player, source_permanent):
    candidates = []
    for permanent in getattr(player, "battlefield", []) or []:
        if permanent is source_permanent or not isinstance(permanent, dict):
            continue
        score = _harnessed_blink_target_score(permanent)
        if score <= 0:
            continue
        candidates.append((score, permanent))
    if not candidates:
        return None, 0
    candidates.sort(key=lambda item: (-item[0], item[1].get("name", "?")))
    return candidates[0][1], candidates[0][0]


def process_harnessed_end_step_blink(player, opponents, all_players, turn, rng):
    for source_permanent in list(getattr(player, "battlefield", []) or []):
        if not isinstance(source_permanent, dict):
            continue
        if not source_permanent.get("harnessed_end_step_blink") or not source_permanent.get("harnessed"):
            continue
        target, target_score = _choose_harnessed_blink_target(player, source_permanent)
        if target is None:
            emit_replay_event(
                "trigger_skipped",
                player=player.name,
                card=source_permanent.get("name", "?"),
                trigger="end_step",
                reason="no_valid_harnessed_blink_target",
                turn=turn,
                phase="end_step",
                **replay_rule_fields(source_permanent),
            )
            continue
        if target in player.battlefield:
            player.battlefield.remove(target)

        target_effect = get_card_effect(target)
        reentry_payload = {**target_effect, **target}
        for transient_key in (
            "tapped",
            "summoning_sick",
            "utility_artifact_used_this_turn",
            "utility_land_used_this_turn",
            "discard_modal_modes_used_this_turn",
        ):
            reentry_payload.pop(transient_key, None)
        returned = prepare_entering_permanent(enrich_card(reentry_payload))
        player.battlefield.append(returned)
        resolve_generic_permanent_etb(player, opponents, returned, reentry_payload, turn, rng)
        emit_replay_event(
            "trigger_resolved",
            player=player.name,
            card=source_permanent.get("name", "?"),
            trigger="end_step",
            effect="harnessed_blink",
            blinked=target.get("name", "?"),
            target_score=target_score,
            returned=returned.get("name", "?"),
            turn=turn,
            phase="end_step",
            **replay_rule_fields(source_permanent),
        )
        check_sbas_until_stable(all_players)


def grant_creatures_until_eot(player, *, keywords=(), power_multiplier=None, power_bonus=0):
    creatures = [
        card
        for card in player.battlefield
        if is_battlefield_creature(card)
    ]
    for creature in creatures:
        for keyword in keywords:
            if keyword == "protection_all":
                continue
            set_until_eot(creature, keyword, True)
        if power_multiplier:
            remember_until_eot(creature, "power")
            try:
                base_power = int(float(creature.get("power", 2)))
            except (TypeError, ValueError):
                base_power = 2
            creature["power"] = base_power * power_multiplier
        if power_bonus:
            remember_until_eot(creature, "power")
            try:
                current_power = int(float(creature.get("power", 2)))
            except (TypeError, ValueError):
                current_power = 2
            creature["power"] = current_power + int(power_bonus)
    return len(creatures)


def grant_permanents_until_eot(player, *, keywords=()):
    permanents = [
        card
        for card in player.battlefield
        if isinstance(card, dict)
    ]
    for permanent in permanents:
        for keyword in keywords:
            set_until_eot(permanent, keyword, True)
    return permanents


def _is_angel_permanent(permanent):
    if not isinstance(permanent, dict):
        return False
    type_line = str(permanent.get("type_line") or "").lower()
    subtype = str(permanent.get("subtype") or permanent.get("token_subtype") or "").lower()
    return "angel" in type_line or subtype == "angel"


def grant_non_angel_creatures_indestructible_until_next_turn(player, *, source_card, effect_data, turn):
    protected = [
        permanent
        for permanent in player.battlefield
        if is_battlefield_creature(permanent) and not _is_angel_permanent(permanent)
    ]
    for permanent in protected:
        set_until_next_turn(
            permanent,
            "indestructible",
            True,
            source_player=player.name,
            turn=turn,
        )
    emit_replay_event(
        "protection_resolved",
        player=player.name,
        card=source_card.get("name", "?"),
        grants=["indestructible"],
        target_scope="non_angel_creatures_you_control",
        duration="until_your_next_turn",
        affected=[permanent.get("name", "?") for permanent in protected[:20]],
        affected_count=len(protected),
        turn=turn,
        **replay_rule_fields(effect_data),
    )
    return protected


def grant_graveyard_flashback_until_eot(player, source_card, effect_data, turn):
    """Grant temporary flashback to instant/sorcery cards in the player's graveyard."""
    granted = []
    skipped_no_mana_cost = []
    for grave_card in list(player.graveyard):
        if not isinstance(grave_card, dict) or not is_instant_or_sorcery_spell(grave_card):
            continue
        mana_cost = str(grave_card.get("mana_cost") or "").strip()
        if not mana_cost:
            skipped_no_mana_cost.append(grave_card.get("name", "?"))
            continue
        set_until_eot(grave_card, "flashback_cost", mana_cost)
        set_until_eot(grave_card, "_flashback_granted_by", source_card.get("name", "?"))
        set_until_eot(
            grave_card,
            "_flashback_granted_rule_key",
            effect_data.get("_rule_logical_key"),
        )
        granted.append(
            {
                "name": grave_card.get("name", "?"),
                "flashback_cost": mana_cost,
            }
        )
    emit_replay_event(
        "graveyard_flashback_granted",
        player=player.name,
        card=source_card.get("name", "?"),
        target_zone=effect_data.get("target_zone", "graveyard"),
        grants_flashback_to=effect_data.get("grants_flashback_to", "instant_or_sorcery"),
        duration=effect_data.get("duration", "until_end_of_turn"),
        granted_count=len(granted),
        granted=granted,
        skipped_no_mana_cost=skipped_no_mana_cost,
        turn=turn,
        **replay_rule_fields(effect_data),
    )
    return granted


def resolve_permanent_dies_draw(owner, permanent, *, destination=None, reason=None, source=None):
    if destination != "graveyard" or not isinstance(permanent, dict):
        return []
    draw_count = max(0, int(permanent.get("draw_cards_when_this_dies") or 0))
    if draw_count <= 0:
        return []
    drawn = owner.draw(draw_count)
    emit_replay_event(
        "dies_draw_resolved",
        player=getattr(owner, "name", "?"),
        card=permanent.get("name", "?"),
        draw_count=draw_count,
        cards_drawn=[card.get("name", "?") for card in drawn if isinstance(card, dict)],
        reason=reason,
        source=source.get("name", "?") if isinstance(source, dict) else source,
        optional=bool(permanent.get("dies_draw_optional")),
        turn=CURRENT_REPLAY_TURN,
        **replay_rule_fields(permanent),
    )
    return drawn


def resolve_permanent_dies_life_gain(owner, permanent, *, destination=None, reason=None, source=None):
    if destination != "graveyard" or not isinstance(permanent, dict):
        return 0
    amount = max(
        0,
        int(
            permanent.get("gain_life_when_this_dies")
            or permanent.get("dies_life_gain_amount")
            or 0
        ),
    )
    if amount <= 0:
        return 0
    life_before = int(getattr(owner, "life", 0) or 0)
    gain_life(owner, amount, cap=999)
    life_after = int(getattr(owner, "life", life_before) or 0)
    gained = max(0, life_after - life_before)
    emit_replay_event(
        "dies_life_gain_resolved",
        player=getattr(owner, "name", "?"),
        card=permanent.get("name", "?"),
        life_gain_requested=amount,
        life_gained=gained,
        controller_life_before=life_before,
        controller_life_after=life_after,
        reason=reason,
        source=source.get("name", "?") if isinstance(source, dict) else source,
        turn=CURRENT_REPLAY_TURN,
        **replay_rule_fields(permanent),
    )
    return gained


def resolve_permanent_dies_add_mana(owner, permanent, *, destination=None, reason=None, source=None):
    if destination != "graveyard" or not isinstance(permanent, dict):
        return 0
    produced = max(0, int(permanent.get("dies_mana_produced") or 0))
    if produced <= 0:
        return 0
    mana_payload = {
        "mana_produced": produced,
        "produced_mana_symbols": list(permanent.get("dies_produced_mana_symbols") or []),
    }
    mana_before = owner.mana_pool.snapshot()
    if not add_fixed_produced_mana_symbols_to_pool(owner, mana_payload, produced):
        return 0
    mana_after = owner.mana_pool.snapshot()
    emit_replay_event(
        "dies_mana_resolved",
        player=getattr(owner, "name", "?"),
        card=permanent.get("name", "?"),
        mana_produced=produced,
        produces=permanent.get("dies_produces"),
        produced_mana_symbols=list(permanent.get("dies_produced_mana_symbols") or []),
        mana_pool_before=mana_before,
        mana_pool_after=mana_after,
        reason=reason,
        source=source.get("name", "?") if isinstance(source, dict) else source,
        turn=CURRENT_REPLAY_TURN,
        **replay_rule_fields(permanent),
    )
    return produced


def resolve_permanent_dies_add_counters(
    owner,
    permanent,
    *,
    destination=None,
    reason=None,
    source=None,
    opponents=None,
    all_players=None,
):
    if destination != "graveyard" or not isinstance(permanent, dict):
        return None
    if not permanent.get("dies_add_counters"):
        return None
    participants = list(all_players or [])
    if not participants:
        participants = [owner] + list(opponents or [])
    resolved_opponents = [
        player
        for player in (opponents or [participant for participant in participants if participant is not owner])
        if player is not None
    ]
    effect_data = {
        **permanent,
        "effect": "add_counters",
        "ability_kind": "triggered",
        "trigger": "dies",
        "trigger_effect": "add_counters",
        "target": permanent.get("dies_add_counters_target") or permanent.get("target") or "creature",
        "target_constraints": permanent.get("target_constraints") or {"card_types": ["creature"]},
        "target_controller": permanent.get("target_controller") or "any",
        "counter_type": (
            permanent.get("dies_add_counters_counter_type")
            or permanent.get("counter_type")
            or "+1/+1"
        ),
        "counter_count": int(
            permanent.get("dies_add_counters_count")
            or permanent.get("counter_count")
            or permanent.get("count")
            or 1
        ),
        "optional": bool(permanent.get("optional") or permanent.get("dies_add_counters_optional")),
        "reason": reason,
        "source": source.get("name", "?") if isinstance(source, dict) else source,
    }
    return resolve_add_counters_target_effect(
        owner,
        resolved_opponents,
        permanent,
        effect_data,
        CURRENT_REPLAY_TURN,
        finish_spell=False,
        event_name="dies_add_counters_resolved",
        trigger="dies",
        phase="dies_trigger",
    )


def resolve_permanent_dies_damage(
    owner,
    permanent,
    *,
    destination=None,
    reason=None,
    source=None,
    opponents=None,
    all_players=None,
):
    if destination != "graveyard" or not isinstance(permanent, dict):
        return 0
    amount = max(
        0,
        int(permanent.get("dies_damage_amount") or permanent.get("damage_when_this_dies") or 0),
    )
    if amount <= 0:
        return 0
    participants = list(all_players or [])
    if not participants:
        participants = [owner] + list(opponents or [])
    resolved_opponents = list(opponents or [player for player in participants if player is not owner])
    resolved_opponents = [player for player in resolved_opponents if player is not None]
    if not resolved_opponents:
        return 0
    effect_data = dict(permanent)
    target = permanent.get("dies_damage_target") or permanent.get("target") or "any_target"
    target_constraints = permanent.get("target_constraints")
    if not isinstance(target_constraints, dict) or not target_constraints:
        if target == "any_target":
            target_constraints = {"scope": "any_target"}
        elif target == "creature":
            target_constraints = {"card_types": ["creature"]}
        elif target == "creature_or_planeswalker":
            target_constraints = {"card_types": ["creature", "planeswalker"]}
        elif target == "player_or_planeswalker":
            target_constraints = {"scope": "player_or_planeswalker"}
        elif target in {"player", "opponent"}:
            target_constraints = {"scope": target}
        else:
            target_constraints = {"target": target}
    effect_data.update(
        {
            "effect": "direct_damage",
            "ability_kind": "triggered",
            "trigger": "dies",
            "amount": amount,
            "damage": amount,
            "target": target,
            "target_constraints": target_constraints,
        }
    )
    apply_direct_damage(
        owner,
        resolved_opponents,
        permanent,
        effect_data,
        CURRENT_REPLAY_TURN,
        random.Random(CURRENT_REPLAY_TURN or 0),
        finish_spell=False,
        phase="dies_trigger",
    )
    emit_replay_event(
        "dies_damage_trigger_resolved",
        player=getattr(owner, "name", "?"),
        card=permanent.get("name", "?"),
        damage=amount,
        target=target,
        reason=reason,
        source=source.get("name", "?") if isinstance(source, dict) else source,
        turn=CURRENT_REPLAY_TURN,
        **replay_rule_fields(permanent),
    )
    return amount


