def resolve_starfall_invocation(player, opponents, card, effect_data, turn, rng):
    players = [player] + list(opponents or [])
    context = board_wipe_decision_context(player, opponents)
    gift_recipient = (
        choose_gift_opponent(player, opponents)
        if effect_data.get("gift_default_promised", True)
        else None
    )
    gift_promised = gift_recipient is not None
    gifted_cards = gift_recipient.draw(1, rng) if gift_promised else []
    destroyed_cards = []
    protected_cards = []
    own_destroyed_candidates = []
    creatures_seen = 0
    own_creatures_destroyed = 0
    opponent_creatures_destroyed = 0
    live_opponent_creatures_destroyed = 0

    for controller in players:
        is_self = controller is player
        is_live_opponent = (not is_self) and controller.is_alive()
        for creature in list(getattr(controller, "battlefield", []) or []):
            if not is_battlefield_creature(creature):
                continue
            creatures_seen += 1
            if creature.get("indestructible"):
                protected_cards.append(
                    {
                        "controller": controller.name,
                        "name": creature.get("name", "?"),
                    }
                )
                continue
            destination = move_creature_from_battlefield(
                controller,
                creature,
                reason="starfall_invocation",
                source=card,
            )
            destroyed_cards.append(
                {
                    "controller": controller.name,
                    "name": creature.get("name", "?"),
                    "type_line": creature.get("type_line", ""),
                    "destination": destination,
                }
            )
            if is_self:
                own_creatures_destroyed += 1
                if destination == "graveyard" and creature in player.graveyard:
                    own_destroyed_candidates.append(creature)
            else:
                opponent_creatures_destroyed += 1
                if is_live_opponent:
                    live_opponent_creatures_destroyed += 1

    returned = None
    if gift_promised and own_destroyed_candidates:
        returned = choose_best_creature_target(own_destroyed_candidates)
        remove_cards_from_graveyard(
            player,
            [returned],
            turn=turn,
            source_event="gift_destroy_all_creatures_return_own_destroyed_creature",
        )
        returned["controller"] = player.name
        returned = prepare_entering_permanent(
            returned,
            controller=player,
            all_players=players,
            turn=turn,
        )
        player.battlefield.append(returned)

    actual_asymmetry = live_opponent_creatures_destroyed - own_creatures_destroyed
    resolution_context = {
        **context,
        "gift_promised": gift_promised,
        "gift_cards_drawn": len(gifted_cards),
        "creatures_seen": creatures_seen,
        "actual_destroyed": len(destroyed_cards),
        "protected": len(protected_cards),
        "returned_own_creature": returned.get("name", "?") if returned else None,
        "own_creatures_destroyed": own_creatures_destroyed,
        "opponent_creatures_destroyed": opponent_creatures_destroyed,
        "live_opponent_creatures_destroyed": live_opponent_creatures_destroyed,
        "effective_opponent_creatures_destroyed": live_opponent_creatures_destroyed,
        "actual_asymmetry": actual_asymmetry,
        "timing_justified": bool(
            context["timing_justified"]
            or actual_asymmetry > 0
            or returned is not None
        ),
    }
    risk_flags = []
    if gift_promised and returned is None:
        risk_flags.append("gift_promised_no_own_destroyed_creature_to_return")
    if not resolution_context["timing_justified"]:
        risk_flags.append("wipe_without_timing_justification")
    elif (
        actual_asymmetry <= 0
        and returned is None
        and not context["lethal_pressure"]
        and not context["behind_on_board"]
    ):
        risk_flags.append("wipe_without_clear_asymmetry")

    fields = replay_rule_fields(effect_data)
    emit_decision_trace(
        decision_type="board_wipe",
        player=player,
        turn=turn,
        phase="resolution",
        available_options=[
            decision_card_option(card, effect_data, action="resolve_gift_destroy_return_wipe"),
            {"action": "defer_wipe_not_available_after_resolution"},
        ],
        chosen_option=decision_card_option(
            card,
            effect_data,
            action="resolve_gift_destroy_return_wipe",
        ),
        rejected_options=[{"action": "defer_wipe_not_available_after_resolution"}],
        score_components=resolution_context,
        rule_source=fields.get("rule_source", "battle_heuristic"),
        rule_status=fields.get("rule_review_status", "heuristic"),
        confidence="medium",
        expected_benefit_score=max(0, actual_asymmetry * 10)
        + min(live_opponent_creatures_destroyed * 5, 35)
        + (18 if returned is not None else 0),
        actual_outcome="board_wipe_resolved",
        reason="destroy_all_creatures_and_return_own_destroyed_creature_if_gifted",
        strategic_principle="convert_symmetric_wipe_into_rebuild_advantage_when_gifted",
        heuristic_version=DECISION_STRATEGY_VERSION,
        resource_delta=resolution_context,
        risk_flags=risk_flags,
        rejected_reason="spell_already_resolving",
    )
    emit_replay_event(
        "board_wipe_resolved",
        player=player.name,
        card=card.get("name", "?"),
        destroyed=len(destroyed_cards),
        protected=len(protected_cards),
        creatures_seen=creatures_seen,
        gift_promised=gift_promised,
        gift_recipient=getattr(gift_recipient, "name", None),
        gift_cards_drawn=len(gifted_cards),
        gift_drawn_cards=[
            gifted.get("name", "?")
            for gifted in gifted_cards
            if isinstance(gifted, dict)
        ],
        returned_own_creature=returned.get("name", "?") if returned else None,
        destroyed_cards=destroyed_cards[:20],
        protected_cards=protected_cards[:20],
        own_creatures_destroyed=own_creatures_destroyed,
        opponent_creatures_destroyed=opponent_creatures_destroyed,
        live_opponent_creatures_destroyed=live_opponent_creatures_destroyed,
        actual_asymmetry=actual_asymmetry,
        risk_flags=risk_flags,
        turn=turn,
        **fields,
    )
    finish_resolved_spell(player, card, turn=turn)


def is_creature_or_planeswalker_permanent(permanent):
    return is_battlefield_creature(permanent) or is_planeswalker_permanent(permanent)


def resolve_single_combat(player, opponents, card, effect_data, turn):
    players = [player] + list(opponents or [])
    context = board_wipe_decision_context(player, opponents)
    choices = []
    sacrificed_cards = []
    permanents_seen = 0
    own_permanents_sacrificed = 0
    opponent_permanents_sacrificed = 0
    live_opponent_permanents_sacrificed = 0

    for controller in players:
        is_self = controller is player
        is_live_opponent = (not is_self) and controller.is_alive()
        candidates = [
            permanent
            for permanent in list(getattr(controller, "battlefield", []) or [])
            if is_creature_or_planeswalker_permanent(permanent)
        ]
        permanents_seen += len(candidates)
        if not candidates:
            continue
        chosen = max(candidates, key=target_priority)
        choices.append(
            {
                "controller": controller.name,
                "name": chosen.get("name", "?"),
                "type_line": chosen.get("type_line", ""),
                "target_score": list(target_priority(chosen)),
            }
        )
        chosen_id = id(chosen)
        for permanent in candidates:
            if id(permanent) == chosen_id:
                continue
            if is_battlefield_creature(permanent):
                destination = move_creature_from_battlefield(
                    controller,
                    permanent,
                    reason="single_combat_sacrifice",
                    source=card,
                )
            else:
                destination = move_permanent_from_battlefield(
                    controller,
                    permanent,
                    reason="single_combat_sacrifice",
                    source=card,
                )
            sacrificed_cards.append(
                {
                    "controller": controller.name,
                    "name": permanent.get("name", "?"),
                    "type_line": permanent.get("type_line", ""),
                    "destination": destination,
                }
            )
            if is_self:
                own_permanents_sacrificed += 1
            else:
                opponent_permanents_sacrificed += 1
                if is_live_opponent:
                    live_opponent_permanents_sacrificed += 1

    locked_players = []
    card_types = list(effect_data.get("spell_type_cast_lock_card_types") or ["creature", "planeswalker"])
    for participant in players:
        add_spell_type_cast_lock(
            participant,
            source=card.get("name", "?"),
            source_player=player.name,
            started_turn=turn,
            card_types=card_types,
            duration=effect_data.get("spell_type_cast_lock_duration") or "until_end_of_your_next_turn",
        )
        locked_players.append(participant.name)

    actual_asymmetry = live_opponent_permanents_sacrificed - own_permanents_sacrificed
    resolution_context = {
        **context,
        "creature_or_planeswalker_permanents_seen": permanents_seen,
        "choices_made": len(choices),
        "actual_sacrificed": len(sacrificed_cards),
        "own_permanents_sacrificed": own_permanents_sacrificed,
        "opponent_permanents_sacrificed": opponent_permanents_sacrificed,
        "live_opponent_permanents_sacrificed": live_opponent_permanents_sacrificed,
        "effective_opponent_creatures_destroyed": live_opponent_permanents_sacrificed,
        "actual_asymmetry": actual_asymmetry,
        "locked_players": locked_players,
        "locked_card_types": card_types,
        "timing_justified": bool(
            context["timing_justified"]
            or actual_asymmetry > 0
            or live_opponent_permanents_sacrificed > own_permanents_sacrificed
        ),
    }
    fields = replay_rule_fields(effect_data)
    emit_decision_trace(
        decision_type="board_wipe",
        player=player,
        turn=turn,
        phase="resolution",
        available_options=[
            decision_card_option(card, effect_data, action="resolve_single_combat"),
            {"action": "defer_wipe_not_available_after_resolution"},
        ],
        chosen_option=decision_card_option(card, effect_data, action="resolve_single_combat"),
        rejected_options=[{"action": "defer_wipe_not_available_after_resolution"}],
        score_components=resolution_context,
        rule_source=fields.get("rule_source", "battle_heuristic"),
        rule_status=fields.get("rule_review_status", "heuristic"),
        confidence="medium",
        expected_benefit_score=max(0, actual_asymmetry * 10)
        + min(live_opponent_permanents_sacrificed * 5, 35),
        actual_outcome="board_wipe_resolved",
        reason="each_player_keeps_best_creature_or_planeswalker_and_sacrifices_rest_then_cast_lock",
        strategic_principle="collapse excess creature_planeswalker boards and pause rebuilds until source next turn ends",
        heuristic_version=DECISION_STRATEGY_VERSION,
        resource_delta=resolution_context,
        risk_flags=[] if resolution_context["timing_justified"] else ["wipe_without_timing_justification"],
        rejected_reason="spell_already_resolving",
    )
    emit_replay_event(
        "single_combat_resolved",
        player=player.name,
        card=card.get("name", "?"),
        choices=choices[:24],
        sacrificed_cards=sacrificed_cards[:24],
        sacrificed=len(sacrificed_cards),
        creature_or_planeswalker_permanents_seen=permanents_seen,
        locked_players=locked_players,
        locked_card_types=card_types,
        lock_duration=effect_data.get("spell_type_cast_lock_duration") or "until_end_of_your_next_turn",
        turn=turn,
        **fields,
    )
    finish_resolved_spell(player, card, turn=turn)


def _permanent_matches_sacrifice_filter(permanent, effect_data):
    card_types = {
        str(value or "").strip().lower()
        for value in _as_list((effect_data or {}).get("sacrifice_card_types") or ["creature"])
        if str(value or "").strip()
    }
    if not card_types:
        card_types = {"creature"}
    type_line = _permanent_type_line(permanent)
    type_matches = False
    if "permanent" in card_types and is_permanent_card(permanent):
        type_matches = True
    if "creature" in card_types and is_battlefield_creature(permanent):
        type_matches = True
    if "land" in card_types and (
        permanent == "land"
        or type_line == "land"
        or " land" in f" {type_line}"
        or (isinstance(permanent, dict) and is_effective_land(permanent))
    ):
        type_matches = True
    if "artifact" in card_types and "artifact" in type_line:
        type_matches = True
    if "enchantment" in card_types and "enchantment" in type_line:
        type_matches = True
    if "planeswalker" in card_types and "planeswalker" in type_line:
        type_matches = True
    if "battle" in card_types and "battle" in type_line:
        type_matches = True
    if not type_matches:
        return False
    if (effect_data or {}).get("sacrifice_requires_multicolored"):
        if len(card_color_symbol_set(permanent)) < 2:
            return False
    return True


def _move_sacrificed_permanent(controller, permanent, card, *, reason):
    if is_battlefield_creature(permanent):
        return move_creature_from_battlefield(
            controller,
            permanent,
            reason=reason,
            source=card,
        )
    if isinstance(permanent, dict):
        return move_permanent_from_battlefield(
            controller,
            permanent,
            reason=reason,
            source=card,
        )
    try:
        controller.battlefield.remove(permanent)
    except ValueError:
        pass
    controller.graveyard.append(permanent)
    return "graveyard"


def resolve_each_player_sacrifice(player, opponents, card, effect_data, turn, *, finish_spell=True):
    players = [player] + list(opponents or [])
    context = board_wipe_decision_context(player, opponents)
    sacrifice_count = max(1, int(effect_data.get("sacrifice_count") or effect_data.get("count") or 1))
    sacrificed_cards = []
    choices = []
    permanents_seen = 0
    creatures_seen = 0
    own_permanents_sacrificed = 0
    opponent_permanents_sacrificed = 0
    live_opponent_permanents_sacrificed = 0
    own_creatures_sacrificed = 0
    opponent_creatures_sacrificed = 0
    live_opponent_creatures_sacrificed = 0

    for controller in players:
        is_self = controller is player
        is_live_opponent = (not is_self) and controller.is_alive()
        candidates = [
            permanent
            for permanent in list(getattr(controller, "battlefield", []) or [])
            if _permanent_matches_sacrifice_filter(permanent, effect_data)
        ]
        permanents_seen += len(candidates)
        creatures_seen += sum(1 for permanent in candidates if is_battlefield_creature(permanent))
        chosen = sorted(candidates, key=target_priority)[:sacrifice_count]
        for permanent in chosen:
            was_creature = is_battlefield_creature(permanent)
            destination = _move_sacrificed_permanent(
                controller,
                permanent,
                card,
                reason="each_player_sacrifice",
            )
            record = {
                "controller": controller.name,
                "name": permanent.get("name", "?") if isinstance(permanent, dict) else str(permanent),
                "type_line": _permanent_type_line(permanent),
                "destination": destination,
            }
            choices.append(record)
            sacrificed_cards.append(record)
            if is_self:
                own_permanents_sacrificed += 1
                if was_creature:
                    own_creatures_sacrificed += 1
            else:
                opponent_permanents_sacrificed += 1
                if is_live_opponent:
                    live_opponent_permanents_sacrificed += 1
                if was_creature:
                    opponent_creatures_sacrificed += 1
                    if is_live_opponent:
                        live_opponent_creatures_sacrificed += 1

    actual_asymmetry = live_opponent_permanents_sacrificed - own_permanents_sacrificed
    resolution_context = {
        **context,
        "sacrifice_count": sacrifice_count,
        "sacrifice_card_types": list(effect_data.get("sacrifice_card_types") or ["creature"]),
        "sacrifice_requires_multicolored": bool(effect_data.get("sacrifice_requires_multicolored")),
        "permanents_seen": permanents_seen,
        "creatures_seen": creatures_seen,
        "actual_sacrificed": len(sacrificed_cards),
        "own_permanents_sacrificed": own_permanents_sacrificed,
        "opponent_permanents_sacrificed": opponent_permanents_sacrificed,
        "live_opponent_permanents_sacrificed": live_opponent_permanents_sacrificed,
        "own_creatures_sacrificed": own_creatures_sacrificed,
        "opponent_creatures_sacrificed": opponent_creatures_sacrificed,
        "live_opponent_creatures_sacrificed": live_opponent_creatures_sacrificed,
        "effective_opponent_creatures_destroyed": live_opponent_creatures_sacrificed,
        "actual_asymmetry": actual_asymmetry,
        "timing_justified": bool(
            context["timing_justified"]
            or actual_asymmetry > 0
            or live_opponent_permanents_sacrificed > own_permanents_sacrificed
        ),
    }
    risk_flags = []
    if not resolution_context["timing_justified"]:
        risk_flags.append("wipe_without_timing_justification")
    elif (
        actual_asymmetry <= 0
        and not context["lethal_pressure"]
        and not context["behind_on_board"]
    ):
        risk_flags.append("wipe_without_clear_asymmetry")
    fields = replay_rule_fields(effect_data)
    emit_decision_trace(
        decision_type="board_wipe",
        player=player,
        turn=turn,
        phase="resolution",
        available_options=[
            decision_card_option(card, effect_data, action="resolve_each_player_sacrifice"),
            {"action": "defer_wipe_not_available_after_resolution"},
        ],
        chosen_option=decision_card_option(card, effect_data, action="resolve_each_player_sacrifice"),
        rejected_options=[{"action": "defer_wipe_not_available_after_resolution"}],
        score_components=resolution_context,
        rule_source=fields.get("rule_source", "battle_heuristic"),
        rule_status=fields.get("rule_review_status", "heuristic"),
        confidence="medium",
        expected_benefit_score=max(0, actual_asymmetry * 10)
        + min(live_opponent_permanents_sacrificed * 5, 35),
        actual_outcome="each_player_sacrifice_resolved",
        reason="each_player_sacrifices_lowest_value_matching_permanents",
        strategic_principle="model_each_controller_choice_as_lowest_value_loss",
        heuristic_version=DECISION_STRATEGY_VERSION,
        resource_delta=resolution_context,
        risk_flags=risk_flags,
        rejected_reason="spell_already_resolving",
    )
    emit_replay_event(
        "each_player_sacrifice_resolved",
        player=player.name,
        card=card.get("name", "?"),
        sacrifice_count=sacrifice_count,
        sacrifice_card_types=list(effect_data.get("sacrifice_card_types") or ["creature"]),
        sacrifice_requires_multicolored=bool(effect_data.get("sacrifice_requires_multicolored")),
        sacrificed=len(sacrificed_cards),
        sacrificed_cards=sacrificed_cards[:24],
        choices=choices[:24],
        trigger=effect_data.get("trigger"),
        trigger_effect=effect_data.get("trigger_effect"),
        permanents_seen=permanents_seen,
        creatures_seen=creatures_seen,
        own_permanents_sacrificed=own_permanents_sacrificed,
        opponent_permanents_sacrificed=opponent_permanents_sacrificed,
        live_opponent_permanents_sacrificed=live_opponent_permanents_sacrificed,
        own_creatures_sacrificed=own_creatures_sacrificed,
        opponent_creatures_sacrificed=opponent_creatures_sacrificed,
        live_opponent_creatures_sacrificed=live_opponent_creatures_sacrificed,
        actual_asymmetry=actual_asymmetry,
        risk_flags=risk_flags,
        turn=turn,
        **fields,
    )
    if finish_spell:
        finish_resolved_spell(player, card, turn=turn)


def permanent_matches_tragic_arrogance_choice(permanent, choice_type):
    if choice_type == "artifact":
        return is_artifact_permanent(permanent)
    if choice_type == "creature":
        return is_battlefield_creature(permanent)
    if choice_type == "enchantment":
        return is_enchantment_permanent(permanent)
    if choice_type == "planeswalker":
        return is_planeswalker_permanent(permanent)
    return False


def resolve_tragic_arrogance(player, opponents, card, effect_data, turn):
    players = [player] + list(opponents or [])
    context = board_wipe_decision_context(player, opponents)
    choice_types = list(
        effect_data.get("choice_types")
        or ["artifact", "creature", "enchantment", "planeswalker"]
    )
    choices = []
    sacrificed_cards = []
    nonland_seen = 0
    own_permanents_sacrificed = 0
    opponent_permanents_sacrificed = 0
    live_opponent_permanents_sacrificed = 0
    own_creatures_sacrificed = 0
    opponent_creatures_sacrificed = 0
    live_opponent_creatures_sacrificed = 0

    for controller in players:
        is_self = controller is player
        is_live_opponent = (not is_self) and controller.is_alive()
        nonland_permanents = [
            permanent
            for permanent in list(getattr(controller, "battlefield", []) or [])
            if isinstance(permanent, dict) and not is_effective_land(permanent)
        ]
        nonland_seen += len(nonland_permanents)
        chosen_ids = set()
        for choice_type in choice_types:
            candidates = [
                permanent
                for permanent in nonland_permanents
                if permanent_matches_tragic_arrogance_choice(permanent, choice_type)
            ]
            if not candidates:
                continue
            chosen = max(candidates, key=target_priority)
            chosen_ids.add(id(chosen))
            choices.append(
                {
                    "controller": controller.name,
                    "choice_type": choice_type,
                    "name": chosen.get("name", "?"),
                    "type_line": chosen.get("type_line", ""),
                    "target_score": list(target_priority(chosen)),
                }
            )

        for permanent in nonland_permanents:
            if id(permanent) in chosen_ids:
                continue
            was_creature = is_battlefield_creature(permanent)
            destination = move_permanent_from_battlefield(
                controller,
                permanent,
                reason="tragic_arrogance",
                source=card,
            )
            sacrificed_cards.append(
                {
                    "controller": controller.name,
                    "name": permanent.get("name", "?"),
                    "type_line": permanent.get("type_line", ""),
                    "destination": destination,
                }
            )
            if is_self:
                own_permanents_sacrificed += 1
                if was_creature:
                    own_creatures_sacrificed += 1
            else:
                opponent_permanents_sacrificed += 1
                if is_live_opponent:
                    live_opponent_permanents_sacrificed += 1
                if was_creature:
                    opponent_creatures_sacrificed += 1
                    if is_live_opponent:
                        live_opponent_creatures_sacrificed += 1

    actual_asymmetry = live_opponent_permanents_sacrificed - own_permanents_sacrificed
    resolution_context = {
        **context,
        "nonland_permanents_seen": nonland_seen,
        "choices_made": len(choices),
        "actual_sacrificed": len(sacrificed_cards),
        "own_permanents_sacrificed": own_permanents_sacrificed,
        "opponent_permanents_sacrificed": opponent_permanents_sacrificed,
        "live_opponent_permanents_sacrificed": live_opponent_permanents_sacrificed,
        "own_creatures_sacrificed": own_creatures_sacrificed,
        "opponent_creatures_sacrificed": opponent_creatures_sacrificed,
        "live_opponent_creatures_sacrificed": live_opponent_creatures_sacrificed,
        "effective_opponent_creatures_destroyed": live_opponent_creatures_sacrificed,
        "actual_asymmetry": actual_asymmetry,
        "timing_justified": bool(
            context["timing_justified"]
            or actual_asymmetry > 0
            or live_opponent_permanents_sacrificed > own_permanents_sacrificed
        ),
    }
    risk_flags = []
    if not resolution_context["timing_justified"]:
        risk_flags.append("wipe_without_timing_justification")
    elif (
        actual_asymmetry <= 0
        and not context["lethal_pressure"]
        and not context["behind_on_board"]
    ):
        risk_flags.append("wipe_without_clear_asymmetry")

    fields = replay_rule_fields(effect_data)
    emit_decision_trace(
        decision_type="board_wipe",
        player=player,
        turn=turn,
        phase="resolution",
        available_options=[
            decision_card_option(card, effect_data, action="resolve_selective_nonland_sacrifice"),
            {"action": "defer_wipe_not_available_after_resolution"},
        ],
        chosen_option=decision_card_option(
            card,
            effect_data,
            action="resolve_selective_nonland_sacrifice",
        ),
        rejected_options=[{"action": "defer_wipe_not_available_after_resolution"}],
        score_components=resolution_context,
        rule_source=fields.get("rule_source", "battle_heuristic"),
        rule_status=fields.get("rule_review_status", "heuristic"),
        confidence="medium",
        expected_benefit_score=max(0, actual_asymmetry * 10)
        + min(live_opponent_permanents_sacrificed * 5, 35),
        actual_outcome="board_wipe_resolved",
        reason="controller_chooses_each_player_kept_permanents_then_sacrifices_other_nonlands",
        strategic_principle="keep_best_per_type_while_collapsing_excess_nonland_boards",
        heuristic_version=DECISION_STRATEGY_VERSION,
        resource_delta=resolution_context,
        risk_flags=risk_flags,
        rejected_reason="spell_already_resolving",
    )
    emit_replay_event(
        "board_wipe_resolved",
        player=player.name,
        card=card.get("name", "?"),
        destroyed=len(sacrificed_cards),
        sacrificed=len(sacrificed_cards),
        protected=len({(entry["controller"], entry["name"]) for entry in choices}),
        nonland_permanents_seen=nonland_seen,
        choices=choices[:24],
        sacrificed_cards=sacrificed_cards[:24],
        own_permanents_sacrificed=own_permanents_sacrificed,
        opponent_permanents_sacrificed=opponent_permanents_sacrificed,
        live_opponent_permanents_sacrificed=live_opponent_permanents_sacrificed,
        own_creatures_sacrificed=own_creatures_sacrificed,
        opponent_creatures_sacrificed=opponent_creatures_sacrificed,
        live_opponent_creatures_sacrificed=live_opponent_creatures_sacrificed,
        actual_asymmetry=actual_asymmetry,
        risk_flags=risk_flags,
        turn=turn,
        **fields,
    )
    finish_resolved_spell(player, card, turn=turn)


CREATURE_TYPE_STOPWORDS = {
    "artifact",
    "battle",
    "creature",
    "enchantment",
    "instant",
    "kindred",
    "land",
    "legendary",
    "planeswalker",
    "snow",
    "sorcery",
    "token",
}


def creature_types_for_permanent(permanent):
    if not isinstance(permanent, dict):
        return set()
    explicit = permanent.get("creature_types") or permanent.get("subtypes")
    if isinstance(explicit, str):
        return {
            value.strip().lower()
            for value in re.split(r"[,/ ]+", explicit)
            if value.strip()
        }
    if isinstance(explicit, (list, tuple, set)):
        return {
            str(value).strip().lower()
            for value in explicit
            if str(value).strip()
        }

    type_line = str(permanent.get("type_line") or "")
    if "creature" not in type_line.lower():
        return set()
    if "—" in type_line:
        subtype_text = type_line.split("—", 1)[1]
    elif " - " in type_line:
        subtype_text = type_line.split(" - ", 1)[1]
    else:
        match = re.search(r"\bcreature\b(.*)$", type_line, flags=re.IGNORECASE)
        subtype_text = match.group(1) if match else ""
    return {
        token.strip().lower()
        for token in re.split(r"[^A-Za-z0-9']+", subtype_text)
        if token.strip() and token.strip().lower() not in CREATURE_TYPE_STOPWORDS
    }


def convoked_creature_types_for_wipe(player, effect_data):
    explicit = (effect_data or {}).get("convoked_creature_types")
    if isinstance(explicit, str):
        values = {
            value.strip().lower()
            for value in re.split(r"[,/ ]+", explicit)
            if value.strip()
        }
        if values:
            return values, "explicit"
    if isinstance(explicit, (list, tuple, set)):
        values = {
            str(value).strip().lower()
            for value in explicit
            if str(value).strip()
        }
        if values:
            return values, "explicit"

    inferred = set()
    for permanent in getattr(player, "battlefield", []) or []:
        if not is_battlefield_creature(permanent):
            continue
        if permanent.get("convoked_this_spell") or permanent.get("tapped_for_convoke"):
            inferred.update(creature_types_for_permanent(permanent))
    if inferred:
        return inferred, "marked_convoked_permanents"

    if (effect_data or {}).get("infer_convoked_types_from_controller_creatures"):
        for permanent in getattr(player, "battlefield", []) or []:
            if is_battlefield_creature(permanent):
                inferred.update(creature_types_for_permanent(permanent))
        if inferred:
            return inferred, "controller_creature_inference"

    return set(), "fallback_no_convoked_types"


def permanent_matches_everything_comes_to_dust(permanent, convoked_types):
    if not isinstance(permanent, dict):
        return False, "not_permanent"
    if is_artifact_permanent(permanent):
        return True, "artifact"
    if is_enchantment_permanent(permanent):
        return True, "enchantment"
    if not is_battlefield_creature(permanent):
        return False, "not_creature_artifact_or_enchantment"
    creature_types = creature_types_for_permanent(permanent)
    if creature_types and convoked_types and creature_types.intersection(convoked_types):
        return False, "shares_convoked_creature_type"
    return True, "creature_without_convoked_type"


def resolve_everything_comes_to_dust(player, opponents, card, effect_data, turn):
    convoked_types, convoked_type_source = convoked_creature_types_for_wipe(
        player,
        effect_data,
    )
    context = board_wipe_decision_context(player, opponents)
    exiled = []
    preserved_by_convoke = []
    seen = 0
    own_exiled = 0
    opponent_exiled = 0
    live_opponent_exiled = 0
    own_creatures_exiled = 0
    opponent_creatures_exiled = 0
    live_opponent_creatures_exiled = 0
    for controller in [player] + list(opponents or []):
        is_self = controller is player
        is_live_opponent = (not is_self) and controller.is_alive()
        for permanent in list(getattr(controller, "battlefield", []) or []):
            should_exile, reason = permanent_matches_everything_comes_to_dust(
                permanent,
                convoked_types,
            )
            if reason != "not_permanent":
                seen += 1
            if not should_exile:
                if reason == "shares_convoked_creature_type":
                    preserved_by_convoke.append(
                        {
                            "controller": controller.name,
                            "name": permanent.get("name", "?"),
                            "type_line": permanent.get("type_line", ""),
                            "creature_types": sorted(
                                creature_types_for_permanent(permanent)
                            ),
                        }
                    )
                continue

            was_creature = is_battlefield_creature(permanent)
            destination = move_zone_object_to_exile(
                controller,
                "battlefield",
                permanent,
                reason="everything_comes_to_dust",
                source=card,
                turn=turn,
            )
            exiled.append(
                {
                    "controller": controller.name,
                    "name": permanent.get("name", "?"),
                    "type_line": permanent.get("type_line", ""),
                    "match_reason": reason,
                    "destination": destination,
                }
            )
            if is_self:
                own_exiled += 1
            else:
                opponent_exiled += 1
                if is_live_opponent:
                    live_opponent_exiled += 1
            if was_creature:
                if is_self:
                    own_creatures_exiled += 1
                else:
                    opponent_creatures_exiled += 1
                    if is_live_opponent:
                        live_opponent_creatures_exiled += 1

    actual_asymmetry = live_opponent_exiled - own_exiled
    resolution_context = {
        **context,
        "destination": "exile",
        "convoked_creature_types": sorted(convoked_types),
        "convoked_type_source": convoked_type_source,
        "permanents_seen": seen,
        "actual_exiled": len(exiled),
        "preserved_by_convoke": len(preserved_by_convoke),
        "own_permanents_exiled": own_exiled,
        "opponent_permanents_exiled": opponent_exiled,
        "live_opponent_permanents_exiled": live_opponent_exiled,
        "own_creatures_exiled": own_creatures_exiled,
        "opponent_creatures_exiled": opponent_creatures_exiled,
        "live_opponent_creatures_exiled": live_opponent_creatures_exiled,
        "effective_opponent_creatures_destroyed": live_opponent_creatures_exiled,
        "actual_asymmetry": actual_asymmetry,
        "timing_justified": bool(
            context["timing_justified"]
            or actual_asymmetry > 0
            or live_opponent_exiled > 0
        ),
    }
    risk_flags = []
    if convoked_type_source == "fallback_no_convoked_types":
        risk_flags.append("convoke_creature_types_not_observed")
    if not resolution_context["timing_justified"]:
        risk_flags.append("wipe_without_timing_justification")
    elif (
        actual_asymmetry <= 0
        and not context["lethal_pressure"]
        and not context["behind_on_board"]
    ):
        risk_flags.append("wipe_without_clear_asymmetry")

    fields = replay_rule_fields(effect_data)
    emit_decision_trace(
        decision_type="board_wipe",
        player=player,
        turn=turn,
        phase="resolution",
        available_options=[
            decision_card_option(card, effect_data, action="resolve_convoke_exile_wipe"),
            {"action": "defer_wipe_not_available_after_resolution"},
        ],
        chosen_option=decision_card_option(
            card,
            effect_data,
            action="resolve_convoke_exile_wipe",
        ),
        rejected_options=[{"action": "defer_wipe_not_available_after_resolution"}],
        score_components=resolution_context,
        rule_source=fields.get("rule_source", "battle_heuristic"),
        rule_status=fields.get("rule_review_status", "heuristic"),
        confidence="medium"
        if convoked_type_source != "fallback_no_convoked_types"
        else "low",
        expected_benefit_score=max(0, actual_asymmetry * 10)
        + min(live_opponent_exiled * 5, 35),
        actual_outcome="board_wipe_resolved",
        reason="resolve_convoke_exception_exile_wipe",
        strategic_principle="exile_wipe_when_opponent_board_loss_outweighs_own_loss",
        heuristic_version=DECISION_STRATEGY_VERSION,
        resource_delta=resolution_context,
        risk_flags=risk_flags,
        rejected_reason="spell_already_resolving",
    )
    emit_replay_event(
        "board_wipe_resolved",
        player=player.name,
        card=card.get("name", "?"),
        destroyed=0,
        exiled=len(exiled),
        protected=len(preserved_by_convoke),
        destination="exile",
        convoked_creature_types=sorted(convoked_types),
        convoked_type_source=convoked_type_source,
        preserved_by_convoke=preserved_by_convoke[:20],
        exiled_cards=exiled[:20],
        own_permanents_exiled=own_exiled,
        opponent_permanents_exiled=opponent_exiled,
        live_opponent_permanents_exiled=live_opponent_exiled,
        own_creatures_exiled=own_creatures_exiled,
        opponent_creatures_exiled=opponent_creatures_exiled,
        live_opponent_creatures_exiled=live_opponent_creatures_exiled,
        actual_asymmetry=actual_asymmetry,
        risk_flags=risk_flags,
        turn=turn,
        **fields,
    )
    finish_resolved_spell(player, card, turn=turn)


def is_wheel_of_misfortune_model(card, effect_data):
    if not isinstance(effect_data, dict):
        effect_data = {}
    name = normalize_card_name(card.get("name", "")) if isinstance(card, dict) else ""
    return bool(effect_data.get("misfortune_secret_number_model")) or name == "wheel of misfortune"


def wheel_decision_context(player, opponents, draw_count, effect_data=None):
    effect_data = effect_data if isinstance(effect_data, dict) else {}
    misfortune_model = is_wheel_of_misfortune_model(effect_data, effect_data)
    hand_size = len(player.hand)
    library_cards_before = len(getattr(player, "library", []) or [])
    library_can_support_draw = library_cards_before >= draw_count
    opponent_hands = [len(opp.hand) for opp in opponents if opp.is_alive()]
    net_cards_for_player = draw_count - hand_size
    if misfortune_model:
        opponent_refill_risk = 0
        opponent_net_cards = [0 for _size in opponent_hands]
    else:
        opponent_refill_risk = sum(1 for size in opponent_hands if size < draw_count)
        opponent_net_cards = [
            draw_count - size
            for size in opponent_hands
        ]
    total_opponent_net_cards = sum(max(0, value) for value in opponent_net_cards)
    payoff_names = {
        permanent.get("name")
        for permanent in player.battlefield
        if isinstance(permanent, dict)
        and permanent.get("name") in {"Smothering Tithe", "Notion Thief", "Narset, Parter of Veils"}
    }
    payoff_expected = bool(payoff_names)
    timing_justified = library_can_support_draw and (
        payoff_expected
        or (net_cards_for_player >= 4 and opponent_refill_risk == 0)
        or (net_cards_for_player >= 5 and total_opponent_net_cards <= net_cards_for_player)
    )
    return {
        "hand_size_before": hand_size,
        "draw_count": draw_count,
        "library_cards_before": library_cards_before,
        "library_can_support_draw": library_can_support_draw,
        "net_cards_for_player": net_cards_for_player,
        "opponent_hand_sizes": opponent_hands,
        "opponent_net_cards": opponent_net_cards,
        "total_opponent_net_cards": total_opponent_net_cards,
        "opponent_refill_risk": opponent_refill_risk,
        "wheel_payoffs": sorted(payoff_names),
        "payoff_expected": payoff_expected,
        "timing_justified": timing_justified,
        "model_scope": (
            "wheel_of_misfortune_secret_number_compact_v1"
            if misfortune_model
            else "multiplayer_discard_draw_v1"
        ),
    }


def is_land_tax_upkeep_permanent(permanent):
    return (
        isinstance(permanent, dict)
        and (
            permanent.get("effect") == "land_tax"
            or permanent.get("battle_model_scope")
            == "land_tax_upkeep_opponent_more_lands_basic_land_tutor_to_hand_v1"
            or normalize_card_name(permanent.get("name", "")) == "land tax"
        )
    )


def resolve_land_tax_upkeep_trigger(player, permanent, turn, all_players=None):
    """Resolve Land Tax's beginning-of-upkeep basic-land tutor."""
    effect_data = permanent if isinstance(permanent, dict) else {}
    fields = replay_rule_fields(effect_data)
    all_players = list(all_players or [])
    opponents = [
        candidate
        for candidate in all_players
        if candidate is not player and getattr(candidate, "is_alive", lambda: True)()
    ]
    player_land_count = controlled_land_count(player)
    opponent_land_counts = [
        {
            "player": getattr(opponent, "name", "Opponent"),
            "lands": controlled_land_count(opponent),
        }
        for opponent in opponents
    ]
    max_opponent_land_count = max(
        (entry["lands"] for entry in opponent_land_counts),
        default=0,
    )
    condition_met = max_opponent_land_count > player_land_count
    target_type = str(effect_data.get("tutor_target") or effect_data.get("target") or "basic_land")
    try:
        max_count = max(0, int(effect_data.get("max_count") or effect_data.get("count") or 3))
    except (TypeError, ValueError):
        max_count = 3

    if not condition_met:
        emit_replay_event(
            "land_tax_trigger_skipped",
            player=player.name,
            card=permanent.get("name", "Land Tax"),
            trigger="beginning_of_your_upkeep",
            condition="opponent_controls_more_lands",
            condition_met=False,
            player_land_count=player_land_count,
            opponent_land_counts=opponent_land_counts,
            max_opponent_land_count=max_opponent_land_count,
            turn=turn,
            **fields,
        )
        return 0

    candidates = constrained_library_tutor_candidates(player, target_type, effect_data)
    scored_candidates = [
        (
            candidate,
            *tutor_candidate_score(candidate, target_type, player, opponents, turn),
        )
        for candidate in candidates
    ]
    scored_candidates.sort(
        key=lambda item: (
            -item[1],
            item[0].get("name", ""),
            str(item[0].get("type_line") or ""),
        )
    )
    selected = scored_candidates[:max_count]
    moved = []
    for selected_card, _score, _reason in selected:
        if selected_card not in player.library:
            continue
        player.library.remove(selected_card)
        player.hand.append(selected_card)
        moved.append(selected_card)

    selected_names = [card.get("name", "?") for card in moved]
    expected_score = sum(score for _card, score, _reason in selected)
    risk_flags = [] if moved else ["no_basic_land_target"]
    chosen_option = {
        "card": permanent.get("name", "Land Tax"),
        "action": "resolve_upkeep_tutor",
        "effect": "land_tax",
        "score": expected_score,
        "found_cards": selected_names,
        "target_type": target_type,
    }
    rejected_land_options = [
        decision_card_option(
            candidate,
            get_card_effect(candidate),
            score=score,
            action="reject_tutor_target",
            reason=reason,
            target_type=target_type,
        )
        for candidate, score, reason in scored_candidates[max_count:10]
    ]
    if moved and not rejected_land_options:
        rejected_land_options.append(
            {
                "action": "decline_optional_tutor",
                "target_type": target_type,
                "score": 0,
                "reason": "optional_trigger_but_card_advantage_selected",
            }
        )
    emit_decision_trace(
        decision_type="land_tax_upkeep_tutor",
        player=player,
        turn=turn,
        phase="upkeep",
        available_options=[
            decision_card_option(
                candidate,
                get_card_effect(candidate),
                score=score,
                action="tutor_to_hand",
                reason=reason,
                target_type=target_type,
            )
            for candidate, score, reason in scored_candidates[:10]
        ] or [{"action": "resolve_without_target", "target_type": target_type}],
        chosen_option=chosen_option,
        rejected_options=rejected_land_options,
        score_components={
            "player_land_count": player_land_count,
            "opponent_land_counts": opponent_land_counts,
            "max_opponent_land_count": max_opponent_land_count,
            "candidate_count": len(scored_candidates),
            "selected_count": len(moved),
            "max_count": max_count,
            "reveals": bool(effect_data.get("reveals", True)),
            "shuffle_after": bool(effect_data.get("shuffle_after", True)),
        },
        rule_source=fields.get("rule_source", "battle_rule"),
        rule_status=fields.get("rule_review_status", "active"),
        confidence="medium",
        expected_benefit_score=expected_score,
        actual_outcome="land_tax_upkeep_tutor_resolved",
        reason="opponent_controls_more_lands",
        strategic_principle="convert_land_deficit_into_basic_land_card_advantage",
        heuristic_version=DECISION_STRATEGY_VERSION,
        resource_delta={
            "cards": len(moved),
            "lands": 0,
            "selected": selected_names,
            "zone_move": "library_to_hand",
        },
        risk_flags=risk_flags,
        rejected_reason="not_selected_within_land_tax_limit",
    )
    emit_replay_event(
        "land_tax_trigger_resolved",
        player=player.name,
        card=permanent.get("name", "Land Tax"),
        trigger="beginning_of_your_upkeep",
        condition="opponent_controls_more_lands",
        condition_met=True,
        target_type=target_type,
        found=selected_names[0] if selected_names else None,
        found_cards=selected_names,
        found_count=len(moved),
        max_count=max_count,
        destination="hand",
        reveals=bool(effect_data.get("reveals", True)),
        shuffle_after=bool(effect_data.get("shuffle_after", True)),
        library_order_model="deterministic_no_random_shuffle",
        player_land_count=player_land_count,
        opponent_land_counts=opponent_land_counts,
        max_opponent_land_count=max_opponent_land_count,
        turn=turn,
        **fields,
    )
    return len(moved)


def process_upkeep_utility_lands(player, turn, all_players=None):
    """Resolve low-risk beginning-of-upkeep utility effects."""
    triggers = 0
    artifact_count = controlled_artifact_count(player)
    land_nonmana_suppressed = lands_have_nonmana_abilities_suppressed(
        all_players,
        player=player,
    )
    for permanent in list(player.battlefield):
        if not is_land_tax_upkeep_permanent(permanent):
            continue
        if permanent.get("land_tax_last_trigger_turn") == turn:
            continue
        permanent["land_tax_last_trigger_turn"] = turn
        triggers += resolve_land_tax_upkeep_trigger(
            player,
            permanent,
            turn,
            all_players=all_players,
        )
    for permanent in list(player.battlefield):
        if not isinstance(permanent, dict) or not is_effective_land(permanent):
            continue
        initialize_special_land_runtime_state(permanent, turn=None)
        if is_urzas_saga(permanent):
            if land_nonmana_suppressed:
                _utility_land_skip_event(
                    player,
                    permanent,
                    turn,
                    "land_nonmana_abilities_suppressed",
                    phase="upkeep",
                    risk_flags=["global_land_static_suppression"],
                )
                continue
            current_chapter = max(
                int(permanent.get("current_chapter") or 1),
                int(permanent.get("lore_counters") or 0),
            )
            if permanent.get("saga_last_lore_turn") != turn and current_chapter < 3:
                next_chapter = current_chapter + 1
                permanent["current_chapter"] = next_chapter
                permanent["lore_counters"] = next_chapter
                permanent["saga_last_lore_turn"] = turn
                permanent["chapter_ability_pending"] = True
                emit_replay_event(
                    "saga_chapter_progressed",
                    player=player.name,
                    card=permanent.get("name", "?"),
                    chapter=next_chapter,
                    turn=turn,
                )
                if next_chapter == 3:
                    candidates = [
                        candidate
                        for candidate in player.library
                        if isinstance(candidate, dict)
                        and "artifact" in str(candidate.get("type_line") or "").lower()
                        and int(float(candidate.get("cmc") or 0)) <= 1
                        and "discard a land card" not in str(candidate.get("oracle_text") or "").lower()
                        and "imprint" not in str(candidate.get("oracle_text") or "").lower()
                    ]
                    scored_candidates = [
                        (
                            candidate,
                            *tutor_candidate_score(candidate, "artifact_cmc_1_or_less", player, [], turn),
                        )
                        for candidate in candidates
                    ]
                    scored_candidates.sort(
                        key=lambda item: (
                            -item[1],
                            int(float(item[0].get("cmc") or 0)),
                            item[0].get("name", ""),
                        )
                    )
                    found = None
                    found_score = 0
                    found_reason = "no_safe_artifact_target"
                    if scored_candidates:
                        found, found_score, found_reason = scored_candidates[0]
                        player.library.remove(found)
                        permanent_effect = get_card_effect(found)
                        found_permanent = prepare_entering_permanent(
                            enrich_card({**found, **permanent_effect})
                        )
                        if is_creature_card(found_permanent):
                            found_permanent["effect"] = "creature"
                        player.battlefield.append(found_permanent)
                    emit_decision_trace(
                        decision_type="saga_chapter_resolution",
                        player=player,
                        turn=turn,
                        phase="upkeep",
                        available_options=[
                            decision_card_option(
                                candidate,
                                get_card_effect(candidate),
                                score=score,
                                action="tutor_to_battlefield",
                                reason=reason,
                                target_type="artifact_cmc_1_or_less",
                            )
                            for candidate, score, reason in scored_candidates[:10]
                        ],
                        chosen_option=(
                            decision_card_option(
                                found,
                                get_card_effect(found),
                                score=found_score,
                                action="tutor_to_battlefield",
                                reason=found_reason,
                                target_type="artifact_cmc_1_or_less",
                            )
                            if found is not None
                            else {
                                "action": "resolve_without_target",
                                "target_type": "artifact_cmc_1_or_less",
                                "reason": found_reason,
                            }
                        ),
                        rejected_options=[
                            decision_card_option(
                                candidate,
                                get_card_effect(candidate),
                                score=score,
                                action="reject_tutor_target",
                                reason=reason,
                                target_type="artifact_cmc_1_or_less",
                            )
                            for candidate, score, reason in scored_candidates[1:10]
                        ],
                        score_components={
                            "chapter": 3,
                            "candidate_count": len(scored_candidates),
                            "selected_reason": found_reason,
                        },
                        rule_source="utility_land_activation_v1",
                        rule_status="verified",
                        confidence="medium",
                        expected_benefit_score=found_score,
                        reason="convert_final_saga_chapter_into_best_safe_artifact",
                        strategic_principle="tutor_best_low_cost_artifact_before_saga_leaves",
                        resource_delta={
                            "cards": 1 if found is not None else 0,
                            "lands": 0,
                            "selected": found.get("name", "?") if found is not None else None,
                            "zone_move": "library_to_battlefield",
                        },
                        risk_flags=[] if found is not None else ["no_safe_target"],
                        rejected_reason="lower_contextual_tutor_score",
                    )
                    emit_replay_event(
                        "saga_chapter_resolved",
                        player=player.name,
                        card=permanent.get("name", "?"),
                        chapter=3,
                        target_type="artifact_cmc_1_or_less",
                        found=found.get("name", "?") if found is not None else None,
                        candidate_count=len(scored_candidates),
                        candidate_names=[
                            candidate.get("name", "?")
                            for candidate, _score, _reason in scored_candidates[:10]
                        ],
                        legal_target_count=len(candidates),
                        legal_target_names=[
                            candidate.get("name", "?")
                            for candidate in candidates[:20]
                        ],
                        selected_reason=found_reason,
                        turn=turn,
                    )
                permanent["chapter_ability_pending"] = False
                triggers += 1
        if normalize_card_name(permanent.get("name", "")) == "inventors' fair":
            if land_nonmana_suppressed:
                _utility_land_skip_event(
                    player,
                    permanent,
                    turn,
                    "land_nonmana_abilities_suppressed",
                    phase="upkeep",
                    risk_flags=["global_land_static_suppression"],
                )
                continue
            if artifact_count >= 3:
                gain_life(player, 1, cap=999)
                emit_replay_event(
                    "utility_land_triggered",
                    player=player.name,
                    card=permanent.get("name", "?"),
                    trigger_kind="upkeep_life_gain",
                    life_gained=1,
                    artifact_count=artifact_count,
                    turn=turn,
                )
                triggers += 1
    return triggers


def _saga_chapter_entry(permanent, chapter):
    chapters = permanent.get("saga_chapter_effects") or {}
    if not isinstance(chapters, dict):
        return {}
    return chapters.get(str(chapter)) or chapters.get(chapter) or {}


def resolve_modeled_saga_chapter(player, opponents, permanent, chapter, turn, rng, *, stack=None, all_players=None, phase="after_draw_step"):
    chapter_effect = _saga_chapter_entry(permanent, chapter)
    if not isinstance(chapter_effect, dict):
        chapter_effect = {}
    effect_kind = chapter_effect.get("effect")
    if effect_kind == "token_maker":
        token_fields = dict(permanent)
        token_fields.update(chapter_effect)
        created = create_creature_tokens_from_effect(
            player,
            token_fields,
            count=int(chapter_effect.get("token_count") or token_fields.get("token_count") or 1),
            opponents=opponents,
            turn=turn,
            source_event="saga_chapter_token_created",
            stack=stack,
            active_player=player,
            all_players=all_players or [player, *(opponents or [])],
        )
        emit_replay_event(
            "saga_chapter_resolved",
            player=player.name,
            card=permanent.get("name", "?"),
            chapter=chapter,
            effect="token_maker",
            tokens_created=created,
            token_name=chapter_effect.get("token_name") or permanent.get("token_name") or "Token",
            turn=turn,
            phase=phase,
            **replay_rule_fields(permanent),
        )
        return created
    if effect_kind == "discard_draw":
        max_count = max(0, int(chapter_effect.get("max_discard") or 0))
        candidates = [
            card
            for card in list(getattr(player, "hand", []) or [])
            if isinstance(card, dict) and not card.get("is_commander")
        ]
        candidates.sort(
            key=lambda card: (
                0 if is_effective_land(card) else 1,
                int(float(card.get("cmc") or 0)),
                card.get("name", ""),
            )
        )
        discarded = candidates[:max_count]
        for discarded_card in discarded:
            if discarded_card in player.hand:
                player.hand.remove(discarded_card)
                player.graveyard.append(discarded_card)
        if discarded:
            process_player_discard_triggers(
                player,
                discarded,
                opponents=opponents,
                turn=turn,
                phase=phase,
                rng=rng,
            )
        drawn = player.draw(len(discarded), rng)
        process_player_draw_triggers(
            player,
            len(drawn),
            turn,
            phase,
            all_players or [player, *(opponents or [])],
            stack=stack,
            turn_player=player,
        )
        emit_replay_event(
            "saga_chapter_resolved",
            player=player.name,
            card=permanent.get("name", "?"),
            chapter=chapter,
            effect="discard_draw",
            discarded=[card.get("name", "?") for card in discarded],
            cards_discarded=len(discarded),
            cards_drawn=len(drawn),
            turn=turn,
            phase=phase,
            **replay_rule_fields(permanent),
        )
        return len(drawn)
    if effect_kind == "transform":
        transform_to = dict(permanent.get("transform_to") or chapter_effect.get("transform_to") or {})
        if permanent in player.battlefield:
            player.battlefield.remove(permanent)
            player.exile.append(permanent)
        transformed = enrich_card(transform_to)
        transformed.setdefault("effect", transform_to.get("effect") or "creature")
        transformed = prepare_entering_permanent(
            transformed,
            controller=player,
            all_players=all_players or [player, *(opponents or [])],
            turn=turn,
        )
        player.battlefield.append(transformed)
        emit_replay_event(
            "saga_chapter_resolved",
            player=player.name,
            card=permanent.get("name", "?"),
            chapter=chapter,
            effect="transform",
            transformed_to=transformed.get("name", "?"),
            turn=turn,
            phase=phase,
            **replay_rule_fields(permanent),
        )
        return transformed
    emit_replay_event(
        "saga_chapter_resolved",
        player=player.name,
        card=permanent.get("name", "?"),
        chapter=chapter,
        effect=effect_kind or "none",
        result="no_modeled_effect",
        turn=turn,
        phase=phase,
        **replay_rule_fields(permanent),
    )
    return None


def process_after_draw_step_sagas(player, opponents, all_players, turn, rng, *, stack=None):
    triggers = 0
    for permanent in list(getattr(player, "battlefield", []) or []):
        if not has_modeled_saga_chapters(permanent):
            continue
        initialize_saga_runtime_state(permanent)
        current_chapter = max(
            int(permanent.get("current_chapter") or 1),
            int(permanent.get("lore_counters") or 1),
        )
        if permanent.get("saga_last_lore_turn") == turn:
            continue
        final_chapter = int(permanent.get("final_chapter") or permanent.get("saga_final_chapter") or 3)
        if current_chapter >= final_chapter:
            continue
        next_chapter = current_chapter + 1
        permanent["current_chapter"] = next_chapter
        permanent["lore_counters"] = next_chapter
        permanent["saga_last_lore_turn"] = turn
        permanent["chapter_ability_pending"] = True
        emit_replay_event(
            "saga_chapter_progressed",
            player=player.name,
            card=permanent.get("name", "?"),
            chapter=next_chapter,
            turn=turn,
            phase="after_draw_step",
            **replay_rule_fields(permanent),
        )
        resolve_modeled_saga_chapter(
            player,
            opponents,
            permanent,
            next_chapter,
            turn,
            rng,
            stack=stack,
            all_players=all_players,
            phase="after_draw_step",
        )
        permanent["chapter_ability_pending"] = False
        triggers += 1
    return triggers


def graveyard_enchantment_recovery_score(card, player, turn):
    effect_data = get_card_effect(card)
    effect = str(effect_data.get("effect") or card.get("effect") or "unknown")
    score = threat_score(effect, card.get("name", "?"), player, [player], turn)
    cmc = int(float(card.get("cmc") or 0))
    expected_next_turn_mana = max(controlled_land_count(player), 1) if player is not None else 1
    reason = "highest_contextual_enchantment_recovery_value"
    if effect in ("ramp_engine", "draw_engine", "topdeck_manipulation", "attack_limit", "attack_tax"):
        score = max(score, 70)
        if cmc <= expected_next_turn_mana + 1:
            score += 8
        reason = "recover_engine_enchantment"
    elif effect in ("token_maker", "finisher", "approach", "wincon"):
        score = max(score, 35)
        if cmc > expected_next_turn_mana + 1:
            score -= min((cmc - (expected_next_turn_mana + 1)) * 8, 32)
        reason = "recover_closing_enchantment"
    elif effect == "passive":
        score = max(score, 48)
        if cmc <= expected_next_turn_mana + 1:
            score += 6
        reason = "recover_static_value_enchantment"
    return score, reason


def should_cast_board_wipe(player, opponents):
    return board_wipe_decision_context(player, opponents)["timing_justified"]


def worldfire_decision_context(player, opponents):
    commander = None
    if player.command_zone:
        first = player.command_zone[0]
        if isinstance(first, dict):
            commander = first
    commander_tax = int(player.commander_tax or 0)
    floating_mana_after_reset = int(player.available_mana())
    treasures_before_reset = int(player.treasures or 0)
    commander_redeploy_available = False
    commander_name = None
    commander_effect = {}
    if commander is not None:
        commander_name = commander.get("name", "?")
        commander_effect = get_card_effect(commander)
        saved_treasures = player.treasures
        try:
            player.treasures = 0
            commander_redeploy_available = player.can_pay_card(
                commander,
                additional_generic=commander_tax,
            )
        finally:
            player.treasures = saved_treasures
    commander_immediate_damage = False
    if commander_redeploy_available:
        commander_immediate_damage = (
            commander_effect.get("effect") == "deal_damage"
            or int(commander_effect.get("damage") or 0) >= 1
            or int(commander_effect.get("etb_damage") or 0) >= 1
        )
    return {
        "model_scope": "worldfire_total_reset_v1",
        "floating_mana_after_reset": floating_mana_after_reset,
        "treasures_lost_to_reset": treasures_before_reset,
        "commander_name": commander_name,
        "commander_tax": commander_tax,
        "commander_redeploy_available": commander_redeploy_available,
        "commander_immediate_damage": commander_immediate_damage,
        "known_follow_up_line": commander_immediate_damage,
        "timing_justified": commander_immediate_damage,
        "opponents_alive": sum(1 for opp in opponents if opp.is_alive()),
    }


def should_cast_worldfire_reset(player, opponents):
    return worldfire_decision_context(player, opponents)["timing_justified"]


def should_cast_wheel(player, opponents, effect_data):
    draw_count = wheel_like_draw_count(
        effect_data if isinstance(effect_data, dict) and effect_data.get("name") else {},
        effect_data,
        player=player,
        opponents=opponents,
    )
    return wheel_decision_context(
        player,
        opponents,
        draw_count,
        effect_data,
    )["timing_justified"]


def resolve_wheel_of_misfortune(player, opponents, card, draw_count, turn, rng, effect_data):
    fields = replay_rule_fields(effect_data if isinstance(effect_data, dict) else {})
    participants = [participant for participant in [player] + list(opponents) if participant.is_alive()]
    controller_choice = int(effect_data.get("controller_secret_number") or draw_count or 7)
    opponent_choice = int(effect_data.get("opponent_secret_number") or 0)
    choices = []
    for participant in participants:
        choice = controller_choice if participant is player else opponent_choice
        choices.append({"player": participant.name, "number": max(0, choice)})
    highest_number = max((entry["number"] for entry in choices), default=0)
    lowest_number = min((entry["number"] for entry in choices), default=0)
    highest_players = {entry["player"] for entry in choices if entry["number"] == highest_number}
    lowest_players = {entry["player"] for entry in choices if entry["number"] == lowest_number}

    damaged = []
    for participant in participants:
        if participant.name not in highest_players or highest_number <= 0:
            continue
        life_before = participant.life
        if deal_damage(participant, highest_number):
            damaged.append(
                {
                    "player": participant.name,
                    "damage": highest_number,
                    "life_before": life_before,
                    "life_after": participant.life,
                }
            )

    results = []
    total_opponent_drawn = 0
    treasures_before = player.treasures
    for participant in participants:
        if participant.name in lowest_players:
            results.append({
                "player": participant.name,
                "number": next(entry["number"] for entry in choices if entry["player"] == participant.name),
                "lowest_number": True,
                "discarded": 0,
                "drawn": 0,
                "hand_after": len(participant.hand),
            })
            continue
        discarded_cards = list(participant.hand)
        participant.hand = []
        discard_resolution = resolve_effect_discard_cards(
            participant,
            discarded_cards,
            top_limit=draw_count,
            opponents=[candidate for candidate in participants if candidate is not participant],
            turn=turn,
            phase="resolution",
            rng=rng,
        )
        drawn = participant.draw(draw_count, rng)
        process_player_draw_triggers(
            participant,
            len(drawn),
            turn,
            "resolution",
            participants,
            turn_player=player,
        )
        if participant is not player:
            total_opponent_drawn += len(drawn)
        results.append({
            "player": participant.name,
            "number": next(entry["number"] for entry in choices if entry["player"] == participant.name),
            "lowest_number": False,
            "discarded": len(discarded_cards),
            "discarded_to_top": [entry.get("name", "?") for entry in discard_resolution["to_top"]],
            "discarded_to_graveyard": [
                entry.get("name", "?") for entry in discard_resolution["to_graveyard"]
            ],
            "drawn": len(drawn),
            "hand_after": len(participant.hand),
        })

    treasures_created = max(0, player.treasures - treasures_before)
    emit_replay_event(
        "wheel_resolved",
        player=player.name,
        card=card.get("name", "?"),
        draw_count=draw_count,
        participants=results,
        number_choices=choices,
        highest_number=highest_number,
        lowest_number=lowest_number,
        damaged=damaged,
        lowest_number_players=sorted(lowest_players),
        opponent_cards_drawn=total_opponent_drawn,
        secret_number_choice_model=effect_data.get(
            "secret_number_choice_model",
            "compact_controller_draw_count_opponents_zero_v1",
        ),
        damage_model_status=effect_data.get(
            "damage_model_status",
            "runtime_highest_number_damage",
        ),
        discard_draw_model=effect_data.get(
            "discard_draw_model",
            "runtime_non_lowest_discard_draw_seven",
        ),
        treasures_created=treasures_created,
        turn=turn,
        **fields,
    )
    return results


def resolve_wheel_like_draw(player, opponents, card, draw_count, turn, rng, effect_data=None):
    fields = replay_rule_fields(effect_data if isinstance(effect_data, dict) else {})
    effect_data = effect_data if isinstance(effect_data, dict) else {}
    if is_wheel_of_misfortune_model(card, effect_data):
        return resolve_wheel_of_misfortune(
            player,
            opponents,
            card,
            draw_count,
            turn,
            rng,
            effect_data,
        )
    participants = [participant for participant in [player] + list(opponents) if participant.is_alive()]
    results = []
    total_opponent_drawn = 0
    treasures_before = player.treasures
    for participant in participants:
        discarded_cards = list(participant.hand)
        participant.hand = []
        discard_resolution = resolve_effect_discard_cards(
            participant,
            discarded_cards,
            top_limit=draw_count,
            opponents=[candidate for candidate in participants if candidate is not participant],
            turn=turn,
            phase="resolution",
            rng=rng,
        )
        drawn = participant.draw(draw_count, rng)
        process_player_draw_triggers(
            participant,
            len(drawn),
            turn,
            "resolution",
            participants,
            turn_player=player,
        )
        if participant is not player:
            total_opponent_drawn += len(drawn)
        results.append({
            "player": participant.name,
            "discarded": len(discarded_cards),
            "discarded_to_top": [entry.get("name", "?") for entry in discard_resolution["to_top"]],
            "discarded_to_graveyard": [
                entry.get("name", "?") for entry in discard_resolution["to_graveyard"]
            ],
            "drawn": len(drawn),
            "hand_after": len(participant.hand),
        })
    treasures_created = max(0, player.treasures - treasures_before)
    emit_replay_event(
        "wheel_resolved",
        player=player.name,
        card=card.get("name", "?"),
        draw_count=draw_count,
        participants=results,
        opponent_cards_drawn=total_opponent_drawn,
        treasures_created=treasures_created,
        turn=turn,
        **fields,
    )
    return results


def is_wheel_like_card(card, effect_data):
    if isinstance(effect_data, dict) and "wheel_like" in effect_data:
        value = effect_data.get("wheel_like")
        if isinstance(value, str):
            return value.strip().lower() in {"1", "true", "yes", "y"}
        return bool(value)
    name = normalize_card_name(card.get("name", "")) if isinstance(card, dict) else ""
    count = wheel_like_draw_count(card, effect_data)
    return count >= 7 or any(
        marker in name
        for marker in ("wheel", "windfall", "timetwister", "reforge")
    )


def resolve_etb_library_creature_tutor(player, source, effect_data, turn):
    limit = int(effect_data.get("etb_tutor_nonlegendary_green_creature_mv_lte") or 0)
    if limit <= 0:
        return None
    candidates = [
        candidate
        for candidate in player.library
        if isinstance(candidate, dict)
        and is_creature_card(candidate)
        and card_has_color(candidate, "G")
        and "legendary" not in str(candidate.get("type_line") or "").lower()
        and int(float(candidate.get("cmc") or 0)) <= limit
    ]
    scored_candidates = [
        (
            candidate,
            *tutor_candidate_score(candidate, "green_creature_to_battlefield", player, [], turn),
        )
        for candidate in candidates
    ]
    scored_candidates.sort(
        key=lambda item: (
            -item[1],
            -int(float(item[0].get("cmc") or 0)),
            item[0].get("name", ""),
        )
    )
    found = scored_candidates[0][0] if scored_candidates else None
    if found:
        player.library.remove(found)
        permanent_effect = get_card_effect(found)
        permanent = prepare_entering_permanent(enrich_card({**found, **permanent_effect}))
        if is_creature_card(permanent):
            permanent["effect"] = "creature"
            permanent["haste"] = has_haste(permanent)
            permanent["summoning_sick"] = not permanent["haste"]
        player.battlefield.append(permanent)
    emit_replay_event(
        "etb_tutor_resolved",
        player=player.name,
        card=source.get("name", "?") if isinstance(source, dict) else "?",
        target_type=f"nonlegendary_green_creature_mv_lte_{limit}",
        found=found.get("name", "?") if found else None,
        destination="battlefield" if found else None,
        turn=turn,
        **replay_rule_fields(effect_data),
    )
    return found


def wheel_like_draw_count(card, effect_data, *, player=None, opponents=None):
    count = int(effect_data.get("count") or 0)
    if count > 0:
        return count
    name = normalize_card_name(card.get("name", "")) if isinstance(card, dict) else ""
    if any(marker in name for marker in ("wheel", "reforge", "timetwister")):
        return 7
    if "windfall" in name and player is not None:
        hand_sizes = [len(player.hand)]
        hand_sizes.extend(len(opp.hand) for opp in (opponents or []) if opp.is_alive())
        return max(hand_sizes) if hand_sizes else 0
    return 0


def move_zone_object_to_exile(owner, zone_name, card, *, reason=None, source=None, turn=None):
    if not isinstance(card, dict):
        zone = getattr(owner, zone_name, None)
        if isinstance(zone, list) and card in zone:
            zone.remove(card)
        move_to_exile(owner, card, reason=reason, turn=turn)
        return "exile"

    zone = getattr(owner, zone_name, None)
    if isinstance(zone, list):
        for zone_object in zone:
            if zone_object is card:
                card = zone_object
                break
        else:
            for zone_object in zone:
                if zone_object == card:
                    card = zone_object
                    break
            else:
                target_name = card.get("name") or card.get("card_name")
                if target_name:
                    name_matches = [
                        zone_object
                        for zone_object in zone
                        if isinstance(zone_object, dict)
                        and (zone_object.get("name") or zone_object.get("card_name")) == target_name
                    ]
                    if len(name_matches) == 1:
                        card = name_matches[0]
        for index, zone_object in enumerate(zone):
            if zone_object is card:
                del zone[index]
                break
        else:
            try:
                zone.remove(card)
            except ValueError:
                pass

    if zone_name == "battlefield":
        card["_lki_snapshot"] = {
            "name": card.get("name", card.get("card_name", "")),
            "power": card.get("power", 0),
            "toughness": card.get("toughness", 0),
            "cmc": card.get("cmc", 0),
            "type_line": card.get("type_line", ""),
            "is_commander": card.get("is_commander", False),
            "owner": card.get("owner", card.get("controller", "")),
        }
        card["_zone_id"] = card.get("_zone_id", 0) + 1
        card["_last_zone"] = "battlefield"

    if card.get("is_commander"):
        event = ReplacementRegistry.process_event(
            ReplacementEvent(
                "zone_change",
                affected_player=owner,
                card=card,
                from_zone=zone_name,
                to_zone="exile",
                source=source,
                reason=reason,
            )
        )
        if event.to_zone == "command_zone":
            owner.command_zone.append(card)
            return "command_zone"

    if zone_name == "battlefield" and (
        card.get("tag") == "token"
        or "token" in str(card.get("type_line") or "").lower()
    ):
        return "vanished_token"

    move_to_exile(owner, card, reason=reason, turn=turn)
    return "exile"


def move_permanent_from_battlefield_to_exile(owner, permanent, *, reason=None, source=None, turn=None):
    if not isinstance(permanent, dict):
        return "none"
    moved = battlefield_object_for_target(owner, permanent) or permanent
    destination = move_zone_object_to_exile(
        owner,
        "battlefield",
        moved,
        reason=reason or "battlefield_to_exile",
        source=source,
        turn=turn,
    )
    if destination == "none":
        return destination
    _clear_battlefield_only_state(moved)
    current_turn = turn if turn is not None else CURRENT_REPLAY_TURN
    if destination == "exile":
        moved["_put_into_exile_from_battlefield_turn"] = current_turn
    emit_replay_event(
        "permanent_moved_from_battlefield",
        player=getattr(owner, "name", "?"),
        card=moved.get("name", "?"),
        permanent_type="permanent",
        from_zone="battlefield",
        to_zone=destination,
        destination=destination,
        reason=reason,
        source=source.get("name", "?") if isinstance(source, dict) else source,
        turn=current_turn,
    )
    resolve_leave_battlefield_treasure_trigger(
        owner,
        moved,
        destination=destination,
        reason=reason,
        source=source,
    )
    refresh_controlled_static_indestructible(
        owner,
        turn=current_turn,
        phase="leave_battlefield",
        emit_events=True,
    )
    refresh_controlled_static_power_toughness_bonuses(
        owner,
        turn=current_turn,
        phase="leave_battlefield",
        emit_events=True,
    )
    refresh_controlled_static_keywords(
        owner,
        turn=current_turn,
        phase="leave_battlefield",
        emit_events=True,
    )
    return destination


def commander_color_identity_count(player):
    commander = player.commander if isinstance(player.commander, dict) else None
    if commander is None and player.command_zone:
        first = player.command_zone[0]
        if isinstance(first, dict):
            commander = first
    if commander is None:
        return 1
    colors = compute_color_identity(commander)
    return len(colors) if colors else 1


def _can_pay_card_with_bonus_mana(
    player,
    card,
    *,
    bonus_amount=1,
    bonus_color="colorless",
    additional_generic=0,
):
    if bonus_amount <= 0:
        return player.can_pay_card(card, additional_generic=additional_generic)
    current = getattr(player.mana_pool, bonus_color, 0)
    setattr(player.mana_pool, bonus_color, current + int(bonus_amount))
    try:
        return player.can_pay_card(card, additional_generic=additional_generic)
    finally:
        setattr(player.mana_pool, bonus_color, current)


def _restore_mana_payment_state(player, pool_snapshot, treasures, restricted_mana, conditional_sources, life):
    for color, amount in pool_snapshot.items():
        setattr(player.mana_pool, color, amount)
    player.treasures = treasures
    player.restricted_mana = copy.deepcopy(restricted_mana)
    player.conditional_mana_sources = copy.deepcopy(conditional_sources)
    player.life = life


def _can_pay_card_with_bonus_mana_source(
    player,
    card,
    source,
    *,
    bonus_amount,
    activation_cost=None,
    additional_generic=0,
):
    if bonus_amount <= 0:
        return player.can_pay_card(card, additional_generic=additional_generic)
    pool_snapshot = player.mana_pool.snapshot()
    treasures_snapshot = player.treasures
    restricted_snapshot = copy.deepcopy(player.restricted_mana)
    conditional_snapshot = copy.deepcopy(getattr(player, "conditional_mana_sources", []))
    life_snapshot = player.life
    try:
        if activation_cost and not player.spend_mana(activation_cost):
            return False
        if not add_player_mana_source_to_pool(player, source):
            return False
        return player.can_pay_card(card, additional_generic=additional_generic)
    finally:
        _restore_mana_payment_state(
            player,
            pool_snapshot,
            treasures_snapshot,
            restricted_snapshot,
            conditional_snapshot,
            life_snapshot,
        )


def current_state_unlock_candidates(
    player,
    opponents,
    all_players,
    turn,
    *,
    baseline_card_ids=None,
    baseline_commander_castable=False,
):
    candidates = []
    baseline_card_ids = set(baseline_card_ids or [])

    if player.command_zone:
        commander = player.command_zone[0]
        commander_tax = int(player.commander_tax or 0)
        already_on_board = any(
            isinstance(permanent, dict)
            and permanent.get("name") == commander.get("name")
            for permanent in player.battlefield
        )
        if (
            not already_on_board
            and not baseline_commander_castable
            and player.can_pay_card(commander, additional_generic=commander_tax)
        ):
            effective_cost = int(float(commander.get("cmc") or 0)) + commander_tax
            candidates.append(
                {
                    "card": commander,
                    "effect_data": get_card_effect(commander),
                    "score": max(40, effective_cost * 6),
                    "reason": "unlock_commander_cast",
                    "unlock_type": "commander",
                    "cmc": effective_cost,
                }
            )

    for card in player.hand:
        if not isinstance(card, dict) or is_effective_land(card):
            continue
        if id(card) in baseline_card_ids:
            continue
        effect_data = get_card_effect(card)
        effect = str(effect_data.get("effect") or "unknown")
        if effect == "unknown":
            effect = str(card.get("effect") or card.get("tag") or "unknown")
        if effect == "unknown":
            continue
        if not player.can_pay_card(card):
            continue
        if effect in BOARD_WIPE_LIKE_EFFECTS and not should_cast_board_wipe(player, opponents):
            continue
        if effect == "draw_cards" and is_wheel_like_card(card, effect_data):
            if not should_cast_wheel(player, opponents, {**effect_data, "name": card.get("name")}):
                continue

        cmc = int(float(card.get("cmc") or 0))
        score = threat_score(effect, card.get("name", "?"), player, all_players, turn)
        reason = "unlock_contextual_spell"
        if effect in ("ramp_permanent", "ramp_engine", "land_ramp", "ramp_ritual"):
            score += 24 if turn <= 4 else 12
            reason = "unlock_ramp_curve_step"
        elif effect in ("remove_creature", "remove_permanent", "counter", "protect_creature", "cannot_lose_turn"):
            score += 20
            reason = "unlock_interaction"
        elif effect in ("creature", "draw_engine", "topdeck_manipulation", "attack_limit", "attack_tax", "equipment_static_attachment", "aura_static_attachment"):
            score += 16 if cmc <= 4 else 8
            reason = "unlock_board_or_engine_development"
        elif effect in (
            BOARD_WIPE_LIKE_EFFECTS
            | {
                "finisher",
                "approach",
                "token_maker",
                "damage_wipe_treasure",
                "redistribute_life_totals",
                "worldfire_reset",
            }
        ):
            score += 26
            reason = "unlock_high_impact_spell"
        else:
            score += max(6, 14 - cmc)

        candidates.append(
            {
                "card": card,
                "effect_data": effect_data,
                "score": score,
                "reason": reason,
                "unlock_type": "spell",
                "cmc": cmc,
            }
        )

    candidates.sort(
        key=lambda item: (
            -int(item.get("score") or 0),
            int(item.get("cmc") or 0),
            item["card"].get("name", ""),
        )
    )
    return candidates


