def _is_artifact_with_mana_ability_card(candidate):
    if not isinstance(candidate, dict):
        return False
    type_line = str(candidate.get("type_line") or "").lower()
    if "artifact" not in type_line:
        return False
    effect_data = get_card_effect(candidate)
    merged = {**effect_data, **candidate}
    return bool(
        merged.get("activated_mana_ability")
        or merged.get("is_mana_source")
        or merged.get("mana_produced") is not None
        or merged.get("produces")
    )


def library_tutor_candidates(player, target_type):
    target_type = str(target_type or "any").lower()
    for suffix in ("_to_top", "_to_hand", "_to_battlefield", "_to_graveyard"):
        if target_type.endswith(suffix):
            target_type = target_type[: -len(suffix)] or "any"
            break
    candidates = []
    for candidate in getattr(player, "library", []) or []:
        if not isinstance(candidate, dict):
            continue
        type_line = str(candidate.get("type_line") or "").lower()
        if target_type == "any":
            candidates.append(candidate)
        elif target_type in ("artifact", "artifact_to_graveyard"):
            if "artifact" in type_line:
                candidates.append(candidate)
        elif target_type in ("enchantment", "enchantment_to_hand"):
            if "enchantment" in type_line:
                candidates.append(candidate)
        elif target_type in ("planeswalker", "planeswalker_to_hand"):
            if "planeswalker" in type_line:
                candidates.append(candidate)
        elif target_type in (
            "artifact_or_enchantment",
            "artifact_or_enchantment_to_hand",
            "artifact_or_enchantment_to_top",
        ):
            if (
                ("artifact" in type_line or "enchantment" in type_line)
                and candidate.get("name") != "Approach of the Second Sun"
            ):
                candidates.append(candidate)
        elif target_type in ("artifact_or_dragon", "artifact_or_dragon_to_battlefield"):
            if "artifact" in type_line or "dragon" in type_line:
                candidates.append(candidate)
        elif target_type == "land":
            if is_effective_land(candidate):
                candidates.append(candidate)
        elif target_type == "basic_land":
            type_line = str(candidate.get("type_line") or "").lower()
            if is_effective_land(candidate) and "basic" in type_line:
                candidates.append(candidate)
        elif target_type == "forest":
            if is_effective_land(candidate) and (
                normalize_card_name(candidate.get("name", "")) == "forest"
                or "forest" in type_line
            ):
                candidates.append(candidate)
        elif target_type == "snow_land":
            if is_effective_land(candidate) and "snow" in type_line:
                candidates.append(candidate)
        elif target_type == "basic_land_type":
            if is_effective_land(candidate) and any(
                land_type in type_line
                for land_type in ("plains", "island", "swamp", "mountain", "forest")
            ):
                candidates.append(candidate)
        elif target_type == "basic_forest_or_island":
            if (
                is_effective_land(candidate)
                and "basic" in type_line
                and ("forest" in type_line or "island" in type_line)
            ):
                candidates.append(candidate)
        elif target_type == "plains_island_swamp_or_mountain":
            if is_effective_land(candidate) and any(
                land_type in type_line
                for land_type in ("plains", "island", "swamp", "mountain")
            ):
                candidates.append(candidate)
        elif target_type == "basic_land_or_gate":
            if is_effective_land(candidate) and ("basic" in type_line or "gate" in type_line):
                candidates.append(candidate)
        elif target_type == "basic_land_or_cave":
            if is_effective_land(candidate) and ("basic" in type_line or "cave" in type_line):
                candidates.append(candidate)
        elif target_type == "basic_land_or_town":
            if is_effective_land(candidate) and ("basic" in type_line or "town" in type_line):
                candidates.append(candidate)
        elif target_type == "basic_plains":
            type_line = str(candidate.get("type_line") or "").lower()
            if (
                is_effective_land(candidate)
                and "basic" in type_line
                and (
                    normalize_card_name(candidate.get("name", "")) == "plains"
                    or "plains" in type_line
                )
            ):
                candidates.append(candidate)
        elif target_type == "plains":
            type_line = str(candidate.get("type_line") or "").lower()
            if (
                is_effective_land(candidate)
                and (
                    normalize_card_name(candidate.get("name", "")) == "plains"
                    or "plains" in type_line
                )
            ):
                candidates.append(candidate)
        elif target_type == "basic_plains_or_creature_mana_value_1_or_less":
            type_line = str(candidate.get("type_line") or "").lower()
            try:
                candidate_cmc = int(float(candidate.get("cmc") or candidate.get("mana_value")))
            except (TypeError, ValueError):
                candidate_cmc = None
            if (
                is_effective_land(candidate)
                and "basic" in type_line
                and (
                    normalize_card_name(candidate.get("name", "")) == "plains"
                    or "plains" in type_line
                )
            ) or (
                is_creature_card(candidate)
                and candidate_cmc is not None
                and candidate_cmc <= 1
            ):
                candidates.append(candidate)
        elif target_type in ("graveyard", "graveyard_nonlegendary"):
            if target_type == "graveyard" or "legendary" not in str(candidate.get("type_line") or "").lower():
                candidates.append(candidate)
        elif target_type in ("creature", "creature_to_battlefield"):
            if is_creature_card(candidate):
                candidates.append(candidate)
        elif target_type in ("minotaur_creatures", "minotaur_creatures_to_battlefield"):
            if is_creature_card(candidate) and permanent_has_subtype(candidate, "minotaur"):
                candidates.append(candidate)
        elif target_type in (
            "small_creature",
            "creature_mana_value_1_or_less",
            "creature_mana_value_lte_1",
        ):
            try:
                candidate_cmc = int(float(candidate.get("cmc") or candidate.get("mana_value")))
            except (TypeError, ValueError):
                candidate_cmc = None
            if is_creature_card(candidate) and candidate_cmc is not None and candidate_cmc <= 1:
                candidates.append(candidate)
        elif target_type == "creature_power_lte_2":
            try:
                candidate_power = int(float(candidate.get("power")))
            except (TypeError, ValueError):
                candidate_power = None
            if is_creature_card(candidate) and candidate_power is not None and candidate_power <= 2:
                candidates.append(candidate)
        elif target_type == "creature_toughness_lte_2":
            try:
                candidate_toughness = int(float(candidate.get("toughness")))
            except (TypeError, ValueError):
                candidate_toughness = None
            if (
                is_creature_card(candidate)
                and candidate_toughness is not None
                and candidate_toughness <= 2
            ):
                candidates.append(candidate)
        elif target_type == "instant_or_sorcery":
            if is_instant_or_sorcery_spell(candidate):
                candidates.append(candidate)
        elif target_type == "instant":
            if is_instant(candidate):
                candidates.append(candidate)
        elif target_type == "sorcery":
            if is_sorcery(candidate):
                candidates.append(candidate)
        elif target_type == "cheap_instant_or_sorcery":
            try:
                candidate_cmc = int(float(candidate.get("cmc") or candidate.get("mana_value")))
            except (TypeError, ValueError):
                candidate_cmc = None
            if (
                is_instant_or_sorcery_spell(candidate)
                and candidate_cmc is not None
                and candidate_cmc <= 2
            ):
                candidates.append(candidate)
        elif target_type == "artifact_mana_value_3":
            try:
                candidate_cmc = int(float(candidate.get("cmc") or candidate.get("mana_value")))
            except (TypeError, ValueError):
                candidate_cmc = None
            if (
                "artifact" in type_line
                and candidate_cmc is not None
                and candidate_cmc == 3
            ):
                candidates.append(candidate)
        elif target_type in (
            "artifact_mana_ability_or_basic_land",
            "artifact_with_mana_ability_or_basic_land",
        ):
            if (is_effective_land(candidate) and "basic" in type_line) or _is_artifact_with_mana_ability_card(candidate):
                candidates.append(candidate)
        elif target_type in ("green_creature", "green_creature_to_battlefield"):
            if is_creature_card(candidate) and card_has_color(candidate, "G"):
                candidates.append(candidate)
        elif target_type == "demon":
            if "demon" in type_line:
                candidates.append(candidate)
    return candidates


def _tutor_mana_value_cap(effect_data):
    if not isinstance(effect_data, dict):
        return None
    explicit = first_present_value(
        effect_data,
        (
            "target_mana_value_max",
            "target_cmc_max",
            "max_target_mana_value",
            "max_target_cmc",
        ),
    )
    if explicit is not None:
        try:
            return int(float(explicit))
        except Exception:
            return None
    if effect_data.get("target_mana_value_max_from_x"):
        cast_context = effect_data.get("_cast_context") or {}
        try:
            return int(float(cast_context.get("x_value") or 0))
        except Exception:
            return 0
    return None


def _tutor_mana_value_floor(effect_data):
    if not isinstance(effect_data, dict):
        return None
    explicit = first_present_value(
        effect_data,
        (
            "target_mana_value_min",
            "target_cmc_min",
            "min_target_mana_value",
            "min_target_cmc",
        ),
    )
    if explicit is not None:
        try:
            return int(float(explicit))
        except Exception:
            return None
    return None


def constrained_library_tutor_candidates(player, target_type, effect_data=None):
    candidates = library_tutor_candidates(player, target_type)
    if isinstance(effect_data, dict):
        required_names = {
            normalize_card_name(name)
            for name in _as_list(effect_data.get("target_names"))
            if str(name).strip()
        }
        if required_names:
            candidates = [
                candidate
                for candidate in candidates
                if normalize_card_name(candidate.get("name", "")) in required_names
            ]
        required_subtypes = [
            str(subtype).strip().lower()
            for subtype in _as_list(effect_data.get("target_subtypes"))
            if str(subtype).strip()
        ]
        if required_subtypes:
            candidates = [
                candidate
                for candidate in candidates
                if any(permanent_has_subtype(candidate, subtype) for subtype in required_subtypes)
            ]
        required_card_types = [
            str(card_type).strip().lower()
            for card_type in _as_list(effect_data.get("target_card_types"))
            if str(card_type).strip()
        ]
        if required_card_types:
            candidates = [
                candidate
                for candidate in candidates
                if _card_type_matches(candidate, required_card_types)
            ]
        required_colors = [
            str(color).strip()
            for color in _as_list(effect_data.get("target_colors"))
            if str(color).strip()
        ]
        if required_colors:
            candidates = [
                candidate
                for candidate in candidates
                if all(card_has_color(candidate, color) for color in required_colors)
            ]
        required_supertypes = [
            str(supertype).strip().lower()
            for supertype in _as_list(effect_data.get("required_supertypes"))
            if str(supertype).strip()
        ]
        if required_supertypes:
            candidates = [
                candidate
                for candidate in candidates
                if all(
                    supertype in str(candidate.get("type_line") or "").lower()
                    for supertype in required_supertypes
                )
            ]
        if effect_data.get("requires_different_names"):
            unique = []
            seen_names = set()
            for candidate in candidates:
                normalized = normalize_card_name(candidate.get("name", ""))
                if normalized in seen_names:
                    continue
                seen_names.add(normalized)
                unique.append(candidate)
            candidates = unique
    mana_value_floor = _tutor_mana_value_floor(effect_data)
    if mana_value_floor is not None:
        filtered = []
        for candidate in candidates:
            try:
                if card_mana_value(candidate) < mana_value_floor:
                    continue
            except Exception:
                continue
            filtered.append(candidate)
        candidates = filtered
    mana_value_cap = _tutor_mana_value_cap(effect_data)
    if mana_value_cap is not None:
        filtered = []
        for candidate in candidates:
            try:
                if card_mana_value(candidate) > mana_value_cap:
                    continue
            except Exception:
                continue
            filtered.append(candidate)
        candidates = filtered
    return candidates


def spell_has_required_library_target(player, effect_data):
    if str((effect_data or {}).get("effect") or "") != "tutor":
        return True
    return bool(
        constrained_library_tutor_candidates(
            player,
            (effect_data or {}).get("target", "any"),
            effect_data,
        )
    )


def tutor_destination_for_target_type(target_type):
    target_type = str(target_type or "any").lower()
    if str(target_type).endswith("_to_top"):
        return "library_top"
    if str(target_type).endswith("_to_graveyard"):
        return "graveyard"
    if target_type in ("graveyard", "graveyard_nonlegendary"):
        return "graveyard"
    if str(target_type).endswith("_to_battlefield"):
        return "battlefield"
    return "hand"


def move_library_tutor_selection(player, selected_cards, target_type, effect_data=None):
    destination = tutor_destination_for_target_type(target_type)
    moved_cards = []
    library_top_insert_index = 0
    tutor_enters_tapped = bool(
        isinstance(effect_data, dict)
        and effect_data.get("tutor_enters_tapped")
        and destination == "battlefield"
    )
    tutor_tapped_known = isinstance(effect_data, dict) and "tutor_enters_tapped" in effect_data
    for selected_card in selected_cards:
        if selected_card not in player.library:
            continue
        player.library.remove(selected_card)
        moved_cards.append(selected_card)
        if destination == "graveyard":
            player.graveyard.append(selected_card)
        elif destination == "library_top":
            player.library.insert(library_top_insert_index, selected_card)
            library_top_insert_index += 1
        elif destination == "battlefield":
            permanent_effect = get_card_effect(selected_card)
            permanent = enrich_card({**selected_card, **permanent_effect})
            if tutor_tapped_known:
                permanent["tapped"] = tutor_enters_tapped
            if is_creature_card(selected_card):
                permanent["effect"] = "creature"
                permanent["haste"] = has_haste(permanent)
                permanent["summoning_sick"] = not permanent["haste"]
                if not tutor_tapped_known:
                    permanent["tapped"] = False
            player.battlefield.append(permanent)
        else:
            player.hand.append(selected_card)
    return moved_cards, destination if moved_cards else None


def lorehold_low_artifact_tutor_score(candidate, target_type, player):
    if str(target_type or "").lower() != "artifact_cmc_1_or_less":
        return None
    if not player_has_lorehold_game_plan(player):
        return None
    normalized_name = normalize_card_name(candidate.get("name", ""))
    effect_data = get_card_effect(candidate)
    effect = str(effect_data.get("effect") or candidate.get("effect") or "unknown")
    if normalized_name == "sensei's divining top":
        return 180, "find_lorehold_topdeck_miracle_engine"
    if normalized_name == "library of leng":
        return 170, "find_lorehold_discard_to_top_engine"
    if normalized_name == "sol ring":
        return 150, "accelerate_lorehold_commander_miracle_plan"
    if effect == "topdeck_manipulation":
        return 145, "find_lorehold_topdeck_miracle_engine"
    if effect_data.get("discard_effect_to_top_replacement"):
        return 140, "find_lorehold_discard_to_top_engine"
    if effect in {"ramp_permanent", "land_ramp", "ramp_engine"}:
        return 125, "accelerate_lorehold_commander_miracle_plan"
    return None


def tutor_candidate_score(candidate, target_type, player, opponents, turn):
    target_key = str(target_type or "any").lower()
    for suffix in ("_to_top", "_to_hand", "_to_battlefield", "_to_graveyard"):
        if target_key.endswith(suffix):
            target_key = target_key[: -len(suffix)] or "any"
            break
    effect_data = get_card_effect(candidate)
    effect = str(effect_data.get("effect") or candidate.get("effect") or "unknown")
    cmc = int(float(candidate.get("cmc") or 0))
    lands = controlled_land_count(player)
    opponent_creatures = sum(
        battlefield_creature_stats(opp)["count"]
        for opp in opponents
        if opp.is_alive()
    )
    score = threat_score(effect, candidate.get("name", ""), player, [player] + list(opponents), turn)
    reason = "highest_contextual_value"
    type_line = str(candidate.get("type_line") or "").lower()
    if target_key == "basic_plains_or_creature_mana_value_1_or_less":
        is_basic_plains = (
            is_effective_land(candidate)
            and "basic" in type_line
            and (
                normalize_card_name(candidate.get("name", "")) == "plains"
                or "plains" in type_line
            )
        )
        is_small_creature = is_creature_card(candidate) and cmc <= 1
        if is_basic_plains:
            score += 85 if lands < 3 else 18
            reason = "fix_mana_with_basic_plains_tutor" if lands < 3 else "bank_basic_plains_option"
        elif is_small_creature:
            score += 62 if lands >= 3 else 24
            reason = "find_one_drop_creature_payoff" if lands >= 3 else "keep_small_creature_fallback"
    elif target_key == "plains":
        score += 82 if lands < 3 else 28
        reason = "fix_mana_with_plains_tutor" if lands < 3 else "bank_plains_option"
    elif target_key in {
        "land",
        "basic_land",
        "forest",
        "snow_land",
        "basic_land_type",
        "basic_forest_or_island",
        "plains_island_swamp_or_mountain",
        "basic_land_or_gate",
        "basic_land_or_town",
        "basic_plains",
        "artifact_mana_ability_or_basic_land",
        "artifact_with_mana_ability_or_basic_land",
    } or (is_effective_land(candidate) and lands < 3 and "land" in target_key):
        score += 80 if lands < 3 else 25
        reason = "fix_mana_or_land_drop"
    elif target_key == "any" and is_effective_land(candidate) and lands < 3 and turn <= 3:
        score += 45
        reason = "fix_mana_or_land_drop"
    elif effect in ("ramp_permanent", "land_ramp", "ramp_engine") and lands < 4:
        score += 65
        reason = "accelerate_underdeveloped_mana"
    elif effect in ("airbend_other_creatures", "remove_creature", "remove_permanent", "board_wipe") and opponent_creatures >= 3:
        score += 55
        reason = "find_interaction_for_board_pressure"
    elif effect in ("draw_engine", "topdeck_manipulation", "attack_limit", "attack_tax") and turn <= 5:
        score += 50
        reason = "establish_value_engine"
    elif effect in ("wincon", "approach", "finisher", "overload_recursion", "worldfire_reset", "life_total_change") and turn >= 5:
        score += 70
        reason = "find_closing_line"
    elif str(target_type).endswith("_to_battlefield") and is_creature_card(candidate):
        score += max(20, cmc * 5)
        reason = "battlefield_tutor_prefers_material_impact"
    lorehold_artifact_score = lorehold_low_artifact_tutor_score(candidate, target_type, player)
    if lorehold_artifact_score is not None and lorehold_artifact_score[0] > score:
        score, reason = lorehold_artifact_score
    return score, reason


def resolve_attack_class_rummage_triggers(player, opponents, all_players, turn, rng, *, phase="combat"):
    trigger_events = []
    for permanent in list(getattr(player, "battlefield", []) or []):
        if not isinstance(permanent, dict):
            continue
        if not permanent.get("attack_trigger_optional_discard_draw"):
            continue
        discard_card, discard_reason, risk_flags, use_top_replacement, _scored_options = (
            choose_lorehold_rummage_discard(player)
        )
        if not discard_card:
            emit_replay_event(
                "trigger_skipped",
                player=player.name,
                card=permanent.get("name", "?"),
                trigger="attack",
                reason="no_discard_candidate",
                turn=turn,
                phase=phase,
                **replay_rule_fields(permanent),
            )
            continue
        if discard_card not in player.hand:
            emit_replay_event(
                "trigger_skipped",
                player=player.name,
                card=permanent.get("name", "?"),
                trigger="attack",
                reason="discard_candidate_missing_on_resolution",
                turn=turn,
                phase=phase,
                **replay_rule_fields(permanent),
            )
            continue
        player.hand.remove(discard_card)
        discard_resolution = resolve_effect_discard_cards(
            player,
            [discard_card],
            top_limit=1 if use_top_replacement else 0,
            opponents=opponents,
            turn=turn,
            phase=phase,
            rng=rng,
        )
        drawn = player.draw(1, rng)
        process_player_draw_triggers(
            player,
            len(drawn),
            turn,
            phase,
            all_players,
            turn_player=player,
        )
        event_payload = {
            "player": player.name,
            "card": permanent.get("name", "?"),
            "trigger": "attack",
            "effect": "rummage",
            "discarded": discard_card.get("name", "?"),
            "discard_reason": discard_reason,
            "discarded_to_top": [
                card.get("name", "?")
                for card in discard_resolution.get("to_top", [])
            ],
            "discarded_to_graveyard": [
                card.get("name", "?")
                for card in discard_resolution.get("to_graveyard", [])
            ],
            "cards_drawn": len(drawn),
            "drawn": [card.get("name", "?") for card in drawn],
            "risk_flags": risk_flags,
            "class_level": int(permanent.get("class_level") or 1),
            "turn": turn,
            "phase": phase,
            **replay_rule_fields(permanent),
        }
        emit_replay_event("trigger_resolved", **event_payload)
        trigger_events.append(event_payload)
    return trigger_events


def resolve_attacking_discard_draw_activations(player, attackers, opponents, all_players, turn, rng, *, phase="combat"):
    activations = []
    attacking_ids = {id(attacker) for attacker in attackers if isinstance(attacker, dict)}
    for permanent in list(getattr(player, "battlefield", []) or []):
        if not isinstance(permanent, dict):
            continue
        if id(permanent) not in attacking_ids:
            continue
        if not permanent.get("attacking_activated_discard_draw"):
            continue
        cost = permanent.get("attacking_activated_discard_draw_cost") or "{1}{R}"
        if not player.can_pay(cost):
            emit_replay_event(
                "activated_ability_skipped",
                player=player.name,
                card=permanent.get("name", "?"),
                activation_kind="attacking_discard_draw",
                reason="insufficient_mana",
                cost=cost,
                turn=turn,
                phase=phase,
                **replay_rule_fields(permanent),
            )
            continue
        discard_card, discard_reason, risk_flags, use_top_replacement, _scored_options = (
            choose_lorehold_rummage_discard(player)
        )
        if discard_card is None:
            emit_replay_event(
                "activated_ability_skipped",
                player=player.name,
                card=permanent.get("name", "?"),
                activation_kind="attacking_discard_draw",
                reason="no_discard_candidate",
                cost=cost,
                turn=turn,
                phase=phase,
                **replay_rule_fields(permanent),
            )
            continue
        if discard_card not in player.hand:
            emit_replay_event(
                "activated_ability_skipped",
                player=player.name,
                card=permanent.get("name", "?"),
                activation_kind="attacking_discard_draw",
                reason="discard_candidate_missing_on_resolution",
                cost=cost,
                turn=turn,
                phase=phase,
                **replay_rule_fields(permanent),
            )
            continue
        mana_pool_before = player.mana_pool.snapshot()
        mana_before = player.available_mana()
        if not player.spend_mana(cost):
            continue
        player.hand.remove(discard_card)
        discard_resolution = resolve_effect_discard_cards(
            player,
            [discard_card],
            top_limit=1 if use_top_replacement else 0,
            opponents=opponents,
            turn=turn,
            phase=phase,
            rng=rng,
        )
        draw_count = int(permanent.get("attacking_activated_draw_count") or 1)
        drawn = player.draw(draw_count, rng)
        process_player_draw_triggers(
            player,
            len(drawn),
            turn,
            phase,
            all_players,
            turn_player=player,
        )
        event_payload = {
            "player": player.name,
            "card": permanent.get("name", "?"),
            "activation_kind": "attacking_discard_draw",
            "cost": cost,
            "mana_before": mana_before,
            "mana_after": player.available_mana(),
            "mana_pool_before": mana_pool_before,
            "mana_pool_after": player.mana_pool.snapshot(),
            "discarded": discard_card.get("name", "?"),
            "discard_reason": discard_reason,
            "discarded_to_top": [
                card.get("name", "?")
                for card in discard_resolution.get("to_top", [])
            ],
            "discarded_to_graveyard": [
                card.get("name", "?")
                for card in discard_resolution.get("to_graveyard", [])
            ],
            "cards_drawn": len(drawn),
            "drawn": [card.get("name", "?") for card in drawn],
            "risk_flags": risk_flags,
            "turn": turn,
            "phase": phase,
            **replay_rule_fields(permanent),
        }
        emit_replay_event("activated_ability", **event_payload)
        activations.append(event_payload)
    return activations


def activate_class_level_abilities(player, opponents, all_players, turn, rng, *, phase="precombat_main"):
    activations = 0
    for permanent in list(getattr(player, "battlefield", []) or []):
        if not isinstance(permanent, dict):
            continue
        level_costs = permanent.get("class_level_costs") or {}
        if not isinstance(level_costs, dict) or not level_costs:
            continue
        try:
            current_level = int(permanent.get("class_level") or permanent.get("class_level_start") or 1)
        except Exception:
            current_level = 1
        next_levels = sorted(
            int(level)
            for level in level_costs
            if str(level).isdigit() and int(level) > current_level
        )
        for next_level in next_levels:
            cost = level_costs.get(str(next_level)) or level_costs.get(next_level)
            if not cost or not player.can_pay(cost):
                continue
            mana_before = player.available_mana()
            mana_pool_before = player.mana_pool.snapshot()
            if not player.spend_mana(cost):
                continue
            permanent["class_level"] = next_level
            activations += 1
            emit_replay_event(
                "class_level_gained",
                player=player.name,
                card=permanent.get("name", "?"),
                class_level=next_level,
                cost=cost,
                mana_before=mana_before,
                mana_after=player.available_mana(),
                mana_pool_before=mana_pool_before,
                mana_pool_after=player.mana_pool.snapshot(),
                turn=turn,
                phase=phase,
                **replay_rule_fields(permanent),
            )
            if (
                next_level == 3
                and permanent.get("class_level3_tutor_any_to_hand_random_discard")
                and not permanent.get("class_level3_triggered")
            ):
                permanent["class_level3_triggered"] = True
                candidates = library_tutor_candidates(player, "any")
                selected = None
                tutor_reason = "no_library_candidate"
                if candidates:
                    scored = [
                        (
                            candidate,
                            *tutor_candidate_score(candidate, "any", player, opponents, turn),
                        )
                        for candidate in candidates
                    ]
                    scored.sort(
                        key=lambda item: (
                            -item[1],
                            -int(float(item[0].get("cmc") or 0)),
                            item[0].get("name", ""),
                        )
                    )
                    selected, _score, tutor_reason = scored[0]
                    moved, destination = move_library_tutor_selection(player, [selected], "any")
                    emit_replay_event(
                        "class_level_trigger_resolved",
                        player=player.name,
                        card=permanent.get("name", "?"),
                        trigger="becomes_class_level",
                        class_level=next_level,
                        effect="tutor",
                        target="any",
                        tutored=[card.get("name", "?") for card in moved],
                        destination=destination,
                        tutor_reason=tutor_reason,
                        turn=turn,
                        phase=phase,
                        **replay_rule_fields(permanent),
                    )
                if player.hand:
                    discard_index = rng.randrange(len(player.hand))
                    discarded = player.hand.pop(discard_index)
                    discard_resolution = resolve_effect_discard_cards(
                        player,
                        [discarded],
                        opponents=opponents,
                        turn=turn,
                        phase=phase,
                        rng=rng,
                    )
                    emit_replay_event(
                        "random_discard_after_tutor",
                        player=player.name,
                        card=permanent.get("name", "?"),
                        discarded=discarded.get("name", "?"),
                        discarded_to_graveyard=[
                            card.get("name", "?")
                            for card in discard_resolution.get("to_graveyard", [])
                        ],
                        class_level=next_level,
                        turn=turn,
                        phase=phase,
                        **replay_rule_fields(permanent),
                    )
                elif selected is None:
                    emit_replay_event(
                        "class_level_trigger_skipped",
                        player=player.name,
                        card=permanent.get("name", "?"),
                        trigger="becomes_class_level",
                        class_level=next_level,
                        reason=tutor_reason,
                        turn=turn,
                        phase=phase,
                        **replay_rule_fields(permanent),
                    )
            current_level = next_level
    return activations


def mizzix_mastery_graveyard_candidates(player):
    return [
        grave_card
        for grave_card in getattr(player, "graveyard", []) or []
        if isinstance(grave_card, dict) and is_instant_or_sorcery_spell(grave_card)
    ]


def resolve_mizzix_mastery(player, opponents, card, effect_data, turn, rng, *, stack=None, phase=None):
    cast_context = effect_data.get("_cast_context") or {}
    overloaded = (
        bool(effect_data.get("overloaded"))
        or cast_context.get("alternative_cost_kind") == "overload"
    )
    candidates = mizzix_mastery_graveyard_candidates(player)
    scored = [
        (
            candidate,
            threat_score(
                get_card_effect(candidate).get("effect", ""),
                candidate.get("name", ""),
                player,
                [player] + list(opponents or []),
                turn,
            ),
        )
        for candidate in candidates
    ]
    scored.sort(
        key=lambda item: (
            -item[1],
            -int(float(item[0].get("cmc") or 0)),
            item[0].get("name", ""),
        )
    )
    selected = [item[0] for item in scored] if overloaded else [item[0] for item in scored[:1]]

    exiled_originals = []
    for original in selected:
        if original not in player.graveyard:
            continue
        remove_cards_from_graveyard(
            player,
            [original],
            turn=turn,
            source_event="mizzix_mastery_target_exile",
        )
        move_to_exile(player, original, reason="mizzix_mastery_target", turn=turn)
        exiled_originals.append(original)

    resolved_copies = []
    for original in exiled_originals:
        copy_card = copy.deepcopy(original)
        copy_card["is_copy"] = True
        copy_card["_copied_from_spell"] = original.get("name", "?")
        copy_card["_copied_by"] = card.get("name", "?")
        copy_effect = copy.deepcopy(get_card_effect(original))
        copy_effect["_copied_from_spell"] = original.get("name", "?")
        copy_effect["_copied_by"] = card.get("name", "?")
        attach_direct_resolution_context(
            copy_effect,
            copy_card,
            phase,
            priority_window="mizzix_mastery_copy_resolution",
            source_zone="stack_copy",
            locked_cost=zero_mana_cost_snapshot("cast_without_paying_mana_cost"),
            alternative_cost="{0}",
            alternative_cost_kind="cast_without_paying_mana",
        )
        emit_replay_event(
            "mizzix_mastery_copy_cast",
            player=player.name,
            card=card.get("name", "?"),
            copied_spell=original.get("name", "?"),
            cast_without_paying_mana_cost=True,
            overloaded=overloaded,
            turn=turn,
            phase=phase,
            **replay_rule_fields(effect_data),
        )
        apply_effect_immediate(
            player,
            opponents,
            copy_card,
            turn,
            rng,
            effect_data_override=copy_effect,
            stack=stack,
            phase=phase,
        )
        resolved_copies.append(original.get("name", "?"))

    emit_replay_event(
        "mizzix_mastery_resolved",
        player=player.name,
        card=card.get("name", "?"),
        overloaded=overloaded,
        candidate_count=len(candidates),
        exiled_targets=[item.get("name", "?") for item in exiled_originals],
        copied_spells=resolved_copies,
        cast_without_paying_mana_cost=True,
        turn=turn,
        phase=phase,
        **replay_rule_fields(effect_data),
    )
    finish_resolved_spell(player, card, turn=turn, effect_data=effect_data)


def choose_surge_to_victory_graveyard_spell(player, opponents, turn):
    candidates = mizzix_mastery_graveyard_candidates(player)
    if not candidates:
        return None
    scored = [
        (
            candidate,
            threat_score(
                get_card_effect(candidate).get("effect", ""),
                candidate.get("name", ""),
                player,
                [player] + list(opponents or []),
                turn,
            ),
        )
        for candidate in candidates
    ]
    scored.sort(
        key=lambda item: (
            -item[1],
            -int(float(item[0].get("cmc") or 0)),
            item[0].get("name", ""),
        )
    )
    return scored[0][0]


def cast_spell_copy_without_paying_mana(
    player,
    opponents,
    all_players,
    source_card,
    original,
    turn,
    rng,
    *,
    source_effect_data,
    stack=None,
    phase=None,
    priority_window="copy_cast_without_paying_mana",
    trigger_context=None,
):
    if not isinstance(original, dict):
        return None
    copy_card = copy.deepcopy(original)
    copy_card["is_copy"] = True
    copy_card["_copied_from_spell"] = original.get("name", "?")
    copy_card["_copied_by"] = source_card.get("name", "?")
    copy_effect = copy.deepcopy(get_card_effect(original))
    if (
        copy_effect.get("effect") in {None, "unknown"}
        and isinstance(original, dict)
        and original.get("effect") not in {None, "unknown"}
    ):
        copy_effect = copy.deepcopy(original)
    copy_effect["_copied_from_spell"] = original.get("name", "?")
    copy_effect["_copied_by"] = source_card.get("name", "?")
    attach_direct_resolution_context(
        copy_effect,
        copy_card,
        phase,
        priority_window=priority_window,
        source_zone="stack_copy",
        locked_cost=zero_mana_cost_snapshot("cast_without_paying_mana_cost"),
        alternative_cost="{0}",
        alternative_cost_kind="cast_without_paying_mana",
    )
    player.record_spell_cast(CURRENT_REPLAY_TURN, card=copy_card)
    emit_replay_event(
        "spell_copied",
        player=player.name,
        card=source_card.get("name", "?"),
        copied_spell=original.get("name", "?"),
        copy_controller=player.name,
        copy_is_cast=True,
        cast_without_paying_mana_cost=True,
        turn=turn,
        phase=phase,
        **(trigger_context or {}),
        **replay_rule_fields(source_effect_data),
    )
    copy_cast_fields = copy.deepcopy(copy_effect.get("_resolution_context") or {})
    copy_cast_fields.pop("phase", None)
    copy_cast_fields.pop("result", None)
    emit_replay_event(
        "spell_cast",
        player=player.name,
        card=copy_card.get("name", "?"),
        effect=copy_effect.get("effect", "unknown"),
        type_line=copy_card.get("type_line", ""),
        cmc=copy_card.get("cmc", 0),
        cast_without_paying_mana_cost=True,
        turn=turn,
        phase=phase,
        **copy_cast_fields,
        **replay_rule_fields(copy_effect),
    )
    mark_cast_ledger_emitted(copy_effect)
    trigger_spell_cast_engines(
        player,
        all_players,
        copy_card,
        turn,
        phase,
        stack=stack,
        active_player=player,
    )
    trigger_opponent_spell_draw_engines(
        player,
        list(opponents or []),
        copy_card,
        turn,
        phase,
        rng,
        stack=stack,
        active_player=player,
        all_players=all_players,
    )
    apply_effect_immediate(
        player,
        list(opponents or []),
        copy_card,
        turn,
        rng,
        effect_data_override=copy_effect,
        stack=stack,
        phase=phase,
    )
    return copy_card


def resolve_surge_to_victory(player, opponents, all_players, card, effect_data, turn, rng, *, stack=None, phase=None):
    target_spell = choose_surge_to_victory_graveyard_spell(player, opponents, turn)
    if target_spell is None:
        emit_replay_event(
            "surge_to_victory_resolved",
            player=player.name,
            card=card.get("name", "?"),
            result="no_graveyard_target",
            turn=turn,
            phase=phase,
            **replay_rule_fields(effect_data),
        )
        finish_resolved_spell(player, card, turn=turn, effect_data=effect_data)
        return
    remove_cards_from_graveyard(
        player,
        [target_spell],
        turn=turn,
        source_event="surge_to_victory_target_exile",
    )
    move_to_exile(player, target_spell, reason="surge_to_victory_target", turn=turn)
    try:
        power_bonus = max(0, int(float(target_spell.get("cmc") or 0)))
    except Exception:
        power_bonus = 0
    creatures_buffed = grant_creatures_until_eot(player, power_bonus=power_bonus)
    player.surge_to_victory_delayed_triggers.append(
        {
            "source_card": card.get("name", "?"),
            "exiled_card": copy.deepcopy(target_spell),
            "power_bonus": power_bonus,
            "_rule_logical_key": effect_data.get("_rule_logical_key"),
            "_rule_oracle_hash": effect_data.get("_rule_oracle_hash"),
            "_rule_review_status": effect_data.get("_rule_review_status"),
            "_rule_execution_status": effect_data.get("_rule_execution_status"),
            "battle_model_scope": effect_data.get("battle_model_scope"),
        }
    )
    emit_replay_event(
        "surge_to_victory_resolved",
        player=player.name,
        card=card.get("name", "?"),
        exiled_card=target_spell.get("name", "?"),
        power_bonus=power_bonus,
        creatures_buffed=creatures_buffed,
        delayed_triggers=len(player.surge_to_victory_delayed_triggers),
        turn=turn,
        phase=phase,
        **replay_rule_fields(effect_data),
    )
    finish_resolved_spell(player, card, turn=turn, effect_data=effect_data)


def process_surge_to_victory_combat_damage_triggers(
    player,
    opponents,
    all_players,
    creature,
    damaged_player,
    turn,
    rng,
    *,
    stack=None,
    phase="combat_damage",
):
    delayed_triggers = list(getattr(player, "surge_to_victory_delayed_triggers", []) or [])
    if not delayed_triggers:
        return 0
    resolved = 0
    for delayed_trigger in delayed_triggers:
        exiled_card = delayed_trigger.get("exiled_card")
        if not isinstance(exiled_card, dict):
            continue
        trigger_context = {
            "trigger": "combat_damage_to_player",
            "trigger_creature": creature.get("name", "?") if isinstance(creature, dict) else "?",
            "damaged_player": getattr(damaged_player, "name", "?"),
        }
        copied_card = cast_spell_copy_without_paying_mana(
            player,
            opponents,
            all_players,
            {"name": delayed_trigger.get("source_card", "Surge to Victory")},
            exiled_card,
            turn,
            rng,
            source_effect_data=delayed_trigger,
            stack=stack,
            phase=phase,
            priority_window="surge_to_victory_combat_damage_copy_cast",
            trigger_context=trigger_context,
        )
        emit_replay_event(
            "trigger_resolved",
            player=player.name,
            card=delayed_trigger.get("source_card", "Surge to Victory"),
            trigger="combat_damage_to_player",
            trigger_creature=creature.get("name", "?") if isinstance(creature, dict) else "?",
            damaged_player=getattr(damaged_player, "name", "?"),
            effect="copy_spell",
            copied_spell=exiled_card.get("name", "?"),
            copied_card=copied_card.get("name", "?") if isinstance(copied_card, dict) else None,
            cast_without_paying_mana_cost=True,
            turn=turn,
            phase=phase,
            **replay_rule_fields(delayed_trigger),
        )
        resolved += 1
    return resolved


def process_combat_damage_resource_triggers(
    player,
    opponents,
    all_players,
    damaging_creatures,
    damaged_player,
    turn,
    *,
    stack=None,
    phase="combat_damage",
    rng=None,
):
    if not damaging_creatures:
        return 0
    damaged_player_name = getattr(damaged_player, "name", "?")
    trigger_creature_names = [
        creature.get("name", "?")
        for creature in damaging_creatures
        if isinstance(creature, dict)
    ]
    resolved = 0
    for permanent in list(player.battlefield):
        if not isinstance(permanent, dict):
            continue
        if permanent.get("effect") not in ("ramp_engine", "token_maker"):
            continue
        if permanent.get("trigger") != "combat_damage_to_player":
            continue
        source_specific = bool(permanent.get("trigger_source_deals_combat_damage_to_player"))
        if not permanent.get("trigger_creatures_you_control") and not source_specific:
            continue
        if source_specific and permanent not in damaging_creatures:
            continue
        if source_specific:
            trigger_names = [permanent.get("name", "?")]
        else:
            trigger_names = list(trigger_creature_names)

        def resolve_combat_damage_resource_trigger(
            permanent=permanent,
            trigger_creature_names=tuple(trigger_names),
            damaged_player_name=damaged_player_name,
        ):
            treasures_before = player.treasures
            die_roll = None
            die_sides = None
            token_count = 0
            if (
                permanent.get("treasure_count_source") == "d20_result"
                or permanent.get("token_count_source") == "d20_result"
            ):
                die_sides = int(permanent.get("die_sides") or 20)
                die_roll = (rng or random.Random(turn or 0)).randint(1, die_sides)
            if permanent.get("treasure_count_source") == "d20_result":
                treasure_count = die_roll
            else:
                default_treasure_count = (
                    0
                    if permanent.get("token_count_source") or permanent.get("token_count") not in (None, "", False)
                    else 1
                )
                treasure_count = max(0, int(permanent.get("treasure_count") or default_treasure_count))
            if permanent.get("token_count_source") == "d20_result":
                token_count = die_roll or 0
            elif permanent.get("token_count") not in (None, "", False):
                token_count = max(0, int(permanent.get("token_count") or 0))
            if treasure_count:
                player.treasures += treasure_count
            if token_count:
                create_creature_tokens_from_effect(
                    player,
                    permanent,
                    count=token_count,
                    opponents=opponents,
                    turn=turn,
                    source_event="combat_damage_token_trigger",
                    stack=stack,
                    active_player=player,
                    all_players=all_players,
                )
            emit_replay_event(
                "trigger_resolved",
                player=player.name,
                card=permanent.get("name", "?"),
                trigger="combat_damage_to_player",
                trigger_creatures=list(trigger_creature_names),
                damaged_player=damaged_player_name,
                effect=permanent.get("effect", "ramp_engine"),
                treasures_created=treasure_count,
                treasure_count_source=permanent.get("treasure_count_source"),
                tokens_created=token_count,
                token_count_source=permanent.get("token_count_source"),
                token_name=permanent.get("token_name"),
                token_power=permanent.get("token_power"),
                token_toughness=permanent.get("token_toughness"),
                token_subtype=permanent.get("token_subtype"),
                token_colors=permanent.get("token_colors") or [],
                token_flying=bool(permanent.get("token_flying") or permanent.get("flying")),
                die_roll=die_roll,
                die_sides=die_sides,
                treasures_before=treasures_before,
                treasures_after=player.treasures,
                turn=turn,
                phase=phase,
                **replay_rule_fields(permanent),
            )

        resolve_or_enqueue_trigger(
            player,
            permanent,
            "combat_damage_to_player",
            resolve_combat_damage_resource_trigger,
            stack=stack,
            active_player=player,
            all_players=all_players,
        )
        resolved += 1
    return resolved


def resolve_damage_any_target(
    controller,
    opponents,
    source_card,
    amount,
    *,
    turn=None,
    phase=None,
    exclude_permanent=None,
):
    alive_opponents = [opponent for opponent in (opponents or []) if opponent.is_alive()]
    result = {
        "amount": max(0, int(amount or 0)),
        "target_player": None,
        "target": None,
        "result": "no_legal_target_or_zero_damage",
        "destination": None,
        "life_before": None,
        "life_after": None,
    }
    if result["amount"] <= 0:
        return result

    lethal_player_options = [
        (
            opponent,
            apply_static_damage_replacements(
                controller,
                opponent,
                opponent,
                source_card,
                result["amount"],
                damage_event_type="player",
                turn=turn,
                phase=phase,
                emit=False,
            ),
        )
        for opponent in alive_opponents
    ]
    lethal_player = min(
        (
            (opponent, target_amount)
            for opponent, target_amount in lethal_player_options
            if opponent.life <= target_amount
        ),
        key=lambda item: (item[0].life, item[0].name),
        default=None,
    )

    killable_creatures = []
    excluded_permanent_id = id(exclude_permanent) if exclude_permanent is not None else None
    for opponent in alive_opponents:
        for creature in removal_target_candidates(
            opponent,
            {"effect": "remove_creature", "target": "creature"},
            controller=controller,
            source=source_card,
        ):
            if excluded_permanent_id is not None and id(creature) == excluded_permanent_id:
                continue
            if creature.get("indestructible"):
                continue
            target_amount = apply_static_damage_replacements(
                controller,
                opponent,
                creature,
                source_card,
                result["amount"],
                damage_event_type="permanent",
                turn=turn,
                phase=phase,
                emit=False,
            )
            if card_toughness_value(creature, default=2) <= target_amount:
                killable_creatures.append((target_priority(creature), opponent, creature))

    if lethal_player is not None:
        target_player, _lethal_amount = lethal_player
        result["life_before"] = target_player.life
        damage_dealt, target_amount, dealt = deal_damage_to_player_with_static_replacements(
            controller,
            target_player,
            source_card,
            result["amount"],
            turn=turn,
            phase=phase,
            damage_event_type="player",
        )
        result.update(
            {
                "amount": target_amount,
                "target_player": target_player.name,
                "result": "player_damage" if dealt else "prevented",
                "life_after": target_player.life,
            }
        )
        return result

    if killable_creatures:
        _priority, target_controller, target_creature = max(
            killable_creatures,
            key=lambda item: item[0],
        )
        target_amount = apply_static_damage_replacements(
            controller,
            target_controller,
            target_creature,
            source_card,
            result["amount"],
            damage_event_type="permanent",
            turn=turn,
            phase=phase,
        )
        process_taii_wakeen_noncombat_damage_to_creature(
            controller,
            target_controller,
            source_card,
            target_creature,
            target_amount,
            turn=turn,
            phase=phase,
        )
        destination = move_creature_from_battlefield(
            target_controller,
            target_creature,
            reason="damage",
            source=source_card,
        )
        result.update(
            {
                "amount": target_amount,
                "target_player": target_controller.name,
                "target": target_creature.get("name", "?"),
                "result": "creature_destroyed",
                "destination": destination,
            }
        )
        return result

    if alive_opponents:
        target_player = min(alive_opponents, key=lambda opponent: (opponent.life, opponent.name))
        result["life_before"] = target_player.life
        damage_dealt, target_amount, dealt = deal_damage_to_player_with_static_replacements(
            controller,
            target_player,
            source_card,
            result["amount"],
            turn=turn,
            phase=phase,
            damage_event_type="player",
        )
        result.update(
            {
                "amount": target_amount,
                "target_player": target_player.name,
                "result": "player_damage" if dealt else "prevented",
                "life_after": target_player.life,
            }
        )
    return result


def creature_enter_trigger_matches(permanent, entering_permanent, *, entering_controller_is_source_controller=True):
    if not isinstance(permanent, dict) or not isinstance(entering_permanent, dict):
        return False
    trigger = str(permanent.get("trigger") or "")
    controller_scope = str(permanent.get("trigger_controller_scope") or "")
    if trigger == "creature_you_control_enters" or controller_scope == "self":
        if not entering_controller_is_source_controller:
            return False
    card_types = [
        str(value).strip().lower()
        for value in permanent.get("trigger_entering_card_types") or []
        if value
    ]
    if card_types and "creature" in card_types and not is_battlefield_creature(entering_permanent):
        return False
    power_min = int(permanent.get("trigger_entering_power_min") or 0)
    if power_min > 0 and card_power_value(entering_permanent, default=0) < power_min:
        return False
    subtypes = [
        str(value).strip().lower()
        for value in permanent.get("trigger_entering_subtypes") or []
        if value
    ]
    if subtypes and not any(permanent_has_subtype(entering_permanent, subtype) for subtype in subtypes):
        return False
    return True


def process_controlled_creature_enters_triggers(
    player,
    opponents,
    entering_permanent,
    turn,
    *,
    source_event="creature_enters_battlefield",
    stack=None,
    active_player=None,
    all_players=None,
):
    if not isinstance(entering_permanent, dict) or not is_battlefield_creature(entering_permanent):
        return 0
    trigger_sources = [
        permanent
        for permanent in list(getattr(player, "battlefield", []) or [])
        if isinstance(permanent, dict)
        and permanent.get("trigger") in {"creature_you_control_enters", "creature_enters"}
        and permanent.get("trigger_effect") in {"damage_each_opponent", "damage_any_target", "gain_life", "draw_cards"}
    ]
    resolved = 0
    for permanent in trigger_sources:
        if not creature_enter_trigger_matches(
            permanent,
            entering_permanent,
            entering_controller_is_source_controller=True,
        ):
            continue
        if (
            permanent is entering_permanent
            and permanent.get("trigger_another_creature_you_control_enters")
            or permanent is entering_permanent
            and permanent.get("trigger_another_creature_enters")
        ):
            continue
        if permanent.get("trigger_effect") == "draw_cards":
            limit = int(permanent.get("trigger_limit_each_turn") or 0)
            if limit > 0 and permanent.get("creature_enters_draw_last_trigger_turn") == turn:
                continue
            requested = int(permanent.get("trigger_draw_count") or permanent.get("draw_count") or 0)
            if requested <= 0:
                continue
            if limit > 0:
                permanent["creature_enters_draw_last_trigger_turn"] = turn

            def resolve_creature_enters_draw_trigger(permanent=permanent, requested=requested):
                hand_before = len(player.hand)
                library_before = len(player.library)
                drawn = player.draw(requested)
                if all_players is not None and drawn:
                    process_player_draw_triggers(
                        player,
                        len(drawn),
                        turn,
                        "trigger_resolution",
                        all_players,
                        stack=stack,
                        turn_player=player,
                    )
                emit_replay_event(
                    "trigger_resolved",
                    player=player.name,
                    card=permanent.get("name", "?"),
                    trigger=permanent.get("trigger") or "creature_you_control_enters",
                    entering_creature=entering_permanent.get("name", "?"),
                    entering_controller=getattr(player, "name", "?"),
                    source_event=source_event,
                    effect="draw_cards",
                    cards_requested=requested,
                    cards_drawn=len(drawn),
                    hand_before=hand_before,
                    hand_after=len(player.hand),
                    library_before=library_before,
                    library_after=len(player.library),
                    trigger_optional=bool(permanent.get("trigger_optional")),
                    turn=turn,
                    **replay_rule_fields(permanent),
                )

            resolve_or_enqueue_trigger(
                player,
                permanent,
                permanent.get("trigger") or "creature_you_control_enters",
                resolve_creature_enters_draw_trigger,
                stack=stack,
                active_player=active_player,
                all_players=all_players,
                data={
                    "entering_creature": entering_permanent.get("name", "?"),
                    "source_event": source_event,
                },
            )
            resolved += 1
            continue
        if permanent.get("trigger_effect") == "gain_life":
            amount = int(
                permanent.get("trigger_gain_life")
                or permanent.get("gain_life")
                or permanent.get("controller_gain_life")
                or 0
            )
            if amount <= 0:
                continue

            def resolve_creature_enters_gain_life_trigger(permanent=permanent, amount=amount):
                controller_life_before = player.life
                gain_life(player, amount, cap=999)
                controller_life_after = player.life
                emit_replay_event(
                    "trigger_resolved",
                    player=player.name,
                    card=permanent.get("name", "?"),
                    trigger=permanent.get("trigger") or "creature_you_control_enters",
                    entering_creature=entering_permanent.get("name", "?"),
                    entering_controller=getattr(player, "name", "?"),
                    source_event=source_event,
                    effect="gain_life",
                    amount=amount,
                    life_gain_requested=amount,
                    life_gained=max(0, controller_life_after - controller_life_before),
                    controller_life_before=controller_life_before,
                    controller_life_after=controller_life_after,
                    turn=turn,
                    **replay_rule_fields(permanent),
                )

            resolve_or_enqueue_trigger(
                player,
                permanent,
                permanent.get("trigger") or "creature_you_control_enters",
                resolve_creature_enters_gain_life_trigger,
                stack=stack,
                active_player=active_player,
                all_players=all_players,
                data={
                    "entering_creature": entering_permanent.get("name", "?"),
                    "source_event": source_event,
                },
            )
            resolved += 1
            continue

        if permanent.get("trigger_effect") == "damage_each_opponent":
            amount = int(permanent.get("trigger_damage_each_opponent") or permanent.get("damage") or 1)
            if amount <= 0:
                continue

            def resolve_creature_enters_damage_trigger(permanent=permanent, amount=amount):
                damaged = []
                for opponent in opponents or []:
                    if not getattr(opponent, "is_alive", lambda: True)():
                        continue
                    damage_dealt, target_amount, dealt = deal_damage_to_player_with_static_replacements(
                        player,
                        opponent,
                        permanent,
                        amount,
                        turn=turn,
                        phase="trigger_resolution",
                        damage_event_type="player",
                    )
                    if dealt:
                        damaged.append(
                            {
                                "player": opponent.name,
                                "amount": target_amount,
                                "dealt": damage_dealt,
                                "life_after": opponent.life,
                            }
                        )
                emit_replay_event(
                    "trigger_resolved",
                    player=player.name,
                    card=permanent.get("name", "?"),
                    trigger="creature_you_control_enters",
                    entering_creature=entering_permanent.get("name", "?"),
                    source_event=source_event,
                    effect="damage_each_opponent",
                    amount=amount,
                    damaged=damaged,
                    turn=turn,
                    **replay_rule_fields(permanent),
                )

            resolve_or_enqueue_trigger(
                player,
                permanent,
                "creature_you_control_enters",
                resolve_creature_enters_damage_trigger,
                stack=stack,
                active_player=active_player,
                all_players=all_players,
                data={
                    "entering_creature": entering_permanent.get("name", "?"),
                    "source_event": source_event,
                },
            )
            resolved += 1
            continue

        amount_source = str(permanent.get("trigger_damage_amount_source") or "")
        if amount_source in {
            "entering_creature_power",
            "entered_creature_power",
            "creature_power",
        }:
            amount = card_power_value(entering_permanent, default=0)
        else:
            amount = int(permanent.get("trigger_damage") or permanent.get("damage") or 1)
        amount = apply_controller_noncombat_damage_modifiers(
            player,
            amount,
            permanent,
            turn=turn,
            phase="trigger_resolution",
            target=entering_permanent,
        )
        if amount <= 0:
            continue

        def resolve_creature_enters_damage_any_target_trigger(
            permanent=permanent,
            amount=amount,
            amount_source=amount_source,
        ):
            result = resolve_damage_any_target(
                player,
                opponents,
                permanent,
                amount,
                turn=turn,
                phase="trigger_resolution",
            )
            emit_replay_event(
                "trigger_resolved",
                player=player.name,
                card=permanent.get("name", "?"),
                trigger="creature_you_control_enters",
                entering_creature=entering_permanent.get("name", "?"),
                entering_creature_power=card_power_value(entering_permanent, default=0),
                source_event=source_event,
                effect="damage_any_target",
                amount=result["amount"],
                original_amount=amount,
                amount_source=amount_source or "static",
                target_player=result["target_player"],
                target=result["target"],
                result=result["result"],
                destination=result["destination"],
                life_before=result["life_before"],
                life_after=result["life_after"],
                turn=turn,
                **replay_rule_fields(permanent),
            )

        resolve_or_enqueue_trigger(
            player,
            permanent,
            "creature_you_control_enters",
            resolve_creature_enters_damage_any_target_trigger,
            stack=stack,
            active_player=active_player,
            all_players=all_players,
            data={
                "entering_creature": entering_permanent.get("name", "?"),
                "source_event": source_event,
            },
        )
        resolved += 1
    return resolved


def process_opponent_controlled_creature_enters_triggers(
    entering_controller,
    entering_permanent,
    turn,
    *,
    source_event="creature_enters_battlefield",
    stack=None,
    active_player=None,
    all_players=None,
):
    if (
        not isinstance(entering_permanent, dict)
        or not is_battlefield_creature(entering_permanent)
        or not all_players
    ):
        return 0
    resolved = 0
    for source_controller in all_players:
        if source_controller is entering_controller:
            continue
        trigger_sources = [
            permanent
            for permanent in list(getattr(source_controller, "battlefield", []) or [])
            if isinstance(permanent, dict)
            and permanent.get("trigger") in {"creature_enters_under_opponent_control", "creature_enters"}
            and permanent.get("trigger_effect") in {"gain_life", "draw_cards"}
        ]
        for permanent in trigger_sources:
            if not creature_enter_trigger_matches(
                permanent,
                entering_permanent,
                entering_controller_is_source_controller=False,
            ):
                continue
            if permanent.get("trigger_effect") == "draw_cards":
                limit = int(permanent.get("trigger_limit_each_turn") or 0)
                if limit > 0 and permanent.get("creature_enters_draw_last_trigger_turn") == turn:
                    continue
                requested = int(permanent.get("trigger_draw_count") or permanent.get("draw_count") or 0)
                if requested <= 0:
                    continue
                if limit > 0:
                    permanent["creature_enters_draw_last_trigger_turn"] = turn

                def resolve_opponent_creature_enters_draw_trigger(
                    source_controller=source_controller,
                    permanent=permanent,
                    requested=requested,
                ):
                    hand_before = len(source_controller.hand)
                    library_before = len(source_controller.library)
                    drawn = source_controller.draw(requested)
                    if all_players is not None and drawn:
                        process_player_draw_triggers(
                            source_controller,
                            len(drawn),
                            turn,
                            "trigger_resolution",
                            all_players,
                            stack=stack,
                            turn_player=entering_controller,
                        )
                    emit_replay_event(
                        "trigger_resolved",
                        player=source_controller.name,
                        card=permanent.get("name", "?"),
                        trigger=permanent.get("trigger") or "creature_enters",
                        entering_creature=entering_permanent.get("name", "?"),
                        entering_controller=getattr(entering_controller, "name", "?"),
                        source_event=source_event,
                        effect="draw_cards",
                        cards_requested=requested,
                        cards_drawn=len(drawn),
                        hand_before=hand_before,
                        hand_after=len(source_controller.hand),
                        library_before=library_before,
                        library_after=len(source_controller.library),
                        trigger_optional=bool(permanent.get("trigger_optional")),
                        turn=turn,
                        **replay_rule_fields(permanent),
                    )

                resolve_or_enqueue_trigger(
                    source_controller,
                    permanent,
                    permanent.get("trigger") or "creature_enters",
                    resolve_opponent_creature_enters_draw_trigger,
                    stack=stack,
                    active_player=active_player,
                    all_players=all_players,
                    data={
                        "entering_creature": entering_permanent.get("name", "?"),
                        "entering_controller": getattr(entering_controller, "name", "?"),
                        "source_event": source_event,
                    },
                )
                resolved += 1
                continue
            amount = int(
                permanent.get("trigger_gain_life")
                or permanent.get("gain_life")
                or permanent.get("controller_gain_life")
                or 0
            )
            if amount <= 0:
                continue

            def resolve_opponent_creature_enters_gain_life_trigger(
                source_controller=source_controller,
                permanent=permanent,
                amount=amount,
            ):
                controller_life_before = source_controller.life
                gain_life(source_controller, amount, cap=999)
                controller_life_after = source_controller.life
                emit_replay_event(
                    "trigger_resolved",
                    player=source_controller.name,
                    card=permanent.get("name", "?"),
                    trigger=permanent.get("trigger") or "creature_enters_under_opponent_control",
                    entering_creature=entering_permanent.get("name", "?"),
                    entering_controller=getattr(entering_controller, "name", "?"),
                    source_event=source_event,
                    effect="gain_life",
                    amount=amount,
                    life_gain_requested=amount,
                    life_gained=max(0, controller_life_after - controller_life_before),
                    controller_life_before=controller_life_before,
                    controller_life_after=controller_life_after,
                    turn=turn,
                    **replay_rule_fields(permanent),
                )

            resolve_or_enqueue_trigger(
                source_controller,
                permanent,
                permanent.get("trigger") or "creature_enters_under_opponent_control",
                resolve_opponent_creature_enters_gain_life_trigger,
                stack=stack,
                active_player=active_player,
                all_players=all_players,
                data={
                    "entering_creature": entering_permanent.get("name", "?"),
                    "entering_controller": getattr(entering_controller, "name", "?"),
                    "source_event": source_event,
                },
            )
            resolved += 1
    return resolved


def create_creature_token(
    player,
    *,
    name="Token",
    power=2,
    toughness=None,
    haste=False,
    flying=False,
    keywords=None,
    landwalk_land_types=None,
    artifact=False,
    subtype=None,
    colors=None,
    sacrifice_for_colorless_mana=False,
    mana_activation_requires_sacrifice=False,
    mana_activation_requires_tap=False,
    mana_produced=None,
    produces=None,
    produced_mana_symbols=None,
    tapped=False,
    cant_block=False,
    opponents=None,
    turn=None,
    source_event="token_created",
    stack=None,
    active_player=None,
    all_players=None,
):
    base_type_line = "Artifact Creature Token" if artifact else "Creature Token"
    if subtype:
        base_type_line = f"{base_type_line} — {subtype}"
    token = {
        "name": name,
        "cmc": 0,
        "tag": "token",
        "effect": "creature",
        "type_line": base_type_line,
        "power": power,
        "toughness": toughness if toughness is not None else power,
        "haste": bool(haste),
        "summoning_sick": not bool(haste),
        "tapped": bool(tapped),
    }
    if cant_block:
        token["cant_block"] = True
        token["cant_block_source"] = source_event
    if sacrifice_for_colorless_mana or mana_activation_requires_sacrifice:
        produced_amount = max(1, int(mana_produced or 1))
        token["sacrifice_for_colorless_mana"] = bool(sacrifice_for_colorless_mana)
        token["battle_model_scope"] = "xmage_self_sacrifice_mana_source_permanent_v1"
        token["ability_kind"] = "activated_mana"
        token["is_mana_source"] = True
        token["mana_source_contextual_only"] = True
        token["mana_activation_requires_sacrifice"] = True
        token["activation_requires_sacrifice"] = True
        token["mana_activation_requires_tap"] = bool(mana_activation_requires_tap)
        token["activation_requires_tap"] = bool(mana_activation_requires_tap)
        token["mana_produced"] = produced_amount
        token["produces"] = produces or "C"
        token["produced_mana_symbols"] = list(produced_mana_symbols or ["C"])
        token["xmage_ability_class"] = "SimpleManaAbility"
        token["xmage_cost_class"] = "SacrificeSourceCost"
    if colors:
        token["colors"] = list(colors)
        token["color_identity"] = list(colors)
    token_keywords = list(keywords or [])
    if flying:
        token["flying"] = True
        token_keywords.append("flying")
    if token_keywords:
        token["keywords"] = list(dict.fromkeys(token_keywords))
        for keyword in token["keywords"]:
            normalized_keyword = str(keyword or "").lower().replace(" ", "_")
            if normalized_keyword in SELF_KEYWORD_ABILITIES:
                token[normalized_keyword] = True
    if "prowess" in token_keywords:
        token["prowess"] = True
    normalized_landwalk_types = []
    raw_landwalk_types = landwalk_land_types or []
    if isinstance(raw_landwalk_types, str):
        raw_landwalk_types = [raw_landwalk_types]
    for value in raw_landwalk_types:
        land_type = str(value or "").strip().lower()
        if land_type in {"plains", "island", "swamp", "mountain", "forest"}:
            normalized_landwalk_types.append(land_type)
    if normalized_landwalk_types:
        token["landwalk"] = True
        token["landwalk_land_types"] = list(dict.fromkeys(normalized_landwalk_types))
        if len(token["landwalk_land_types"]) == 1:
            token["landwalk_land_type"] = token["landwalk_land_types"][0]
    token = prepare_entering_permanent(
        token,
        controller=player,
        all_players=all_players,
        turn=turn,
    )
    player.battlefield.append(token)
    if opponents is not None and turn is not None:
        process_controlled_creature_enters_triggers(
            player,
            opponents,
            token,
            turn,
            source_event=source_event,
            stack=stack,
            active_player=active_player,
            all_players=all_players,
        )
        process_opponent_controlled_creature_enters_triggers(
            player,
            token,
            turn,
            source_event=source_event,
            stack=stack,
            active_player=active_player,
            all_players=all_players,
        )

    if artifact:
        replacement_engines = [
            permanent
            for permanent in player.battlefield
            if isinstance(permanent, dict) and permanent.get("artifact_token_replacement")
        ]
        for _ in replacement_engines:
            thopter = {
                "name": "Thopter Token",
                "cmc": 0,
                "tag": "token",
                "effect": "creature",
                "type_line": "Artifact Creature Token — Thopter",
                "power": 1,
                "toughness": 1,
                "flying": True,
                "keywords": ["flying"],
                "summoning_sick": True,
                "tapped": False,
            }
            thopter = prepare_entering_permanent(
                thopter,
                controller=player,
                all_players=all_players,
                turn=turn,
            )
            player.battlefield.append(thopter)
            if opponents is not None and turn is not None:
                process_controlled_creature_enters_triggers(
                    player,
                    opponents,
                    thopter,
                    turn,
                    source_event="artifact_token_replacement",
                    stack=stack,
                    active_player=active_player,
                    all_players=all_players,
                )
                process_opponent_controlled_creature_enters_triggers(
                    player,
                    thopter,
                    turn,
                    source_event="artifact_token_replacement",
                    stack=stack,
                    active_player=active_player,
                    all_players=all_players,
                )
    return token


def create_artifact_token(
    player,
    *,
    name="Artifact Token",
    subtype=None,
    token_class=None,
    tapped=False,
    effect_data=None,
    source_event="artifact_token_created",
    turn=None,
    all_players=None,
):
    type_line = "Artifact Token"
    if subtype:
        type_line = f"{type_line} — {subtype}"
    token = {
        "name": name,
        "cmc": 0,
        "tag": "token",
        "token": True,
        "effect": "artifact",
        "type_line": type_line,
        "artifact": True,
        "artifact_token": True,
        "token_artifact_only": True,
        "tapped": bool(tapped),
    }
    if subtype:
        token["subtype"] = subtype
    if token_class:
        token["xmage_token_class"] = token_class
    data = dict(effect_data or {})
    token["token_activated_ability_status"] = data.get(
        "token_activated_ability_status",
        "created_token_only",
    )
    if data.get("token_activated_ability"):
        token["token_activated_ability"] = data.get("token_activated_ability")
    activated_scope = data.get("token_activated_battle_model_scope")
    if activated_scope:
        token["activated_battle_model_scope"] = activated_scope
    if activated_scope == PERMANENT_ACTIVATED_LIFE_GAIN_SCOPE:
        token["battle_model_scope"] = activated_scope
        token["activated_life_gain_amount"] = int(data.get("token_activated_life_gain_amount") or 0)
        token["life_gain_amount"] = int(data.get("token_activated_life_gain_amount") or 0)
        token["activation_cost_mana"] = data.get("token_activation_cost_mana") or "{2}"
        token["activation_cost_generic"] = int(data.get("token_activation_cost_generic") or 2)
        token["activation_requires_tap"] = bool(data.get("token_activation_requires_tap"))
        token["activation_requires_sacrifice"] = bool(data.get("token_activation_requires_sacrifice"))
    if data.get("token_activated_draw_on_self_sacrifice") or data.get("token_activated_self_sacrifice_draw"):
        token["activated_draw_on_self_sacrifice"] = True
        token["activated_self_sacrifice_draw"] = True
        token["draw_on_self_sacrifice"] = int(data.get("token_draw_on_self_sacrifice") or 1)
        token["draw_count"] = int(data.get("token_draw_count") or 1)
        token["activation_cost_mana"] = data.get("token_activation_cost_mana") or "{2}"
        token["activation_cost_generic"] = int(data.get("token_activation_cost_generic") or 2)
        token["activation_requires_tap"] = bool(data.get("token_activation_requires_tap"))
        token["activation_requires_sacrifice"] = bool(data.get("token_activation_requires_sacrifice"))
    if data.get("token_is_mana_source"):
        token["is_mana_source"] = True
        token["mana_source_contextual_only"] = bool(data.get("token_mana_source_contextual_only", True))
        token["mana_activation_requires_tap"] = bool(data.get("token_mana_activation_requires_tap", True))
        token["activation_requires_tap"] = bool(data.get("token_activation_requires_tap", True))
        token["mana_produced"] = int(data.get("token_mana_produced") or 1)
        token["produces"] = data.get("token_produces") or "C"
        token["produced_mana_symbols"] = list(data.get("token_produced_mana_symbols") or ["C"])
        if data.get("token_mana_spend_restriction"):
            token["mana_spend_restriction"] = data.get("token_mana_spend_restriction")
    token = prepare_entering_permanent(
        token,
        controller=player,
        all_players=all_players,
        turn=turn,
    )
    player.battlefield.append(token)
    emit_replay_event(
        source_event,
        player=player.name,
        token=token.get("name"),
        token_subtype=subtype,
        token_class=token_class,
        token_artifact_only=True,
        turn=turn,
        **replay_rule_fields(data),
    )
    return token


def create_food_token(
    player,
    *,
    source_card=None,
    copied_activated_ability_fields=None,
    turn=None,
    source_event="food_token_created",
    effect_data=None,
):
    token = {
        "name": "Food Token",
        "cmc": 0,
        "tag": "token",
        "token": True,
        "effect": "artifact",
        "type_line": "Artifact Token — Food",
        "artifact_token": True,
        "subtype": "Food",
        "tapped": False,
    }
    copied_fields = dict(copied_activated_ability_fields or {})
    if copied_fields:
        token.update(copied_fields)
        token["hazel_brewmaster_activated_abilities_copied"] = sorted(copied_fields)
    player.battlefield.append(token)
    emit_replay_event(
        source_event,
        player=player.name,
        card=(source_card or {}).get("name", "?") if isinstance(source_card, dict) else "?",
        token=token["name"],
        copied_activated_ability_fields=sorted(copied_fields),
        turn=turn,
        **replay_rule_fields(effect_data or {}),
    )
    return token


def _hazel_brewmaster_target_candidates(player, opponents):
    participants = [player] + list(opponents or [])
    candidates = []
    for owner in participants:
        for card in list(getattr(owner, "graveyard", []) or []):
            if not isinstance(card, dict):
                continue
            is_creature = is_creature_card(card) or is_battlefield_creature(card)
            score = (1 if is_creature else 0, card_power_value(card, default=0), str(card.get("name") or ""))
            candidates.append((score, owner, card))
    return sorted(candidates, key=lambda row: row[0], reverse=True)


def _activated_ability_fields_for_hazel(card):
    if not isinstance(card, dict):
        return {}
    copied = {}
    for key, value in card.items():
        if key.startswith("activated_") or key in {
            "is_mana_source",
            "mana_produced",
            "mana_colors",
            "mana_produced_colors",
        }:
            copied[key] = copy.deepcopy(value)
    return copied


def resolve_hazels_brewmaster_trigger(
    player,
    opponents,
    source,
    effect_data,
    turn,
    *,
    source_event,
):
    candidates = _hazel_brewmaster_target_candidates(player, opponents)
    selected_owner = None
    selected_card = None
    if candidates:
        _score, selected_owner, selected_card = candidates[0]
        selected_owner.graveyard.remove(selected_card)
        move_to_exile(selected_owner, selected_card, reason="hazels_brewmaster", turn=turn)
    exiled_creatures = list(source.get("hazel_exiled_creature_cards") or [])
    copied_fields = {}
    if selected_card is not None and (is_creature_card(selected_card) or is_battlefield_creature(selected_card)):
        exiled_creatures.append(copy.deepcopy(selected_card))
        copied_fields.update(_activated_ability_fields_for_hazel(selected_card))
    source["hazel_exiled_creature_cards"] = exiled_creatures
    if copied_fields:
        source.setdefault("hazel_shared_activated_ability_fields", {}).update(copied_fields)
    food = create_food_token(
        player,
        source_card=source,
        copied_activated_ability_fields=source.get("hazel_shared_activated_ability_fields"),
        turn=turn,
        source_event="hazels_brewmaster_food_created",
        effect_data=effect_data,
    )
    emit_replay_event(
        "trigger_resolved",
        player=player.name,
        card=source.get("name", "?"),
        trigger="enters_battlefield_or_attacks",
        source_event=source_event,
        effect="exile_graveyard_card_create_food",
        exiled_card=selected_card.get("name", "?") if isinstance(selected_card, dict) else None,
        exiled_card_owner=getattr(selected_owner, "name", None),
        exiled_card_is_creature=bool(
            selected_card is not None
            and (is_creature_card(selected_card) or is_battlefield_creature(selected_card))
        ),
        food_token=food.get("name"),
        foods_gain_activated_abilities=bool(effect_data.get("foods_gain_activated_abilities_from_exiled_creatures")),
        copied_activated_ability_fields=sorted(source.get("hazel_shared_activated_ability_fields") or {}),
        turn=turn,
        **replay_rule_fields(effect_data),
    )
    return food


def resolve_hazels_brewmaster_attack_triggers(player, attackers, opponents, turn):
    resolved = 0
    for attacker in list(attackers or []):
        if not isinstance(attacker, dict):
            continue
        if not attacker.get("hazel_brewmaster_etb_or_attack_exile_graveyard_card_create_food"):
            continue
        resolve_hazels_brewmaster_trigger(
            player,
            opponents,
            attacker,
            attacker,
            turn,
            source_event="attacks",
        )
        resolved += 1
    return resolved


def x_value_from_effect_context(effect_data, default=0):
    if not isinstance(effect_data, dict):
        return int(default or 0)
    context = {}
    context.update(effect_data.get("_cast_context") or {})
    context.update(effect_data.get("_resolution_context") or {})
    try:
        return max(0, int(float(context.get("x_value") or effect_data.get("x_value") or default or 0)))
    except Exception:
        return int(default or 0)


def token_count_for_effect(player, effect_data, default=5, opponents=None):
    token_count_source = str((effect_data or {}).get("token_count_source") or "").lower()
    if isinstance(effect_data, dict) and token_count_source == "x_value":
        per_x = int(effect_data.get("token_count_per_x") or 1)
        return x_value_from_effect_context(effect_data) * max(0, per_x)
    if isinstance(effect_data, dict) and token_count_source == "controlled_permanents_with_subtype":
        subtype = str(effect_data.get("token_count_subtype") or "").strip()
        if not subtype:
            return 0
        return sum(
            1
            for permanent in getattr(player, "battlefield", [])
            if isinstance(permanent, dict) and permanent_has_subtype(permanent, subtype)
        )
    if isinstance(effect_data, dict) and token_count_source == "all_creatures_on_battlefield":
        participants = [player, *(opponents or [])]
        return sum(
            1
            for participant in participants
            for permanent in getattr(participant, "battlefield", []) or []
            if isinstance(permanent, dict) and is_battlefield_creature(permanent)
        )
    if isinstance(effect_data, dict) and token_count_source == "attacking_creatures":
        participants = [player, *(opponents or [])]
        return sum(
            1
            for participant in participants
            for permanent in getattr(participant, "battlefield", []) or []
            if isinstance(permanent, dict) and is_battlefield_creature(permanent) and permanent.get("attacking")
        )
    if isinstance(effect_data, dict) and token_count_source == "controlled_tapped_creatures":
        return sum(
            1
            for permanent in getattr(player, "battlefield", []) or []
            if isinstance(permanent, dict) and is_battlefield_creature(permanent) and permanent.get("tapped")
        )
    if isinstance(effect_data, dict) and token_count_source == "greatest_power_among_controlled_creatures":
        powers = [
            int(permanent.get("power") or 0)
            for permanent in getattr(player, "battlefield", []) or []
            if isinstance(permanent, dict) and is_battlefield_creature(permanent)
        ]
        return max([0, *powers])
    if isinstance(effect_data, dict) and token_count_source == "controller_hand_count":
        return len(getattr(player, "hand", []) or [])
    if isinstance(effect_data, dict) and token_count_source == "domain_basic_land_types":
        return _domain_basic_land_type_count(player)
    if isinstance(effect_data, dict) and token_count_source == "controller_graveyard_creature_count":
        return sum(
            1
            for card in getattr(player, "graveyard", []) or []
            if isinstance(card, dict) and _card_type_matches(card, ["creature"])
        )
    if isinstance(effect_data, dict) and token_count_source == "controller_graveyard_instant_sorcery_count":
        return sum(
            1
            for card in getattr(player, "graveyard", []) or []
            if isinstance(card, dict) and _card_type_matches(card, ["instant", "sorcery"])
        )
    if isinstance(effect_data, dict) and token_count_source == "creatures_you_control_died_this_turn":
        turn_marker = (effect_data or {}).get("turn") or CURRENT_REPLAY_TURN
        if hasattr(player, "creatures_died_this_turn_count"):
            return player.creatures_died_this_turn_count(turn_marker)
        return int(getattr(player, "creatures_died_this_turn", 0) or 0)
    if isinstance(effect_data, dict) and token_count_source.startswith("devotion_to_"):
        color_symbols = {
            "devotion_to_white": "W",
            "devotion_to_blue": "U",
            "devotion_to_black": "B",
            "devotion_to_red": "R",
            "devotion_to_green": "G",
        }
        return devotion_to_color(player, color_symbols.get(token_count_source))
    if isinstance(effect_data, dict) and token_count_source == "named_cards_in_controller_graveyard_plus_base":
        target_name = normalize_card_name(effect_data.get("token_count_card_name") or effect_data.get("card_name") or "")
        base = int(effect_data.get("token_count_base") or 0)
        named_count = sum(
            1
            for card in getattr(player, "graveyard", []) or []
            if isinstance(card, dict) and normalize_card_name(card.get("name") or "") == target_name
        )
        return base + named_count
    per_opponent = (effect_data or {}).get("token_count_per_opponent")
    if per_opponent not in (None, "", False):
        live_opponents = [
            opponent
            for opponent in (opponents or [])
            if getattr(opponent, "is_alive", lambda: True)()
        ]
        return int(per_opponent) * len(live_opponents)
    token_count = (effect_data or {}).get("token_count", default)
    if isinstance(token_count, str):
        if token_count == "life_total":
            token_count = player.life
        elif token_count == "lands":
            token_count = controlled_land_count(player)
        elif token_count == "opponents":
            token_count = len([
                opponent
                for opponent in (opponents or [])
                if getattr(opponent, "is_alive", lambda: True)()
            ])
    return int(token_count)


def token_enters_with_counter_count(effect_data, default=0):
    if not isinstance(effect_data, dict):
        return int(default or 0)
    source = str(effect_data.get("token_enters_with_counters_source") or "").lower()
    if source == "x_value" or effect_data.get("token_enters_with_plus_one_counters_from_x"):
        return x_value_from_effect_context(effect_data, default=default)
    return max(0, int(effect_data.get("token_enters_with_counters") or default or 0))


def apply_token_entering_counters(token, effect_data):
    if not isinstance(token, dict) or not isinstance(effect_data, dict):
        return 0
    counter_count = token_enters_with_counter_count(effect_data)
    if counter_count <= 0:
        return 0
    counter_type = str(effect_data.get("token_enters_with_counter_type") or "+1/+1")
    if counter_type == "+1/+1":
        add_plus_one_counters(token, counter_count)
    elif counter_type == "-1/-1":
        add_minus_one_counters(token, counter_count)
    else:
        add_named_counters(token, counter_type, counter_count)
    token["entered_with_counter_type"] = counter_type
    token["entered_with_counters"] = counter_count
    return counter_count


def attack_each_opponent_tokens_runtime_enabled(effect_data):
    return runtime_executor_status_enabled(
        (effect_data or {}).get("attack_each_opponent_this_turn_status")
    )


def _live_opponents(opponents):
    return [
        opponent
        for opponent in (opponents or [])
        if getattr(opponent, "is_alive", lambda: True)()
    ]


def _mark_token_must_attack_defender_until_eot(token, defender, source_card_name, turn):
    if not isinstance(token, dict) or defender is None:
        return
    set_until_eot(token, "must_attack_if_able", True)
    set_until_eot(token, "must_attack_defender", defender.name)
    set_until_eot(token, "must_attack_source", source_card_name)
    if turn is not None:
        set_until_eot(token, "must_attack_until_turn", turn)


def create_creature_tokens_from_effect(
    player,
    effect_data,
    *,
    count=None,
    opponents=None,
    turn=None,
    source_event="token_created",
    stack=None,
    active_player=None,
    all_players=None,
):
    if isinstance(effect_data, dict):
        effect_data.pop("_last_token_attack_assignments", None)
    token_count = (
        token_count_for_effect(player, effect_data, opponents=opponents)
        if count is None
        else int(count)
    )
    token_name = (effect_data or {}).get("token_name") or "Token"
    token_subtype = (effect_data or {}).get("token_subtype")
    token_power = (effect_data or {}).get("token_power", 2)
    token_toughness = (effect_data or {}).get("token_toughness", token_power)
    token_haste = bool((effect_data or {}).get("token_haste") or (effect_data or {}).get("haste"))
    token_flying = bool((effect_data or {}).get("token_flying") or (effect_data or {}).get("flying"))
    token_keywords = list((effect_data or {}).get("token_keywords") or [])
    token_landwalk_land_types = (
        (effect_data or {}).get("token_landwalk_land_types")
        or (effect_data or {}).get("token_landwalk_land_type")
        or []
    )
    token_sacrifice_for_colorless_mana = bool((effect_data or {}).get("token_sacrifice_for_colorless_mana"))
    token_mana_activation_requires_sacrifice = bool(
        (effect_data or {}).get("token_mana_activation_requires_sacrifice")
        or token_sacrifice_for_colorless_mana
    )
    token_mana_activation_requires_tap = bool((effect_data or {}).get("token_mana_activation_requires_tap"))
    token_mana_produced = (effect_data or {}).get("token_mana_produced")
    token_produces = (effect_data or {}).get("token_produces")
    token_produced_mana_symbols = (effect_data or {}).get("token_produced_mana_symbols")
    token_tapped = bool((effect_data or {}).get("token_tapped"))
    token_cant_block = bool((effect_data or {}).get("token_cant_block") or (effect_data or {}).get("cant_block"))
    token_artifact_only = bool((effect_data or {}).get("token_artifact_only"))
    token_class = (effect_data or {}).get("xmage_token_class")
    if (effect_data or {}).get("token_prowess") and "prowess" not in token_keywords:
        token_keywords.append("prowess")
    artifact_tokens = bool((effect_data or {}).get("artifact_tokens"))
    token_colors = (effect_data or {}).get("token_colors") or []
    capped_token_count = min(max(0, token_count), 20)
    per_opponent = (effect_data or {}).get("token_count_per_opponent")
    counters_added_total = 0
    if (
        count is None
        and per_opponent not in (None, "", False)
        and attack_each_opponent_tokens_runtime_enabled(effect_data)
    ):
        assignments = []
        created = 0
        source_card_name = (effect_data or {}).get("_source_card_name") or (effect_data or {}).get("card_name")
        for opponent in _live_opponents(opponents):
            if created >= capped_token_count:
                break
            defender_tokens = 0
            for _ in range(max(0, int(per_opponent))):
                if created >= capped_token_count:
                    break
                if token_artifact_only:
                    token = create_artifact_token(
                        player,
                        name=token_name,
                        subtype=token_subtype,
                        token_class=token_class,
                        tapped=token_tapped,
                        effect_data=effect_data,
                        source_event=source_event,
                        turn=turn,
                        all_players=all_players,
                    )
                else:
                    token = create_creature_token(
                        player,
                        name=token_name,
                        power=token_power,
                        toughness=token_toughness,
                        haste=token_haste,
                        flying=token_flying,
                        keywords=token_keywords,
                        landwalk_land_types=token_landwalk_land_types,
                        artifact=artifact_tokens,
                        subtype=token_subtype,
                        colors=token_colors,
                        sacrifice_for_colorless_mana=token_sacrifice_for_colorless_mana,
                        mana_activation_requires_sacrifice=token_mana_activation_requires_sacrifice,
                        mana_activation_requires_tap=token_mana_activation_requires_tap,
                        mana_produced=token_mana_produced,
                        produces=token_produces,
                        produced_mana_symbols=token_produced_mana_symbols,
                        tapped=token_tapped,
                        cant_block=token_cant_block,
                        opponents=opponents,
                        turn=turn,
                        source_event=source_event,
                        stack=stack,
                        active_player=active_player,
                        all_players=all_players,
                    )
                counters_added_total += apply_token_entering_counters(token, effect_data)
                _mark_token_must_attack_defender_until_eot(
                    token,
                    opponent,
                    source_card_name,
                    turn,
                )
                defender_tokens += 1
                created += 1
            if defender_tokens:
                assignments.append({
                    "defender": opponent.name,
                    "tokens": defender_tokens,
                })
        if isinstance(effect_data, dict):
            effect_data["_last_token_attack_assignments"] = assignments
            effect_data["_last_token_entering_counters_added"] = counters_added_total
        return token_count

    for _ in range(capped_token_count):
        if token_artifact_only:
            token = create_artifact_token(
                player,
                name=token_name,
                subtype=token_subtype,
                token_class=token_class,
                tapped=token_tapped,
                effect_data=effect_data,
                source_event=source_event,
                turn=turn,
                all_players=all_players,
            )
        else:
            token = create_creature_token(
                player,
                name=token_name,
                power=token_power,
                toughness=token_toughness,
                haste=token_haste,
                flying=token_flying,
                keywords=token_keywords,
                landwalk_land_types=token_landwalk_land_types,
                artifact=artifact_tokens,
                subtype=token_subtype,
                colors=token_colors,
                sacrifice_for_colorless_mana=token_sacrifice_for_colorless_mana,
                mana_activation_requires_sacrifice=token_mana_activation_requires_sacrifice,
                mana_activation_requires_tap=token_mana_activation_requires_tap,
                mana_produced=token_mana_produced,
                produces=token_produces,
                produced_mana_symbols=token_produced_mana_symbols,
                tapped=token_tapped,
                cant_block=token_cant_block,
                opponents=opponents,
                turn=turn,
                source_event=source_event,
                stack=stack,
                active_player=active_player,
                all_players=all_players,
            )
        counters_added_total += apply_token_entering_counters(token, effect_data)
    if isinstance(effect_data, dict):
        effect_data["_last_token_entering_counters_added"] = counters_added_total
    return token_count


def battlefield_controller_for_permanent(permanent, participants):
    for participant in participants or []:
        if permanent in (getattr(participant, "battlefield", []) or []):
            return participant
    return None


def permanent_is_opponent_enter_tapped_subject(permanent):
    if not isinstance(permanent, dict):
        return False
    type_line = str(permanent.get("type_line") or "").lower()
    return is_battlefield_creature(permanent) or "artifact" in type_line or "land" in type_line


def opponent_enter_tapped_static_sources(permanent, controller, all_players):
    if (
        not permanent_is_opponent_enter_tapped_subject(permanent)
        or controller is None
        or not all_players
    ):
        return []
    sources = []
    for source_controller in all_players:
        for source in getattr(source_controller, "battlefield", []) or []:
            if not isinstance(source, dict):
                continue
            permanent_type_line = str(permanent.get("type_line") or "").lower()
            if (
                source.get("nonphyrexian_creatures_enter_tapped")
                and is_battlefield_creature(permanent)
                and "phyrexian" not in permanent_type_line
            ):
                sources.append((source_controller, source, "nonphyrexian_creature"))
                continue
            if source_controller is controller:
                continue
            if source.get("opponents_creatures_enter_tapped") and is_battlefield_creature(permanent):
                sources.append((source_controller, source, "opponent_creature"))
                continue
            if (
                source.get("opponents_nonbasic_lands_enter_tapped")
                and "land" in permanent_type_line
                and "basic" not in permanent_type_line
            ):
                sources.append((source_controller, source, "opponent_nonbasic_land"))
                continue
            if (
                source.get("opponents_artifacts_creatures_enter_tapped")
                or source.get("opponents_artifacts_and_creatures_enter_tapped")
            ):
                sources.append((source_controller, source, "opponent_artifact_or_creature"))
    return sources


def apply_opponent_enter_tapped_static(permanent, controller, all_players, turn=None):
    sources = opponent_enter_tapped_static_sources(permanent, controller, all_players)
    if not sources:
        return False
    source_controller, source, applies_to = sources[0]
    permanent["enters_tapped"] = True
    permanent["tapped"] = True
    permanent["entered_tapped_by_static"] = source.get("name", "?")
    permanent["entered_tapped_by_static_rule_key"] = source.get("_rule_logical_key")
    emit_replay_event(
        "static_enter_tapped_applied",
        player=getattr(controller, "name", "?"),
        card=permanent.get("name", "?"),
        type_line=permanent.get("type_line", ""),
        source_player=getattr(source_controller, "name", "?"),
        source_card=source.get("name", "?"),
        applies_to=applies_to,
        turn=turn,
        **replay_rule_fields(source),
    )
    return True


def apply_graveyard_count_creature_static(
    permanent,
    controller,
    turn=None,
    phase=None,
    emit_event=False,
):
    if not isinstance(permanent, dict):
        return False
    threshold = permanent.get("creature_if_graveyard_count_at_least")
    if threshold in (None, "", False):
        return False
    try:
        required_count = max(0, int(threshold or 0))
    except (TypeError, ValueError):
        required_count = 0
    graveyard_count = len(getattr(controller, "graveyard", []) or [])
    active = graveyard_count >= required_count
    was_active = bool(permanent.get("graveyard_count_creature_active"))

    permanent["graveyard_count_creature_active"] = active
    permanent["graveyard_count_creature_required"] = required_count
    permanent["graveyard_count_current"] = graveyard_count
    if active:
        permanent.pop("creature_type_suppressed", None)
        permanent["is_creature_permanent"] = True
        permanent["haste"] = has_haste(permanent)
        if "summoning_sick" not in permanent:
            permanent["summoning_sick"] = not permanent["haste"]
        if permanent.get("power") in (None, ""):
            permanent["power"] = int(permanent.get("base_power") or 1)
        if permanent.get("toughness") in (None, ""):
            permanent["toughness"] = int(permanent.get("base_toughness") or permanent.get("power") or 1)
    else:
        permanent["creature_type_suppressed"] = True
        permanent["is_creature_permanent"] = False
        permanent.pop("summoning_sick", None)

    if emit_event and active != was_active:
        emit_replay_event(
            "static_graveyard_count_creature_state_changed",
            player=getattr(controller, "name", "?"),
            card=permanent.get("name", "?"),
            active=active,
            graveyard_count=graveyard_count,
            required_graveyard_count=required_count,
            creature_type_suppressed=bool(permanent.get("creature_type_suppressed")),
            turn=turn,
            phase=phase,
            **replay_rule_fields(permanent),
        )
    return active


def refresh_graveyard_count_creature_statics_for_player(
    player,
    turn=None,
    phase=None,
    emit_events=False,
    all_players=None,
):
    refreshed = []
    participants = all_players or [player]
    for permanent in list(getattr(player, "battlefield", []) or []):
        if not isinstance(permanent, dict):
            continue
        row = {"card": permanent.get("name", "?")}
        touched = False
        if permanent.get("creature_if_graveyard_count_at_least") not in (None, "", False):
            active = apply_graveyard_count_creature_static(
                permanent,
                player,
                turn=turn,
                phase=phase,
                emit_event=emit_events,
            )
            row.update(
                {
                    "graveyard_count_creature_active": active,
                    "graveyard_count": permanent.get("graveyard_count_current"),
                    "creature_type_suppressed": bool(permanent.get("creature_type_suppressed")),
                }
            )
            touched = True
        if permanent.get("battle_model_scope") == STATIC_GRAVEYARD_COUNT_POWER_TOUGHNESS_SCOPE:
            apply_static_graveyard_count_power_toughness(
                permanent,
                player,
                all_players=participants,
                turn=turn,
                phase=phase,
                emit_event=emit_events,
            )
            row.update(
                {
                    "graveyard_count_power_toughness": permanent.get(
                        "static_graveyard_count_power_toughness_current"
                    ),
                    "power": permanent.get("power"),
                    "toughness": permanent.get("toughness"),
                }
            )
            touched = True
            moved = move_zero_toughness_graveyard_count_creature_to_graveyard(
                player,
                permanent,
                turn=turn,
                phase=phase,
                emit_event=emit_events,
            )
            if moved:
                row["state_based_action"] = "zero_toughness_to_graveyard"
        if permanent.get("battle_model_scope") == STATIC_COUNT_POWER_TOUGHNESS_SCOPE:
            apply_static_count_power_toughness(
                permanent,
                player,
                all_players=participants,
                turn=turn,
                phase=phase,
                emit_event=emit_events,
            )
            row.update(
                {
                    "static_count_power_toughness": permanent.get(
                        "static_count_power_toughness_current"
                    ),
                    "power": permanent.get("power"),
                    "toughness": permanent.get("toughness"),
                }
            )
            touched = True
            moved = move_zero_toughness_graveyard_count_creature_to_graveyard(
                player,
                permanent,
                turn=turn,
                phase=phase,
                emit_event=emit_events,
            )
            if moved:
                row["state_based_action"] = "zero_toughness_to_graveyard"
        if permanent.get("battle_model_scope") == STATIC_GRAVEYARD_THRESHOLD_SOURCE_BOOST_SCOPE:
            active = apply_static_graveyard_threshold_source_boost(
                permanent,
                player,
                all_players=participants,
                turn=turn,
                phase=phase,
                emit_event=emit_events,
            )
            row.update(
                {
                    "graveyard_threshold_boost_active": active,
                    "graveyard_count": permanent.get("static_graveyard_threshold_count_current"),
                    "graveyard_count_threshold": permanent.get("graveyard_count_threshold"),
                    "power": permanent.get("power"),
                    "toughness": permanent.get("toughness"),
                }
            )
            touched = True
        if permanent.get("battle_model_scope") == STATIC_GRAVEYARD_COUNT_SOURCE_BOOST_SCOPE:
            active = apply_static_graveyard_count_source_boost(
                permanent,
                player,
                all_players=participants,
                turn=turn,
                phase=phase,
                emit_event=emit_events,
            )
            row.update(
                {
                    "graveyard_count_source_boost_active": active,
                    "graveyard_count": permanent.get("static_graveyard_count_boost_current"),
                    "power": permanent.get("power"),
                    "toughness": permanent.get("toughness"),
                }
            )
            touched = True
        if touched:
            refreshed.append(row)
    return refreshed


def choose_damage_reflection_player(controller, all_players):
    candidates = [
        participant
        for participant in all_players or []
        if participant is not None
        and participant is not controller
        and getattr(participant, "is_alive", lambda: True)()
    ]
    if not candidates and controller is not None:
        candidates = [controller]
    if not candidates:
        return None
    return min(
        candidates,
        key=lambda participant: (
            int(getattr(participant, "life", 40) or 40),
            -table_visible_threat_score(participant),
            getattr(participant, "name", ""),
        ),
    )


def apply_as_enters_choose_player_static(
    permanent,
    controller,
    all_players,
    turn=None,
):
    if not isinstance(permanent, dict):
        return None
    if not (
        permanent.get("as_enters_choose_player")
        or permanent.get("source_damage_reflect_to_chosen_player")
    ):
        return None
    if permanent.get("chosen_player_name"):
        return permanent.get("chosen_player_name")
    chosen = choose_damage_reflection_player(controller, all_players)
    if chosen is None:
        return None
    permanent["chosen_player_name"] = getattr(chosen, "name", None)
    permanent["chosen_player_role"] = "controller" if chosen is controller else "opponent"
    emit_replay_event(
        "as_enters_choose_player",
        player=getattr(controller, "name", "?"),
        card=permanent.get("name", "?"),
        chosen_player=permanent["chosen_player_name"],
        chosen_player_role=permanent["chosen_player_role"],
        turn=turn,
        **replay_rule_fields(permanent),
    )
    return permanent["chosen_player_name"]


def controlled_static_indestructible_sources(controller):
    sources = []
    for source in getattr(controller, "battlefield", []) or []:
        if not isinstance(source, dict):
            continue
        if source.get("other_permanents_you_control_have_indestructible"):
            sources.append(source)
    return sources


def apply_controlled_static_indestructible_to_permanent(
    permanent,
    controller,
    *,
    turn=None,
    phase=None,
    emit_event=False,
):
    if not isinstance(permanent, dict) or controller is None:
        return False
    source = next(
        (
            candidate
            for candidate in controlled_static_indestructible_sources(controller)
            if candidate is not permanent
        ),
        None,
    )
    had_static = bool(permanent.get("static_indestructible_source"))
    if source is None:
        if had_static:
            original = bool(permanent.pop("static_indestructible_original", False))
            permanent["indestructible"] = original
            source_name = permanent.pop("static_indestructible_source", None)
            permanent.pop("static_indestructible_rule_key", None)
            if emit_event:
                emit_replay_event(
                    "static_indestructible_removed",
                    player=getattr(controller, "name", "?"),
                    card=permanent.get("name", "?"),
                    source_card=source_name,
                    indestructible=bool(permanent.get("indestructible")),
                    turn=turn,
                    phase=phase,
                )
        return False

    if "static_indestructible_original" not in permanent:
        permanent["static_indestructible_original"] = bool(permanent.get("indestructible"))
    permanent["indestructible"] = True
    permanent["static_indestructible_source"] = source.get("name", "?")
    permanent["static_indestructible_rule_key"] = source.get("_rule_logical_key")
    if emit_event and not had_static:
        emit_replay_event(
            "static_indestructible_applied",
            player=getattr(controller, "name", "?"),
            card=permanent.get("name", "?"),
            source_card=source.get("name", "?"),
            turn=turn,
            phase=phase,
            **replay_rule_fields(source),
        )
    return True


def refresh_controlled_static_indestructible(
    controller,
    *,
    turn=None,
    phase=None,
    emit_events=False,
):
    refreshed = []
    for permanent in list(getattr(controller, "battlefield", []) or []):
        if not isinstance(permanent, dict):
            continue
        active = apply_controlled_static_indestructible_to_permanent(
            permanent,
            controller,
            turn=turn,
            phase=phase,
            emit_event=emit_events,
        )
        if active or permanent.get("static_indestructible_source"):
            refreshed.append(
                {
                    "card": permanent.get("name", "?"),
                    "indestructible": bool(permanent.get("indestructible")),
                    "source": permanent.get("static_indestructible_source"),
                }
            )
    return refreshed


def refresh_all_controlled_static_indestructible(
    participants,
    *,
    turn=None,
    phase=None,
    emit_events=False,
):
    refreshed = []
    seen = set()
    for participant in participants or []:
        if participant is None or id(participant) in seen:
            continue
        seen.add(id(participant))
        refreshed.extend(
            refresh_controlled_static_indestructible(
                participant,
                turn=turn,
                phase=phase,
                emit_events=emit_events,
            )
        )
    return refreshed


STATIC_CONTROLLED_POWER_TOUGHNESS_SCOPE = "xmage_static_controlled_power_toughness_boost_v1"
STATIC_CONTROLLED_KEYWORD_SCOPE = "xmage_static_controlled_keyword_grant_v1"
STATIC_GLOBAL_POWER_TOUGHNESS_SCOPE = "xmage_static_global_power_toughness_boost_v1"
STATIC_GRAVEYARD_COUNT_POWER_TOUGHNESS_SCOPE = "xmage_static_source_power_toughness_equal_graveyard_count_v1"
STATIC_COUNT_POWER_TOUGHNESS_SCOPE = "xmage_static_source_power_toughness_equal_count_v1"
STATIC_GRAVEYARD_THRESHOLD_SOURCE_BOOST_SCOPE = "xmage_static_source_boost_if_graveyard_threshold_v1"
STATIC_GRAVEYARD_COUNT_SOURCE_BOOST_SCOPE = "xmage_static_source_boost_equal_graveyard_count_v1"


def _static_pt_int(value, default=0):
    try:
        return int(float(value))
    except (TypeError, ValueError):
        return default


def _static_pt_tokens(value):
    return {
        token
        for token in re.sub(r"[^a-z0-9]+", " ", str(value or "").lower()).split()
        if token
    }


def _static_pt_subtype_tokens(permanent):
    type_line = str((permanent or {}).get("type_line") or "")
    subtype_text = type_line.split("-", 1)[1] if "-" in type_line else type_line
    return _static_pt_tokens(subtype_text)


def _static_pt_card_type_tokens(card):
    return _static_pt_tokens((card or {}).get("type_line"))


def _static_graveyard_count_card_matches(card, allowed_types, allowed_subtypes=None):
    normalized = {
        str(value).strip().lower()
        for value in (allowed_types or [])
        if str(value).strip()
    }
    subtypes = {
        str(value).strip().lower()
        for value in (allowed_subtypes or [])
        if str(value).strip()
    }
    if subtypes and not _card_subtype_matches(card, subtypes):
        return False
    if not normalized or "card" in normalized:
        return True
    if "permanent" in normalized and is_permanent_card(card):
        return True
    card_types = _static_pt_card_type_tokens(card)
    if "noncreature_nonland" in normalized:
        return "creature" not in card_types and "land" not in card_types
    return bool(normalized.intersection(card_types))


def static_graveyard_count_power_toughness_value(permanent, controller, all_players=None):
    if not isinstance(permanent, dict):
        return None
    if (
        permanent.get("battle_model_scope") != STATIC_GRAVEYARD_COUNT_POWER_TOUGHNESS_SCOPE
        or permanent.get("static_power_toughness_source") != "graveyard_count"
    ):
        return None
    scope = str(permanent.get("graveyard_count_scope") or "controller_graveyard")
    participants = []
    if scope == "all_graveyards":
        participants = [player for player in (all_players or []) if player is not None]
        if controller is not None and all(id(player) != id(controller) for player in participants):
            participants.insert(0, controller)
    else:
        participants = [controller] if controller is not None else []
    allowed_types = permanent.get("graveyard_count_card_types") or ["card"]
    allowed_subtypes = permanent.get("graveyard_count_subtypes") or []
    count = 0
    for participant in participants:
        for card in getattr(participant, "graveyard", []) or []:
            if isinstance(card, dict) and _static_graveyard_count_card_matches(card, allowed_types, allowed_subtypes):
                count += 1
    return count


def apply_static_graveyard_count_power_toughness(
    permanent,
    controller,
    all_players=None,
    *,
    turn=None,
    phase=None,
    emit_event=False,
):
    value = static_graveyard_count_power_toughness_value(
        permanent,
        controller,
        all_players=all_players,
    )
    if value is None:
        return False
    before = {
        "power": permanent.get("power"),
        "toughness": permanent.get("toughness"),
        "value": permanent.get("static_graveyard_count_power_toughness_current"),
    }
    plus_one = _static_pt_int(permanent.get("plus_one_counters"), default=0)
    minus_one = _static_pt_int(permanent.get("minus_one_counters"), default=0)
    adjusted = int(value) + plus_one - minus_one
    permanent["power"] = adjusted
    permanent["toughness"] = adjusted
    permanent["static_graveyard_count_power_toughness_current"] = int(value)
    permanent["_static_graveyard_count_pt_base"] = int(value)
    permanent["static_graveyard_count_scope"] = str(permanent.get("graveyard_count_scope") or "controller_graveyard")
    permanent["static_graveyard_count_card_types"] = list(permanent.get("graveyard_count_card_types") or ["card"])
    changed = (
        before["power"] != permanent.get("power")
        or before["toughness"] != permanent.get("toughness")
        or before["value"] != int(value)
    )
    if emit_event and changed:
        emit_replay_event(
            "static_graveyard_count_power_toughness_changed",
            player=getattr(controller, "name", "?"),
            card=permanent.get("name", "?"),
            graveyard_count=int(value),
            graveyard_count_scope=permanent.get("static_graveyard_count_scope"),
            graveyard_count_card_types=permanent.get("static_graveyard_count_card_types"),
            power_before=before["power"],
            toughness_before=before["toughness"],
            power_after=permanent.get("power"),
            toughness_after=permanent.get("toughness"),
            turn=turn,
            phase=phase,
            **replay_rule_fields(permanent),
        )
    return True


def static_count_power_toughness_value(permanent, controller, all_players=None):
    if not isinstance(permanent, dict):
        return None, {}
    if (
        permanent.get("battle_model_scope") != STATIC_COUNT_POWER_TOUGHNESS_SCOPE
        or permanent.get("static_effect") != "source_power_toughness_equal_count"
    ):
        return None, {}
    participants = [player for player in (all_players or []) if player is not None]
    if controller is not None and all(id(player) != id(controller) for player in participants):
        participants.insert(0, controller)
    opponents = [
        player
        for player in participants
        if controller is None or id(player) != id(controller)
    ]
    count_effect = {
        **permanent,
        "stat_modifier_amount_source": permanent.get("static_power_toughness_source")
        or permanent.get("stat_modifier_amount_source")
        or "battlefield_permanent_count",
        "_count_source_permanent": permanent,
    }
    count, replay_fields = _stat_modifier_count_from_source(controller, opponents, count_effect)
    if count is None:
        return None, replay_fields
    base = _static_pt_int(permanent.get("static_power_toughness_base"), default=0)
    multiplier = _static_pt_int(permanent.get("static_power_toughness_count_multiplier"), default=1)
    return base + (int(count) * multiplier), {
        **replay_fields,
        "static_power_toughness_source": count_effect["stat_modifier_amount_source"],
        "static_power_toughness_base": base,
        "static_power_toughness_count_multiplier": multiplier,
        "static_count_power_toughness_count": int(count),
    }


def apply_static_count_power_toughness(
    permanent,
    controller,
    all_players=None,
    *,
    turn=None,
    phase=None,
    emit_event=False,
):
    value, replay_fields = static_count_power_toughness_value(
        permanent,
        controller,
        all_players=all_players,
    )
    if value is None:
        return False
    before = {
        "power": permanent.get("power"),
        "toughness": permanent.get("toughness"),
        "value": permanent.get("static_count_power_toughness_current"),
    }
    plus_one = _static_pt_int(permanent.get("plus_one_counters"), default=0)
    minus_one = _static_pt_int(permanent.get("minus_one_counters"), default=0)
    adjusted = int(value) + plus_one - minus_one
    permanent["power"] = adjusted
    permanent["toughness"] = adjusted
    permanent["static_count_power_toughness_current"] = int(value)
    permanent["_static_count_pt_base"] = int(value)
    changed = (
        before["power"] != permanent.get("power")
        or before["toughness"] != permanent.get("toughness")
        or before["value"] != int(value)
    )
    if emit_event and changed:
        emit_replay_event(
            "static_count_power_toughness_changed",
            player=getattr(controller, "name", "?"),
            card=permanent.get("name", "?"),
            count=int(replay_fields.get("static_count_power_toughness_count") or value),
            power_before=before["power"],
            toughness_before=before["toughness"],
            power_after=permanent.get("power"),
            toughness_after=permanent.get("toughness"),
            turn=turn,
            phase=phase,
            **replay_rule_fields(permanent),
            **replay_fields,
        )
    return True


def static_graveyard_threshold_boost_count(permanent, controller, all_players=None):
    if not isinstance(permanent, dict):
        return None
    if (
        permanent.get("battle_model_scope") != STATIC_GRAVEYARD_THRESHOLD_SOURCE_BOOST_SCOPE
        or permanent.get("static_effect") != "source_power_toughness_boost_if_graveyard_count"
    ):
        return None
    scope = str(permanent.get("graveyard_count_scope") or "controller_graveyard")
    if scope == "opponents_graveyards":
        participants = [
            player
            for player in (all_players or [])
            if player is not None and (controller is None or id(player) != id(controller))
        ]
    elif scope == "all_graveyards":
        participants = [player for player in (all_players or []) if player is not None]
        if controller is not None and all(id(player) != id(controller) for player in participants):
            participants.insert(0, controller)
    else:
        participants = [controller] if controller is not None else []
    count_mode = str(permanent.get("graveyard_count_mode") or "").strip().lower()
    if count_mode in {"distinct_card_types", "card_type_count"}:
        seen_types = set()
        for participant in participants:
            seen_types.update(_graveyard_card_type_set(participant))
        return len(seen_types)
    if count_mode in {"distinct_mana_values", "mana_value_count"}:
        seen_values = set()
        for participant in participants:
            for card in getattr(participant, "graveyard", []) or []:
                if isinstance(card, dict):
                    seen_values.add(card_mana_value(card))
        return len(seen_values)
    allowed_types = permanent.get("graveyard_count_card_types") or ["card"]
    allowed_subtypes = permanent.get("graveyard_count_subtypes") or []
    count = 0
    for participant in participants:
        for card in getattr(participant, "graveyard", []) or []:
            if isinstance(card, dict) and _static_graveyard_count_card_matches(card, allowed_types, allowed_subtypes):
                count += 1
    return count


