def activated_regenerate_target_effect_for_permanent(permanent):
    if not isinstance(permanent, dict):
        return None
    for effect_data in _activated_rule_effects_for_permanent(permanent):
        if (
            effect_data.get("battle_model_scope") == SIMPLE_ACTIVATED_REGENERATE_TARGET_SCOPE
            and effect_data.get("ability_kind") == "activated"
            and effect_data.get("activated_effect") == "regenerate_target"
        ):
            return effect_data
    return None


def _regenerate_target_activation_cost(effect_data):
    return _self_boost_activation_cost(effect_data)


def _regenerate_target_participants(player, opponents, effect_data):
    target_controller = str((effect_data or {}).get("target_controller") or "any").lower()
    constraint_scope = str(_target_constraints_dict(effect_data or {}).get("controller_scope") or "").lower()
    controller = target_controller or constraint_scope
    if controller in {"self", "you", "controller", "controlled"}:
        return [player]
    if controller in {"opponent", "opponents"}:
        return list(opponents or [])
    return [player, *list(opponents or [])]


def _regenerate_target_candidates(player, opponents, permanent, effect_data, *, auto_only=False):
    target_type = str((effect_data or {}).get("target") or "creature").lower()
    constraints = _target_constraints_dict(effect_data or {})
    source_context = {**dict(permanent or {}), **dict(effect_data or {})}
    candidates = []
    for owner in _regenerate_target_participants(player, opponents, effect_data):
        if auto_only and owner is not player:
            continue
        for target in list(getattr(owner, "battlefield", []) or []):
            if not is_battlefield_creature(target):
                continue
            if constraints.get("exclude_source") and target is permanent:
                continue
            if not is_legal_target(
                source_context,
                target,
                player,
                target_type=target_type,
                target_controller=owner,
            ):
                continue
            candidates.append((owner, target))
    return candidates


def _choose_activated_regenerate_target(player, opponents, permanent, effect_data, *, auto_only=False):
    candidates = _regenerate_target_candidates(
        player,
        opponents,
        permanent,
        effect_data,
        auto_only=auto_only,
    )
    if not candidates:
        return None, None, []
    preferred = [(owner, target) for owner, target in candidates if owner is player]
    if not preferred:
        preferred = candidates
    owner, target = max(
        preferred,
        key=lambda item: (
            target_priority(item[1]),
            int(item[1].get("regeneration_shields") or 0) == 0,
            str(item[1].get("name") or ""),
        ),
    )
    return owner, target, [target for _owner, target in candidates]


def can_activate_generic_regenerate_target_permanent(player, opponents, permanent, *, effect_data=None, auto_only=False):
    effect_data = effect_data or activated_regenerate_target_effect_for_permanent(permanent)
    if effect_data is None:
        return False
    if auto_only:
        return False
    if permanent not in getattr(player, "battlefield", []):
        return False
    if effect_data.get("activation_requires_tap") and permanent.get("tapped"):
        return False
    if (
        effect_data.get("activation_requires_tap")
        and is_battlefield_creature(permanent)
        and permanent.get("summoning_sick")
        and not has_haste(permanent)
    ):
        return False
    activation_cost = _regenerate_target_activation_cost(effect_data)
    if not player.can_pay(activation_cost):
        return False
    if not _can_pay_self_boost_extra_costs(player, effect_data):
        return False
    target_owner, target, _targets = _choose_activated_regenerate_target(
        player,
        opponents,
        permanent,
        effect_data,
        auto_only=auto_only,
    )
    if target_owner is None or target is None:
        return False
    return True


