def spell_cast_token_filter_matches(permanent, controller, spell, *, source_zone="hand"):
    if not isinstance(permanent, dict) or not isinstance(spell, dict):
        return False
    required_zone = str(permanent.get("spell_cast_token_source_zone") or "").strip().lower()
    if required_zone and str(source_zone or "hand").strip().lower() != required_zone:
        return False
    if permanent.get("spell_cast_token_requires_x_mana_cost") and not _spell_has_x_in_mana_cost(spell):
        return False
    required_types = [
        str(value).strip().lower()
        for value in _as_list(permanent.get("spell_cast_token_card_types"))
        if str(value).strip()
    ]
    if required_types:
        artifact_required = "artifact" in required_types
        nonartifact_required_types = [
            card_type for card_type in required_types if card_type != "artifact"
        ]
        type_match = bool(nonartifact_required_types) and _card_type_matches(
            spell,
            nonartifact_required_types,
        )
        artifact_match = artifact_required and is_artifact_spell_for_controller(controller, spell)
        if not type_match and not artifact_match:
            return False
    type_line = str(spell.get("type_line") or "").lower()
    required_subtypes = [
        str(value).replace("_", " ").strip().lower()
        for value in _as_list(permanent.get("spell_cast_token_required_subtypes"))
        if str(value).strip()
    ]
    if required_subtypes and not any(re.search(rf"\b{re.escape(subtype)}\b", type_line) for subtype in required_subtypes):
        return False
    required_supertypes = [
        str(value).strip().lower()
        for value in _as_list(permanent.get("spell_cast_token_required_supertypes"))
        if str(value).strip()
    ]
    if "legendary" in required_supertypes and "legendary" not in type_line and not spell.get("legendary"):
        return False
    if permanent.get("spell_cast_token_requires_multicolored"):
        if len(_spell_color_symbols(spell)) < 2:
            return False
    required_colors = [
        _color_symbol(value)
        for value in _as_list(permanent.get("spell_cast_token_required_colors"))
        if _color_symbol(value)
    ]
    if required_colors and not any(_spell_has_color(spell, color) for color in required_colors):
        return False
    if permanent.get("spell_cast_token_requires_historic"):
        is_historic = (
            is_artifact_spell_for_controller(controller, spell)
            or "legendary" in type_line
            or bool(spell.get("legendary"))
            or re.search(r"\bsaga\b", type_line) is not None
        )
        if not is_historic:
            return False
    mana_value_min = int(permanent.get("spell_cast_token_mana_value_min") or 0)
    if mana_value_min > 0 and card_mana_value(spell) < mana_value_min:
        return False
    return True


def executable_activated_rule_effects(permanent, *, effect=None):
    if not isinstance(permanent, dict):
        return []
    effects = []
    for activated in permanent.get("_activated_rule_effects") or []:
        if not isinstance(activated, dict):
            continue
        if effect is not None and activated.get("effect") != effect:
            continue
        effects.append(activated)
    return effects


def activation_cost_text_for_effect(effect_data):
    if effect_data.get("activation_cost_mana"):
        return str(effect_data.get("activation_cost_mana"))
    return _activation_cost_text(
        int(effect_data.get("activation_cost_generic") or 0),
        effect_data.get("activation_cost_colors") or [],
    )


def activated_copy_creature_token_station_ready(permanent, effect_data):
    station_level_required = int(effect_data.get("station_level_required") or 0)
    if station_level_required <= 0:
        return True
    current_level = int(
        permanent.get("charge_counters")
        or permanent.get("station_level")
        or 0
    )
    return bool(permanent.get("station_online")) or current_level >= station_level_required


def activate_secondary_copy_creature_token_abilities(player, opponents, turn, *, phase="precombat_main"):
    if phase not in MAIN_PHASES:
        return 0
    activations = 0
    for permanent in list(getattr(player, "battlefield", []) or []):
        if not isinstance(permanent, dict):
            continue
        if permanent.get("_activated_copy_creature_token_last_turn") == turn:
            continue
        for ability in executable_activated_rule_effects(permanent, effect="copy_creature_token"):
            if ability.get("activate_only_as_sorcery") and phase not in MAIN_PHASES:
                continue
            if ability.get("activation_requires_tap") and permanent.get("tapped"):
                emit_replay_event(
                    "activated_ability_skipped",
                    player=player.name,
                    card=permanent.get("name", "?"),
                    effect="copy_creature_token",
                    reason="source_already_tapped",
                    turn=turn,
                    phase=phase,
                    **replay_rule_fields(ability),
                )
                continue
            if not activated_copy_creature_token_station_ready(permanent, ability):
                emit_replay_event(
                    "activated_ability_skipped",
                    player=player.name,
                    card=permanent.get("name", "?"),
                    effect="copy_creature_token",
                    reason="station_level_required",
                    station_level_required=ability.get("station_level_required"),
                    station_level=int(permanent.get("charge_counters") or permanent.get("station_level") or 0),
                    turn=turn,
                    phase=phase,
                    **replay_rule_fields(ability),
                )
                continue
            targets = copy_token_target_candidates(player, opponents or [], ability)
            if ability.get("exclude_source_from_copy_targets"):
                targets = [target for target in targets if target is not permanent]
            if not targets:
                emit_replay_event(
                    "activated_ability_skipped",
                    player=player.name,
                    card=permanent.get("name", "?"),
                    effect="copy_creature_token",
                    reason="no_valid_copy_target",
                    turn=turn,
                    phase=phase,
                    **replay_rule_fields(ability),
                )
                continue
            activation_cost = activation_cost_text_for_effect(ability)
            if not player.can_pay(activation_cost) or not player.spend_mana(activation_cost):
                emit_replay_event(
                    "activated_ability_skipped",
                    player=player.name,
                    card=permanent.get("name", "?"),
                    effect="copy_creature_token",
                    reason="failed_to_pay_activation_cost",
                    activation_cost=activation_cost,
                    turn=turn,
                    phase=phase,
                    **replay_rule_fields(ability),
                )
                continue
            if ability.get("activation_requires_tap"):
                permanent["tapped"] = True
            permanent["_activated_copy_creature_token_last_turn"] = turn
            created = resolve_copy_creature_token(
                player,
                permanent,
                ability,
                turn,
                opponents=opponents,
                finish_spell=False,
            )
            emit_replay_event(
                "activated_ability_resolved",
                player=player.name,
                card=permanent.get("name", "?"),
                ability="copy_creature_token",
                activation_cost=activation_cost,
                tokens_created=len(created or []),
                turn=turn,
                phase=phase,
                **replay_rule_fields(ability),
            )
            activations += 1
            break
    return activations


def activate_blink_abilities(player, opponents, all_players, turn, rng, *, phase="precombat_main"):
    if phase not in MAIN_PHASES:
        return 0
    activations = 0
    for permanent in list(getattr(player, "battlefield", []) or []):
        if not isinstance(permanent, dict):
            continue
        if not permanent.get("activated_blink"):
            continue
        if permanent.get("_activated_blink_last_turn") == turn:
            continue
        if permanent.get("activation_requires_tap") and permanent.get("tapped"):
            emit_replay_event(
                "activated_ability_skipped",
                player=player.name,
                card=permanent.get("name", "?"),
                effect="blink",
                reason="source_already_tapped",
                turn=turn,
                phase=phase,
                **replay_rule_fields(permanent),
            )
            continue
        target, target_score = choose_blink_target(
            player,
            permanent,
            source_permanent=permanent,
        )
        if target is None:
            emit_replay_event(
                "activated_ability_skipped",
                player=player.name,
                card=permanent.get("name", "?"),
                effect="blink",
                reason="no_valid_blink_target",
                turn=turn,
                phase=phase,
                **replay_rule_fields(permanent),
            )
            continue
        activation_cost = activation_cost_text_for_effect(permanent)
        if not player.can_pay(activation_cost) or not player.spend_mana(activation_cost):
            emit_replay_event(
                "activated_ability_skipped",
                player=player.name,
                card=permanent.get("name", "?"),
                effect="blink",
                reason="failed_to_pay_activation_cost",
                activation_cost=activation_cost,
                turn=turn,
                phase=phase,
                **replay_rule_fields(permanent),
            )
            continue
        if permanent.get("activation_requires_tap"):
            permanent["tapped"] = True
        permanent["_activated_blink_last_turn"] = turn
        returned = resolve_blink_permanent(
            player,
            opponents,
            permanent,
            permanent,
            target,
            turn,
            rng,
            all_players=all_players,
            phase=phase,
        )
        emit_replay_event(
            "activated_ability_resolved",
            player=player.name,
            card=permanent.get("name", "?"),
            ability="blink",
            activation_cost=activation_cost,
            blinked=target.get("name", "?"),
            returned=returned.get("name", "?") if isinstance(returned, dict) else None,
            target_score=target_score,
            turn=turn,
            phase=phase,
            **replay_rule_fields(permanent),
        )
        activations += 1
    return activations


def process_precombat_main_phase_engines(player, opponents, all_players, turn, rng, *, stack=None):
    activate_blink_abilities(
        player,
        opponents,
        all_players,
        turn,
        rng,
        phase="precombat_main",
    )
    activate_secondary_copy_creature_token_abilities(
        player,
        opponents,
        turn,
        phase="precombat_main",
    )
    for permanent in list(getattr(player, "battlefield", []) or []):
        if not isinstance(permanent, dict):
            continue
        if not permanent.get("precombat_main_choose_modes_treasure_draw_token_life_loss"):
            continue
        if permanent.get("precombat_main_last_trigger_turn") == turn:
            continue
        permanent["precombat_main_last_trigger_turn"] = turn
        life_floor = int(permanent.get("mode_selection_life_floor") or 4)
        modes = list(permanent.get("precombat_main_modes") or [])
        selected_modes = []
        total_life_loss = 0
        for mode in modes:
            life_loss = int(mode.get("life_loss") or 0)
            if player.life - (total_life_loss + life_loss) >= life_floor:
                selected_modes.append(mode)
                total_life_loss += life_loss
        if not selected_modes and modes:
            selected_modes = [modes[0]]

        life_before = player.life
        treasures_before = player.treasures
        cards_drawn = 0
        tokens_created = 0
        selected_names = []
        for mode in selected_modes:
            selected_names.append(mode.get("name") or mode.get("effect") or "mode")
            mode_effect = mode.get("effect")
            if mode_effect == "create_treasure":
                player.treasures += int(mode.get("treasure_count") or 1)
            elif mode_effect == "draw_cards":
                drawn = player.draw(int(mode.get("draw_cards") or 1), rng)
                cards_drawn += len(drawn)
                process_player_draw_triggers(
                    player,
                    len(drawn),
                    turn,
                    "precombat_main",
                    all_players,
                    stack=stack,
                    turn_player=player,
                )
            elif mode_effect == "token_maker":
                token_fields = dict(permanent)
                token_fields.update(mode.get("token") or {})
                tokens_created += create_creature_tokens_from_effect(
                    player,
                    token_fields,
                    count=int(mode.get("token_count") or token_fields.get("token_count") or 1),
                    opponents=opponents,
                    turn=turn,
                    source_event="phase_trigger_token_created",
                    stack=stack,
                    active_player=player,
                    all_players=all_players,
                )
            life_loss = int(mode.get("life_loss") or 0)
            if life_loss > 0:
                change_life(player, -life_loss)

        emit_replay_event(
            "phase_trigger_resolved",
            player=player.name,
            card=permanent.get("name", "?"),
            trigger="beginning_precombat_main",
            effect="modal_resources",
            selected_modes=selected_names,
            mode_selection_model=permanent.get(
                "mode_selection_model",
                "all_modes_if_life_after_loss_at_least_floor",
            ),
            mode_selection_life_floor=life_floor,
            life_lost=max(0, life_before - player.life),
            life_before=life_before,
            life_after=player.life,
            treasures_created=max(0, player.treasures - treasures_before),
            treasures_before=treasures_before,
            treasures_after=player.treasures,
            cards_drawn=cards_drawn,
            tokens_created=tokens_created,
            turn=turn,
            phase="precombat_main",
            **replay_rule_fields(permanent),
        )
    for permanent in list(getattr(player, "battlefield", []) or []):
        if not isinstance(permanent, dict):
            continue
        if not permanent.get("activated_copy_target_another_nonlegendary_creature_you_control"):
            continue
        if permanent.get("activated_copy_last_turn") == turn:
            continue
        if permanent.get("tapped"):
            continue
        activation_cost = int(permanent.get("activation_cost_generic") or 1)
        if activation_cost > 0 and not player.can_pay(str(activation_cost)):
            continue
        if activation_cost > 0:
            player.spend_mana(str(activation_cost))
        permanent["tapped"] = True
        permanent["activated_copy_last_turn"] = turn
        created = resolve_copy_creature_token(
            player,
            permanent,
            permanent,
            turn,
            opponents=opponents,
            finish_spell=False,
        )
        emit_replay_event(
            "activated_ability_resolved",
            player=player.name,
            card=permanent.get("name", "?"),
            ability="copy_target_another_nonlegendary_creature_you_control",
            activation_cost_generic=activation_cost,
            tapped=True,
            tokens_created=len(created or []),
            turn=turn,
            phase="precombat_main",
            **replay_rule_fields(permanent),
        )
    for permanent in list(getattr(player, "battlefield", []) or []):
        if not isinstance(permanent, dict):
            continue
        if permanent.get("effect") != "creature":
            continue
        draw_count = int(permanent.get("activated_multiplayer_discard_draw_count") or 0)
        if draw_count <= 0:
            continue
        if permanent.get("summoning_sick"):
            emit_replay_event(
                "activated_ability_skipped",
                player=player.name,
                card=permanent.get("name", "?"),
                effect="creature",
                reason="summoning_sick",
                activation_kind="multiplayer_discard_draw",
                turn=turn,
                phase="precombat_main",
                **replay_rule_fields(permanent),
            )
            continue
        if permanent.get("activation_requires_tap") and permanent.get("tapped"):
            emit_replay_event(
                "activated_ability_skipped",
                player=player.name,
                card=permanent.get("name", "?"),
                effect="creature",
                reason="source_already_tapped",
                activation_kind="multiplayer_discard_draw",
                turn=turn,
                phase="precombat_main",
                **replay_rule_fields(permanent),
            )
            continue

        activation_colors = list(permanent.get("activation_cost_colors") or [])
        activation_cost_generic = adjusted_activated_ability_generic_cost(
            player,
            permanent,
            int(permanent.get("activation_cost_generic") or 0),
            activation_colors=activation_colors,
        )
        activation_cost_text = ""
        if activation_cost_generic > 0:
            activation_cost_text += "{%d}" % activation_cost_generic
        activation_cost_text += "".join("{%s}" % color for color in activation_colors)
        if not activation_cost_text:
            activation_cost_text = "{0}"

        context = wheel_decision_context(player, opponents, draw_count, permanent)
        if not context["library_can_support_draw"]:
            emit_replay_event(
                "activated_ability_skipped",
                player=player.name,
                card=permanent.get("name", "?"),
                effect="creature",
                reason="insufficient_library_for_wheel",
                activation_kind="multiplayer_discard_draw",
                draw_count=draw_count,
                turn=turn,
                phase="precombat_main",
                **replay_rule_fields(permanent),
            )
            continue
        if not context["timing_justified"]:
            emit_replay_event(
                "activated_ability_skipped",
                player=player.name,
                card=permanent.get("name", "?"),
                effect="creature",
                reason="wheel_strategic_guardrail",
                activation_kind="multiplayer_discard_draw",
                draw_count=draw_count,
                hand_size_before=context["hand_size_before"],
                total_opponent_net_cards=context["total_opponent_net_cards"],
                opponent_refill_risk=context["opponent_refill_risk"],
                turn=turn,
                phase="precombat_main",
                **replay_rule_fields(permanent),
            )
            continue
        if not player.can_pay(activation_cost_text) or not player.spend_mana(activation_cost_text):
            emit_replay_event(
                "activated_ability_skipped",
                player=player.name,
                card=permanent.get("name", "?"),
                effect="creature",
                reason="failed_to_pay_activation_cost",
                activation_kind="multiplayer_discard_draw",
                activation_cost=activation_cost_text,
                turn=turn,
                phase="precombat_main",
                **replay_rule_fields(permanent),
            )
            continue

        hand_before = len(player.hand)
        if permanent.get("activation_requires_tap"):
            permanent["tapped"] = True
        if permanent in player.battlefield:
            player.battlefield.remove(permanent)
        player.graveyard.append(permanent)
        activation_score = max(
            0,
            context["net_cards_for_player"] * 10 - context["total_opponent_net_cards"] * 4,
        )
        emit_decision_trace(
            decision_type="utility_creature_activation",
            player=player,
            turn=turn,
            phase="precombat_main",
            available_options=[
                decision_card_option(
                    permanent,
                    action="activate_multiplayer_discard_draw",
                    effect="creature",
                    score=activation_score,
                ),
                decision_card_option(
                    permanent,
                    action="defer_multiplayer_discard_draw",
                    effect="creature",
                    score=0,
                ),
            ],
            chosen_option=decision_card_option(
                permanent,
                action="activate_multiplayer_discard_draw",
                effect="creature",
                score=activation_score,
            ),
            rejected_options=[
                decision_card_option(
                    permanent,
                    action="defer_multiplayer_discard_draw",
                    effect="creature",
                    score=0,
                )
            ],
            score_components={
                "activation_cost_generic": activation_cost_generic,
                "activation_cost_colors": activation_colors,
                **context,
            },
            rule_source="utility_creature_activation_v1",
            rule_status=permanent.get("_rule_review_status", "active"),
            confidence="medium",
            expected_benefit_score=activation_score,
            reason="convert_low_value_hand_into_wheel_refill_before_spell_casts",
            strategic_principle="use precombat wheel only when the refill clearly improves your hand relative to the table",
            heuristic_version=DECISION_STRATEGY_VERSION,
            resource_delta={
                "mana": -(activation_cost_generic + len(activation_colors)),
                "cards_expected": draw_count,
                "sacrificed_source": permanent.get("name", "?"),
            },
            risk_flags=["tap_creature", "sacrifice_creature", *([] if context["payoff_expected"] else ["opponent_refill"])],
            rejected_reason="lower_expected_refill_value_than_activate",
        )
        resolve_wheel_like_draw(
            player,
            opponents,
            permanent,
            draw_count,
            turn,
            rng,
            permanent,
        )
        emit_replay_event(
            "activated_ability",
            player=player.name,
            card=permanent.get("name", "?"),
            effect="creature",
            activation_kind="tap_sacrifice_multiplayer_discard_draw",
            activation_cost=activation_cost_text,
            draw_count=draw_count,
            hand_before=hand_before,
            hand_after=len(player.hand),
            turn=turn,
            phase="precombat_main",
            **replay_rule_fields(permanent),
        )


def process_postcombat_main_phase_engines(player, opponents, all_players, turn, rng=None, *, stack=None):
    if not player.is_alive():
        return 0

    triggers = 0
    for permanent in list(getattr(player, "battlefield", []) or []):
        if not isinstance(permanent, dict):
            continue
        if permanent.get("effect") != "ramp_engine":
            continue
        if permanent.get("trigger") != "beginning_postcombat_main":
            continue
        if not permanent.get("postcombat_main_add_red_for_opponents_life_lost_this_turn"):
            continue
        if permanent.get("postcombat_main_last_trigger_turn") == turn:
            continue
        permanent["postcombat_main_last_trigger_turn"] = turn

        def resolve_postcombat_life_lost_mana(permanent=permanent):
            live_opponents = [
                opponent
                for opponent in (opponents or [])
                if opponent is not player and getattr(opponent, "is_alive", lambda: True)()
            ]
            opponent_life_lost = sum(
                opponent.life_lost_this_turn_count(turn)
                for opponent in live_opponents
                if hasattr(opponent, "life_lost_this_turn_count")
            )
            mana_per_life = max(0, int(permanent.get("mana_added_per_opponent_life_lost") or 1))
            mana_added = max(0, opponent_life_lost * mana_per_life)
            mana_color = str(permanent.get("mana_color") or "red").lower()
            mana_before = player.mana_pool.snapshot()
            if mana_added > 0:
                player.mana_pool.add(mana_color, mana_added)
            emit_replay_event(
                "phase_trigger_resolved",
                player=player.name,
                card=permanent.get("name", "?"),
                trigger="beginning_postcombat_main",
                effect="add_mana",
                mana_added=mana_added,
                mana_color=mana_color,
                mana_per_opponent_life_lost=mana_per_life,
                opponents_life_lost_this_turn=opponent_life_lost,
                mana_pool_before=mana_before,
                mana_pool_after=player.mana_pool.snapshot(),
                turn=turn,
                phase="postcombat_main",
                **replay_rule_fields(permanent),
            )

        resolve_or_enqueue_trigger(
            player,
            permanent,
            "beginning_postcombat_main",
            resolve_postcombat_life_lost_mana,
            stack=stack,
            active_player=player if stack is not None else None,
            all_players=all_players,
            data=replay_rule_fields(permanent),
        )
        triggers += 1
    return triggers


def end_step_draw_controlled_creature_total_power(controller):
    total = 0
    for permanent in getattr(controller, "battlefield", []) or []:
        if isinstance(permanent, dict) and is_battlefield_creature(permanent):
            total += card_power_value(permanent, default=0)
    return total


def end_step_draw_controller_untapped_lands(controller):
    lands = []
    for permanent in getattr(controller, "battlefield", []) or []:
        if not isinstance(permanent, dict):
            continue
        type_line = str(permanent.get("type_line") or "").lower()
        if "land" in type_line and not bool(permanent.get("tapped")):
            lands.append(permanent)
    return lands


def end_step_draw_condition_satisfied(controller, active_player, all_players, permanent, turn):
    condition = str(permanent.get("end_step_draw_condition") or "").strip()
    threshold = int(permanent.get("end_step_draw_condition_threshold") or 0)
    participants = [p for p in (all_players or []) if getattr(p, "is_alive", lambda: True)()]
    opponents = _live_opponents_for(controller, participants)
    if condition == "creature_died_this_turn":
        count = sum(
            participant.creatures_died_this_turn_count(turn)
            if hasattr(participant, "creatures_died_this_turn_count")
            else int(getattr(participant, "creatures_died_this_turn", 0) or 0)
            for participant in participants
        )
        return count > 0, {"creatures_died_this_turn": count}
    if condition == "controller_did_not_play_land_this_turn":
        lands_played = int(getattr(controller, "lands_played_this_turn", 0) or 0)
        return lands_played <= 0, {"lands_played_this_turn": lands_played}
    if condition == "controlled_creatures_total_power_gte":
        threshold = threshold or 8
        total_power = end_step_draw_controlled_creature_total_power(controller)
        return total_power >= threshold, {
            "controlled_creatures_total_power": total_power,
            "end_step_draw_condition_threshold": threshold,
        }
    if condition == "opponent_lost_life_gte":
        threshold = threshold or 3
        qualified = [
            opponent.name
            for opponent in opponents
            if (
                opponent.life_lost_this_turn_count(turn)
                if hasattr(opponent, "life_lost_this_turn_count")
                else int(getattr(opponent, "life_lost_this_turn", 0) or 0)
            )
            >= threshold
        ]
        return bool(qualified), {
            "qualified_opponents": qualified,
            "end_step_draw_condition_threshold": threshold,
        }
    if condition == "controller_gained_life_gte":
        threshold = threshold or 3
        gained = (
            controller.life_gained_this_turn_count(turn)
            if hasattr(controller, "life_gained_this_turn_count")
            else int(getattr(controller, "life_gained_this_turn", 0) or 0)
        )
        return gained >= threshold, {
            "controller_life_gained_this_turn": gained,
            "end_step_draw_condition_threshold": threshold,
        }
    if condition == "controller_controls_no_untapped_lands":
        lands = end_step_draw_controller_untapped_lands(controller)
        return len(lands) == 0, {
            "untapped_lands_controlled": [land.get("name", "?") for land in lands],
        }
    return False, {"unsupported_end_step_draw_condition": condition}


def process_end_step_phase_engines(active_player, all_players, turn, rng, *, stack=None):
    participants = [p for p in (all_players or []) if getattr(p, "is_alive", lambda: True)()]
    for controller in participants:
        controller_opponents = _live_opponents_for(controller, participants)
        for permanent in list(getattr(controller, "battlefield", []) or []):
            if not isinstance(permanent, dict):
                continue
            if (
                permanent.get("trigger_effect") == "draw_cards"
                and permanent.get("end_step_draw_condition_status") == "runtime_executor_v1"
                and permanent.get("trigger") in {"controller_end_step", "each_end_step"}
            ):
                trigger = str(permanent.get("trigger") or "controller_end_step")
                if trigger == "controller_end_step" and controller is not active_player:
                    continue
                trigger_key = (
                    "controller_end_step"
                    if trigger == "controller_end_step"
                    else "each_end_step"
                )
                last_turn_key = f"{trigger_key}_draw_last_trigger_turn"
                last_player_key = f"{trigger_key}_draw_last_trigger_player"
                if (
                    permanent.get(last_turn_key) == turn
                    and permanent.get(last_player_key) == active_player.name
                ):
                    continue
                permanent[last_turn_key] = turn
                permanent[last_player_key] = active_player.name
                condition_met, condition_details = end_step_draw_condition_satisfied(
                    controller,
                    active_player,
                    participants,
                    permanent,
                    turn,
                )
                if not condition_met:
                    emit_replay_event(
                        "trigger_skipped",
                        player=controller.name,
                        card=permanent.get("name", "?"),
                        trigger=trigger,
                        active_player=active_player.name,
                        effect="draw_cards",
                        reason="end_step_draw_condition_not_met",
                        end_step_draw_condition=permanent.get("end_step_draw_condition"),
                        turn=turn,
                        phase="end_step",
                        **condition_details,
                        **replay_rule_fields(permanent),
                    )
                    continue
                draw_count = max(0, int(permanent.get("end_step_draw_count") or 0))
                if draw_count <= 0:
                    continue
                library_before = len(getattr(controller, "library", []) or [])
                drawn = controller.draw(draw_count, rng, phase="end_step")
                process_player_draw_triggers(
                    controller,
                    len(drawn),
                    turn,
                    "end_step",
                    participants,
                    stack=stack,
                    turn_player=active_player,
                )
                emit_replay_event(
                    "phase_trigger_resolved",
                    player=controller.name,
                    card=permanent.get("name", "?"),
                    trigger=trigger,
                    active_player=active_player.name,
                    effect="draw_cards",
                    cards_drawn=len(drawn),
                    requested_draw_count=draw_count,
                    library_before=library_before,
                    library_after=len(getattr(controller, "library", []) or []),
                    end_step_draw_optional=bool(permanent.get("end_step_draw_optional")),
                    end_step_draw_condition=permanent.get("end_step_draw_condition"),
                    turn=turn,
                    phase="end_step",
                    **condition_details,
                    **replay_rule_fields(permanent),
                )
                continue
            if permanent.get("each_end_step_opponent_extra_draw_land_treasure"):
                if (
                    permanent.get("each_end_step_last_trigger_turn") == turn
                    and permanent.get("each_end_step_last_trigger_player") == active_player.name
                ):
                    continue
                permanent["each_end_step_last_trigger_turn"] = turn
                permanent["each_end_step_last_trigger_player"] = active_player.name
                draw_qualifiers = [
                    opponent
                    for opponent in controller_opponents
                    if int(getattr(opponent, "cards_drawn_this_turn", 0) or 0)
                    >= int(permanent.get("opponent_cards_drawn_threshold") or 2)
                ]
                land_qualifiers = [
                    opponent
                    for opponent in controller_opponents
                    if int(getattr(opponent, "lands_played_this_turn", 0) or 0)
                    >= int(permanent.get("opponent_lands_entered_threshold") or 2)
                ]
                cards_to_draw = len(draw_qualifiers) * int(permanent.get("draw_cards_per_qualified_opponent") or 1)
                treasure_count = len(land_qualifiers) * int(permanent.get("treasure_count_per_qualified_opponent") or 1)
                if cards_to_draw <= 0 and treasure_count <= 0:
                    continue
                treasures_before = controller.treasures
                drawn = controller.draw(cards_to_draw, rng)
                process_player_draw_triggers(
                    controller,
                    len(drawn),
                    turn,
                    "end_step",
                    participants,
                    stack=stack,
                    turn_player=active_player,
                )
                controller.treasures += max(0, treasure_count)
                emit_replay_event(
                    "phase_trigger_resolved",
                    player=controller.name,
                    card=permanent.get("name", "?"),
                    trigger="each_end_step",
                    active_player=active_player.name,
                    effect="draw_cards_create_treasure",
                    cards_drawn=len(drawn),
                    draw_qualified_opponents=[opponent.name for opponent in draw_qualifiers],
                    treasures_created=max(0, treasure_count),
                    treasure_qualified_opponents=[opponent.name for opponent in land_qualifiers],
                    treasures_before=treasures_before,
                    treasures_after=controller.treasures,
                    turn=turn,
                    phase="end_step",
                    **replay_rule_fields(permanent),
                )
                continue

            if (
                permanent.get("controller_end_step_opponent_lost_life_dalek_villainous_choice")
                and controller is active_player
            ):
                if permanent.get("controller_end_step_last_trigger_turn") == turn:
                    continue
                permanent["controller_end_step_last_trigger_turn"] = turn
                threshold = int(permanent.get("opponent_life_lost_threshold") or 3)
                qualified = [
                    opponent
                    for opponent in controller_opponents
                    if opponent.life_lost_this_turn_count(turn) >= threshold
                ]
                if not qualified:
                    continue
                tokens_created = create_creature_tokens_from_effect(
                    controller,
                    permanent,
                    count=int(permanent.get("token_count") or 1),
                    opponents=controller_opponents,
                    turn=turn,
                    source_event="phase_trigger_token_created",
                    stack=stack,
                    active_player=active_player,
                    all_players=participants,
                )
                choices = []
                controller_drawn = 0
                for opponent in qualified:
                    if opponent.hand:
                        discarded = [opponent.hand.pop(0)]
                        opponent.graveyard.extend(discarded)
                        process_player_discard_triggers(
                            opponent,
                            discarded,
                            opponents=[candidate for candidate in participants if candidate is not opponent],
                            turn=turn,
                            phase="end_step",
                            rng=rng,
                        )
                        choices.append({
                            "opponent": opponent.name,
                            "choice": "discard_card",
                            "discarded": discarded[0].get("name", "?"),
                        })
                    else:
                        drawn = controller.draw(1, rng)
                        controller_drawn += len(drawn)
                        process_player_draw_triggers(
                            controller,
                            len(drawn),
                            turn,
                            "end_step",
                            participants,
                            stack=stack,
                            turn_player=active_player,
                        )
                        choices.append({
                            "opponent": opponent.name,
                            "choice": "controller_draws_card",
                            "cards_drawn": len(drawn),
                        })
                emit_replay_event(
                    "phase_trigger_resolved",
                    player=controller.name,
                    card=permanent.get("name", "?"),
                    trigger="controller_end_step",
                    effect="dalek_token_villainous_choice",
                    qualified_opponents=[opponent.name for opponent in qualified],
                    opponent_life_lost_threshold=threshold,
                    tokens_created=tokens_created,
                    villainous_choices=choices,
                    controller_cards_drawn=controller_drawn,
                    turn=turn,
                    phase="end_step",
                    **replay_rule_fields(permanent),
                )
                continue

            if (
                permanent.get("trigger") == "controller_end_step"
                and permanent.get("trigger_effect")
                == "add_named_counter_scry_target_opponent_may_draw_else_mill_life_loss"
                and controller is active_player
            ):
                if permanent.get("controller_end_step_last_trigger_turn") == turn:
                    continue
                permanent["controller_end_step_last_trigger_turn"] = turn
                if not controller_opponents:
                    continue

                counter_type = str(permanent.get("trigger_counter_type") or "influence")
                counters_added = add_named_counters(
                    permanent,
                    counter_type,
                    int(permanent.get("trigger_counter_count") or 1),
                )
                total_counters = get_named_counter_count(permanent, counter_type)
                scry_result = scry_library_for_controller(
                    controller,
                    int(permanent.get("trigger_scry_count") or 0),
                )
                target_opponent = min(
                    controller_opponents,
                    key=lambda opponent: (opponent.life, opponent.name),
                )
                mill_count = total_counters
                projected_mill_cards = list(controller.library[:mill_count])
                projected_life_loss = sum(card_mana_value(card) for card in projected_mill_cards)
                draw_count = int(permanent.get("target_opponent_may_have_you_draw_count") or 1)
                draw_threshold = min(5, max(1, target_opponent.life))
                allow_draw = projected_life_loss >= draw_threshold
                milled = []
                cards_drawn = 0
                life_lost = 0

                if allow_draw:
                    drawn = controller.draw(draw_count, rng)
                    cards_drawn = len(drawn)
                    process_player_draw_triggers(
                        controller,
                        cards_drawn,
                        turn,
                        "end_step",
                        participants,
                        stack=stack,
                        turn_player=active_player,
                    )
                else:
                    library_before = len(controller.library)
                    for _ in range(min(mill_count, len(controller.library))):
                        milled_card = controller.library.pop(0)
                        controller.graveyard.append(milled_card)
                        milled.append(milled_card)
                    life_lost = sum(card_mana_value(card) for card in milled)
                    if milled:
                        emit_replay_event(
                            "mill_resolved",
                            player=controller.name,
                            card=permanent.get("name", "?"),
                            target_player=controller.name,
                            requested_mill=mill_count,
                            cards_milled=len(milled),
                            milled=[
                                milled_card.get("name", "?")
                                for milled_card in milled
                                if isinstance(milled_card, dict)
                            ][:12],
                            target_library_before=library_before,
                            target_library_after=len(controller.library),
                            turn=turn,
                            **replay_rule_fields(permanent),
                        )
                    if life_lost > 0:
                        change_life(target_opponent, -life_lost)

                emit_replay_event(
                    "phase_trigger_resolved",
                    player=controller.name,
                    card=permanent.get("name", "?"),
                    trigger="controller_end_step",
                    active_player=active_player.name,
                    effect="add_counter_scry_target_opponent_draw_or_mill_life_loss",
                    counter_type=counter_type,
                    counters_added=counters_added,
                    total_counters=total_counters,
                    scry_count=int(permanent.get("trigger_scry_count") or 0),
                    scry_looked_at=scry_result["looked_at"],
                    scry_kept_on_top=scry_result["kept_on_top"],
                    scry_bottomed=scry_result["bottomed"],
                    scry_top_after=scry_result["top_after"],
                    target_opponent=target_opponent.name,
                    opponent_choice="allow_draw" if allow_draw else "decline_draw",
                    cards_drawn=cards_drawn,
                    mill_count=mill_count,
                    milled_cards=[
                        milled_card.get("name", "?")
                        for milled_card in milled
                        if isinstance(milled_card, dict)
                    ],
                    projected_life_loss=projected_life_loss,
                    life_lost=life_lost,
                    turn=turn,
                    phase="end_step",
                    **replay_rule_fields(permanent),
                )


def normalize_ward_payment_cost(raw_cost):
    if raw_cost is None or raw_cost is False:
        return None
    if isinstance(raw_cost, (int, float)):
        cost = int(raw_cost)
        if cost <= 0:
            return None
        return {"payment_cost": cost, "mana_value": cost, "raw_cost": raw_cost}
    text = str(raw_cost).strip()
    if not text or text.lower() in ("0", "false", "none", "no", "no ward"):
        return None
    if re.fullmatch(r"\d+", text):
        cost = int(text)
        if cost <= 0:
            return None
        return {"payment_cost": cost, "mana_value": cost, "raw_cost": raw_cost}

    parsed = parse_mana_cost(text, 0)
    mana_value = int(parsed.get("generic", 0) or 0)
    mana_value += sum(int(value or 0) for value in parsed.get("colored", {}).values())
    mana_value += len(parsed.get("hybrid", []) or [])
    mana_value += len(parsed.get("phyrexian", []) or [])
    mana_value += len(parsed.get("phyrexian_hybrid", []) or [])
    mana_value += sum(
        int(option.get("generic", 2) or 2)
        for option in parsed.get("monocolored_hybrid", []) or []
    )
    if mana_value <= 0:
        return {"payment_cost": None, "mana_value": 0, "raw_cost": raw_cost, "unsupported": True}
    return {"payment_cost": text, "mana_value": mana_value, "raw_cost": raw_cost}




def check_ward(target, spell, controller, rng):
    """v9: Ward triggered ability (CR 702.21a).
    If target has ward, spell is countered unless controller pays cost."""
    ward_payment = normalize_ward_payment_cost(target.get("ward_cost") or target.get("ward", 0))
    if not ward_payment:
        return False  # No ward
    ward_cost = ward_payment.get("payment_cost")
    ward_mana_value = int(ward_payment.get("mana_value", 0) or 0)
    if ward_payment.get("unsupported") or ward_cost is None:
        emit_replay_event(
            "ward_cost_unmodeled",
            target=target.get("name"),
            spell=spell.get("name"),
            ward_cost=ward_payment.get("raw_cost"),
        )
        return False

    # Ward triggers: AI opponent pays 50% of the time if affordable
    can_pay = controller.can_pay(ward_cost)
    if not can_pay:
        # Counter the spell (ward resolved)
        emit_replay_event("ward_countered", target=target.get("name"),
                         spell=spell.get("name"), ward_cost=ward_cost, ward_mana_value=ward_mana_value)
        return True  # Spell is countered

    # Decision: pay or let it be countered
    if controller.is_human or rng.random() < 0.5:
        # Pay ward cost
        controller.spend_mana(ward_cost)
        emit_replay_event("ward_paid", target=target.get("name"),
                         spell=spell.get("name"), ward_cost=ward_cost, ward_mana_value=ward_mana_value)
        return False  # Ward paid, spell proceeds
    else:
        emit_replay_event("ward_countered", target=target.get("name"),
                         spell=spell.get("name"), ward_cost=ward_cost, ward_mana_value=ward_mana_value)
        return True  # Spell countered by ward


def can_cast_adventure_spell(card, player, phase):
    if not is_adventure_card(card):
        return False
    adventure = adventure_spell_card(card)
    if not is_instant(adventure) and not (is_sorcery(adventure) and phase in MAIN_PHASES):
        return False
    return player.can_pay_card(adventure)


def cast_adventure_spell_from_hand(player, card, opponents, all_players, turn, phase, stack, rng):
    if not can_cast_adventure_spell(card, player, phase):
        return False
    adventure = adventure_spell_card(card)
    effect_data = get_card_effect(adventure)
    if effect_data.get("effect") in ("unknown", "land", "creature"):
        return False
    cast_ctx = begin_cast_context(
        player,
        adventure,
        phase,
        effect_data=effect_data,
        role="adventure",
        modes=["adventure"],
    )
    if not commit_cast_payment(cast_ctx):
        return False
    player.hand.remove(card)
    emit_replay_event(
        "adventure_cast",
        player=player.name,
        card=card.get("name", "?"),
        adventure=adventure.get("name", "?"),
        effect=effect_data.get("effect", "unknown"),
        type_line=adventure.get("type_line", ""),
        turn=turn,
        phase=phase,
        **cast_ctx.to_replay_fields(),
        **replay_rule_fields(effect_data),
    )
    mark_cast_ledger_emitted(effect_data)
    trigger_spell_cast_engines(
        player, all_players, adventure, turn, phase, stack=stack, active_player=player
    )
    trigger_opponent_spell_draw_engines(
        player,
        opponents,
        adventure,
        turn,
        phase,
        rng,
        stack=stack,
        active_player=player,
        all_players=all_players,
    )
    stack.push(adventure, player, effect_data)
    return True


def cast_adventure_creature_from_exile(player, card, turn, phase):
    if phase not in MAIN_PHASES or not isinstance(card, dict) or not card.get("_adventure_available"):
        return False
    if non_hand_cast_locked(player, turn=turn):
        return False
    if not is_creature_card(card) or not player.can_pay_card(card):
        return False
    effect_data = get_card_effect(card)
    cast_ctx = begin_cast_context(
        player,
        card,
        phase,
        effect_data=effect_data,
        role="adventure_creature",
        modes=["creature_from_exile"],
    )
    if not commit_cast_payment(cast_ctx):
        return False
    player.exile.remove(card)
    permanent = enrich_card({**card, **effect_data})
    permanent.pop("_adventure_available", None)
    permanent.pop("_last_adventure_name", None)
    permanent["effect"] = "creature"
    permanent["haste"] = has_haste(permanent)
    permanent["summoning_sick"] = not permanent["haste"]
    permanent["tapped"] = False
    player.battlefield.append(permanent)
    emit_replay_event(
        "adventure_creature_cast_from_exile",
        player=player.name,
        card=card.get("name", "?"),
        type_line=permanent.get("type_line", ""),
        turn=turn,
        phase=phase,
        **cast_ctx.to_replay_fields(),
        **replay_rule_fields(effect_data),
    )
    return True


TOP_LIBRARY_SMALL_CREATURE_CAST_SCOPE = (
    "top_library_look_any_time_cast_creature_power_2_or_less_once_each_turn_pay_cost_v1"
)


def top_library_small_creature_permission_effect(permanent):
    if not isinstance(permanent, dict):
        return None
    effect_data = permanent if permanent.get("battle_model_scope") else get_card_effect(permanent)
    if not effect_data.get("top_library_cast_once_each_turn"):
        return None
    if effect_data.get("battle_model_scope") != TOP_LIBRARY_SMALL_CREATURE_CAST_SCOPE:
        return None
    cast_types = {
        str(card_type or "").strip().lower()
        for card_type in (effect_data.get("top_library_cast_card_types") or ["creature"])
    }
    if "creature" not in cast_types:
        return None
    return effect_data


def top_library_small_creature_cast_candidate(player, phase, turn):
    if phase not in MAIN_PHASES or not getattr(player, "library", None):
        return None
    top_card = player.library[0]
    if not isinstance(top_card, dict) or not is_creature_card(top_card):
        return None
    top_effect = get_card_effect(top_card)
    if top_effect.get("effect") == "unknown":
        top_effect = {**top_effect, "effect": "creature"}
    power = card_power_value(top_card, default=card_power_value(top_effect, default=999))
    for permanent in list(getattr(player, "battlefield", []) or []):
        permission_effect = top_library_small_creature_permission_effect(permanent)
        if not permission_effect:
            continue
        if permanent.get("top_library_small_creature_cast_last_turn") == turn:
            continue
        power_max = int(permission_effect.get("top_library_cast_power_max") or 2)
        if power > power_max:
            continue
        if not can_cast_in_phase(top_card, top_effect, phase, controller=player):
            continue
        cast_plan = runtime_cast_plan_for_card(player, top_card, top_effect)
        if cast_plan is None:
            continue
        return {
            "source": permanent,
            "source_effect": permission_effect,
            "card": top_card,
            "effect": top_effect,
            "power": power,
            "power_max": power_max,
            "cast_plan": cast_plan,
        }
    return None


def cast_top_library_small_creature_from_static_permission(
    player,
    opponents,
    all_players,
    turn,
    phase,
    stack,
    rng,
):
    candidate = top_library_small_creature_cast_candidate(player, phase, turn)
    if not candidate:
        return False
    source = candidate["source"]
    source_effect = candidate["source_effect"]
    card = candidate["card"]
    effect_data = candidate["effect"]
    cast_plan = candidate["cast_plan"]
    mana_before = player.available_mana()
    cast_ctx = begin_cast_context(
        player,
        card,
        phase,
        effect_data=effect_data,
        role="top_library_small_creature_static_permission",
        modes=["top_library_static_permission", "pay_mana_cost"],
        source_zone="library",
        x_value=cast_plan.get("x_value", 0),
        additional_costs=cast_plan.get("additional_costs"),
        locked_cost_override=cast_plan.get("locked_cost"),
    )
    if not commit_cast_payment(cast_ctx):
        return False
    if getattr(player, "library", None) and player.library[0] is card:
        player.library.pop(0)
    elif card in getattr(player, "library", []):
        player.library.remove(card)
    else:
        return False
    source["top_library_small_creature_cast_last_turn"] = turn
    fields = replay_rule_fields(source_effect)
    score = 20 + int(card_mana_value(card) or 0) + int(candidate.get("power") or 0)
    emit_decision_trace(
        decision_type="cast_spell",
        player=player,
        turn=turn,
        phase=phase,
        available_options=[
            decision_card_option(
                card,
                effect_data,
                score=score,
                action="cast_top_library_small_creature",
            )
        ],
        chosen_option=decision_card_option(
            card,
            effect_data,
            score=score,
            action="cast_top_library_small_creature",
        ),
        rejected_options=[],
        score_components={
            "role": "top_library_static_permission",
            "source": source.get("name", "?"),
            "power": candidate.get("power"),
            "power_max": candidate.get("power_max"),
            "mana_before": mana_before,
            "mana_after_payment": player.available_mana(),
        },
        rule_source=fields.get("rule_source", "curated"),
        rule_status=fields.get("rule_review_status", "verified"),
        confidence="high",
        expected_benefit_score=score,
        actual_outcome="cast_from_library_top",
        reason="top_library_creature_within_power_limit_affordable",
        strategic_principle="convert_static_topdeck_permission_into_extra_card_access_without_free_casting",
        heuristic_version=DECISION_STRATEGY_VERSION,
    )
    emit_replay_event(
        "top_library_static_permission_used",
        player=player.name,
        source=source.get("name", "?"),
        card=card.get("name", "?"),
        type_line=card.get("type_line", ""),
        power=candidate.get("power"),
        power_max=candidate.get("power_max"),
        normal_mana_cost_paid=True,
        once_each_turn=True,
        turn=turn,
        phase=phase,
        **fields,
    )
    emit_replay_event(
        "spell_cast",
        player=player.name,
        card=card.get("name", "?"),
        effect=effect_data.get("effect", "unknown"),
        type_line=card.get("type_line", ""),
        cmc=card.get("cmc", 0),
        turn=turn,
        phase=phase,
        **cast_ctx.to_replay_fields(),
        **replay_rule_fields(effect_data),
    )
    mark_cast_ledger_emitted(effect_data)
    if not pay_additional_card_costs(
        player,
        card,
        effect_data,
        turn=turn,
        cost_context=cast_plan.get("cost_context"),
    ):
        player.graveyard.append(card)
        return False
    trigger_spell_cast_engines(
        player, all_players, card, turn, phase, stack=stack, active_player=player
    )
    trigger_opponent_spell_draw_engines(
        player,
        opponents,
        card,
        turn,
        phase,
        rng,
        stack=stack,
        active_player=player,
        all_players=all_players,
    )
    if stack is not None:
        stack.push(card, player, effect_data)
        priority_round(player, all_players, stack, turn, rng, phase=phase)
        while not stack.empty():
            priority_round(player, all_players, stack, turn, rng, phase=phase)
            if game_winner(all_players):
                return True
    else:
        apply_effect_immediate(
            player,
            opponents,
            card,
            turn,
            rng,
            effect_data_override=effect_data,
            phase=phase,
        )
    return True


def cast_spells_v8(player, opponents, all_players, turn, phase, stack, rng, max_actions=None):
    """v8: Cast spells respecting instant/sorcery timing and stack."""
    mana = player.available_mana()
    if mana <= 0:
        has_top_library_castable = top_library_small_creature_cast_candidate(player, phase, turn) is not None
        has_free_castable = any(
            not is_effective_land(candidate)
            and player.can_pay_card(candidate)
            and can_cast_in_phase(candidate, get_card_effect(candidate), phase, controller=player)
            and str(get_card_effect(candidate).get("effect") or "").lower()
            not in COUNTERLIKE_EFFECTS.union({"unknown"})
            and not should_hold_for_response_window(
                player,
                candidate,
                get_card_effect(candidate),
                phase,
            )
            and not should_reserve_survival_response_mana(
                player,
                candidate,
                get_card_effect(candidate),
                phase,
            )
            and not should_hold_squee_for_lorehold_recursion(player, candidate, phase)
            for candidate in player.hand
        )
        if not has_free_castable and not has_top_library_castable:
            return False

    actions_taken = 0

    def note_action():
        nonlocal actions_taken
        actions_taken += 1
        return max_actions is not None and actions_taken >= max_actions

    is_own_turn = (player == all_players[0]) or (turn > 0)
    is_main_phase = phase in ("precombat_main", "postcombat_main")
    if is_main_phase and cast_prepared_spell_faces(
        player,
        opponents,
        all_players,
        turn,
        phase,
        stack,
        rng,
    ):
        note_action()
        return True

    def ritual_unlocks_same_turn_action(ritual_card, ritual_effect):
        """One-shot mana is only useful when it unlocks a new same-turn action."""
        if ritual_effect.get("effect") != "ramp_ritual":
            return {"unlocks_same_turn_action": False, "resource_gate": "not_one_shot_ritual"}

        def playable_candidates():
            candidates = []
            if is_main_phase and player.command_zone:
                cmd = player.command_zone[0]
                already_there = any(
                    isinstance(permanent, dict)
                    and permanent.get("name") == cmd.get("name")
                    for permanent in player.battlefield
                )
                if not already_there:
                    candidates.append((cmd, player.commander_tax, "commander"))
            for candidate in player.hand:
                if candidate is ritual_card or is_effective_land(candidate):
                    continue
                candidate_effect = get_card_effect(candidate)
                if str(candidate_effect.get("effect") or "").lower() in COUNTERLIKE_EFFECTS.union({"unknown", "ramp_ritual"}):
                    continue
                if not can_cast_in_phase(candidate, candidate_effect, phase, controller=player):
                    continue
                if should_hold_squee_for_lorehold_recursion(player, candidate, phase):
                    continue
                candidates.append((candidate, 0, candidate_effect.get("effect") or "spell"))
            return candidates

        before = {
            (id(candidate), role)
            for candidate, additional_generic, role in playable_candidates()
            if player.can_pay_card(candidate, additional_generic)
        }
        pool_snapshot = player.mana_pool.snapshot()
        restricted_snapshot = copy.deepcopy(player.restricted_mana)
        treasures_snapshot = player.treasures
        life_snapshot = player.life
        try:
            # Keep this check aligned with the current ritual resolution path.
            add_ritual_mana_to_pool(player, ritual_effect, opponents)
            for candidate, additional_generic, role in playable_candidates():
                if (id(candidate), role) in before:
                    continue
                if player.can_pay_card(candidate, additional_generic):
                    effect_data = get_card_effect(candidate)
                    return {
                        "unlocks_same_turn_action": True,
                        "resource_gate": "one_shot_ritual_unlock",
                        "unlock_card": candidate.get("name", "?"),
                        "unlock_role": role,
                        "unlock_effect": effect_data.get("effect", "unknown"),
                        "unlock_reason": (
                            "same_turn_commander_cast"
                            if role == "commander"
                            else "same_turn_castable_spell"
                        ),
                    }
            return None
        finally:
            for color, amount in pool_snapshot.items():
                setattr(player.mana_pool, color, amount)
            player.restricted_mana = restricted_snapshot
            player.treasures = treasures_snapshot
            player.life = life_snapshot

    def playable_payoff_candidates(excluded_card=None):
        candidates = []
        if is_main_phase and player.command_zone:
            cmd = player.command_zone[0]
            already_there = any(
                isinstance(permanent, dict)
                and permanent.get("name") == cmd.get("name")
                for permanent in player.battlefield
            )
            if not already_there:
                candidates.append((cmd, player.commander_tax, "commander"))
        for candidate in player.hand:
            if candidate is excluded_card or is_effective_land(candidate):
                continue
            candidate_effect = get_card_effect(candidate)
            effect_name = str(candidate_effect.get("effect") or "unknown")
            if effect_name in COUNTERLIKE_EFFECTS.union({"unknown", "ramp_ritual", "ramp_permanent", "ramp_engine", "land_ramp", "land_recursion"}):
                continue
            if should_hold_for_response_window(player, candidate, candidate_effect, phase):
                continue
            if should_reserve_survival_response_mana(player, candidate, candidate_effect, phase):
                continue
            if should_hold_squee_for_lorehold_recursion(player, candidate, phase):
                continue
            if effect_name not in HIGH_IMPACT_PAYOFF_EFFECTS:
                continue
            if not can_cast_in_phase(candidate, candidate_effect, phase, controller=player):
                continue
            candidates.append((candidate, 0, "high_impact_spell"))
        return candidates

    def _payoff_context(candidate, additional_generic, role):
        effect_data = get_card_effect(candidate)
        locked_cost = card_mana_cost(candidate, additional_generic)
        nominal_cost = int(locked_cost.get("generic") or 0)
        nominal_cost += sum(int(amount or 0) for amount in (locked_cost.get("colored") or {}).values())
        nominal_cost += len(locked_cost.get("hybrid") or [])
        nominal_cost += len(locked_cost.get("phyrexian") or [])
        nominal_cost += len(locked_cost.get("phyrexian_hybrid") or [])
        nominal_cost += sum(
            int(option.get("generic") or 1)
            for option in (locked_cost.get("monocolored_hybrid") or [])
        )
        return {
            "unlock_card": candidate.get("name", "?"),
            "unlock_role": role,
            "unlock_effect": effect_data.get("effect", "unknown"),
            "unlock_reason": (
                "same_turn_commander_cast"
                if role == "commander"
                else "same_turn_high_impact_spell"
            ),
            "unlock_nominal_cost": nominal_cost,
        }

    def restore_mana_snapshot(pool_snapshot, restricted_snapshot, treasures_snapshot, life_snapshot):
        for color, amount in pool_snapshot.items():
            setattr(player.mana_pool, color, amount)
        player.restricted_mana = restricted_snapshot
        player.treasures = treasures_snapshot
        player.life = life_snapshot

    def ramp_permanent_unlocks_meaningful_action(ramp_card, ramp_effect, *, allowed_roles=None):
        """Permanent fast mana may spend scarce land only with immediate payoff."""
        allowed_roles = set(allowed_roles or [])
        produced_mana = mana_source_production_for_state(
            player,
            enrich_card({**ramp_card, **ramp_effect}),
        )
        if produced_mana <= 0:
            return None
        available_after_ramp = player.available_mana() + produced_mana

        def payoff_is_affordable_by_count(candidate, additional_generic):
            # Scarce-land fast mana is intentionally conservative: the
            # simulated payoff must be affordable by raw mana count as well as
            # by the richer payment planner, otherwise replays can claim Mox
            # unlocked a commander that still fails to cast in the real flow.
            locked_cost = card_mana_cost(candidate, additional_generic)
            nominal_cost = int(locked_cost.get("generic") or 0)
            nominal_cost += sum(int(amount or 0) for amount in (locked_cost.get("colored") or {}).values())
            nominal_cost += len(locked_cost.get("hybrid") or [])
            nominal_cost += len(locked_cost.get("phyrexian") or [])
            nominal_cost += len(locked_cost.get("phyrexian_hybrid") or [])
            nominal_cost += sum(
                int(option.get("generic") or 1)
                for option in (locked_cost.get("monocolored_hybrid") or [])
            )
            return available_after_ramp >= nominal_cost

        before = {
            (id(candidate), role)
            for candidate, additional_generic, role in playable_payoff_candidates(ramp_card)
            if not allowed_roles or role in allowed_roles
            if (
                player.can_pay_card(candidate, additional_generic)
                and payoff_is_affordable_by_count(candidate, additional_generic)
            )
        }
        pool_snapshot = player.mana_pool.snapshot()
        restricted_snapshot = copy.deepcopy(player.restricted_mana)
        treasures_snapshot = player.treasures
        life_snapshot = player.life
        try:
            colors = source_colors(enrich_card({**ramp_card, **ramp_effect}))
            player.mana_pool.add(colors[0] if colors else "generic", produced_mana)
            for candidate, additional_generic, role in playable_payoff_candidates(ramp_card):
                if allowed_roles and role not in allowed_roles:
                    continue
                if (id(candidate), role) in before:
                    continue
                if (
                    payoff_is_affordable_by_count(candidate, additional_generic)
                    and player.can_pay_card(candidate, additional_generic)
                ):
                    return {
                        "unlocks_same_turn_action": True,
                        "resource_gate": "permanent_ramp_unlock",
                        **_payoff_context(candidate, additional_generic, role),
                    }
            return None
        finally:
            restore_mana_snapshot(pool_snapshot, restricted_snapshot, treasures_snapshot, life_snapshot)

    def ramp_cast_plan(ramp_card, ramp_effect):
        """Build a payable cast plan for ramp cards with card-specific costs."""
        additional_costs = []
        modes = []
        metadata = {}
        if ramp_effect.get("hand_exile_mana_ability"):
            return {
                "additional_costs": additional_costs,
                "modes": ["hand_exile_mana_ability"],
                "uses_hand_exile_mana_ability": True,
            }
        if ramp_effect.get("multikicker_generic_cost"):
            cost = int(ramp_effect.get("multikicker_generic_cost") or 0)
            min_kicks = int(ramp_effect.get("min_kicker_count_for_mana") or 1)
            max_kicks = min(2, player.available_mana() // max(1, cost))
            kicker_count = 0
            for candidate_count in range(max_kicks, min_kicks - 1, -1):
                candidate_costs = everflowing_chalice_additional_costs(candidate_count)
                if player.can_pay(card_mana_cost(ramp_card, additional_costs=candidate_costs)):
                    kicker_count = candidate_count
                    additional_costs = candidate_costs
                    break
            if kicker_count < min_kicks:
                return None
            modes.append(f"multikicker:{kicker_count}")
            metadata["kicker_count"] = kicker_count
        if not player.can_pay(card_mana_cost(ramp_card, additional_costs=additional_costs)):
            return None
        return {
            "additional_costs": additional_costs,
            "modes": modes,
            **metadata,
        }

    def ramp_resource_strategy_context(ramp_card, ramp_effect):
        if ramp_cast_plan(ramp_card, ramp_effect) is None:
            return None
        if ramp_effect.get("requires_imprint_nonartifact_nonland"):
            imprint, _options, _risk_flags, _reason = choose_chrome_mox_imprint_card(
                player,
                ramp_card,
            )
            if not imprint:
                return None
            context = ramp_permanent_unlocks_meaningful_action(ramp_card, ramp_effect)
            if not context:
                return None
            return {
                **context,
                "resource_gate": "imprint_ramp_unlock",
                "imprint_card": imprint.get("name", "?"),
            }
        if ramp_effect.get("effect") == "ramp_ritual":
            return ritual_unlocks_same_turn_action(ramp_card, ramp_effect)
        if ramp_effect.get("requires_sacrifice_land"):
            battlefield_lands = [
                candidate
                for candidate in player.battlefield
                if isinstance(candidate, dict) and is_effective_land(candidate)
            ]
            sacrifice_land, _land_options, strategic_risk_flags, _selection_reason = choose_land_for_resource_cost(
                battlefield_lands,
                zone="battlefield",
            )
            if not sacrifice_land:
                return None
            count = int(ramp_effect.get("land_count") or ramp_effect.get("lands_to_battlefield") or 1)
            _targets, target_options = choose_land_ramp_targets(player, ramp_effect, count)
            allowed, benefit_reason = land_sacrifice_has_strategic_benefit(
                strategic_risk_flags,
                target_options,
                count,
            )
            if not allowed:
                return None
            return {
                "unlocks_same_turn_action": False,
                "resource_gate": "land_sacrifice_ramp",
                "strategic_risk_flags": strategic_risk_flags,
                "strategic_benefit_reason": benefit_reason,
                "resource_land": sacrifice_land.get("name", "?"),
                "target_land": (target_options[0]["name"] if target_options else None),
            }
        if not ramp_effect.get("requires_discard_land"):
            return {
                "unlocks_same_turn_action": False,
                "resource_gate": "ramp_without_scarce_land_cost",
                "strategic_benefit_reason": "no_scarce_land_risk",
            }
        hand_lands = [
            candidate
            for candidate in player.hand
            if isinstance(candidate, dict) and is_land(candidate)
        ]
        discard, _land_options, strategic_risk_flags, _selection_reason = choose_land_for_resource_cost(
            hand_lands,
            zone="hand",
        )
        if not discard:
            return None
        if not (
            "spending_last_land" in strategic_risk_flags
            or "spending_unique_color_land" in strategic_risk_flags
        ):
            return {
                "unlocks_same_turn_action": False,
                "resource_gate": "land_discard_ramp",
                "strategic_risk_flags": strategic_risk_flags,
                "strategic_benefit_reason": "no_scarce_land_risk",
                "resource_land": discard.get("name", "?"),
            }
        context = ramp_permanent_unlocks_meaningful_action(
            ramp_card,
            ramp_effect,
            allowed_roles={"commander"},
        )
        if not context:
            return None
        return {
            **context,
            "resource_gate": "land_discard_ramp",
            "strategic_risk_flags": strategic_risk_flags,
            "resource_land": discard.get("name", "?"),
        }

    # Track counters available (count counterspells in hand)
    player.counters_available = sum(
        1 for c in player.hand
        if c.get("effect") == "counter" or card_has_functional_tag(c, "counter", "protection")
    )

    # 1. Cast commander from command zone (main phase only)
    if is_main_phase and player.command_zone:
        cmd = player.command_zone[0]
        already_there = any(isinstance(c, dict) and c.get("name") == cmd.get("name") for c in player.battlefield)
        if already_there:
            cmd = None
    if (
        is_main_phase
        and player.command_zone
        and cmd is not None
    ):
        cmd_eff = get_card_effect(cmd)
        cmd_cast_plan = runtime_cast_plan_for_card(
            player,
            cmd,
            cmd_eff,
            additional_generic=player.commander_tax,
        )
        if cmd_cast_plan is None:
            cmd = None
    if (
        is_main_phase
        and player.command_zone
        and cmd is not None
        and cmd_cast_plan is not None
    ):
        if should_reserve_survival_response_mana(
            player,
            cmd,
            cmd_eff,
            phase,
            additional_generic=player.commander_tax,
        ) or should_prioritize_proactive_combat_defense(
            player,
            cmd,
            cmd_eff,
            phase,
        ):
            cmd = None
        else:
            cast_ctx = begin_cast_context(
                player,
                cmd,
                phase,
                additional_generic=player.commander_tax,
                effect_data=cmd_eff,
                role="commander",
                source_zone="command_zone",
                x_value=cmd_cast_plan.get("x_value", 0),
                additional_costs=cmd_cast_plan.get("additional_costs"),
                locked_cost_override=cmd_cast_plan.get("locked_cost"),
            )
            cost = cmd["cmc"] + player.commander_tax
        if cmd is None:
            pass
        elif commit_cast_payment(cast_ctx):
            if not pay_additional_card_costs(
                player,
                cmd,
                cmd_eff,
                turn=turn,
                cost_context=cmd_cast_plan.get("cost_context"),
            ):
                return False
            player.command_zone.pop(0)
            cmd_copy = enrich_card(cmd)
            haste = has_haste(cmd_copy)
            if is_creature_card(cmd_copy):
                default_stat = max(2, int(float(cmd_copy.get("cmc") or cost or 2)))
                cmd_copy["effect"] = "creature"
                cmd_copy["power"] = cmd_copy.get("power") or default_stat
                cmd_copy["toughness"] = cmd_copy.get("toughness") or cmd_copy.get("power") or default_stat
            cmd_copy["summoning_sick"] = not haste
            cmd_copy["haste"] = haste
            if cmd_eff.get("effect") != "land_recursion_creature":
                player.battlefield.append(cmd_copy)
            player.commander_tax += 2
            fields = replay_rule_fields(cmd_eff)
            commander_score = max(20, int(cost or 0) * 5)
            emit_decision_trace(
                decision_type="cast_spell",
                player=player,
                turn=turn,
                phase=phase,
                available_options=[
                    decision_card_option(
                        cmd,
                        cmd_eff,
                        score=commander_score,
                        action="cast_commander",
                    )
                ],
                chosen_option=decision_card_option(
                    cmd,
                    cmd_eff,
                    score=commander_score,
                    action="cast_commander",
                ),
                rejected_options=[],
                score_components={
                    "commander_tax": player.commander_tax - 2,
                    "effective_cost": cost,
                    "mana_after_payment": player.available_mana(),
                },
                rule_source=fields.get("rule_source", "battle_heuristic"),
                rule_status=fields.get("rule_review_status", "heuristic"),
                confidence="medium",
                expected_benefit_score=commander_score,
                actual_outcome="commander_cast",
                reason="commander_available_and_affordable",
                strategic_principle="cast_commander_when_affordable_and_plan_relevant",
            )
            emit_replay_event(
                "commander_cast",
                player=player.name,
                card=cmd.get("name", "?"),
                effect=cmd_eff.get("effect", "unknown"),
                type_line=cmd_copy.get("type_line", ""),
                cmc=cmd.get("cmc", cost),
                cost=cost,
                turn=turn,
                phase=phase,
                **cast_ctx.to_replay_fields(),
                **replay_rule_fields(cmd_eff),
            )
            trigger_spell_cast_engines(
                player, all_players, cmd, turn, phase, stack=stack, active_player=player
            )
            if cmd_eff.get("effect") == "land_recursion_creature":
                resolve_land_recursion_creature(player, cmd_copy, cmd_eff, turn)
            mana = player.available_mana()
            if note_action():
                return True

    if is_main_phase:
        for exiled_card in list(player.exile):
            if cast_warp_card_from_exile(player, exiled_card, turn, phase):
                if note_action():
                    return True
                break
            if cast_adventure_creature_from_exile(player, exiled_card, turn, phase):
                if note_action():
                    return True
                break
            if cast_airbend_card_from_exile(player, exiled_card, turn, phase):
                if note_action():
                    return True
                break
            if cast_radiant_scrollwielder_card_from_exile(
                player,
                exiled_card,
                opponents,
                all_players,
                turn,
                phase,
                stack,
                rng,
            ):
                while not stack.empty():
                    priority_round(player, all_players, stack, turn, rng, phase=phase)
                    if game_winner(all_players):
                        return True
                if note_action():
                    return True
                break

        for graveyard_card in list(player.graveyard):
            if cast_flashback_spell_from_graveyard(
                player,
                graveyard_card,
                opponents,
                all_players,
                turn,
                phase,
                stack,
                rng,
            ):
                while not stack.empty():
                    priority_round(player, all_players, stack, turn, rng)
                    if game_winner(all_players):
                        return True
                if note_action():
                    return True
                break

        for warp_card in list(player.hand):
            if cast_warp_spell_from_hand(player, warp_card, turn, phase):
                if note_action():
                    return True
                break

        for adventure_card in list(player.hand):
            if cast_adventure_spell_from_hand(
                player,
                adventure_card,
                opponents,
                all_players,
                turn,
                phase,
                stack,
                rng,
            ):
                while not stack.empty():
                    priority_round(player, all_players, stack, turn, rng)
                    if game_winner(all_players):
                        return True
                if note_action():
                    return True
                break

    # 2. Ramp (main phase only)
    if is_main_phase:
        ramp_contexts = {}
        for candidate in list(player.hand):
            effect = get_card_effect(candidate)
            if ramp_cast_plan(candidate, effect) is None:
                continue
            if effect.get("effect") not in (
                "land_ramp",
                "land_recursion",
                "ramp_permanent",
                "ramp_engine",
                "ramp_ritual",
            ):
                continue
            strategy_context = ramp_resource_strategy_context(candidate, effect)
            if strategy_context is None:
                continue
            if should_reserve_survival_response_mana(player, candidate, effect, phase):
                continue
            if should_prioritize_proactive_combat_defense(player, candidate, effect, phase):
                continue
            ramp_contexts[id(candidate)] = strategy_context
        ramp_cards = [c for c in player.hand if id(c) in ramp_contexts]
        for c in ramp_cards[:2]:
            eff = get_card_effect(c)
            strategy_context = ramp_contexts.get(id(c))
            if (
                c in player.hand
                and ramp_cast_plan(c, eff) is not None
                and strategy_context is not None
            ):
                cast_plan = ramp_cast_plan(c, eff) or {}
                ramp_risk_flags = [
                    flag
                    for flag in (
                        "one_shot_mana"
                        if eff.get("effect") == "ramp_ritual"
                        else None,
                        "requires_land_discard"
                        if eff.get("requires_discard_land")
                        else None,
                        "requires_land_sacrifice"
                        if eff.get("requires_sacrifice_land")
                        else None,
                        "requires_imprint"
                        if eff.get("requires_imprint_nonartifact_nonland")
                        else None,
                        "multikicker_paid"
                        if cast_plan.get("kicker_count")
                        else None,
                    )
                    if flag
                ]
                ramp_risk_flags.extend(
                    flag for flag in (strategy_context.get("strategic_risk_flags") or [])
                    if flag and flag not in ramp_risk_flags
                )
                if cast_plan.get("uses_hand_exile_mana_ability"):
                    activate_hand_exile_mana_ability(
                        player,
                        c,
                        eff,
                        turn,
                        opponents,
                        phase=phase,
                    )
                    mana = player.available_mana()
                    if note_action():
                        return True
                    continue
                def ramp_trace_score(option_card, option_context):
                    base_score = max(1, int(option_card.get("cmc", 0) or 0) + 10)
                    if option_context.get("unlocks_same_turn_action"):
                        return base_score + 4
                    if option_context.get("strategic_benefit_reason") in (
                        "high_value_land_target",
                        "untapped_net_mana_upgrade",
                        "flexible_color_fixing",
                    ):
                        return base_score + 2
                    return base_score
                cast_ctx = begin_cast_context(
                    player,
                    c,
                    phase,
                    effect_data=eff,
                    role="ramp",
                    modes=cast_plan.get("modes"),
                    additional_costs=cast_plan.get("additional_costs"),
                )
                if not commit_cast_payment(cast_ctx):
                    continue
                fields = replay_rule_fields(eff)
                emit_decision_trace(
                    decision_type="cast_spell",
                    player=player,
                    turn=turn,
                    phase=phase,
                    available_options=[
                        decision_card_option(
                            option_card,
                            get_card_effect(option_card),
                            score=ramp_trace_score(option_card, ramp_contexts[id(option_card)]),
                            action="cast_ramp",
                        )
                        for option_card in ramp_cards[:8]
                    ],
                    chosen_option=decision_card_option(
                        c,
                        eff,
                        score=ramp_trace_score(c, strategy_context),
                        action="cast_ramp",
                    ),
                    rejected_options=[
                        decision_card_option(
                            option_card,
                            get_card_effect(option_card),
                            score=ramp_trace_score(option_card, ramp_contexts[id(option_card)]),
                            action="defer_ramp",
                        )
                        for option_card in ramp_cards
                        if option_card is not c
                    ][:8],
                    score_components={
                        "role": "ramp",
                        "mana_before": mana,
                        "ramp_options": len(ramp_cards),
                        "unlocks_same_turn_action": 1 if strategy_context.get("unlocks_same_turn_action") else 0,
                        "unlock_card": strategy_context.get("unlock_card"),
                        "unlock_role": strategy_context.get("unlock_role"),
                        "unlock_reason": strategy_context.get("unlock_reason"),
                        "strategic_benefit_reason": strategy_context.get("strategic_benefit_reason"),
                        "resource_gate": strategy_context.get("resource_gate"),
                        "requires_discard_land": bool(eff.get("requires_discard_land")),
                        "requires_sacrifice_land": bool(eff.get("requires_sacrifice_land")),
                        "requires_imprint_nonartifact_nonland": bool(
                            eff.get("requires_imprint_nonartifact_nonland")
                        ),
                        "multikicker_count": int(cast_plan.get("kicker_count") or 0),
                    },
                    rule_source=fields.get("rule_source", "battle_heuristic"),
                    rule_status=fields.get("rule_review_status", "heuristic"),
                    confidence="medium",
                    expected_benefit_score=ramp_trace_score(c, strategy_context),
                    actual_outcome="cast_and_resolve_ramp",
                    reason="early_mana_development",
                    expected_payoff_reason=(
                        strategy_context.get("unlock_reason")
                        or strategy_context.get("strategic_benefit_reason")
                        or "develop_mana_only_when_it_unlocks_or_preserves_plan"
                    ),
                    strategic_principle=(
                        "spend_ramp_resource_only_when_it_unlocks_or_accelerates_plan"
                    ),
                    heuristic_version=DECISION_STRATEGY_VERSION,
                    resource_delta={
                        "effect": eff.get("effect"),
                        "mana_before": mana,
                        "one_shot_mana": ritual_mana_produced(player, eff, opponents)
                        if eff.get("effect") == "ramp_ritual"
                        else 0,
                        "resource_gate": strategy_context.get("resource_gate"),
                        "unlock_card": strategy_context.get("unlock_card"),
                        "unlock_role": strategy_context.get("unlock_role"),
                        "unlock_effect": strategy_context.get("unlock_effect"),
                        "unlock_reason": strategy_context.get("unlock_reason"),
                        "unlock_nominal_cost": strategy_context.get("unlock_nominal_cost"),
                        "strategic_benefit_reason": strategy_context.get("strategic_benefit_reason"),
                        "resource_land": strategy_context.get("resource_land"),
                        "imprint_card": strategy_context.get("imprint_card"),
                        "requires_discard_land": bool(eff.get("requires_discard_land")),
                        "requires_sacrifice_land": bool(eff.get("requires_sacrifice_land")),
                        "requires_imprint_nonartifact_nonland": bool(
                            eff.get("requires_imprint_nonartifact_nonland")
                        ),
                        "multikicker_count": int(cast_plan.get("kicker_count") or 0),
                    },
                    risk_flags=ramp_risk_flags,
                    rejected_reason="deferred_lower_priority_ramp",
                )
                player.hand.remove(c)
                emit_replay_event(
                    "spell_cast",
                    player=player.name,
                    card=c.get("name", "?"),
                    effect=eff.get("effect", "unknown"),
                    type_line=c.get("type_line", ""),
                    cmc=c.get("cmc", 0),
                    turn=turn,
                    phase=phase,
                    **cast_ctx.to_replay_fields(),
                    **replay_rule_fields(eff),
                )
                if not pay_additional_card_costs(
                    player,
                    c,
                    eff,
                    turn=turn,
                    cost_context=strategy_context,
                ):
                    player.graveyard.append(c)
                    return False
                trigger_spell_cast_engines(
                    player, all_players, c, turn, phase, stack=stack, active_player=player
                )
                trigger_opponent_spell_draw_engines(
                    player,
                    opponents,
                    c,
                    turn,
                    phase,
                    rng,
                    stack=stack,
                    active_player=player,
                    all_players=all_players,
                )
                if eff.get("effect") == "ramp_ritual" and eff.get("mana_produced_from_target_opponent_hand_size"):
                    apply_effect_immediate(
                        player,
                        opponents,
                        c,
                        turn,
                        rng,
                        effect_data_override=eff,
                        stack=stack,
                        phase=phase,
                    )
                elif eff.get("effect") == "ramp_ritual":
                    add_ritual_mana_to_pool(player, eff, opponents)
                    player.graveyard.append(c)
                elif eff.get("effect") == "land_ramp":
                    put_lands_from_library(player, c, eff, turn, opponents=opponents, source_event="land_ramp")
                    player.graveyard.append(c)
                elif eff.get("effect") == "land_recursion":
                    return_graveyard_lands_to_battlefield(player, c, turn, opponents=opponents)
                    player.graveyard.append(c)
                else:
                    permanent = prepare_entering_permanent(enrich_card({**c, **eff}))
                    if eff.get("multikicker_generic_cost"):
                        kicker_count = int(cast_plan.get("kicker_count") or 0)
                        permanent["charge_counters"] = kicker_count
                        permanent["mana_produced"] = kicker_count
                        emit_replay_event(
                            "multikicker_paid",
                            player=player.name,
                            card=c.get("name", "?"),
                            kicker_count=kicker_count,
                            additional_costs=cast_plan.get("additional_costs") or [],
                            turn=turn,
                            phase=phase,
                        )
                    if eff.get("requires_imprint_nonartifact_nonland"):
                        resolve_chrome_mox_imprint(player, permanent, c, turn=turn)
                    player.battlefield.append(permanent)
                    resolve_generic_permanent_etb(
                        player,
                        opponents,
                        permanent,
                        eff,
                        turn,
                        rng,
                        stack=stack,
                        all_players=all_players,
                        phase=phase,
                    )
                    if player_mana_source_permanent(player, permanent) and not (
                        is_battlefield_creature(permanent) and permanent.get("summoning_sick")
                    ):
                        produced = mana_source_production_for_state(player, permanent)
                        if (
                            produced > 0
                            and pay_mana_source_activation_costs(player, permanent, turn=turn)
                            and add_player_mana_source_to_pool(player, permanent, turn=turn)
                        ):
                            mark_mana_source_used_if_nonstandard_untap(permanent)
                mana = player.available_mana()
                if note_action():
                    return True

    if is_main_phase:
        if cast_top_library_small_creature_from_static_permission(
            player,
            opponents,
            all_players,
            turn,
            phase,
            stack,
            rng,
        ):
            mana = player.available_mana()
            if note_action():
                return True

    # 2.5. Proactive silence before a same-turn high-impact payoff.
    if is_main_phase:
        silence_options = []
        for c in list(player.hand):
            eff = get_card_effect(c)
            effect_name = str(eff.get("effect") or c.get("effect") or "").lower()
            if effect_name not in SILENCE_WINDOW_EFFECTS or not is_instant(c):
                continue
            cast_plan = runtime_cast_plan_for_card(player, c, eff)
            if cast_plan is None:
                continue
            payoff_plan = silence_payoff_plan(player, phase, silence_card=c)
            if not payoff_plan:
                continue
            silence_options.append((c, eff, cast_plan, payoff_plan))
        if silence_options:
            silence_options.sort(
                key=lambda item: (
                    -int(item[3].get("payoff_score") or 0),
                    int(item[0].get("cmc") or 0),
                    str(item[0].get("name") or ""),
                )
            )
            c, eff, cast_plan, payoff_plan = silence_options[0]
            if c in player.hand:
                cast_ctx = begin_cast_context(
                    player,
                    c,
                    phase,
                    effect_data=eff,
                    role="proactive_silence",
                    x_value=cast_plan.get("x_value", 0),
                    additional_costs=cast_plan.get("additional_costs"),
                    locked_cost_override=cast_plan.get("locked_cost"),
                )
                if commit_cast_payment(cast_ctx):
                    fields = replay_rule_fields(eff)
                    chosen_score = max(60, int(payoff_plan.get("payoff_score") or 0))
                    emit_decision_trace(
                        decision_type="cast_spell",
                        player=player,
                        turn=turn,
                        phase=phase,
                        available_options=[
                            decision_card_option(
                                option_card,
                                option_eff,
                                score=max(60, int(option_plan.get("payoff_score") or 0)),
                                action="cast_proactive_silence",
                            )
                            for option_card, option_eff, _option_cast_plan, option_plan in silence_options[:8]
                        ],
                        chosen_option=decision_card_option(
                            c,
                            eff,
                            score=chosen_score,
                            action="cast_proactive_silence",
                        ),
                        rejected_options=[
                            decision_card_option(
                                option_card,
                                option_eff,
                                score=max(60, int(option_plan.get("payoff_score") or 0)),
                                action="defer_proactive_silence",
                            )
                            for option_card, option_eff, _option_cast_plan, option_plan in silence_options
                            if option_card is not c
                        ][:8],
                        score_components={
                            "role": "proactive_silence",
                            "mana_before": mana,
                            "payoff_card": payoff_plan.get("payoff_card"),
                            "payoff_effect": payoff_plan.get("payoff_effect"),
                            "payoff_score": payoff_plan.get("payoff_score"),
                            "payoff_cmc": payoff_plan.get("payoff_cmc"),
                        },
                        rule_source=fields.get("rule_source", "battle_heuristic"),
                        rule_status=fields.get("rule_review_status", "heuristic"),
                        confidence="medium",
                        expected_benefit_score=chosen_score,
                        actual_outcome="cast_to_stack",
                        reason="protect_same_turn_high_impact_payoff",
                        expected_payoff_reason=(
                            f"protect {payoff_plan.get('payoff_card')} from opponent responses"
                        ),
                        strategic_principle="cast_silence_before_same_turn_decisive_spell",
                        heuristic_version=DECISION_STRATEGY_VERSION,
                    )
                    player.hand.remove(c)
                    emit_replay_event(
                        "spell_cast",
                        player=player.name,
                        card=c.get("name", "?"),
                        effect=eff.get("effect", "unknown"),
                        type_line=c.get("type_line", ""),
                        cmc=c.get("cmc", 0),
                        turn=turn,
                        phase=phase,
                        proactive_silence=True,
                        payoff_card=payoff_plan.get("payoff_card"),
                        payoff_effect=payoff_plan.get("payoff_effect"),
                        payoff_score=payoff_plan.get("payoff_score"),
                        **cast_ctx.to_replay_fields(),
                        **replay_rule_fields(eff),
                    )
                    mark_cast_ledger_emitted(eff)
                    if not pay_additional_card_costs(
                        player,
                        c,
                        eff,
                        turn=turn,
                        cost_context=cast_plan.get("cost_context"),
                    ):
                        player.graveyard.append(c)
                        return False
                    trigger_spell_cast_engines(
                        player, all_players, c, turn, phase, stack=stack, active_player=player
                    )
                    trigger_opponent_spell_draw_engines(
                        player,
                        opponents,
                        c,
                        turn,
                        phase,
                        rng,
                        stack=stack,
                        active_player=player,
                        all_players=all_players,
                    )
                    stack.push(c, player, eff)
                    priority_round(player, all_players, stack, turn, rng, phase=phase)
                    while not stack.empty():
                        priority_round(player, all_players, stack, turn, rng, phase=phase)
                        if game_winner(all_players):
                            return True
                    mana = player.available_mana()
                    if note_action():
                        return True

    # 3. Cast spells to stack
    castable = [
        c for c in player.hand
        if not is_effective_land(c)
        and card_is_runtime_castable(player, c, get_card_effect(c))
        and get_card_effect(c).get("effect") not in (
            "counter",
            "unknown",
            "ramp_ritual",
            "ramp_permanent",
            "ramp_engine",
            "land_ramp",
            "land_recursion",
        )
        and not should_hold_for_response_window(
            player,
            c,
            get_card_effect(c),
            phase,
        )
        and not should_reserve_survival_response_mana(
            player,
            c,
            get_card_effect(c),
            phase,
        )
        and not should_prioritize_proactive_combat_defense(
            player,
            c,
            get_card_effect(c),
            phase,
        )
        and not should_hold_squee_for_lorehold_recursion(player, c, phase)
        and spell_has_required_library_target(player, get_card_effect(c))
    ]
    # v8: Miracle check for Lorehold
    if player.is_human:
        lorehold_on_board = any(isinstance(c, dict) and c.get("name") == "Lorehold, the Historian" for c in player.battlefield)
        for c in castable[:]:
            if (is_sorcery(c) or is_instant(c)) and not is_main_phase:
                if not is_instant(c) or not lorehold_on_board:
                    castable.remove(c)  # can't cast sorcery outside main phase

    # Play spells in priority order
    # v8.2: Play spells needing priority in score order
    # Wincons / high-threat spells first (main phase only)
    if is_main_phase:
        # Sort by threat score (highest first — resolve big plays before small ones)
        scored = [(c, threat_score(get_card_effect(c).get("effect", ""), c.get("name", ""), player, all_players, turn)) for c in castable]
        scored.sort(key=lambda x: -x[1])

        wincons = [c for c, s in scored if s >= 50]
        if wincons:
            c = wincons[0]
            if c in player.hand:
                eff = get_card_effect(c)
                cast_plan = runtime_cast_plan_for_card(player, c, eff)
                if cast_plan is None:
                    wincons = []
                    c = None
                    eff = None
                elif eff.get("effect") in BOARD_WIPE_LIKE_EFFECTS and not should_cast_board_wipe(player, opponents):
                    wincons = []
                elif eff.get("effect") == "worldfire_reset" and not should_cast_worldfire_reset(player, opponents):
                    wincons = []
                elif (
                    eff.get("effect") == "draw_cards"
                    and is_wheel_like_card(c, eff)
                    and not should_cast_wheel(player, opponents, {**eff, "name": c.get("name")})
                ):
                    wincons = []
                elif not additional_card_costs_are_payable(
                    player,
                    c,
                    eff,
                    cast_plan.get("cost_context"),
                ):
                    wincons = []
                if not wincons:
                    c = None
                    eff = None
            if c is not None and c in player.hand:
                eff, declared_targets = prepare_declared_removal_targets(
                    player,
                    opponents,
                    c,
                    eff,
                )
                if missing_required_declared_removal_target(eff, declared_targets):
                    return False
                cast_ctx = begin_cast_context(
                    player,
                    c,
                    phase,
                    effect_data=eff,
                    role="high_threat",
                    targets=declared_targets,
                    x_value=cast_plan.get("x_value", 0),
                    additional_costs=cast_plan.get("additional_costs"),
                    locked_cost_override=cast_plan.get("locked_cost"),
                )
                if not commit_cast_payment(cast_ctx):
                    return False
                chosen_score = next((s for card_item, s in scored if card_item is c), scored[0][1])
                fields = replay_rule_fields(eff)
                emit_decision_trace(
                    decision_type="cast_spell",
                    player=player,
                    turn=turn,
                    phase=phase,
                    available_options=[
                        decision_card_option(
                            option_card,
                            get_card_effect(option_card),
                            score=option_score,
                            action="cast",
                        )
                        for option_card, option_score in scored[:8]
                    ],
                    chosen_option=decision_card_option(c, eff, score=chosen_score, action="cast_high_threat"),
                    rejected_options=[
                        decision_card_option(
                            option_card,
                            get_card_effect(option_card),
                            score=option_score,
                            action="defer_cast",
                        )
                        for option_card, option_score in scored
                        if option_card is not c
                    ][:8],
                    score_components={
                        "threat_score": chosen_score,
                        "castable_count": len(scored),
                        "mana_before": mana,
                    },
                    rule_source=fields.get("rule_source", "battle_heuristic"),
                    rule_status=fields.get("rule_review_status", "heuristic"),
                    confidence="medium",
                    expected_benefit_score=chosen_score,
                    actual_outcome="cast_to_stack",
                    reason="highest_threat_main_phase_spell",
                )
                player.hand.remove(c)
                emit_replay_event(
                    "spell_cast",
                    player=player.name,
                    card=c.get("name", "?"),
                    effect=eff.get("effect", "unknown"),
                    type_line=c.get("type_line", ""),
                    cmc=c.get("cmc", 0),
                    threat_score=scored[0][1],
                    turn=turn,
                    phase=phase,
                    **cast_ctx.to_replay_fields(),
                    **replay_rule_fields(eff),
                )
                mark_cast_ledger_emitted(eff)
                if not pay_additional_card_costs(
                    player,
                    c,
                    eff,
                    turn=turn,
                    cost_context=cast_plan.get("cost_context"),
                ):
                    player.graveyard.append(c)
                    return False
                trigger_spell_cast_engines(
                    player, all_players, c, turn, phase, stack=stack, active_player=player
                )
                trigger_opponent_spell_draw_engines(
                    player,
                    opponents,
                    c,
                    turn,
                    phase,
                    rng,
                    stack=stack,
                    active_player=player,
                    all_players=all_players,
                )
                stack.push(c, player, eff)
                priority_round(player, all_players, stack, turn, rng)
                if game_winner(all_players):
                    return True
                while not stack.empty():
                    priority_round(player, all_players, stack, turn, rng)
                    if game_winner(all_players):
                        return True
                note_action()
                return True

    # Other spells: 2 per phase max
    remaining = sorted(
        [
            c for c in castable
            if runtime_cast_plan_for_card(player, c, get_card_effect(c)) is not None
        ],
        key=lambda c: c["cmc"],
    )
    played = 0
    for c in remaining:
        if played >= 2: break
        if c in player.hand:
            eff = get_card_effect(c)
            if eff.get("effect") in BOARD_WIPE_LIKE_EFFECTS and not should_cast_board_wipe(player, opponents):
                continue
            if eff.get("effect") == "worldfire_reset" and not should_cast_worldfire_reset(player, opponents):
                continue
            if (
                eff.get("effect") == "draw_cards"
                and is_wheel_like_card(c, eff)
                and not should_cast_wheel(player, opponents, {**eff, "name": c.get("name")})
            ):
                continue
            cast_plan = runtime_cast_plan_for_card(player, c, eff)
            if cast_plan is None:
                continue
            if eff.get("effect") == "creature":
                if not is_main_phase: continue  # creatures only in main phase
                cast_ctx = begin_cast_context(
                    player,
                    c,
                    phase,
                    effect_data=eff,
                    role="creature",
                    x_value=cast_plan.get("x_value", 0),
                    additional_costs=cast_plan.get("additional_costs"),
                    locked_cost_override=cast_plan.get("locked_cost"),
                )
                if not commit_cast_payment(cast_ctx):
                    continue
                creature_score = threat_score(
                    eff.get("effect", ""),
                    c.get("name", ""),
                    player,
                    all_players,
                    turn,
                )
                fields = replay_rule_fields(eff)
                emit_decision_trace(
                    decision_type="cast_spell",
                    player=player,
                    turn=turn,
                    phase=phase,
                    available_options=[
                        decision_card_option(
                            option_card,
                            get_card_effect(option_card),
                            score=threat_score(
                                get_card_effect(option_card).get("effect", ""),
                                option_card.get("name", ""),
                                player,
                                all_players,
                                turn,
                            ),
                            action="cast",
                        )
                        for option_card in remaining[:8]
                    ],
                    chosen_option=decision_card_option(
                        c,
                        eff,
                        score=creature_score,
                        action="cast_creature",
                    ),
                    rejected_options=[
                        decision_card_option(
                            option_card,
                            get_card_effect(option_card),
                            score=threat_score(
                                get_card_effect(option_card).get("effect", ""),
                                option_card.get("name", ""),
                                player,
                                all_players,
                                turn,
                            ),
                            action="defer_cast",
                        )
                        for option_card in remaining
                        if option_card is not c
                    ][:8],
                    score_components={
                        "role": "creature",
                        "cmc": c.get("cmc", 0),
                        "remaining_options": len(remaining),
                    },
                    rule_source=fields.get("rule_source", "battle_heuristic"),
                    rule_status=fields.get("rule_review_status", "heuristic"),
                    confidence="medium",
                    expected_benefit_score=creature_score,
                    actual_outcome="creature_to_battlefield",
                    reason="lowest_cmc_castable_creature",
                    expected_payoff_reason="deploy board presence at the best available mana slot",
                )
                player.hand.remove(c)
                c_copy = enrich_card({**c, **eff})
                c_copy["effect"] = "creature"
                c_copy["haste"] = has_haste(c_copy)
                c_copy["summoning_sick"] = not c_copy["haste"]
                c_copy["tapped"] = False
                player.battlefield.append(c_copy)
                refresh_controlled_static_indestructible(
                    player,
                    turn=turn,
                    phase=phase,
                    emit_events=True,
                )
                refresh_controlled_static_power_toughness_bonuses(
                    player,
                    turn=turn,
                    phase=phase,
                    emit_events=True,
                )
                refresh_controlled_static_keywords(
                    player,
                    turn=turn,
                    phase=phase,
                    emit_events=True,
                )
                emit_replay_event(
                    "creature_cast",
                    player=player.name,
                    card=c.get("name", "?"),
                    cmc=c.get("cmc", 0),
                    type_line=c_copy.get("type_line", ""),
                    power=c_copy.get("power"),
                    toughness=c_copy.get("toughness"),
                    effect=eff.get("effect", "creature"),
                    turn=turn,
                    phase=phase,
                    **cast_ctx.to_replay_fields(),
                    **replay_rule_fields(eff),
                )
                if eff.get("etb_land_ramp_count"):
                    etb_eff = {
                        **eff,
                        "land_count": int(eff.get("etb_land_ramp_count") or 1),
                        "requires_sacrifice_land": bool(eff.get("etb_requires_sacrifice_land")),
                    }
                    put_lands_from_library(
                        player,
                        c_copy,
                        etb_eff,
                        turn,
                        opponents=opponents,
                        source_event="etb_land_ramp",
                    )
                if eff.get("etb_draw_count"):
                    player.draw(int(eff.get("etb_draw_count") or 1), rng)
                if eff.get("etb_library_look_count"):
                    resolve_dig_to_hand(
                        player,
                        c_copy,
                        {
                            **eff,
                            "effect": "dig_to_hand",
                            "look_count": int(eff.get("etb_library_look_count") or 0),
                            "pick_count": int(eff.get("etb_library_pick_count") or 1),
                            "pick_target": eff.get("etb_library_pick_target") or "any_card",
                            "rest_destination": eff.get("etb_library_rest_destination") or "graveyard",
                            "pick_all_matching": bool(eff.get("etb_library_pick_all_matching")),
                        },
                        turn,
                    )
                resolve_etb_library_creature_tutor(player, c_copy, eff, turn)
                if eff.get("etb_remove_target") or eff.get("etb_removal_target"):
                    resolve_etb_removal(player, opponents, c_copy, eff, turn, rng)
                if eff.get("etb_token_count"):
                    for _ in range(min(int(eff.get("etb_token_count") or 1), 20)):
                        create_creature_token(
                            player,
                            name=eff.get("etb_token_name", "Token"),
                            power=int(eff.get("etb_token_power") or 1),
                            toughness=int(eff.get("etb_token_toughness") or eff.get("etb_token_power") or 1),
                            artifact=bool(eff.get("etb_artifact_tokens")),
                        )
                if eff.get("etb_recursion_count"):
                    resolve_etb_graveyard_recursion(player, c_copy, eff, turn, [player] + list(opponents or []))
                if eff.get("etb_copy_target_types"):
                    resolve_etb_copy_tokens(player, opponents, c_copy, eff, turn)
                played += 1
                if note_action():
                    return True
            else:
                if not additional_card_costs_are_payable(
                    player,
                    c,
                    eff,
                    cast_plan.get("cost_context"),
                ):
                    continue
                eff, declared_targets = prepare_declared_removal_targets(
                    player,
                    opponents,
                    c,
                    eff,
                )
                if missing_required_declared_removal_target(eff, declared_targets):
                    continue
                cast_ctx = begin_cast_context(
                    player,
                    c,
                    phase,
                    effect_data=eff,
                    role="normal",
                    targets=declared_targets,
                    x_value=cast_plan.get("x_value", 0),
                    additional_costs=cast_plan.get("additional_costs"),
                    locked_cost_override=cast_plan.get("locked_cost"),
                )
                if not commit_cast_payment(cast_ctx):
                    continue
                normal_score = threat_score(eff.get("effect", ""), c.get("name", ""), player, all_players, turn)
                fields = replay_rule_fields(eff)
                emit_decision_trace(
                    decision_type="cast_spell",
                    player=player,
                    turn=turn,
                    phase=phase,
                    available_options=[
                        decision_card_option(
                            option_card,
                            get_card_effect(option_card),
                            score=threat_score(
                                get_card_effect(option_card).get("effect", ""),
                                option_card.get("name", ""),
                                player,
                                all_players,
                                turn,
                            ),
                            action="cast",
                        )
                        for option_card in remaining[:8]
                    ],
                    chosen_option=decision_card_option(c, eff, score=normal_score, action="cast_spell"),
                    rejected_options=[
                        decision_card_option(
                            option_card,
                            get_card_effect(option_card),
                            score=threat_score(
                                get_card_effect(option_card).get("effect", ""),
                                option_card.get("name", ""),
                                player,
                                all_players,
                                turn,
                            ),
                            action="defer_cast",
                        )
                        for option_card in remaining
                        if option_card is not c
                    ][:8],
                    score_components={
                        "threat_score": normal_score,
                        "cmc": c.get("cmc", 0),
                        "remaining_options": len(remaining),
                    },
                    rule_source=fields.get("rule_source", "battle_heuristic"),
                    rule_status=fields.get("rule_review_status", "heuristic"),
                    confidence="medium",
                    expected_benefit_score=normal_score,
                    actual_outcome="cast_to_stack",
                    reason="lowest_cmc_castable_spell",
                    expected_payoff_reason="advance stack development with the best affordable spell line",
                )
                player.hand.remove(c)
                emit_replay_event(
                    "spell_cast",
                    player=player.name,
                    card=c.get("name", "?"),
                    effect=eff.get("effect", "unknown"),
                    type_line=c.get("type_line", ""),
                    cmc=c.get("cmc", 0),
                    turn=turn,
                    phase=phase,
                    **cast_ctx.to_replay_fields(),
                    **replay_rule_fields(eff),
                )
                mark_cast_ledger_emitted(eff)
                if not pay_additional_card_costs(
                    player,
                    c,
                    eff,
                    turn=turn,
                    cost_context=cast_plan.get("cost_context"),
                ):
                    player.graveyard.append(c)
                    continue
                trigger_spell_cast_engines(
                    player, all_players, c, turn, phase, stack=stack, active_player=player
                )
                trigger_opponent_spell_draw_engines(
                    player,
                    opponents,
                    c,
                    turn,
                    phase,
                    rng,
                    stack=stack,
                    active_player=player,
                    all_players=all_players,
                )
                stack.push(c, player, eff)
                played += 1
                if note_action():
                    while not stack.empty():
                        priority_round(player, all_players, stack, turn, rng)
                        if game_winner(all_players):
                            return True
                    return True

# Resolve stack
    while not stack.empty():
        priority_round(player, all_players, stack, turn, rng)
        if game_winner(all_players):
            return True
    return actions_taken > 0


def _tempting_offer_runtime_components(effect_data):
    components = [
        component
        for component in list((effect_data or {}).get("_composite_rule_components") or [])
        if runtime_executor_status_enabled(component.get("tempting_offer_opponent_choice_status"))
    ]
    if not components:
        return None, None
    draw_component = next(
        (component for component in components if component.get("effect") == "draw_cards"),
        None,
    )
    token_component = next(
        (component for component in components if component.get("effect") == "token_maker"),
        None,
    )
    if draw_component is None or token_component is None:
        return None, None
    return draw_component, token_component


def _tempting_offer_choice_model(effect_data, components):
    for source in [effect_data, *list(components or [])]:
        if not isinstance(source, dict):
            continue
        model = source.get("tempting_offer_choice_model")
        if model:
            return str(model)
        default = source.get("tempting_offer_default")
        if default:
            return str(default)
    return "opponents_decline"


def _opponent_accepts_tempting_offer(controller, opponent, model):
    normalized = str(model or "opponents_decline").strip().lower()
    if normalized in {"opponents_accept", "opponent_accepts", "accept", "always_accept"}:
        return True, "accept_offer"
    if normalized in {"opponents_decline", "opponent_declines", "decline", "always_decline"}:
        return False, "decline_offer"
    if normalized in {"table_intent_heuristic_v1", "compact_table_intent_v1"}:
        controller_life = int(getattr(controller, "life", 0) or 0)
        opponent_life = int(getattr(opponent, "life", 0) or 0)
        controller_board = table_visible_board_power(controller)
        opponent_board = table_visible_board_power(opponent)
        accept = opponent_life <= controller_life - 8 and opponent_board <= controller_board
        return accept, "accept_offer" if accept else "decline_offer"
    return False, "decline_offer"


def resolve_tempting_offer_runtime(player, opponents, card, effect_data, turn, rng, *, stack=None, phase="resolution"):
    draw_component, token_component = _tempting_offer_runtime_components(effect_data)
    if draw_component is None or token_component is None:
        return None

    participants = [player, *list(opponents or [])]
    model = _tempting_offer_choice_model(effect_data, [draw_component, token_component])
    draw_count = int(draw_component.get("count") or draw_component.get("amount") or draw_component.get("draw_count") or 1)
    token_count = int(token_component.get("token_count") or 1)
    choices = []
    accepted = 0
    opponent_cards_drawn = 0
    opponent_tokens_created = 0

    for opponent in _live_opponents(opponents):
        accepts, choice = _opponent_accepts_tempting_offer(player, opponent, model)
        opponent_drawn = 0
        opponent_tokens = 0
        if accepts:
            accepted += 1
            drawn = opponent.draw(max(0, draw_count), rng)
            opponent_drawn = len(drawn)
            opponent_cards_drawn += opponent_drawn
            process_player_draw_triggers(
                opponent,
                opponent_drawn,
                turn,
                phase,
                participants,
                stack=stack,
                turn_player=player,
            )
            opponent_tokens = create_creature_tokens_from_effect(
                opponent,
                token_component,
                count=token_count,
                opponents=[participant for participant in participants if participant is not opponent],
                turn=turn,
                source_event="tempting_offer_opponent_token",
                stack=stack,
                active_player=player,
                all_players=participants,
            )
            opponent_tokens_created += min(max(0, opponent_tokens), 20)
        choices.append({
            "opponent": opponent.name,
            "choice": choice,
            "cards_drawn": opponent_drawn,
            "tokens_created": opponent_tokens,
        })

    controller_bonus_draws = 0
    controller_bonus_tokens = 0
    if accepted:
        drawn = player.draw(max(0, draw_count * accepted), rng)
        controller_bonus_draws = len(drawn)
        process_player_draw_triggers(
            player,
            controller_bonus_draws,
            turn,
            phase,
            participants,
            stack=stack,
            turn_player=player,
        )
        controller_bonus_tokens = create_creature_tokens_from_effect(
            player,
            token_component,
            count=token_count * accepted,
            opponents=opponents,
            turn=turn,
            source_event="tempting_offer_controller_bonus_token",
            stack=stack,
            active_player=player,
            all_players=participants,
        )

    emit_replay_event(
        "tempting_offer_resolved",
        player=player.name,
        card=card.get("name", "?"),
        choice_model=model,
        opponents_accepted=accepted,
        opponents_declined=max(0, len(choices) - accepted),
        choices=choices,
        opponent_cards_drawn=opponent_cards_drawn,
        opponent_tokens_created=opponent_tokens_created,
        controller_bonus_cards_drawn=controller_bonus_draws,
        controller_bonus_tokens_created=min(max(0, controller_bonus_tokens), 20),
        turn=turn,
        phase=phase,
        **replay_rule_fields(effect_data),
    )
    return {
        "effect": "tempting_offer",
        "opponents_accepted": accepted,
        "opponents_declined": max(0, len(choices) - accepted),
        "controller_bonus_cards_drawn": controller_bonus_draws,
        "controller_bonus_tokens_created": min(max(0, controller_bonus_tokens), 20),
    }


def _look_at_hand_target_player(player, opponents, effect_data):
    candidates = [player] + [
        opponent for opponent in (opponents or []) if getattr(opponent, "is_alive", lambda: True)()
    ]
    declared_names = []
    for entry in effect_data.get("declared_targets") or []:
        if isinstance(entry, dict):
            target = entry.get("target")
            name = (
                entry.get("target_player")
                or entry.get("player")
                or entry.get("name")
                or getattr(target, "name", None)
            )
            if name:
                declared_names.append(str(name))
        elif entry:
            declared_names.append(str(entry))
    for declared_name in declared_names:
        for candidate in candidates:
            if getattr(candidate, "name", None) == declared_name:
                if str(effect_data.get("target_player_scope") or "any") == "opponent" and candidate is player:
                    continue
                return candidate, "declared_target"

    alive_opponents = [
        opponent for opponent in (opponents or []) if getattr(opponent, "is_alive", lambda: True)()
    ]
    if alive_opponents:
        alive_opponents = prioritize_evaluation_target_opponents(player, alive_opponents)
        return alive_opponents[0], "opponent_preferred"
    if str(effect_data.get("target_player_scope") or "any") == "opponent":
        return player, "fallback_self_no_opponent"
    return player, "self_fallback"


def resolve_look_at_target_player_hand(player, opponents, card, effect_data, turn, *, phase="resolution"):
    target_player, target_reason = _look_at_hand_target_player(player, opponents, effect_data)
    hand_cards = [
        hand_card
        for hand_card in (getattr(target_player, "hand", []) or [])
        if isinstance(hand_card, dict)
    ]
    hand_names = [hand_card.get("name", "?") for hand_card in hand_cards]
    emit_replay_event(
        "look_at_target_player_hand_resolved",
        player=player.name,
        card=card.get("name", "?"),
        target_player=getattr(target_player, "name", "?"),
        target_reason=target_reason,
        target_player_scope=str(effect_data.get("target_player_scope") or "any"),
        hand_size=len(hand_cards),
        hand_card_names=hand_names,
        turn=turn,
        phase=phase,
        **replay_rule_fields(effect_data),
    )
    return {
        "effect": "look_at_target_player_hand",
        "target_player": getattr(target_player, "name", "?"),
        "target_reason": target_reason,
        "target_player_scope": str(effect_data.get("target_player_scope") or "any"),
        "hand_size": len(hand_cards),
        "hand_card_names": hand_names,
    }


def resolve_composite_resolution_effect(player, opponents, card, effect_data, turn, rng, *, stack=None, phase="resolution"):
    """Resolve opt-in same-spell components without moving the source card twice."""
    applied = []
    skipped = []
    components = effect_data.get("_composite_rule_components") or []
    participants = [player, *list(opponents or [])]
    for index, component in enumerate(components):
        component_effect = component.get("effect")
        component_fields = replay_rule_fields(component)
        outcome = "unsupported_component"
        if component_effect == "draw_cards":
            if component.get("discover_value"):
                discover_result = resolve_discover_value(
                    player,
                    opponents,
                    participants,
                    card,
                    component,
                    turn,
                    rng,
                    stack=stack,
                    phase=phase,
                    finish=False,
                )
                effect_data["_last_discover_result"] = discover_result
                outcome = "discover_resolved"
                applied.append({"effect": component_effect, **discover_result})
            else:
                count = int(component.get("count") or component.get("amount") or component.get("draw_count") or 1)
                optional_cost = str(component.get("optional_cost") or "").strip()
                if optional_cost == "discard_card":
                    discard_count = max(
                        1,
                        int(component.get("optional_cost_count") or component.get("discard_count") or 1),
                    )
                    hand_candidates = [
                        candidate
                        for candidate in (getattr(player, "hand", []) or [])
                        if isinstance(candidate, dict)
                    ]
                    if len(hand_candidates) < discard_count:
                        outcome = "optional_discard_cost_unpaid"
                        component_fields["optional_cost"] = optional_cost
                        component_fields["optional_cost_count"] = discard_count
                        component_fields["optional_cost_paid"] = False
                        skipped.append(
                            {
                                "effect": component_effect,
                                "reason": outcome,
                                "optional_cost": optional_cost,
                                "optional_cost_count": discard_count,
                            }
                        )
                    else:
                        discarded_cards = _draw_discard_spell_selected_discards(
                            player,
                            discard_count,
                            rng=rng,
                        )
                        if len(discarded_cards) != discard_count:
                            outcome = "optional_discard_cost_unpaid"
                            component_fields["optional_cost"] = optional_cost
                            component_fields["optional_cost_count"] = discard_count
                            component_fields["optional_cost_paid"] = False
                            skipped.append(
                                {
                                    "effect": component_effect,
                                    "reason": outcome,
                                    "optional_cost": optional_cost,
                                    "optional_cost_count": discard_count,
                                }
                            )
                        else:
                            discard_resolution = resolve_effect_discard_cards(
                                player,
                                discarded_cards,
                                top_limit=0,
                                opponents=opponents,
                                turn=turn,
                                phase=phase,
                                rng=rng,
                            )
                            drawn = player.draw(max(0, count), rng)
                            outcome = "cards_drawn"
                            discarded_names = [
                                discarded.get("name", "?")
                                for discarded in discarded_cards
                                if isinstance(discarded, dict)
                            ]
                            component_fields["optional_cost"] = optional_cost
                            component_fields["optional_cost_count"] = discard_count
                            component_fields["optional_cost_paid"] = True
                            component_fields["discarded"] = discarded_names
                            component_fields["discarded_to_graveyard"] = [
                                entry.get("name", "?")
                                for entry in discard_resolution.get("to_graveyard", [])
                                if isinstance(entry, dict)
                            ]
                            applied.append(
                                {
                                    "effect": component_effect,
                                    "count": len(drawn),
                                    "optional_cost": optional_cost,
                                    "discarded": discarded_names,
                                }
                            )
                else:
                    player.draw(max(0, count), rng)
                    outcome = "cards_drawn"
                    applied.append({"effect": component_effect, "count": count})
        elif component_effect == "proliferate":
            component_payload = dict(component)
            component_payload["_composite_component_index"] = index
            for key in (
                "_rule_source",
                "_rule_review_status",
                "_rule_execution_status",
                "_rule_confidence",
                "_rule_version",
                "_rule_logical_key",
                "_rule_oracle_hash",
                "card_id",
                "semantic_hash",
                "semantics_hash",
            ):
                if effect_data.get(key) is not None and component_payload.get(key) is None:
                    component_payload[key] = effect_data.get(key)
            summary = resolve_proliferate_effect(
                player,
                opponents,
                card,
                component_payload,
                turn,
                finish=False,
                component_index=index,
                phase=phase,
            )
            outcome = "proliferate_resolved"
            applied.append(summary)
        elif component_effect == "put_land_from_hand_onto_battlefield":
            selected_land, land_options, selection_reason = choose_land_from_hand_to_put_onto_battlefield(player)
            if selected_land is None:
                outcome = "no_land_card_in_hand"
                skipped.append({"effect": component_effect, "reason": outcome})
                emit_replay_event(
                    "put_land_from_hand_to_battlefield_resolved",
                    player=player.name,
                    card=card.get("name", "?"),
                    result="no_land_card_in_hand",
                    optional=bool(component.get("optional", True)),
                    land_options=land_options,
                    component_index=index,
                    turn=turn,
                    phase=phase,
                    **component_fields,
                )
            else:
                if selected_land in player.hand:
                    player.hand.remove(selected_land)
                permanent = enrich_card({**selected_land, "effect": "land"})
                if component.get("put_land_tapped"):
                    permanent["enters_tapped"] = True
                permanent = prepare_entering_permanent(
                    permanent,
                    controller=player,
                    all_players=participants,
                    turn=turn,
                )
                initialize_special_land_runtime_state(permanent, turn=turn)
                player.battlefield.append(permanent)
                trigger_landfall(
                    player,
                    permanent,
                    turn,
                    "put_land_from_hand_to_battlefield",
                    opponents=opponents,
                    stack=stack,
                    active_player=player,
                    all_players=participants,
                )
                outcome = "land_put_onto_battlefield"
                applied.append(
                    {
                        "effect": component_effect,
                        "land": permanent.get("name", "?"),
                        "destination": "battlefield",
                        "tapped": bool(permanent.get("tapped")),
                    }
                )
                emit_replay_event(
                    "put_land_from_hand_to_battlefield_resolved",
                    player=player.name,
                    card=card.get("name", "?"),
                    result="land_put_onto_battlefield",
                    land=permanent.get("name", "?"),
                    destination="battlefield",
                    tapped=bool(permanent.get("tapped")),
                    optional=bool(component.get("optional", True)),
                    land_options=land_options,
                    selection_reason=selection_reason,
                    component_index=index,
                    turn=turn,
                    phase=phase,
                    **component_fields,
                )
        elif component_effect == "life_total_change":
            target = _life_total_change_target(player, opponents, component)
            life_before = int(getattr(target, "life", 0) or 0)
            dynamic_replay_fields = {}
            if component.get("life_gain_amount_source"):
                dynamic_amount, dynamic_replay_fields = dynamic_life_gain_amount(player, opponents, component)
                requested_delta = int(dynamic_amount or 0)
            else:
                requested_delta = int(component.get("life_gain_amount") or 0)
            changed = gain_life(target, requested_delta, cap=999) if requested_delta else False
            life_after = int(getattr(target, "life", life_before) or 0)
            outcome = "life_total_changed"
            applied.append(
                {
                    "effect": component_effect,
                    "life_gain_amount": requested_delta,
                    "life_gained": max(0, life_after - life_before),
                }
            )
            emit_replay_event(
                "life_total_changed",
                player=player.name,
                card=card.get("name", "?"),
                target_player=getattr(target, "name", None),
                mode="gain_life",
                requested_delta=requested_delta,
                life_before=life_before,
                expected_life_after=life_before + requested_delta,
                life_after=life_after,
                changed=changed,
                component_index=index,
                turn=turn,
                **dynamic_replay_fields,
                **component_fields,
            )
        elif component_effect == "stat_modifier_until_eot":
            component_payload = dict(component)
            component_payload["_composite_component_index"] = index
            target_result = resolve_stat_modifier_until_eot_spell(
                player,
                opponents,
                card,
                component_payload,
                turn,
                finish=False,
            )
            power_delta = int(component.get("power_delta") or component.get("power_boost") or 0)
            toughness_delta = int(component.get("toughness_delta") or component.get("toughness_boost") or 0)
            targets = (
                [target for target in target_result if isinstance(target, dict)]
                if isinstance(target_result, list)
                else ([target_result] if isinstance(target_result, dict) else [])
            )
            if not targets:
                outcome = "no_legal_target"
                skipped.append({"effect": component_effect, "reason": outcome})
            else:
                outcome = "stat_modifier_until_eot_applied"
                summary = {
                    "effect": component_effect,
                    "target_count": len(targets),
                    "targets": [target.get("name", "?") for target in targets],
                    "power_delta": power_delta,
                    "toughness_delta": toughness_delta,
                }
                if len(targets) == 1:
                    summary["target"] = targets[0].get("name", "?")
                applied.append(summary)
        elif component_effect == "stat_modifier_until_eot_untap_target":
            component_payload = dict(component)
            component_payload["_composite_component_index"] = index
            targets = resolve_stat_modifier_until_eot_untap_target_spell(
                player,
                opponents,
                card,
                component_payload,
                turn,
                finish=False,
            )
            power_delta = int(component.get("power_delta") or component.get("power_boost") or 0)
            toughness_delta = int(component.get("toughness_delta") or component.get("toughness_boost") or 0)
            if not targets:
                outcome = "no_legal_target"
                skipped.append({"effect": component_effect, "reason": outcome})
            else:
                outcome = "stat_modifier_until_eot_untap_target_applied"
                applied.append(
                    {
                        "effect": component_effect,
                        "target_count": len(targets),
                        "power_delta": power_delta,
                        "toughness_delta": toughness_delta,
                        "target_colors_until_eot": component.get("target_colors_until_eot") or [],
                    }
                )
        elif component_effect == "tap_target":
            component_payload = dict(component)
            component_payload["_composite_component_index"] = index
            tapped_targets = apply_tap_target_spell(
                player,
                opponents,
                card,
                component_payload,
                turn,
                rng,
                finish=False,
            )
            if not tapped_targets:
                outcome = "no_legal_target"
                skipped.append({"effect": component_effect, "reason": outcome})
            else:
                outcome = "tap_target_spell_used"
                applied.append(
                    {
                        "effect": component_effect,
                        "target_count": len(tapped_targets),
                        "target_colors_until_eot": component.get("target_colors_until_eot") or [],
                    }
                )
        elif component_effect == "global_stat_modifier_until_eot":
            component_payload = dict(component)
            component_payload["_composite_component_index"] = index
            affected = resolve_global_stat_modifier_until_eot_spell(
                player,
                opponents,
                card,
                component_payload,
                turn,
                finish=False,
            )
            power_delta = int(component.get("power_delta") or component.get("power_boost") or 0)
            toughness_delta = int(component.get("toughness_delta") or component.get("toughness_boost") or 0)
            if not affected:
                outcome = "no_affected_creatures"
                skipped.append({"effect": component_effect, "reason": outcome})
            else:
                outcome = "global_stat_modifier_until_eot_applied"
                applied.append(
                    {
                        "effect": component_effect,
                        "affected_count": len(affected),
                        "power_delta": power_delta,
                        "toughness_delta": toughness_delta,
                    }
                )
        elif component_effect == "ramp_ritual":
            produced, symbols = add_ritual_mana_to_pool(player, component, opponents)
            outcome = "ritual_mana_added"
            applied.append({"effect": component_effect, "mana_added": produced, "mana_symbols_added": symbols})
        elif component_effect == "treasure_maker":
            if component.get("discover_treasure_difference"):
                discover_result = effect_data.get("_last_discover_result") or {}
                discover_value = int(discover_result.get("discover_value") or component.get("discover_value") or 0)
                hit_mana_value = discover_result.get("hit_mana_value")
                treasure_count = (
                    max(0, discover_value - int(hit_mana_value or 0))
                    if hit_mana_value is not None
                    else int(component.get("treasure_count") or 0)
                )
            else:
                treasure_count = int(component.get("treasure_count") or 1)
            draw_count = int(component.get("draw_count") or 0)
            player.treasures += treasure_count
            if draw_count > 0:
                player.draw(draw_count, rng)
            outcome = "treasure_created"
            applied.append({
                "effect": component_effect,
                "treasures_created": treasure_count,
                "cards_drawn": draw_count,
            })
        elif component_effect == "token_maker":
            token_count = create_creature_tokens_from_effect(
                player,
                component,
                opponents=opponents,
                turn=turn,
                source_event="composite_token_maker",
                stack=stack,
                active_player=player,
                all_players=participants,
            )
            outcome = "tokens_created"
            applied.append({"effect": component_effect, "tokens_created": token_count})
        elif component_effect == "phase_out":
            include_lands = bool(component.get("phase_out_includes_lands"))
            targets = []
            for permanent in list(player.battlefield):
                if include_lands:
                    targets.append(permanent)
                elif isinstance(permanent, dict) and permanent.get("effect") != "land":
                    targets.append(permanent)
            target_ids = {id(permanent) for permanent in targets}
            player.phased_out.extend(targets)
            player.battlefield = [
                permanent
                for permanent in player.battlefield
                if id(permanent) not in target_ids
            ]
            if component.get("life_total_cant_change"):
                player.life_cant_change = True
                player.life_cant_change_source = card
            if component.get("protection_from_everything"):
                player.protection_from_everything = True
                player.protection_from_everything_source = card
            outcome = "phase_out_resolved"
            applied.append({"effect": component_effect, "phased_count": len(targets)})
            emit_replay_event(
                "phase_out_resolved",
                player=player.name,
                card=card.get("name", "?"),
                phased=[
                    permanent.get("name", permanent.get("effect", "?"))
                    if isinstance(permanent, dict)
                    else str(permanent)
                    for permanent in targets
                ],
                phased_count=len(targets),
                phase_out_includes_lands=include_lands,
                life_total_cant_change=bool(component.get("life_total_cant_change")),
                protection_from_everything=bool(component.get("protection_from_everything")),
                component_index=index,
                turn=turn,
                **component_fields,
            )
        elif component_effect == "extra_turn":
            turns = int(component.get("turns") or 1)
            player.extra_turns += turns
            if component.get("lose_after_extra_turn"):
                player.extra_turn_loss_pending += turns
            outcome = "extra_turn_scheduled"
            applied.append({"effect": component_effect, "extra_turns": turns})
        elif component_effect == "extra_combat":
            combats = int(component.get("combats") or component.get("extra_combats") or 1)
            player.extra_combats += max(0, combats)
            if component.get("untap_creatures", True):
                for permanent in player.battlefield:
                    if is_battlefield_creature(permanent):
                        permanent["tapped"] = False
            outcome = "extra_combat_scheduled"
            applied.append({"effect": component_effect, "extra_combats": combats})
        elif component_effect == "scry":
            count = int(component.get("count") or component.get("scry_count") or 1)
            scry_result = scry_library_for_controller(player, count)
            outcome = "scry_resolved"
            applied.append(
                {
                    "effect": component_effect,
                    "count": count,
                    "looked_at": scry_result["looked_at"],
                    "kept_on_top": scry_result["kept_on_top"],
                    "bottomed": scry_result["bottomed"],
                    "top_after": scry_result["top_after"],
                }
            )
            emit_replay_event(
                "scry_resolved",
                player=player.name,
                card=card.get("name", "?"),
                scry_count=count,
                looked_at=scry_result["looked_at"],
                kept_on_top=scry_result["kept_on_top"],
                bottomed=scry_result["bottomed"],
                top_after=scry_result["top_after"],
                component_index=index,
                turn=turn,
                phase=phase,
                **component_fields,
            )
        elif component_effect == "surveil":
            count = int(component.get("count") or component.get("surveil_count") or 1)
            surveil_result = surveil_library_for_controller(player, count)
            outcome = "surveil_resolved"
            applied.append(
                {
                    "effect": component_effect,
                    "count": count,
                    "looked_at": surveil_result["looked_at"],
                    "kept_on_top": surveil_result["kept_on_top"],
                    "moved_to_graveyard": surveil_result["moved_to_graveyard"],
                    "top_after": surveil_result["top_after"],
                }
            )
            emit_replay_event(
                "surveil_resolved",
                player=player.name,
                card=card.get("name", "?"),
                surveil_count=count,
                looked_at=surveil_result["looked_at"],
                kept_on_top=surveil_result["kept_on_top"],
                moved_to_graveyard=surveil_result["moved_to_graveyard"],
                top_after=surveil_result["top_after"],
                component_index=index,
                turn=turn,
                phase=phase,
                **component_fields,
            )
        elif component_effect == "look_at_target_player_hand":
            component_payload = dict(component)
            component_payload["_composite_component_index"] = index
            summary = resolve_look_at_target_player_hand(
                player,
                opponents,
                card,
                component_payload,
                turn,
                phase=phase,
            )
            outcome = "look_at_hand_resolved"
            applied.append(summary)
        elif component_effect == "direct_damage":
            component_payload = dict(component)
            component_payload["_composite_component_index"] = index
            damage_payload = apply_direct_damage(
                player,
                opponents,
                card,
                component_payload,
                turn,
                rng,
                finish_spell=False,
                phase=phase,
            )
            if isinstance(damage_payload, dict):
                effect_data["_last_direct_damage_payload"] = dict(damage_payload)
                if damage_payload.get("target_player"):
                    effect_data["_last_direct_damage_target_player"] = damage_payload.get("target_player")
            amount = int(component.get("amount") or component.get("damage") or 0)
            outcome = "direct_damage_resolved"
            applied.append(
                {
                    "effect": component_effect,
                    "amount": amount,
                    "target": component.get("target"),
                }
            )
        elif component_effect == "target_player_discard":
            component_payload = dict(component)
            component_payload["_composite_component_index"] = index
            forced_target_player = None
            forced_target_reason = None
            if (
                component_payload.get("target_from_previous_damage")
                or str(component_payload.get("target_preference") or "").strip().lower()
                in {
                    "previous_damage_target",
                    "previous_damage_target_controller",
                    "last_damaged_player",
                }
            ):
                target_player_name = (
                    effect_data.get("_last_direct_damage_target_player")
                    or (effect_data.get("_last_direct_damage_payload") or {}).get("target_player")
                )
                forced_target_player = next(
                    (
                        participant
                        for participant in participants
                        if getattr(participant, "name", None) == target_player_name
                    ),
                    None,
                )
                if forced_target_player is not None:
                    forced_target_reason = "previous_damage_target_controller"
            discard_payload = resolve_target_player_discard_effect(
                player,
                opponents,
                card,
                component_payload,
                turn,
                rng,
                phase=phase,
                all_players=participants,
                event_name="target_player_discard_resolved",
                forced_target_player=forced_target_player,
                forced_target_reason=forced_target_reason,
            )
            outcome = "target_player_discard_resolved"
            applied.append(
                {
                    "effect": component_effect,
                    "discarded_count": int(discard_payload.get("discarded_count") or 0),
                    "target_player": discard_payload.get("target_player"),
                }
            )
        elif component_effect == "damage_each_opponent":
            component_payload = dict(component)
            component_payload["_composite_component_index"] = index
            apply_damage_each_opponent(
                player,
                opponents,
                card,
                component_payload,
                turn,
                finish_spell=False,
            )
            amount = int(component.get("amount") or component.get("damage") or 0)
            outcome = "damage_each_opponent_resolved"
            applied.append(
                {
                    "effect": component_effect,
                    "amount": amount,
                    "target_controller": component.get("target_controller") or "opponents",
                }
            )
        elif component_effect == "damage_wipe":
            component_payload = dict(component)
            component_payload["_composite_component_index"] = index
            apply_damage_wipe(
                player,
                opponents,
                card,
                component_payload,
                turn,
                finish_spell=False,
            )
            amount = int(component.get("amount") or component.get("damage") or 0)
            outcome = "damage_wipe_resolved"
            applied.append(
                {
                    "effect": component_effect,
                    "amount": amount,
                    "damage_scope": component.get("damage_scope"),
                }
            )
        elif component_effect in ("remove_creature", "remove_permanent", "remove_artifact_or_3dmg"):
            removed = False
            if resolve_multi_target_removal(player, opponents, card, component, turn, rng):
                removed = True
            else:
                for opp in opponents:
                    target_type = str(component.get("target") or "").lower()
                    if not target_type:
                        target_type = "creature" if component_effect == "remove_creature" else "nonland_permanent"
                    targets = removal_target_candidates(opp, component, controller=player, source=card)
                    if not targets:
                        continue
                    target = choose_best_creature_target(targets)
                    decision = targeting_decision(
                        card,
                        target,
                        player,
                        target_controller=opp,
                        target_type=target_type,
                    )
                    if check_ward(target, card, player, rng):
                        emit_replay_event(
                            "removal_countered_by_ward",
                            player=player.name,
                            card=card.get("name", "?"),
                            target_player=opp.name,
                            target=target.get("name", "?"),
                            component_index=index,
                            turn=turn,
                            **decision,
                        )
                        break
                    destination = removal_destination(component)
                    move_removed_permanent_to_destination(
                        opp,
                        target,
                        card,
                        component,
                        turn,
                        rng,
                        all_players=participants,
                    )
                    create_removal_compensation_tokens(component, opp, card, turn)
                    create_controller_treasures_after_removal(component, player, card, turn)
                    emit_replay_event(
                        "removal_resolved",
                        player=player.name,
                        card=card.get("name", "?"),
                        target_player=opp.name,
                        target=target.get("name", "?"),
                        target_effect=get_card_effect(target).get("effect", target.get("effect")),
                        target_power=target.get("power"),
                        target_toughness=target.get("toughness"),
                        target_is_creature=is_battlefield_creature(target),
                        target_type_line=target.get("type_line", ""),
                        available_targets=len(targets),
                        **target_selection_replay_fields(target, targets),
                        destination=destination,
                        component_index=index,
                        turn=turn,
                        **decision,
                    )
                    removed = True
                    break
            outcome = "removal_resolved" if removed else "no_legal_target"
            applied.append({"effect": component_effect, "removed": removed})
        elif component_effect == "graveyard_exile":
            component_payload = dict(component)
            component_payload["_composite_component_index"] = index
            exiled = resolve_graveyard_exile_spell(
                player,
                opponents,
                participants,
                card,
                component_payload,
                turn,
                phase=phase,
            )
            outcome = "graveyard_exile_resolved" if exiled else "no_legal_graveyard_target"
            applied.append({"effect": component_effect, "exiled": len(exiled)})
        else:
            skipped.append({"effect": component_effect, "reason": "unsupported_component"})

        emit_replay_event(
            "composite_rule_component_resolved",
            player=player.name,
            card=card.get("name", "?"),
            component_index=index,
            component_effect=component_effect,
            outcome=outcome,
            turn=turn,
            **component_fields,
        )
    tempting_offer_summary = resolve_tempting_offer_runtime(
        player,
        opponents,
        card,
        effect_data,
        turn,
        rng,
        stack=stack,
        phase=phase,
    )
    if tempting_offer_summary is not None:
        applied.append(tempting_offer_summary)
    return {"applied": applied, "skipped": skipped}


def _mode_with_parent_rule_fields(mode, parent_effect):
    payload = dict(mode or {})
    for key in (
        "_rule_source",
        "_rule_review_status",
        "_rule_execution_status",
        "_rule_confidence",
        "_rule_version",
        "_rule_logical_key",
        "_rule_oracle_hash",
        "card_id",
        "semantic_hash",
        "semantics_hash",
    ):
        if key in parent_effect and key not in payload:
            payload[key] = parent_effect[key]
    return payload


def _modal_mode_score(player, opponents, card, mode, turn, *, phase="resolution"):
    mode_effect = str((mode or {}).get("effect") or "")
    if mode_effect == "direct_damage":
        amount = int((mode or {}).get("amount") or (mode or {}).get("damage") or 0)
        if amount <= 0:
            return 0
        best = 0
        for opp in direct_damage_target_participants(player, opponents, mode):
            for target in removal_target_candidates(opp, mode, controller=player, source=card):
                target_amount = apply_static_damage_replacements(
                    player,
                    opp,
                    target,
                    card,
                    amount,
                    damage_event_type="permanent",
                    turn=turn,
                    phase=phase,
                    emit=False,
                )
                lethal = False
                if is_battlefield_creature(target):
                    lethal = card_toughness_value(target, default=2) <= target_amount
                elif is_planeswalker_permanent(target):
                    lethal = int(target.get("loyalty", target.get("starting_loyalty", 0)) or 0) <= target_amount
                elif is_battle_permanent(target):
                    lethal = int(target.get("defense", target.get("starting_defense", 0)) or 0) <= target_amount
                best = max(best, (90 if lethal else 40) + target_priority(target)[1])
        if direct_damage_targets_player(mode):
            for opp in opponents or []:
                if not opp.is_alive():
                    continue
                best = max(best, 120 if opp.life <= amount else 20 + min(amount, 10))
        return best
    if mode_effect in {"remove_creature", "remove_permanent", "remove_artifact_or_3dmg"}:
        best = 0
        for opp in opponents or []:
            for target in removal_target_candidates(opp, mode, controller=player, source=card):
                priority = target_priority(target)
                best = max(best, 100 + priority[1] + priority[2])
        return best
    return 0


def _resolve_modal_single_removal_mode(player, opponents, card, mode, turn, rng, *, phase="resolution"):
    for opp in opponents or []:
        target_type = str(mode.get("target") or "").lower()
        if not target_type:
            target_type = "creature" if mode.get("effect") == "remove_creature" else "nonland_permanent"
        targets = removal_target_candidates(opp, mode, controller=player, source=card)
        if not targets:
            continue
        target = choose_best_creature_target(targets)
        decision = targeting_decision(
            card,
            target,
            player,
            target_controller=opp,
            target_type=target_type,
        )
        if check_ward(target, card, player, rng):
            emit_replay_event(
                "removal_countered_by_ward",
                player=player.name,
                card=card.get("name", "?"),
                target_player=opp.name,
                target=target.get("name", "?"),
                turn=turn,
                phase=phase,
                **decision,
                **replay_rule_fields(mode),
            )
            return {"effect": mode.get("effect"), "outcome": "countered_by_ward", "target": target.get("name", "?")}
        destination = removal_destination(mode)
        emit_replay_event(
            "removal_resolved",
            player=player.name,
            card=card.get("name", "?"),
            target_player=opp.name,
            target=target.get("name", "?"),
            target_effect=get_card_effect(target).get("effect", target.get("effect")),
            target_power=target.get("power"),
            target_toughness=target.get("toughness"),
            target_is_creature=is_battlefield_creature(target),
            target_type_line=target.get("type_line", ""),
            available_targets=len(targets),
            **target_selection_replay_fields(target, targets),
            destination=destination,
            turn=turn,
            phase=phase,
            **decision,
            **replay_rule_fields(mode),
        )
        move_removed_permanent_to_destination(
            opp,
            target,
            card,
            mode,
            turn,
            rng,
            all_players=[player, *list(opponents or [])],
        )
        return {
            "effect": mode.get("effect"),
            "outcome": "removal_resolved",
            "target": target.get("name", "?"),
            "target_player": opp.name,
            "destination": destination,
        }
    return {"effect": mode.get("effect"), "outcome": "no_legal_target"}


def resolve_modal_damage_or_destroy_spell(player, opponents, card, effect_data, turn, rng, *, phase="resolution"):
    modes = [
        mode
        for mode in (effect_data.get("modal_modes") or [])
        if isinstance(mode, dict)
    ]
    scored_modes = [
        (_modal_mode_score(player, opponents, card, mode, turn, phase=phase), -index, index, mode)
        for index, mode in enumerate(modes)
    ]
    scored_modes = [item for item in scored_modes if item[0] > 0]
    if scored_modes:
        _score, _tie, selected_index, selected_mode = max(scored_modes)
    elif modes:
        selected_index, selected_mode = 0, modes[0]
    else:
        selected_index, selected_mode = -1, {}
    selected_payload = _mode_with_parent_rule_fields(selected_mode, effect_data)
    selected_payload["modal_mode_index"] = selected_index
    selected_payload["modal_mode"] = selected_mode.get("mode")
    if selected_mode.get("effect") == "direct_damage":
        apply_direct_damage(
            player,
            opponents,
            card,
            selected_payload,
            turn,
            rng,
            finish_spell=False,
            phase=phase,
        )
        outcome = "direct_damage_resolved"
    elif selected_mode.get("effect") in {"remove_creature", "remove_permanent", "remove_artifact_or_3dmg"}:
        removal_summary = _resolve_modal_single_removal_mode(
            player,
            opponents,
            card,
            selected_payload,
            turn,
            rng,
            phase=phase,
        )
        outcome = str(removal_summary.get("outcome") or "unknown")
    else:
        outcome = "unsupported_mode"
    selected_summary = {
        "index": selected_index,
        "mode": selected_mode.get("mode"),
        "effect": selected_mode.get("effect"),
        "outcome": outcome,
    }
    emit_replay_event(
        "modal_spell_resolved",
        player=player.name,
        card=card.get("name", "?"),
        selected_modes=[selected_summary] if selected_index >= 0 else [],
        mode_count=1 if selected_index >= 0 else 0,
        mode_min=int(effect_data.get("mode_min") or 1),
        mode_max=int(effect_data.get("mode_max") or 1),
        mode_selection=effect_data.get("mode_selection"),
        mode_selection_model=effect_data.get("mode_selection_model"),
        turn=turn,
        phase=phase,
        **replay_rule_fields(effect_data),
    )
    finish_resolved_spell(player, card, turn=turn, effect_data=effect_data)


def _life_total_change_target(player, opponents, effect_data):
    target = str((effect_data or {}).get("target") or "self").lower()
    if target in {"self", "controller"}:
        return player
    if target == "player" and (effect_data or {}).get("target_preference") == "self":
        return player
    return player


def resolve_life_total_change(player, opponents, card, effect_data, turn, rng):
    target = _life_total_change_target(player, opponents, effect_data)
    life_before = int(getattr(target, "life", 0) or 0)
    mode = "unknown"
    requested_delta = 0
    expected_life_after = life_before
    dynamic_replay_fields = {}

    if effect_data.get("life_total_becomes_library_size"):
        mode = "life_total_becomes_library_size"
        expected_life_after = len(getattr(target, "library", []) or [])
        requested_delta = expected_life_after - life_before
    elif effect_data.get("double_target_player_life_total"):
        mode = "double_target_player_life_total"
        expected_life_after = life_before * 2
        requested_delta = expected_life_after - life_before
    elif effect_data.get("life_gain_amount_source"):
        mode = "gain_life"
        dynamic_amount, dynamic_replay_fields = dynamic_life_gain_amount(player, opponents, effect_data)
        requested_delta = int(dynamic_amount or 0)
        expected_life_after = life_before + requested_delta
    else:
        mode = "gain_life"
        requested_delta = int(effect_data.get("life_gain_amount") or 0)
        expected_life_after = life_before + requested_delta

    if mode == "gain_life":
        changed = gain_life(target, requested_delta, cap=999) if requested_delta else False
    else:
        changed = change_life(target, requested_delta) if requested_delta else False
    life_after = int(getattr(target, "life", life_before) or 0)
    emit_replay_event(
        "life_total_changed",
        player=player.name,
        card=card.get("name", "?"),
        target_player=getattr(target, "name", None),
        mode=mode,
        requested_delta=requested_delta,
        life_before=life_before,
        expected_life_after=expected_life_after,
        life_after=life_after,
        changed=changed,
        turn=turn,
        **dynamic_replay_fields,
        **replay_rule_fields(effect_data),
    )

    if effect_data.get("shuffle_self_into_library_on_resolution"):
        player.library.append(card)
        player.shuffle(rng)
        emit_replay_event(
            "spell_shuffled_into_library_on_resolution",
            player=player.name,
            card=card.get("name", "?"),
            turn=turn,
            **replay_rule_fields(effect_data),
        )
    else:
        finish_resolved_spell(player, card, turn=turn, effect_data=effect_data)
    return changed


def _discard_unless_candidate_matches(card, effect_data):
    if not isinstance(card, dict):
        return False
    if effect_data.get("discard_unless_basic_land"):
        return _is_basic_land_card(card)
    card_types = [
        str(value).lower()
        for value in _as_list(effect_data.get("discard_unless_card_types"))
        if value
    ]
    if card_types:
        return _card_type_matches(card, card_types)
    return False


def _draw_discard_spell_selected_discards(player, discard_count, *, random_discard=False, rng=None, effect_data=None):
    discard_count = max(0, int(discard_count or 0))
    if discard_count <= 0:
        return []
    candidates = [card for card in getattr(player, "hand", []) or [] if isinstance(card, dict)]
    if not candidates:
        return []
    effect_data = effect_data or {}
    if effect_data.get("discard_unless_status") == "runtime_executor_v1":
        filtered = [card for card in candidates if _discard_unless_candidate_matches(card, effect_data)]
        if filtered:
            filtered.sort(
                key=lambda card: (
                    int(card_mana_value(card) or 0),
                    str(card.get("name") or ""),
                )
            )
            selected = [filtered[0]]
            if selected[0] in player.hand:
                player.hand.remove(selected[0])
            return selected
    if random_discard:
        chooser = rng or random
        selected = list(chooser.sample(candidates, min(discard_count, len(candidates))))
    else:
        selected = []
        for _ in range(discard_count):
            discard_card = _choose_currency_converter_discard(player)
            if discard_card is None:
                break
            selected.append(discard_card)
            player.hand.remove(discard_card)
        return selected
    for discard_card in selected:
        if discard_card in player.hand:
            player.hand.remove(discard_card)
    return selected


def _draw_discard_spell_requested_discard_count(discarded_cards, discard_count, effect_data):
    if effect_data.get("discard_unless_status") != "runtime_executor_v1":
        return discard_count
    paid_count = max(0, int(effect_data.get("discard_unless_count") or 1))
    if paid_count <= 0 or len(discarded_cards) != paid_count:
        return discard_count
    if all(_discard_unless_candidate_matches(card, effect_data) for card in discarded_cards):
        return paid_count
    return discard_count


def resolve_draw_discard_spell(
    player,
    opponents,
    card,
    effect_data,
    turn,
    rng,
    *,
    phase=None,
    all_players=None,
    stack=None,
):
    draw_count = max(0, int(effect_data.get("draw_count") or effect_data.get("count") or 0))
    discard_count = max(0, int(effect_data.get("discard_count") or 0))
    order = str(effect_data.get("draw_discard_order") or "draw_then_discard")
    random_discard = bool(effect_data.get("discard_random"))
    phase_name = phase or "resolution"
    all_players_for_triggers = all_players or [player] + list(opponents or [])
    drawn_cards = []
    discarded_cards = []
    discard_resolution = {
        "to_top": [],
        "to_graveyard": [],
        "used_replacement": False,
        "trigger_events": [],
    }

    def draw_step():
        nonlocal drawn_cards
        drawn_cards = player.draw(draw_count, rng)
        process_player_draw_triggers(
            player,
            len(drawn_cards),
            turn,
            phase_name,
            all_players_for_triggers,
            stack=stack,
            turn_player=player,
        )

    def discard_step():
        nonlocal discarded_cards, discard_resolution
        discarded_cards = _draw_discard_spell_selected_discards(
            player,
            discard_count,
            random_discard=random_discard,
            rng=rng,
            effect_data=effect_data,
        )
        if discarded_cards:
            discard_resolution = resolve_effect_discard_cards(
                player,
                discarded_cards,
                top_limit=0,
                opponents=opponents,
                turn=turn,
                phase=phase_name,
                rng=rng,
            )

    if order == "discard_then_draw":
        discard_step()
        draw_step()
    else:
        draw_step()
        discard_step()

    requested_discard_count = _draw_discard_spell_requested_discard_count(
        discarded_cards,
        discard_count,
        effect_data,
    )
    emit_replay_event(
        "draw_discard_spell_resolved",
        player=player.name,
        card=card.get("name", "?"),
        order=order,
        cards_drawn=len(drawn_cards),
        requested_draw_count=draw_count,
        cards_discarded=len(discarded_cards),
        requested_discard_count=requested_discard_count,
        discard_random=random_discard,
        discarded_to_graveyard=[
            entry.get("name", "?")
            for entry in discard_resolution.get("to_graveyard", [])
            if isinstance(entry, dict)
        ],
        discarded_to_library_top=[
            entry.get("name", "?")
            for entry in discard_resolution.get("to_top", [])
            if isinstance(entry, dict)
        ],
        library_remaining=len(player.library),
        hand_size=len(player.hand),
        turn=turn,
        **replay_rule_fields(effect_data),
    )


def _draw_lose_life_target_player(player, opponents, effect_data):
    candidates = [player] + [
        opponent for opponent in (opponents or []) if getattr(opponent, "is_alive", lambda: True)()
    ]
    declared_names = []
    for entry in effect_data.get("declared_targets") or []:
        if isinstance(entry, dict):
            name = entry.get("target_player") or entry.get("player") or entry.get("name")
            if name:
                declared_names.append(str(name))
        elif entry:
            declared_names.append(str(entry))
    for declared_name in declared_names:
        for candidate in candidates:
            if getattr(candidate, "name", None) == declared_name:
                return candidate, "declared_target"

    life_loss = max(0, int(effect_data.get("life_loss") or 0))
    lethal_opponents = [
        opponent
        for opponent in (opponents or [])
        if getattr(opponent, "is_alive", lambda: True)()
        and int(getattr(opponent, "life", 0) or 0) <= life_loss
    ]
    if lethal_opponents:
        lethal_opponents.sort(key=lambda opponent: (int(getattr(opponent, "life", 0) or 0), opponent.name))
        return lethal_opponents[0], "lethal_opponent"
    return player, "self_draw_preferred"


def _target_player_draw_target_player(player, opponents, effect_data):
    candidates = [player] + [
        opponent for opponent in (opponents or []) if getattr(opponent, "is_alive", lambda: True)()
    ]
    declared_names = []
    for entry in effect_data.get("declared_targets") or []:
        if isinstance(entry, dict):
            target = entry.get("target")
            name = (
                entry.get("target_player")
                or entry.get("player")
                or entry.get("name")
                or getattr(target, "name", None)
            )
            if name:
                declared_names.append(str(name))
        elif entry:
            declared_names.append(str(entry))
    for declared_name in declared_names:
        for candidate in candidates:
            if getattr(candidate, "name", None) == declared_name:
                return candidate, "declared_target"

    if str(effect_data.get("target_preference") or "self") == "opponent":
        alive_opponents = [
            opponent for opponent in (opponents or []) if getattr(opponent, "is_alive", lambda: True)()
        ]
        if alive_opponents:
            alive_opponents.sort(key=lambda opponent: (len(getattr(opponent, "hand", []) or []), opponent.name))
            return alive_opponents[0], "opponent_preferred"
    return player, "self_draw_preferred"


def resolve_target_player_draw_spell(
    player,
    opponents,
    card,
    effect_data,
    turn,
    rng,
    *,
    phase=None,
    all_players=None,
    stack=None,
):
    if str(effect_data.get("draw_count_source") or "").strip().lower() == "x_value":
        draw_count = x_value_from_effect_context(effect_data)
    else:
        draw_count = max(0, int(effect_data.get("draw_count") or effect_data.get("count") or 0))
    target_player, target_reason = _target_player_draw_target_player(player, opponents, effect_data)
    drawn_cards = target_player.draw(draw_count, rng)
    process_player_draw_triggers(
        target_player,
        len(drawn_cards),
        turn,
        phase or "resolution",
        all_players or [player] + list(opponents or []),
        stack=stack,
        turn_player=player,
    )
    emit_replay_event(
        "draw_cards_resolved",
        player=player.name,
        card=card.get("name", "?"),
        target_player=getattr(target_player, "name", "?"),
        target_reason=target_reason,
        target_controller=str(effect_data.get("target_controller") or "target_player"),
        target_player_draw=True,
        cards_drawn=len(drawn_cards),
        requested_draw_count=draw_count,
        library_remaining=len(target_player.library),
        hand_size=len(target_player.hand),
        turn=turn,
        **replay_rule_fields(effect_data),
    )


def _target_player_mill_target_player(player, opponents, effect_data, mill_count):
    candidates = [player] + [
        opponent for opponent in (opponents or []) if getattr(opponent, "is_alive", lambda: True)()
    ]
    declared_names = []
    for entry in (effect_data or {}).get("declared_targets") or []:
        if isinstance(entry, dict):
            target = entry.get("target")
            name = (
                entry.get("target_player")
                or entry.get("player")
                or entry.get("name")
                or getattr(target, "name", None)
            )
            if name:
                declared_names.append(str(name))
        elif entry:
            declared_names.append(str(entry))
    for declared_name in declared_names:
        for candidate in candidates:
            if getattr(candidate, "name", None) == declared_name:
                return candidate, "declared_target"

    preference = str((effect_data or {}).get("target_preference") or "opponent").lower()
    if preference in {"self", "controller"}:
        return player, "self_preference"
    target = choose_mill_target(player, opponents or [], mill_count)
    if target is player:
        return target, "fallback_self_no_opponent"
    return target, "opponent_mill_preferred"


def resolve_target_player_mill_spell(
    player,
    opponents,
    card,
    effect_data,
    turn,
    rng,
    *,
    phase=None,
    all_players=None,
    stack=None,
):
    mill_count = max(0, int((effect_data or {}).get("mill_count") or (effect_data or {}).get("count") or 0))
    target_player, target_reason = _target_player_mill_target_player(
        player,
        opponents,
        effect_data,
        mill_count,
    )
    library_before = len(getattr(target_player, "library", []) or [])
    milled = []
    for _ in range(min(mill_count, len(getattr(target_player, "library", []) or []))):
        milled_card = target_player.library.pop(0)
        target_player.graveyard.append(milled_card)
        milled.append(milled_card)
    emit_replay_event(
        "mill_resolved",
        player=player.name,
        card=card.get("name", "?"),
        target_player=getattr(target_player, "name", "?"),
        target_reason=target_reason,
        target_controller=str((effect_data or {}).get("target_controller") or "target_player"),
        target_player_mill=True,
        requested_mill=mill_count,
        cards_milled=len(milled),
        milled=[milled_card.get("name", "?") for milled_card in milled if isinstance(milled_card, dict)][:12],
        target_library_before=library_before,
        target_library_after=len(getattr(target_player, "library", []) or []),
        turn=turn,
        phase=phase or "resolution",
        **replay_rule_fields(effect_data),
    )


def resolve_draw_lose_life_spell(
    player,
    opponents,
    card,
    effect_data,
    turn,
    rng,
    *,
    phase=None,
    all_players=None,
    stack=None,
):
    draw_count = max(0, int(effect_data.get("draw_count") or effect_data.get("count") or 0))
    life_loss = max(0, int(effect_data.get("life_loss") or 0))
    life_loss_mode = str(effect_data.get("life_loss_mode") or "").strip().lower()
    target_controller = str(effect_data.get("target_controller") or "self")
    if target_controller == "target_player":
        target_player, target_reason = _draw_lose_life_target_player(player, opponents, effect_data)
    else:
        target_player, target_reason = player, "self_fixed"

    drawn_cards = target_player.draw(draw_count, rng)
    process_player_draw_triggers(
        target_player,
        len(drawn_cards),
        turn,
        phase or "resolution",
        all_players or [player] + list(opponents or []),
        stack=stack,
        turn_player=player,
    )
    life_before = int(getattr(target_player, "life", 0) or 0)
    if life_loss_mode == "half_rounded_up":
        life_loss = max(0, (life_before + 1) // 2)
    if life_loss:
        change_life(target_player, -life_loss)
    life_after = int(getattr(target_player, "life", life_before) or 0)
    emit_replay_event(
        "draw_lose_life_spell_resolved",
        player=player.name,
        card=card.get("name", "?"),
        target_player=getattr(target_player, "name", "?"),
        target_reason=target_reason,
        target_controller=target_controller,
        cards_drawn=len(drawn_cards),
        requested_draw_count=draw_count,
        life_lost=life_loss,
        life_loss_mode=life_loss_mode or None,
        life_loss_rounding=effect_data.get("life_loss_rounding"),
        life_before=life_before,
        life_after=life_after,
        library_remaining=len(target_player.library),
        hand_size=len(target_player.hand),
        turn=turn,
        **replay_rule_fields(effect_data),
    )


def _target_player_discard_target_player(player, opponents, effect_data):
    preference = str((effect_data or {}).get("target_preference") or "opponent").lower()
    if preference in {"self", "controller"}:
        return player, "self_preference"
    candidates = [
        opponent
        for opponent in prioritize_evaluation_target_opponents(player, opponents or [])
        if getattr(opponent, "is_alive", lambda: True)()
    ]
    if not candidates:
        return player, "fallback_self_no_opponent"
    return max(
        candidates,
        key=lambda opponent: (
            len(getattr(opponent, "hand", []) or []),
            -int(getattr(opponent, "life", 0) or 0),
            getattr(opponent, "name", ""),
        ),
    ), "opponent_most_cards_in_hand"


def _target_player_discard_cards(target_player, discard_count, discard_random, rng):
    count = max(0, int(discard_count or 0))
    candidates = [card for card in getattr(target_player, "hand", []) or [] if isinstance(card, dict)]
    if count <= 0 or not candidates:
        return []
    count = min(count, len(candidates))
    if discard_random:
        chooser = rng or random
        return list(chooser.sample(candidates, count))
    return sorted(
        candidates,
        key=lambda card: (
            discard_replacement_priority(card, target_player),
            int(_opening_hand_card_cmc(card) or 0),
            card.get("name", "?"),
        ),
    )[:count]


def target_player_discard_count_from_effect(player, effect_data):
    count_source = str((effect_data or {}).get("discard_count_source") or "").strip().lower()
    if count_source == "x_value":
        return x_value_from_effect_context(effect_data), count_source
    if count_source == "domain_basic_land_types":
        return _domain_basic_land_type_count(player), count_source
    return max(0, int((effect_data or {}).get("discard_count") or (effect_data or {}).get("count") or 0)), ""


def resolve_target_player_discard_effect(
    player,
    opponents,
    card,
    effect_data,
    turn,
    rng,
    *,
    phase=None,
    all_players=None,
    event_name="target_player_discard_resolved",
    trigger=None,
    forced_target_player=None,
    forced_target_reason=None,
):
    discard_count, discard_count_source = target_player_discard_count_from_effect(player, effect_data)
    discard_random = bool(effect_data.get("discard_random"))
    if forced_target_player is not None:
        target_player = forced_target_player
        target_reason = forced_target_reason or "forced_target_player"
    else:
        target_player, target_reason = _target_player_discard_target_player(player, opponents, effect_data)
    hand_size_before = len(getattr(target_player, "hand", []) or [])
    discard_cards = _target_player_discard_cards(target_player, discard_count, discard_random, rng)
    removed = _remove_exact_cards_from_hand(target_player, discard_cards)
    participants = list(all_players or [player] + list(opponents or []))
    discard_resolution = resolve_effect_discard_cards(
        target_player,
        removed,
        top_limit=0,
        opponents=[participant for participant in participants if participant is not target_player],
        turn=turn,
        phase=phase or "resolution",
        rng=rng,
    )
    payload = {
        "player": player.name,
        "card": card.get("name", "?"),
        "target_player": getattr(target_player, "name", "?"),
        "target_reason": target_reason,
        "trigger": trigger or effect_data.get("trigger"),
        "effect": "target_player_discard",
        "requested_discard_count": discard_count,
        "discard_count_source": discard_count_source or None,
        "discarded_count": len(removed),
        "discard_random": discard_random,
        "discarded": [discarded.get("name", "?") for discarded in removed],
        "discarded_to_graveyard": [
            discarded.get("name", "?")
            for discarded in discard_resolution.get("to_graveyard", [])
        ],
        "discarded_to_top": [
            discarded.get("name", "?")
            for discarded in discard_resolution.get("to_top", [])
        ],
        "hand_size_before": hand_size_before,
        "hand_size_after": len(getattr(target_player, "hand", []) or []),
        "turn": turn,
        "phase": phase or "resolution",
        **replay_rule_fields(effect_data),
    }
    if effect_data.get("damaged_player"):
        payload["damaged_player"] = effect_data.get("damaged_player")
    if effect_data.get("reason") is not None:
        payload["reason"] = effect_data.get("reason")
    if effect_data.get("source") is not None:
        payload["source"] = effect_data.get("source")
    emit_replay_event(event_name, **payload)
    return payload


def resolve_target_player_discard_spell(
    player,
    opponents,
    card,
    effect_data,
    turn,
    rng,
    *,
    phase=None,
    all_players=None,
):
    return resolve_target_player_discard_effect(
        player,
        opponents,
        card,
        effect_data,
        turn,
        rng,
        phase=phase,
        all_players=all_players,
        event_name="target_player_discard_resolved",
    )


def resolve_proliferate_effect(
    player,
    opponents,
    card,
    effect_data,
    turn,
    *,
    finish=True,
    component_index=None,
    phase="resolution",
):
    participants = [player, *list(opponents or [])]
    permanent_details = []
    player_details = []
    total_counters_added = 0
    for participant in participants:
        player_added = []
        for counter_name in player_counter_names(participant):
            if add_one_player_counter_by_name(participant, counter_name):
                total_counters_added += 1
                player_added.append(
                    {
                        "counter": counter_name,
                        "new_count": int(
                            getattr(participant, "poison", 0) or 0
                        )
                        if counter_name == "poison"
                        else int((getattr(participant, "counters", {}) or {}).get(counter_name) or 0),
                    }
                )
        if player_added:
            player_details.append(
                {
                    "player": getattr(participant, "name", "?"),
                    "counters_added": player_added,
                }
            )
        for permanent in getattr(participant, "battlefield", []) or []:
            if not isinstance(permanent, dict):
                continue
            permanent_added = []
            for counter_name in counter_names_on_permanent(permanent):
                if add_one_counter_by_name(permanent, counter_name):
                    total_counters_added += 1
                    permanent_added.append(
                        {
                            "counter": counter_name,
                            "new_count": get_named_counter_count(permanent, counter_name),
                        }
                    )
            if permanent_added:
                permanent_details.append(
                    {
                        "controller": getattr(participant, "name", "?"),
                        "permanent": permanent.get("name", "?"),
                        "counters_added": permanent_added,
                    }
                )
    summary = {
        "effect": "proliferate",
        "permanent_count": len(permanent_details),
        "player_count": len(player_details),
        "counters_added": total_counters_added,
        "permanents": permanent_details,
        "players": player_details,
    }
    emit_replay_event(
        "proliferate_resolved",
        player=player.name,
        card=card.get("name", "?"),
        permanent_count=len(permanent_details),
        player_count=len(player_details),
        counters_added=total_counters_added,
        permanents=permanent_details,
        players=player_details,
        component_index=component_index,
        turn=turn,
        phase=phase,
        **replay_rule_fields(effect_data),
    )
    if finish:
        finish_resolved_spell(player, card, turn=turn, effect_data=effect_data)
    return summary


def apply_effect_immediate(
    player,
    opponents,
    card,
    turn,
    rng,
    effect_data_override=None,
    *,
    stack=None,
    phase=None,
):
    """v8: Apply card effect (called when spell resolves from stack)."""
    effect_data = copy.deepcopy(effect_data_override) if effect_data_override else get_card_effect(card)
    effect_data = normalize_runtime_effect_aliases(card, effect_data)
    if isinstance(card, dict) and isinstance(card.get("_cast_context"), dict) and not isinstance(effect_data.get("_cast_context"), dict):
        effect_data["_cast_context"] = copy.deepcopy(card["_cast_context"])
    if isinstance(card, dict) and card.get("x_value") is not None and effect_data.get("x_value") is None:
        effect_data["x_value"] = card.get("x_value")
    if isinstance(card, dict) and isinstance(effect_data.get("_cast_context"), dict):
        card["_cast_context"] = copy.deepcopy(effect_data["_cast_context"])
    effect = effect_data.get("effect", "unknown")
    if effect == "ramp_ritual" and effect_data.get("hand_exile_mana_ability"):
        activate_hand_exile_mana_ability(
            player,
            card,
            effect_data,
            turn,
            opponents,
            phase=phase,
        )
        return
    if (
        isinstance(card, dict)
        and (card.get("is_copy") or effect_data.get("_copied_from_spell"))
        and not effect_data.get("_resolution_context")
    ):
        attach_direct_resolution_context(
            effect_data,
            card,
            phase or "copy_resolution",
            priority_window="copy_direct_resolution",
            source_zone="stack_copy",
            locked_cost={"copied_spell": True},
        )
    if effect in TARGETED_REMOVAL_EFFECTS and not effect_data.get("declared_targets"):
        effect_data, _ = prepare_declared_removal_targets(
            player,
            opponents,
            card,
            effect_data,
        )
    if effect == "fated_clash_protect_then_destroy" and not effect_data.get("declared_targets"):
        effect_data, _ = prepare_fated_clash_targets(
            player,
            opponents,
            card,
            effect_data,
        )
    spell_resolved_fields = {
        **spell_resolution_context_fields(card, effect_data, effect, player=player),
        **replay_fields_for_declared_targets(effect_data),
        **replay_rule_fields(effect_data),
    }
    emit_replay_event(
        "spell_resolved",
        player=player.name,
        card=card.get("name", "?"),
        cmc=card.get("cmc", 0),
        type_line=card.get("type_line", ""),
        effect=effect,
        turn=turn,
        **spell_resolved_fields,
    )
    all_players_for_entry = bind_table_context([player] + list(opponents or []))

    def prepare_resolved_permanent(payload):
        if isinstance(payload, dict):
            cast_context = {}
            if isinstance(effect_data, dict):
                cast_context.update(copy.deepcopy(effect_data.get("_cast_context") or {}))
                cast_context.update(copy.deepcopy(effect_data.get("_resolution_context") or {}))
            if isinstance(card, dict):
                cast_context.update(copy.deepcopy(card.get("_cast_context") or {}))
            explicit_source_zone = (
                cast_context.get("source_zone")
                or payload.get("cast_from_zone")
                or payload.get("source_zone")
            )
            has_explicit_cast_context = bool(
                cast_context
                or payload.get("was_cast") is not None
                or explicit_source_zone
            )
            source_zone = str(explicit_source_zone or "").strip().lower()
            is_stack_copy = source_zone == "stack_copy" or bool(payload.get("is_copy"))
            if has_explicit_cast_context:
                payload["was_cast"] = bool(payload.get("was_cast", not is_stack_copy)) and not is_stack_copy
                payload["cast_from_zone"] = source_zone if not is_stack_copy else "stack_copy"
            else:
                payload.setdefault("was_cast", False)
                payload.setdefault("cast_from_zone", "")
        return prepare_entering_permanent(
            payload,
            controller=player,
            all_players=all_players_for_entry,
            turn=turn,
        )

    def refresh_static_power_toughness_after_battlefield_change():
        refresh_graveyard_count_creature_statics_for_player(
            player,
            turn=turn,
            phase=phase or "resolution",
            emit_events=True,
            all_players=all_players_for_entry,
        )
        controlled_refreshed = refresh_controlled_static_power_toughness_bonuses(
            player,
            turn=turn,
            phase=phase or "resolution",
            emit_events=True,
        )
        keyword_refreshed = refresh_controlled_static_keywords(
            player,
            turn=turn,
            phase=phase or "resolution",
            emit_events=True,
        )
        global_refreshed = refresh_all_global_static_power_toughness_bonuses(
            all_players_for_entry,
            turn=turn,
            phase=phase or "resolution",
            emit_events=True,
        )
        attachment_refreshed = refresh_all_dynamic_attachment_static_power_toughness(
            all_players_for_entry,
            turn=turn,
            phase=phase or "resolution",
            emit_events=True,
        )
        return controlled_refreshed + keyword_refreshed + global_refreshed + attachment_refreshed

    if effect == "composite_resolution":
        summary = resolve_composite_resolution_effect(
            player,
            opponents,
            card,
            effect_data,
            turn,
            rng,
            stack=stack,
            phase=phase or "resolution",
        )
        emit_replay_event(
            "composite_rule_resolved",
            player=player.name,
            card=card.get("name", "?"),
            components_applied=len(summary["applied"]),
            components_skipped=len(summary["skipped"]),
            applied=summary["applied"],
            skipped=summary["skipped"],
            turn=turn,
            **replay_rule_fields(effect_data),
        )
        if effect_data.get("exiles_self"):
            move_to_exile(player, card, reason="spell_exiles_self", turn=turn)
        else:
            finish_resolved_spell(player, card, turn=turn, effect_data=effect_data)
    elif effect == "life_total_change":
        resolve_life_total_change(player, opponents, card, effect_data, turn, rng)
    elif effect == "damage_prevention_reflect":
        chosen_source = effect_data.get("_chosen_damage_source") or {}
        chosen_source_name = (
            effect_data.get("_chosen_damage_source_name")
            or (chosen_source.get("name") if isinstance(chosen_source, dict) else None)
        )
        chosen_source_controller = effect_data.get("_chosen_damage_source_controller")
        reflect_player = next(
            (
                participant
                for participant in all_players_for_entry
                if participant.name == chosen_source_controller
            ),
            None,
        )
        prevention_amount = int(effect_data.get("prevent_damage_amount") or 999)
        if chosen_source_name and reflect_player is not None:
            add_damage_prevention_shield(
                player,
                prevention_amount,
                source=card.get("name", "damage_prevention_reflect"),
                source_match="chosen_source",
                chosen_source_name=chosen_source_name,
                chosen_source_controller=chosen_source_controller,
                reflect_to_player=reflect_player,
                reflect_card={**card, **effect_data},
                consume_once=True,
                turn=turn,
            )
            result = "shield_created"
        else:
            result = "no_chosen_source"
        emit_replay_event(
            "damage_prevention_reflect_created",
            player=player.name,
            card=card.get("name", "?"),
            chosen_source=chosen_source_name,
            chosen_source_controller=chosen_source_controller,
            reflect_target_player=getattr(reflect_player, "name", None),
            prevention_amount=prevention_amount if result == "shield_created" else 0,
            result=result,
            turn=turn,
            **replay_rule_fields(effect_data),
        )
        finish_resolved_spell(player, card, turn=turn, effect_data=effect_data)
    elif effect == "damage_prevention_shield":
        if is_instant(card) or is_sorcery(card):
            if (
                effect_data.get("prevent_all_combat_damage_this_turn")
                or effect_data.get("prevent_damage_from_creature_sources_this_turn")
            ):
                prevention = {
                    "source": card.get("name", "damage_prevention_shield"),
                    "source_controller": player.name,
                    "battle_model_scope": effect_data.get("battle_model_scope"),
                    "prevent_damage_scope": effect_data.get("prevent_damage_scope", "all_combat_damage"),
                    "prevent_damage_kind": effect_data.get("prevent_damage_kind", "combat_damage"),
                    "prevent_source_constraints": effect_data.get("prevent_source_constraints") or {},
                    "duration": effect_data.get("prevent_damage_duration", "until_end_of_turn"),
                    "turn": turn,
                }
                for participant in all_players_for_entry:
                    participant.combat_damage_prevention_effects.append(dict(prevention))
                emit_replay_event(
                    "combat_damage_prevention_created",
                    player=player.name,
                    card=card.get("name", "?"),
                    affected_players=[participant.name for participant in all_players_for_entry],
                    prevent_damage_scope=prevention["prevent_damage_scope"],
                    duration=prevention["duration"],
                    turn=turn,
                    **replay_rule_fields(effect_data),
                )
                finish_resolved_spell(player, card, turn=turn, effect_data=effect_data)
                return
            chosen_source = effect_data.get("_chosen_damage_source") or {}
            chosen_source_name = (
                effect_data.get("_chosen_damage_source_name")
                or (chosen_source.get("name") if isinstance(chosen_source, dict) else None)
            )
            chosen_source_controller = effect_data.get("_chosen_damage_source_controller")
            prevention_amount = int(effect_data.get("prevent_damage_amount") or 999)
            if chosen_source_name:
                add_damage_prevention_shield(
                    player,
                    prevention_amount,
                    source=card.get("name", "damage_prevention_shield"),
                    source_match="chosen_source",
                    chosen_source_name=chosen_source_name,
                    chosen_source_controller=chosen_source_controller,
                    consume_once=True,
                    turn=turn,
                )
                result = "shield_created"
            else:
                result = "no_chosen_source"
            emit_replay_event(
                "damage_prevention_shield_created",
                player=player.name,
                card=card.get("name", "?"),
                chosen_source=chosen_source_name,
                chosen_source_controller=chosen_source_controller,
                prevention_amount=prevention_amount if result == "shield_created" else 0,
                result=result,
                turn=turn,
                **replay_rule_fields(effect_data),
            )
            finish_resolved_spell(player, card, turn=turn, effect_data=effect_data)
        else:
            permanent = prepare_resolved_permanent(enrich_card({**card, **effect_data}))
            permanent["effect"] = "damage_prevention_shield"
            player.battlefield.append(permanent)
    elif effect == "land": pass
    elif effect == "creature":
        permanent = prepare_resolved_permanent(enrich_card({**card, **effect_data}))
        if not permanent.get("creature_type_suppressed"):
            permanent["effect"] = "creature"
        player.battlefield.append(permanent)
        register_static_spell_limit_restriction(
            player,
            permanent,
            all_players_for_entry,
            turn=turn,
        )
        refresh_controlled_static_indestructible(
            player,
            turn=turn,
            phase=phase or "resolution",
            emit_events=True,
        )
        refresh_static_power_toughness_after_battlefield_change()
        resolve_generic_permanent_etb(
            player,
            opponents,
            permanent,
            effect_data,
            turn,
            rng,
            stack=stack,
            all_players=all_players_for_entry,
            phase=phase or "resolution",
        )
        process_controlled_creature_enters_triggers(
            player,
            opponents,
            permanent,
            turn,
            source_event="creature_spell_resolved",
            stack=stack,
            active_player=player,
            all_players=[player, *(opponents or [])],
        )
        process_opponent_controlled_creature_enters_triggers(
            player,
            permanent,
            turn,
            source_event="creature_spell_resolved",
            stack=stack,
            active_player=player,
            all_players=[player, *(opponents or [])],
        )
        emit_replay_event(
            "creature_to_battlefield",
            player=player.name,
            card=card.get("name", "?"),
            is_mana_source=bool(permanent.get("is_mana_source")),
            mana_produced=permanent.get("mana_produced"),
            summoning_sick=permanent.get("summoning_sick"),
            turn=turn,
        )
    elif effect in {"artifact", "enchantment", "permanent"}:
        permanent = prepare_resolved_permanent(enrich_card({**card, **effect_data}))
        permanent["effect"] = effect
        player.battlefield.append(permanent)
        register_static_spell_limit_restriction(
            player,
            permanent,
            all_players_for_entry,
            turn=turn,
        )
        refresh_controlled_static_indestructible(
            player,
            turn=turn,
            phase=phase or "resolution",
            emit_events=True,
        )
        refresh_static_power_toughness_after_battlefield_change()
        resolve_generic_permanent_etb(
            player,
            opponents,
            permanent,
            effect_data,
            turn,
            rng,
            stack=stack,
            all_players=all_players_for_entry,
            phase=phase or "resolution",
        )
        if is_battlefield_creature(permanent):
            process_controlled_creature_enters_triggers(
                player,
                opponents,
                permanent,
                turn,
                source_event="permanent_spell_resolved",
                stack=stack,
                active_player=player,
                all_players=[player, *(opponents or [])],
            )
            process_opponent_controlled_creature_enters_triggers(
                player,
                permanent,
                turn,
                source_event="permanent_spell_resolved",
                stack=stack,
                active_player=player,
                all_players=[player, *(opponents or [])],
            )
        emit_replay_event(
            "permanent_to_battlefield",
            player=player.name,
            card=card.get("name", "?"),
            effect=effect,
            is_mana_source=bool(permanent.get("is_mana_source")),
            turn=turn,
            **replay_rule_fields(effect_data),
        )
    elif effect == "goad_opponents_creatures_cant_block":
        affected = []
        source_player = getattr(player, "name", None)
        for opponent in opponents or []:
            for permanent in getattr(opponent, "battlefield", []) or []:
                if not is_battlefield_creature(permanent):
                    continue
                apply_until_next_turn_to_card(
                    permanent,
                    {
                        "goaded": True,
                        "goaded_by": card.get("name", "?"),
                        "must_attack_each_combat_if_able": True,
                        "cant_block": True,
                        "cant_block_source": card.get("name", "?"),
                    },
                    source_player=source_player,
                    turn=turn,
                )
                affected.append(
                    {
                        "controller": getattr(opponent, "name", "?"),
                        "card": permanent.get("name", "?"),
                    }
                )
        emit_replay_event(
            "goad_opponents_creatures_cant_block_resolved",
            player=player.name,
            card=card.get("name", "?"),
            affected_count=len(affected),
            affected=affected,
            duration="until_your_next_turn",
            turn=turn,
            **replay_rule_fields(effect_data),
        )
        finish_resolved_spell(player, card, turn=turn, effect_data=effect_data)
    elif effect == "copy_permanent_etb":
        permanent = enrich_card({**card, **effect_data})
        permanent = resolve_copy_permanent_etb(player, opponents, permanent, effect_data, turn)
        player.battlefield.append(permanent)
        resolve_generic_permanent_etb(
            player,
            opponents,
            permanent,
            permanent,
            turn,
            rng,
            stack=stack,
            all_players=all_players_for_entry,
            phase=phase or "resolution",
        )
        if is_battlefield_creature(permanent):
            process_controlled_creature_enters_triggers(
                player,
                opponents,
                permanent,
                turn,
                source_event="copy_permanent_etb",
                stack=stack,
                active_player=player,
                all_players=[player, *(opponents or [])],
            )
            process_opponent_controlled_creature_enters_triggers(
                player,
                permanent,
                turn,
                source_event="copy_permanent_etb",
                stack=stack,
                active_player=player,
                all_players=[player, *(opponents or [])],
            )
            emit_replay_event(
                "creature_to_battlefield",
                player=player.name,
                card=card.get("name", "?"),
                is_mana_source=bool(permanent.get("is_mana_source")),
                mana_produced=permanent.get("mana_produced"),
                summoning_sick=permanent.get("summoning_sick"),
                turn=turn,
            )
    elif effect == "blink":
        resolve_blink_effect(
            player,
            opponents,
            card,
            effect_data,
            turn,
            rng,
            all_players=all_players_for_entry,
            phase=phase or "resolution",
        )
        finish_resolved_spell(player, card, turn=turn, effect_data=effect_data)
    elif effect == "passive":
        if is_instant(card) or is_sorcery(card):
            finish_resolved_spell(player, card, turn=turn)
        else:
            permanent = prepare_resolved_permanent(enrich_card({**card, **effect_data}))
            permanent["effect"] = "passive"
            player.battlefield.append(permanent)
            if (
                permanent.get("battle_model_scope") == PROTOTYPE_PORTAL_SCOPE
                and permanent.get("imprint_artifact_card_from_hand_on_enter")
            ):
                resolve_prototype_portal_imprint(player, permanent, card, turn=turn)
            register_static_spell_limit_restriction(
                player,
                permanent,
                all_players_for_entry,
                turn=turn,
            )
            refresh_static_power_toughness_after_battlefield_change()
            resolve_generic_permanent_etb(
                player,
                opponents,
                permanent,
                effect_data,
                turn,
                rng,
                stack=stack,
                all_players=all_players_for_entry,
                phase=phase or "resolution",
            )
    elif effect == "static_cost_reduction":
        if is_instant(card) or is_sorcery(card):
            finish_resolved_spell(player, card, turn=turn)
        else:
            permanent = prepare_resolved_permanent(enrich_card({**card, **effect_data}))
            permanent["effect"] = "static_cost_reduction"
            player.battlefield.append(permanent)
            if (
                effect_data.get("choose_card_type_on_enter")
                or str(effect_data.get("cost_reduction_applies_to") or "").strip().lower()
                == CHOSEN_CARD_TYPE_COST_REDUCTION_APPLIES_TO
            ):
                resolve_chosen_card_type_cost_reducer(player, permanent, effect_data, turn=turn)
            if (
                effect_data.get("requires_imprint_nonland_card")
                or str(effect_data.get("cost_reduction_applies_to") or "").strip().lower()
                == SHARED_CARD_TYPE_COST_REDUCTION_APPLIES_TO
            ):
                resolve_semblance_anvil_imprint(player, permanent, card, turn=turn)
    elif effect == "static_cost_increase":
        if is_instant(card) or is_sorcery(card):
            finish_resolved_spell(player, card, turn=turn)
        else:
            permanent = prepare_resolved_permanent(enrich_card({**card, **effect_data}))
            permanent["effect"] = "static_cost_increase"
            player.battlefield.append(permanent)
    elif effect == "topdeck_play":
        if is_instant(card) or is_sorcery(card):
            finish_resolved_spell(player, card, turn=turn, effect_data=effect_data)
        else:
            permanent = prepare_resolved_permanent(enrich_card({**card, **effect_data}))
            permanent["effect"] = "topdeck_play"
            player.battlefield.append(permanent)
            if is_battlefield_creature(permanent):
                process_controlled_creature_enters_triggers(
                    player,
                    opponents,
                    permanent,
                    turn,
                    source_event="topdeck_play_permanent_resolved",
                    stack=stack,
                    active_player=player,
                    all_players=[player, *(opponents or [])],
                )
                process_opponent_controlled_creature_enters_triggers(
                    player,
                    permanent,
                    turn,
                    source_event="topdeck_play_permanent_resolved",
                    stack=stack,
                    active_player=player,
                    all_players=[player, *(opponents or [])],
                )
            emit_replay_event(
                "topdeck_play_static_permission_entered",
                player=player.name,
                card=card.get("name", "?"),
                look_top_library_any_time=bool(permanent.get("look_top_library_any_time")),
                each_player_top_library_revealed=bool(
                    permanent.get("each_player_top_library_revealed")
                ),
                activated_target_player_shuffle_library=bool(
                    permanent.get("activated_target_player_shuffle_library")
                ),
                look_opponent_face_down_creatures_any_time=bool(
                    permanent.get("look_opponent_face_down_creatures_any_time")
                ),
                play_lands_from_top_library=bool(permanent.get("play_lands_from_top_library")),
                may_cast_without_paying_mana_cost=bool(
                    permanent.get("may_cast_without_paying_mana_cost")
                ),
                turn=turn,
                **replay_rule_fields(effect_data),
            )
    elif effect == "flash_permission":
        permanent = prepare_resolved_permanent(enrich_card({**card, **effect_data}))
        permanent["effect"] = "flash_permission"
        player.battlefield.append(permanent)
        emit_replay_event(
            "static_permission_entered",
            player=player.name,
            card=card.get("name", "?"),
            permission="cast_nonland_spells_as_flash",
            filter=permanent.get("flash_permission_filter", "nonland_spells"),
            controller=permanent.get("flash_permission_controller", "self"),
            turn=turn,
            **replay_rule_fields(effect_data),
        )
    elif effect == "discard_trigger_modal_draw_treasure_opponent_life_loss":
        permanent = prepare_resolved_permanent(enrich_card({**card, **effect_data}))
        permanent["effect"] = effect
        player.battlefield.append(permanent)
    elif effect in ("attack_limit", "attack_tax"):
        permanent = prepare_resolved_permanent(enrich_card({**card, **effect_data}))
        permanent["effect"] = effect
        player.battlefield.append(permanent)
    elif effect == "land_tax":
        permanent = prepare_resolved_permanent(enrich_card({**card, **effect_data}))
        permanent["effect"] = "land_tax"
        player.battlefield.append(permanent)
    elif effect == "ramp_permanent":
        if not pay_additional_card_costs(player, card, effect_data, turn=turn):
            finish_resolved_spell(player, card, turn=turn)
            return
        permanent = prepare_resolved_permanent(enrich_card({**card, **effect_data}))
        player.battlefield.append(permanent)
        resolve_generic_permanent_etb(
            player,
            opponents,
            permanent,
            effect_data,
            turn,
            rng,
            stack=stack,
            all_players=all_players_for_entry,
            phase=phase or "resolution",
        )
        enters_treasure = int(
            effect_data.get("enters_treasure")
            or (
                effect_data.get("treasure_count")
                if effect_data.get("dies_or_graveyard_from_battlefield_treasure")
                else 0
            )
            or 0
        )
        if enters_treasure > 0:
            treasures_before = player.treasures
            player.treasures += enters_treasure
            emit_replay_event(
                "trigger_resolved",
                player=player.name,
                card=card.get("name", "?"),
                trigger="enters_battlefield",
                effect="create_treasure",
                treasures_created=enters_treasure,
                treasures_before=treasures_before,
                treasures_after=player.treasures,
                turn=turn,
                **replay_rule_fields(effect_data),
            )
    elif effect == "untap_land_engine":
        permanent = prepare_resolved_permanent(enrich_card({**card, **effect_data}))
        if is_creature_card(card) and effect_data.get("etb_untap_lands_count"):
            permanent["effect"] = "creature"
            permanent["haste"] = has_haste(permanent)
            permanent["summoning_sick"] = not permanent["haste"]
            permanent["tapped"] = False
        else:
            permanent["effect"] = "untap_land_engine"
        player.battlefield.append(permanent)
        etb_untap_count = int(effect_data.get("etb_untap_lands_count") or 0)
        if etb_untap_count > 0:
            tapped_lands = [
                land
                for land in player.battlefield
                if isinstance(land, dict)
                and is_effective_land(land)
                and land.get("tapped")
            ]
            selected_lands = tapped_lands[:etb_untap_count]
            for land in selected_lands:
                land["tapped"] = False
            emit_replay_event(
                "trigger_resolved",
                player=player.name,
                card=card.get("name", "?"),
                trigger="enters_battlefield",
                effect="untap_lands",
                untapped_lands=[land.get("name", "?") for land in selected_lands],
                untapped_count=len(selected_lands),
                max_count=etb_untap_count,
                optional=bool(effect_data.get("etb_untap_lands_optional")),
                turn=turn,
                phase=phase or "resolution",
                **replay_rule_fields(effect_data),
            )
    elif effect == "ramp_ritual":
        if not pay_additional_card_costs(player, card, effect_data, turn=turn):
            finish_resolved_spell(player, card, turn=turn)
